  function accessoryPixels(acc) {
    const out = [];
    if (!acc || !acc.rows) return out;
    Object.entries(acc.rows).forEach(([yKey, rowStr]) => {
      const y = Number(yKey);
      for (let x = 0; x < rowStr.length; x += 1) {
        const ch = rowStr[x];
        const fill = ch && ch !== '.' ? acc.colors?.[ch] : null;
        if (fill) out.push({ x, y, fill });
      }
    });
    return out;
  }



  function accessoryPatternPixels(pattern, colors = {}) {
    const rows = Array.isArray(pattern?.rows) ? pattern.rows : [];
    const out = [];
    rows.forEach((rowStr, y) => {
      for (let x = 0; x < String(rowStr || '').length; x += 1) {
        const ch = rowStr[x];
        const fill = ch && ch !== '.' ? colors?.[ch] : null;
        if (fill) out.push({ x, y, fill });
      }
    });
    return out;
  }

  function accessorySvg(acc) {
    const rects = accessoryPixels(acc).map((p) => `<rect x="${p.x}" y="${p.y}" width="1" height="1" fill="${p.fill}"/>`).join('');
    return `<svg class="ptg-acc-svg" viewBox="0 0 16 16" shape-rendering="crispEdges" aria-hidden="true">${rects}</svg>`;
  }

  function spriteAnchors(frame, eyeFrame) {
    const wsrc = eyeFrame || frame;
    const maxRun = (row) => {
      let best = 0; let cur = 0;
      for (const ch of row) { if (ch && ch !== '.') { cur += 1; if (cur > best) best = cur; } else cur = 0; }
      return best;
    };
    let headTop = 16;
    for (let y = 0; y < frame.length; y += 1) {
      const row = frame[y] || '';
      for (let x = 0; x < row.length; x += 1) if (row[x] && row[x] !== '.') { if (y < headTop) headTop = y; break; }
    }
    if (headTop === 16) headTop = 2;
    // 头顶锚点用“最长连续实心段”最先达标的行（额头/头顶主体），跳过耳尖、新芽与外鳃等细窄突起。
    const runs = frame.map((row) => maxRun(row || ''));
    const globalMax = Math.max(1, ...runs);
    const target = Math.min(8, globalMax);
    let crownRow = runs.findIndex((r) => r >= target);
    if (crownRow < 0) crownRow = headTop;
    const crownXs = [];
    { const row = frame[crownRow] || ''; for (let x = 0; x < row.length; x += 1) if (row[x] && row[x] !== '.') crownXs.push(x); }

    const eyePixels = [];
    for (let y = 0; y < wsrc.length; y += 1) {
      const row = wsrc[y] || '';
      for (let x = 0; x < row.length; x += 1) if (row[x] === 'W') eyePixels.push({ x, y });
    }
    const avg = (arr, fallback) => (arr.length ? Math.round(arr.reduce((a, b) => a + b, 0) / arr.length) : fallback);
    const headCenterX = avg(crownXs, 8);
    const eyeRow = eyePixels.length ? avg(eyePixels.map((p) => p.y), crownRow + 3) : crownRow + 3;
    const eyeCenterX = eyePixels.length ? avg(eyePixels.map((p) => p.x), headCenterX) : headCenterX;

    // 不再只保留一个“眼部中心点”。宽脸、横向水生体型会记录左右两只眼睛的独立锚点，
    // 双镜片配饰可以拆开后分别贴合，单片眼镜和眼罩也会落到指定眼睛上。
    let eyePoints = [];
    if (eyePixels.length >= 2) {
      const minEyeX = Math.min(...eyePixels.map((p) => p.x));
      const maxEyeX = Math.max(...eyePixels.map((p) => p.x));
      if (maxEyeX > minEyeX) {
        const splitX = (minEyeX + maxEyeX) / 2;
        const left = eyePixels.filter((p) => p.x <= splitX);
        const right = eyePixels.filter((p) => p.x > splitX);
        const pointOf = (list, fallbackX) => ({
          x: avg(list.map((p) => p.x), fallbackX),
          y: avg(list.map((p) => p.y), eyeRow),
        });
        if (left.length && right.length) eyePoints = [pointOf(left, minEyeX), pointOf(right, maxEyeX)];
      }
    }
    if (eyePoints.length < 2) {
      eyePoints = [
        { x: eyeCenterX, y: eyeRow },
        { x: eyeCenterX, y: eyeRow },
      ];
    }
    return {
      crownRow,
      headTop,
      headCenterX,
      eyeRow,
      eyeCenterX,
      eyePoints,
      eyeLeftX: eyePoints[0].x,
      eyeRightX: eyePoints[eyePoints.length - 1].x,
    };
  }

  function buildAccessoryRects(frame, eyeFrame) {
    const equipped = app.save?.wardrobe?.equipped || {};
    const anchors = spriteAnchors(frame, eyeFrame);
    let rects = '';

    const appendPlacedPixels = (pixels, targetX, targetY, anchorX = null, anchorY = null) => {
      if (!pixels.length) return;
      const xs = pixels.map((p) => p.x);
      const ys = pixels.map((p) => p.y);
      const sourceX = Number.isFinite(Number(anchorX)) ? Number(anchorX) : Math.round((Math.min(...xs) + Math.max(...xs)) / 2);
      const sourceY = Number.isFinite(Number(anchorY)) ? Number(anchorY) : Math.round((Math.min(...ys) + Math.max(...ys)) / 2);
      let dx = Math.round(Number(targetX) - sourceX);
      let dy = Math.round(Number(targetY) - sourceY);

      const minX = Math.min(...xs) + dx;
      const maxX = Math.max(...xs) + dx;
      const minY = Math.min(...ys) + dy;
      const maxY = Math.max(...ys) + dy;
      if (minX < 0) dx -= minX;
      if (maxX > 15) dx -= maxX - 15;
      if (minY < 0) dy -= minY;
      if (maxY > 15) dy -= maxY - 15;

      pixels.forEach((p) => {
        const X = p.x + dx;
        const Y = p.y + dy;
        if (X >= 0 && X < 16 && Y >= 0 && Y < 16) rects += `<rect x="${X}" y="${Y}" width="1" height="1" fill="${p.fill}"/>`;
      });
    };

    ['head', 'eyes'].forEach((slot) => {
      const acc = ACCESSORY_DEFS[equipped[slot]];
      if (!acc || acc.slot !== slot) return;
      const px = accessoryPixels(acc);
      if (!px.length) return;

      if (slot === 'head') {
        const xs = px.map((p) => p.x);
        const ys = px.map((p) => p.y);
        const placement = acc.headPlacement || {};
        const sourceX = Number.isFinite(Number(placement.anchorX)) ? Number(placement.anchorX) : Math.round((Math.min(...xs) + Math.max(...xs)) / 2);
        const sourceY = Number.isFinite(Number(placement.anchorY)) ? Number(placement.anchorY) : Math.max(...ys);
        const targetX = anchors.headCenterX + (Number(placement.offsetX) || 0);
        let targetY = anchors.crownRow + (Number(placement.offsetY) || 0);
        if (Number.isFinite(Number(placement.minTargetY))) targetY = Math.max(targetY, Number(placement.minTargetY));
        if (acc.floatAnimation) rects += '<g class="ptg-accessory-float">';
        appendPlacedPixels(px, targetX, targetY, sourceX, sourceY);
        if (acc.floatAnimation) {
          rects += '<animateTransform attributeName="transform" type="translate" values="0 0;0 -1;0 0" keyTimes="0;0.5;1" dur="1.6s" repeatCount="indefinite" calcMode="discrete"/></g>';
        }
        return;
      }

      const leftEye = anchors.eyePoints[0] || { x: anchors.eyeCenterX, y: anchors.eyeRow };
      const rightEye = anchors.eyePoints[anchors.eyePoints.length - 1] || leftEye;

      // 双镜片不再从整副眼镜的像素图中“硬切一半”。每个镜片都有独立的局部图案和明确的眼球锚点，
      // 因此宽眼距、窄眼距和不同脸型都只会移动镜片本身，不会把镜框中心或鼻梁误当成镜片中心。
      if (acc.eyeLayout === 'dual' && acc.eyePieces?.left && acc.eyePieces?.right) {
        const leftPixels = accessoryPatternPixels(acc.eyePieces.left, acc.colors);
        const rightPixels = accessoryPatternPixels(acc.eyePieces.right, acc.colors);
        const leftAnchor = acc.eyePieces.left.anchor || { x: 1, y: 1 };
        const rightAnchor = acc.eyePieces.right.anchor || { x: 1, y: 1 };
        if (leftEye.x === rightEye.x && leftEye.y === rightEye.y) {
          // 侧脸等只有一只可见眼睛的形态，只绘制一个镜片，避免两片完全叠在一起形成错位黑块。
          appendPlacedPixels(leftPixels, leftEye.x, leftEye.y, leftAnchor.x, leftAnchor.y);
        } else {
          appendPlacedPixels(leftPixels, leftEye.x, leftEye.y, leftAnchor.x, leftAnchor.y);
          appendPlacedPixels(rightPixels, rightEye.x, rightEye.y, rightAnchor.x, rightAnchor.y);
        }
        return;
      }

      const targetEye = acc.eyeLayout === 'left' ? leftEye : (acc.eyeLayout === 'right' ? rightEye : { x: anchors.eyeCenterX, y: anchors.eyeRow });
      appendPlacedPixels(px, targetEye.x, targetEye.y, acc.eyeAnchor?.x, acc.eyeAnchor?.y);
    });
    return rects;
  }


