  function randomAttributes() {
    const keys = Object.keys(ATTRIBUTE_DEFS);
    const result = Object.fromEntries(keys.map((key) => [key, 8]));
    for (let point = 0; point < 35; point += 1) {
      const candidates = keys.filter((key) => result[key] < 25);
      const key = randomChoice(candidates.length ? candidates : keys);
      result[key] += 1;
    }
    return result;
  }

  function normalizeAttributes(raw) {
    const fallback = randomAttributes();
    const source = raw && typeof raw === 'object' ? raw : fallback;
    return Object.fromEntries(Object.keys(ATTRIBUTE_DEFS).map((key) => [key, clamp(Math.round(Number(source[key] ?? fallback[key]) || 0), 0, 100)]));
  }

  function jobRequirementsMet(pet, job) {
    if (!pet || !job) return false;
    return Object.entries(job.requirements || {}).every(([key, required]) => Number(pet.attributes?.[key] || 0) >= Number(required));
  }

  function shiftWageMultiplier(durationHours) {
    if (durationHours >= 8) return 1.25;
    if (durationHours >= 4) return 1.15;
    if (durationHours >= 2) return 1.05;
    return 1;
  }

  function calculateJobReward(job, durationHours) {
    return Math.max(0, Math.floor(Number(job?.hourlyWage || 0) * durationHours * shiftWageMultiplier(durationHours)));
  }

  function shiftStrainMultiplier(durationHours) {
    if (durationHours >= 8) return 1.7;
    if (durationHours >= 4) return 1.4;
    if (durationHours >= 2) return 1.18;
    return 1;
  }

