      if (node.type === 'folder' || Array.isArray(node.scripts)) {
        visit(node.scripts, effectiveEnabled);
        return;
      }
      if (node.type !== 'script') return;
      const id = String(node.id || '').trim();
      const name = String(node.name || '').trim();
      if (id) byId.set(id, effectiveEnabled);
      if (name) byName.set(name, Boolean(byName.get(name)) || effectiveEnabled);
    });
  };
  ['global', 'preset', 'character'].forEach((type) => {
    try {
      const trees = getScriptTrees({ type });
      if (Array.isArray(trees)) {
        inspected = true;
        visit(trees, true);
      }
    } catch (_) {}
  });
  return inspected ? { byId, byName } : null;
}

function gameModuleScriptEnabled(module, states = null) {
  const snapshot = states || readTavernScriptStates();
  if (!snapshot || !module) return null;
  const scriptId = String(module.scriptId || '').trim();
  const scriptName = String(module.scriptName || BUILTIN_GAME_SCRIPT_NAMES[module.id] || '').trim();
  if (scriptId && snapshot.byId.has(scriptId)) return snapshot.byId.get(scriptId) === true;
  if (scriptName && snapshot.byName.has(scriptName)) return snapshot.byName.get(scriptName) === true;
  // 有脚本身份但已经从脚本树中删除，也视为未安装；完全没有身份信息的第三方运行时模块保持兼容。
  if (scriptId || scriptName) return false;
  return null;
}

function syncGameExtensionsWithScriptStates(force = false) {
  const now = Date.now();
  if (!force && now - lastGameScriptStateSyncAt < 1800) return false;
  lastGameScriptStateSyncAt = now;
  const states = readTavernScriptStates();
  if (!states) return false;
  const staleIds = [];
  GAME_MODULES.forEach((module, gameId) => {
    if (gameModuleScriptEnabled(module, states) === false) staleIds.push(gameId);
  });
  staleIds.forEach((gameId) => {
    if (gameExtensionBus?.modules?.has?.(gameId) && typeof gameExtensionBus.unregister === 'function') gameExtensionBus.unregister(gameId);
    else unregisterGameExtension(gameId);
  });
  return staleIds.length > 0;
}

function registerGameExtension(rawModule) {
  const module = normalizeGameExtensionModule(rawModule);
  if (!module) {
    console.warn('[像素拓麻歌子] 忽略了无效的小游戏扩展：', rawModule);
    return false;
  }
  const enabledState = gameModuleScriptEnabled(module);
  if (enabledState === false) {
    gameExtensionBus?.modules?.delete?.(module.id);
    return false;
  }
  const previous = GAME_MODULES.get(module.id);
  if (previous && previous !== module) {
    if (app.games.selected === module.id) releaseGameState(module.id);
    unloadGameExtensionImplementation(previous);
  }
  if (!loadGameExtensionImplementation(module)) return false;
  GAME_MODULES.set(module.id, module);
  GAME_DEFS[module.id] = module.definition;
  GAME_STATE_PROPERTY[module.id] = module.stateProperty;
  if (!(module.stateProperty in app.games)) app.games[module.stateProperty] = null;
  refreshGameOrder();
  ensureRegisteredGameSaveSlots(module.id);
  if (app.characterContextReady && app.save) {
    host.setTimeout(() => { void restoreLocalHighScoresFromLeaderboardOnce(); }, 120);
  }
  if (app.initialized && app.root?.classList.contains('ptg-open') && app.activeTab === 'games') render();
  return true;
}

function unregisterGameExtension(gameId) {
  const id = String(gameId || '');
  if (!GAME_MODULES.has(id)) return false;
  releaseGameState(id);
  unloadGameExtensionImplementation(GAME_MODULES.get(id));
  GAME_MODULES.delete(id);
  delete GAME_DEFS[id];
  delete GAME_STATE_PROPERTY[id];
  refreshGameOrder();
  if (app.games.leaderboardGameId === id) app.games.leaderboardGameId = GAME_IDS[0] || '';
  if (app.initialized && app.root?.classList.contains('ptg-open') && app.activeTab === 'games') render();
  return true;
}

function createGameExtensionBus() {
  let bus = host[GAME_EXTENSION_BUS_KEY];
  if (!bus || typeof bus !== 'object') bus = {};
  // 酒馆会让不同子脚本运行在不同 iframe / JS realm 中。
  // 跨 realm 的 Map / Set 无法通过当前脚本的 instanceof 判断，不能因此重建并清空共享注册表。
  const modulesAreMapLike = bus.modules
    && typeof bus.modules.get === 'function'
    && typeof bus.modules.set === 'function'
    && typeof bus.modules.delete === 'function'
    && typeof bus.modules.values === 'function';
  const listenersAreSetLike = bus.listeners
    && typeof bus.listeners.add === 'function'
    && typeof bus.listeners.delete === 'function'
    && typeof bus.listeners.forEach === 'function';
  if (!modulesAreMapLike) bus.modules = new (host.Map || Map)();
  if (!listenersAreSetLike) bus.listeners = new (host.Set || Set)();
  bus.apiVersion = GAME_EXTENSION_API_VERSION;
  bus.register = function register(module) {
    const id = String(module?.id || '').trim();
    if (!id) return false;
    this.modules.set(id, module);
    this.listeners.forEach((listener) => { try { listener('register', module); } catch (error) { console.warn('[像素拓麻歌子] 小游戏注册监听失败：', error); } });
    return true;
  };
  bus.unregister = function unregister(id) {
    const key = String(id || '');
    const existed = this.modules.delete(key);
    if (existed) this.listeners.forEach((listener) => { try { listener('unregister', key); } catch (_) {} });
    return existed;
  };
  bus.list = function list() { return [...this.modules.values()]; };
  host[GAME_EXTENSION_BUS_KEY] = bus;
  try { window[GAME_EXTENSION_BUS_KEY] = bus; } catch (_) {}
  return bus;
}

function connectGameExtensionBus() {
  gameExtensionBus = createGameExtensionBus();
  if (gameExtensionBusListener) gameExtensionBus.listeners.delete(gameExtensionBusListener);
  gameExtensionBusListener = (type, payload) => {
    if (type === 'register') registerGameExtension(payload);
    else if (type === 'unregister') unregisterGameExtension(payload);
  };
  gameExtensionBus.listeners.add(gameExtensionBusListener);
  gameExtensionBus.list().forEach(registerGameExtension);
  syncGameExtensionsWithScriptStates(true);
}

function disconnectGameExtensionBus() {
  if (gameExtensionBus && gameExtensionBusListener) gameExtensionBus.listeners.delete(gameExtensionBusListener);
  gameExtensionBusListener = null;
  gameExtensionBus = null;
}

