  function gachaWeightedRarity(cosmetics) {
    if (Math.max(0, Number(cosmetics.holoPity) || 0) >= GACHA_HOLO_PITY - 1) return 'holo';
    const roll = Math.random() * 100; let cursor = 0;
    for (const rarity of GACHA_RARITY_ORDER) { cursor += GACHA_RARITY_META[rarity].chance; if (roll < cursor) return rarity; }
    return 'common';
  }
  function gachaRandomRewardId(rarity) { const pool = GACHA_DRAWABLE_REWARD_IDS.filter((id) => GACHA_REWARDS[id].rarity === rarity); return pool[Math.floor(Math.random() * pool.length)] || GACHA_DRAWABLE_REWARD_IDS[0]; }
  function markLeaderboardShowcaseDirty() {
    const profile = leaderboardProfile(); if (!profile) return;
    profile.uploadedShowcaseSignatures = {};
    profile.updatedAt = nowMs();
    scheduleLeaderboardSync(180);
  }

  function gachaActualEquipped(profile = null) {
    const cosmetics = normalizeGachaState(profile?.cosmetics || leaderboardProfile()?.cosmetics);
    return Object.fromEntries(GACHA_SHOWCASE_SLOTS.map((slot) => [slot, cosmetics.equipped?.[slot] || null]));
  }

  function resetGachaShowcaseDraft(profile = null) {
    const target = profile || leaderboardProfile();
    app.games.gachaDraftEquipped = gachaActualEquipped(target);
    app.games.gachaDraftTouched = false;
    return app.games.gachaDraftEquipped;
  }

  function ensureGachaShowcaseDraft(profile = null) {
    const target = profile || leaderboardProfile();
    if (!app.games.gachaDraftEquipped || typeof app.games.gachaDraftEquipped !== 'object') return resetGachaShowcaseDraft(target);
    const draftSource = app.games.gachaDraftEquipped;
    const actual = gachaActualEquipped(target);
    const normalized = { badge: null, title: null, frame: null, gradient: null };
    GACHA_SHOWCASE_SLOTS.forEach((slot) => {
      const sourceValue = slot === 'gradient' && !Object.prototype.hasOwnProperty.call(draftSource, slot) ? actual.gradient : draftSource[slot];
      const id = String(sourceValue || '');
      const reward = GACHA_REWARDS[id];
      if (reward && gachaOwnedCount(id, target) > 0 && gachaRewardFitsShowcaseSlot(reward, slot)) normalized[slot] = id;
    });
    app.games.gachaDraftEquipped = normalized;
    return normalized;
  }

  function gachaDraftShowcase(profile = null) {
    return normalizePublicShowcase({ equipped: ensureGachaShowcaseDraft(profile) });
  }

  function gachaDraftChanged(profile = null) {
    const target = profile || leaderboardProfile();
    return JSON.stringify(gachaDraftShowcase(target)) !== JSON.stringify(gachaPublicShowcase(target));
  }

  function gachaRewardEquippedSlots(id, showcase) {
    const reward = GACHA_REWARDS[id];
    const equipped = normalizePublicShowcase(showcase).equipped;
    if (!reward) return [];
    if (reward.type === 'set') return GACHA_SHOWCASE_SLOTS.filter((slot) => equipped[slot] === id);
    return equipped[reward.type] === id ? [reward.type] : [];
  }

  function gachaRewardMatchesShowcase(id, showcase) {
    const reward = GACHA_REWARDS[id];
    const slots = gachaRewardEquippedSlots(id, showcase);
    if (!reward) return false;
    return reward.type === 'set' ? slots.length === GACHA_SHOWCASE_SLOTS.length : slots.length > 0;
  }

  function previewGachaReward(id, requestedSlot = '') {
    const profile = leaderboardProfile(); const reward = GACHA_REWARDS[id];
    if (!profile || !reward || gachaOwnedCount(id, profile) <= 0) return false;
    const draft = ensureGachaShowcaseDraft(profile);
    let changedSlot = reward.type;
    if (reward.type === 'set') {
      if (GACHA_SHOWCASE_SLOTS.includes(requestedSlot) && gachaRewardFitsShowcaseSlot(reward, requestedSlot)) {
        draft[requestedSlot] = id;
        changedSlot = requestedSlot;
      } else {
        GACHA_SHOWCASE_SLOTS.forEach((slot) => { draft[slot] = id; });
        changedSlot = 'all';
      }
    } else {
      draft[reward.type] = id;
    }
    app.games.gachaDraftTouched = true;
    const partText = changedSlot === 'all' ? '整套' : (GACHA_SHOWCASE_SLOT_NAMES[changedSlot] || GACHA_TYPE_NAMES[changedSlot] || '装扮');
    app.message = `正在预览「${reward.name}」的${partText}，点击“保存并上传”后才会同步到排行榜。`;
    return true;
  }

  function clearGachaShowcaseDraft(type = 'all') {
    const profile = leaderboardProfile(); if (!profile) return false;
    const draft = ensureGachaShowcaseDraft(profile);
    if (type === 'all') {
      GACHA_SHOWCASE_SLOTS.forEach((slot) => { draft[slot] = null; });
    } else if (GACHA_SHOWCASE_SLOTS.includes(type)) {
      draft[type] = null;
    } else return false;
    app.games.gachaDraftTouched = true;
    app.message = type === 'all' ? '预览中已卸下全部装扮，尚未保存。' : `预览中已卸下${GACHA_TYPE_NAMES[type] || GACHA_SHOWCASE_SLOT_NAMES[type]}，尚未保存。`;
    return true;
  }

  function cancelGachaShowcaseDraft() {
    const profile = leaderboardProfile(); if (!profile) return false;
    resetGachaShowcaseDraft(profile);
    app.message = '已取消本次预览，恢复当前已保存的排行榜装扮。';
    return true;
  }

  function saveGachaShowcaseDraft() {
    const profile = leaderboardProfile(); const cosmetics = profile?.cosmetics;
    if (!profile || !cosmetics) return false;
    const draft = ensureGachaShowcaseDraft(profile);
    if (!gachaDraftChanged(profile)) {
      app.games.gachaDraftTouched = false;
      app.message = '当前预览与已保存装扮相同，无需重复上传。';
      render();
      return false;
    }
    cosmetics.equipped = Object.fromEntries(GACHA_SHOWCASE_SLOTS.map((slot) => [slot, draft[slot] || null]));
    cosmetics.updatedAt = nowMs();
    app.games.gachaDraftTouched = false;
    saveCurrent();
    markLeaderboardShowcaseDirty();
    app.message = '排行榜装扮已保存；徽章、称号、边框与字体渐变会按当前搭配分别同步。';
    render();
    return true;
