    function delay(){if(!running)return 0;if(gameId==='tetris')return tdelay();if(gameId==='snake')return Math.max(85,190-Math.floor((state.score||0)/50)*8);if(gameId==='match3')return 100;if(gameId==='kitchen')return 110;if(gameId==='minesweeper')return 200;return 0;}
