  const LOGIC_WORKER_GAME_IDS = new Set(['tetris','snake','2048','match3','minesweeper','collectHoney','zombieGarden','kitchen']);

  function logicWorkerStateSlot(gameId) {
    if (gameId === '2048') return 'game2048';
    return LOGIC_WORKER_GAME_IDS.has(gameId) ? gameId : null;
  }

  function logicWorkerCanHandle(gameId = app.games?.selected) {
    return Boolean(gameId && app.logicWorker.worker && app.logicWorker.gameId === gameId);
  }

  function stopLogicGameWorker(reason = 'stopped') {
    const runtime = app.logicWorker;
    if (!runtime?.worker) {
      if (app.performanceDiagnostics.activeSession && LOGIC_WORKER_GAME_IDS.has(app.performanceDiagnostics.activeSession.gameId)) endPerformanceSession(reason);
      return;
    }
    try { runtime.worker.postMessage({ type: 'destroy', reason }); } catch (_) {}
    try { runtime.worker.terminate(); } catch (_) {}
    if (runtime.objectUrl) {
      try { (host.URL || globalThis.URL).revokeObjectURL(runtime.objectUrl); } catch (_) {}
    }
    runtime.worker = null;
    runtime.gameId = null;
    runtime.mode = 'none';
    runtime.objectUrl = null;
    runtime.ready = false;
    runtime.generation += 1;
    if (app.performanceDiagnostics.activeSession && LOGIC_WORKER_GAME_IDS.has(app.performanceDiagnostics.activeSession.gameId)) endPerformanceSession(reason);
  }

  function applyLogicWorkerState(gameId, nextState) {
    const slot = logicWorkerStateSlot(gameId);
    const target = slot ? app.games?.[slot] : null;
    if (!target || !nextState || typeof nextState !== 'object') return;
    const preservedView = gameId === 'minesweeper' ? target.view : null;
    Object.keys(target).forEach((key) => { delete target[key]; });
    Object.assign(target, nextState);
    if (preservedView) target.view = preservedView;
  }

  function handleLogicWorkerState(gameId, nextState) {
    if (!nextState || app.games.selected !== gameId) return;
    applyLogicWorkerState(gameId, nextState);
    queueGameRuntimeRefresh(false);
  }

  function startLogicGameWorker(gameId) {
    if (!LOGIC_WORKER_GAME_IDS.has(gameId) || app.logicWorker.disabledGames.has(gameId)) return false;
    if (app.logicWorker.worker && app.logicWorker.gameId === gameId) return true;
    stopLogicGameWorker('restart');
    const WorkerCtor = host.Worker || globalThis.Worker;
    const BlobCtor = host.Blob || globalThis.Blob;
    const URLApi = host.URL || globalThis.URL;
    if (!WorkerCtor || !BlobCtor || !URLApi?.createObjectURL) return false;
    let objectUrl = null;
    let worker = null;
    try {
      objectUrl = URLApi.createObjectURL(new BlobCtor([`(${ptgAllGameLogicWorkerMain.toString()})()`], { type: 'text/javascript' }));
      worker = new WorkerCtor(objectUrl);
    } catch (error) {
      if (objectUrl) try { URLApi.revokeObjectURL(objectUrl); } catch (_) {}
      app.logicWorker.disabledGames.add(gameId);
      recordPerformanceError(`${gameId}-logic-worker-create`, error);
      return false;
    }
    const generation = ++app.logicWorker.generation;
    Object.assign(app.logicWorker, { worker, gameId, mode: 'logic-worker', objectUrl, ready: false });
    beginPerformanceSession(gameId, 'logic-worker');
    worker.onmessage = (event) => {
      if (generation !== app.logicWorker.generation || worker !== app.logicWorker.worker) return;
      const message = event.data || {};
      if (message.type === 'ready') {
        app.logicWorker.ready = true;
        app.logicWorker.mode = message.mode || 'logic-worker';
        if (app.performanceDiagnostics.activeSession) app.performanceDiagnostics.activeSession.mode = app.logicWorker.mode;
      } else if (message.type === 'state') {
        handleLogicWorkerState(gameId, message.state);
      } else if (message.type === 'event') {
        if (gameId === 'match3') finishMatch3RuntimePreview();
        if (message.event === 'serve') playSfx('serve');
        else if (message.event === 'fail') playSfx('fail');
        else if (message.event === 'confirm') playSfx('confirm');
        else playSfx('game');
      } else if (message.type === 'stats') {
        app.performanceDiagnostics.workerStats[gameId] = { at: nowMs(), mode: app.logicWorker.mode, ...message.stats };
        if (app.performanceDiagnostics.activeSession?.gameId === gameId) app.performanceDiagnostics.activeSession.stats.push({ at: nowMs(), ...message.stats });
      } else if (message.type === 'ended') {
        applyLogicWorkerState(gameId, message.state);
        stopLogicGameWorker('game-over');
        finishGame(gameId, message.reason || '本局结束');
      } else if (message.type === 'error') {
        recordPerformanceError(`${gameId}-logic-worker`, message.message);
      }
    };
    worker.onerror = (event) => {
      recordPerformanceError(`${gameId}-logic-worker-error`, event?.message || event);
      app.logicWorker.disabledGames.add(gameId);
      stopLogicGameWorker('worker-error');
      app.message = `${GAME_DEFS[gameId]?.name || '小游戏'}的 Worker 不兼容当前环境，已自动切回兼容模式。`;
      scheduleGameTick();
      queueGameRuntimeRefresh(true);
    };
    const state = gameState(gameId);
    try { worker.postMessage({ type: 'init', gameId, state }); }
    catch (error) {
      recordPerformanceError(`${gameId}-logic-worker-init`, error);
      app.logicWorker.disabledGames.add(gameId);
      stopLogicGameWorker('worker-init-error');
      return false;
    }
    return true;
  }

  function sendLogicGameCommand(action, payload = {}, gameId = app.games?.selected) {
    if (!logicWorkerCanHandle(gameId)) return false;
    try {
      app.logicWorker.worker.postMessage({ type: 'command', action, payload, seq: ++app.logicWorker.commandSeq });
      return true;
    } catch (error) {
      recordPerformanceError(`${gameId}-logic-command`, error);
      return false;
    }
  }

  function realtimeStateSlot(gameId) {
    return gameId === 'bulletHell' ? 'bulletHell' : gameId === 'watermelon' ? 'watermelon' : gameId === 'petRogue' ? 'petRogue' : null;
  }

  function realtimeWorkerAvailable(canvas) {
    const WorkerCtor = host.Worker || globalThis.Worker;
    const BlobCtor = host.Blob || globalThis.Blob;
    return Boolean(canvas && WorkerCtor && BlobCtor && (host.URL || globalThis.URL)?.createObjectURL);
  }

  function realtimeInputPayload() {
    const keys = {};
    app.games.bulletHellKeys?.forEach?.((code) => { keys[code] = true; });
    const joy = app.games.bulletHellJoystick || {};
    return {
      keys,
      joyX: Number(joy.x) || 0,
      joyY: Number(joy.y) || 0,
      joystickSensitivity: Math.max(.25, Math.min(2, Number(app.save?.settings?.bulletJoystickSensitivity) || 1)),
      keyboardSensitivity: Math.max(.25, Math.min(2, Number(app.save?.settings?.bulletKeyboardSensitivity) || 1)),
    };
  }

  function beginPerformanceSession(gameId, mode) {
    const perf = app.performanceDiagnostics;
    if (perf.activeSession) endPerformanceSession('replaced');
    perf.activeSession = { gameId, mode, startedAt: nowMs(), endedAt: null, reason: '', stats: [] };
  }

  function endPerformanceSession(reason = 'stopped') {
    const perf = app.performanceDiagnostics;
    if (!perf.activeSession) return;
    perf.activeSession.endedAt = nowMs();
    perf.activeSession.reason = reason;
    perf.sessions.push(perf.activeSession);
    if (perf.sessions.length > 20) perf.sessions.splice(0, perf.sessions.length - 20);
    perf.activeSession = null;
  }

  function recordPerformanceError(scope, error) {
    const perf = app.performanceDiagnostics;
    perf.errors.push({ at: nowMs(), scope, message: String(error?.stack || error || 'unknown') });
    if (perf.errors.length > 80) perf.errors.splice(0, perf.errors.length - 80);
  }

  function startPerformanceDiagnostics() {
    const perf = app.performanceDiagnostics;
    try {
      if (typeof host.PerformanceObserver === 'function') {
        perf.longTaskObserver = new host.PerformanceObserver((list) => {
          list.getEntries().forEach((entry) => perf.longTasks.push({ at: nowMs(), duration: Math.round(Number(entry.duration) || 0), name: entry.name || 'longtask' }));
          if (perf.longTasks.length > 160) perf.longTasks.splice(0, perf.longTasks.length - 160);
        });
        perf.longTaskObserver.observe({ entryTypes: ['longtask'] });
      }
    } catch (_) { perf.longTaskObserver = null; }
    perf.errorHandler = (event) => recordPerformanceError('window-error', event?.error || event?.message);
    perf.rejectionHandler = (event) => recordPerformanceError('unhandled-rejection', event?.reason);
    host.addEventListener('error', perf.errorHandler);
    host.addEventListener('unhandledrejection', perf.rejectionHandler);
  }

  function stopPerformanceDiagnostics() {
    const perf = app.performanceDiagnostics;
    try { perf.longTaskObserver?.disconnect?.(); } catch (_) {}
    perf.longTaskObserver = null;
    if (perf.errorHandler) host.removeEventListener('error', perf.errorHandler);
    if (perf.rejectionHandler) host.removeEventListener('unhandledrejection', perf.rejectionHandler);
    perf.errorHandler = null;
    perf.rejectionHandler = null;
    endPerformanceSession('script-destroy');
  }

  function exportPerformanceReport() {
    const perf = app.performanceDiagnostics;
    const memory = host.performance?.memory ? {
      usedJSHeapSize: Number(host.performance.memory.usedJSHeapSize) || 0,
      totalJSHeapSize: Number(host.performance.memory.totalJSHeapSize) || 0,
      jsHeapSizeLimit: Number(host.performance.memory.jsHeapSizeLimit) || 0,
    } : null;
    const report = {
      format: 'pixel_tamagotchi_performance_report',
      version: CORE_VERSION,
      exportedAt: new Date().toISOString(),
      userAgent: String(host.navigator?.userAgent || ''),
      hardwareConcurrency: Number(host.navigator?.hardwareConcurrency) || null,
      deviceMemory: Number(host.navigator?.deviceMemory) || null,
      devicePixelRatio: Number(host.devicePixelRatio) || 1,
      workerSupported: typeof (host.Worker || globalThis.Worker) === 'function',
      offscreenCanvasSupported: typeof host.HTMLCanvasElement?.prototype?.transferControlToOffscreen === 'function',
      activeGame: app.games.selected || null,
      activeWorkerMode: app.realtimeWorker.mode !== 'none' ? app.realtimeWorker.mode : app.logicWorker.mode,
      logicWorkerGameId: app.logicWorker.gameId,
      memory,
      longTasks: perf.longTasks.slice(-120),
      workerStats: perf.workerStats,
      sessions: [...perf.sessions, ...(perf.activeSession ? [{ ...perf.activeSession, endedAt: nowMs(), reason: 'report-export' }] : [])],
      errors: perf.errors.slice(-60),
    };
    const blob = new Blob([JSON.stringify(report, null, 2)], { type: 'application/json;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const anchor = doc.createElement('a');
    anchor.href = url;
    anchor.download = `像素拓麻歌子_性能报告_${localDayKey()}.json`;
    doc.body.appendChild(anchor); anchor.click(); anchor.remove();
    host.setTimeout(() => URL.revokeObjectURL(url), 1000);
    app.message = '性能报告已导出，可直接发给作者排查卡顿。';
    render();
  }

  function stopRealtimeGameWorker(reason = 'stopped') {
    const runtime = app.realtimeWorker;
    if (!runtime.worker) {
      if (app.performanceDiagnostics.activeSession && ['bulletHell','watermelon','petRogue'].includes(app.performanceDiagnostics.activeSession.gameId)) endPerformanceSession(reason);
      return;
    }
    runtime.generation += 1;
    try { runtime.worker.postMessage({ type: 'destroy' }); } catch (_) {}
    try { runtime.worker.terminate(); } catch (_) {}
    if (runtime.objectUrl) { try { (host.URL || URL).revokeObjectURL(runtime.objectUrl); } catch (_) {} }
    runtime.worker = null; runtime.gameId = null; runtime.mode = 'none'; runtime.canvas = null; runtime.objectUrl = null;
    endPerformanceSession(reason);
  }


  function syncRealtimeWorkerInput() {
    const worker = app.realtimeWorker.worker;
    if (!worker) return;
    try {
      if (app.realtimeWorker.gameId === 'bulletHell') worker.postMessage({ type: 'input', input: realtimeInputPayload() });
      else if (app.realtimeWorker.gameId === 'petRogue') worker.postMessage({ type: 'input', input: petRogueRealtimeInputPayload() });
    } catch (_) {}
  }





  function handleRealtimeWorkerState(gameId, nextState, options = {}) {
    const slot = realtimeStateSlot(gameId);
    if (!slot || !nextState || app.games.selected !== gameId) return;
    app.games[slot] = nextState;
    const canvas = app.realtimeWorker.canvas;
    if (app.realtimeWorker.mode === 'logic-worker' && canvas?.isConnected) {
      if (gameId === 'bulletHell') drawBulletHellCanvas(canvas, nextState);
      else if (gameId === 'watermelon') drawWatermelonCanvas(canvas, nextState);
      else if (gameId === 'petRogue') drawPetRogueCanvas(canvas, nextState);
    }
    if (gameId === 'bulletHell') updateBulletHellHud(nextState);
    else if (gameId === 'watermelon') refreshWatermelonHud(nextState);
    else if (gameId === 'petRogue') {
      refreshPetRogueHud(nextState);
      syncPetRogueChoiceOverlay(app.root, nextState);
      if (nextState.choosing) resetPetRogueControlState(true, true);
      if (options.persist) { persistGameSnapshot(false); saveCurrent(); }
    }
  }

  function startRealtimeGameWorker(gameId, canvas) {
    if (!['bulletHell','watermelon','petRogue'].includes(gameId) || app.realtimeWorker.disabledGames.has(gameId) || !realtimeWorkerAvailable(canvas)) return false;
    stopRealtimeGameWorker('restart');
    const WorkerCtor = host.Worker || globalThis.Worker;
    const BlobCtor = host.Blob || globalThis.Blob;
    const URLApi = host.URL || globalThis.URL;
    let worker, objectUrl, offscreen = null, mode = 'logic-worker';
    try {
      objectUrl = URLApi.createObjectURL(new BlobCtor([buildRealtimeWorkerSource(gameId)], { type: 'text/javascript' }));
      worker = new WorkerCtor(objectUrl);
      if (typeof canvas.transferControlToOffscreen === 'function') {
        try { offscreen = canvas.transferControlToOffscreen(); mode = 'offscreen-worker'; } catch (_) { offscreen = null; }
      }
      if (gameId === 'petRogue' && !offscreen) throw new Error('宠物奇旅需要 OffscreenCanvas，当前环境将使用主线程兼容模式。');
    } catch (error) {
      if (worker) { try { worker.terminate(); } catch (_) {} }
      if (objectUrl) { try { URLApi.revokeObjectURL(objectUrl); } catch (_) {} }
      recordPerformanceError(`${gameId}-worker-create`, error);
      return false;
    }
    const generation = ++app.realtimeWorker.generation;
    Object.assign(app.realtimeWorker, { worker, gameId, mode, canvas, objectUrl });
    beginPerformanceSession(gameId, mode);
    worker.onmessage = (event) => {
      if (generation !== app.realtimeWorker.generation || worker !== app.realtimeWorker.worker) return;
      const message = event.data || {};
      if (message.type === 'ready') {
        app.realtimeWorker.mode = message.mode || mode;
        if (app.performanceDiagnostics.activeSession) app.performanceDiagnostics.activeSession.mode = app.realtimeWorker.mode;
      } else if (message.type === 'state') {
        handleRealtimeWorkerState(gameId, message.state, { persist: Boolean(message.persist) });
      } else if (message.type === 'event') {
        if (message.event === 'mergeSound') playWatermelonMergeSound(Number(message.value) || 1, 0);
        else if (message.event === 'dropSound') playToneSequence([{ frequency: 185 + Number(message.value || 0) * 18, endFrequency: 145 + Number(message.value || 0) * 16, duration: .065, type: 'triangle', gain: .1 }]);
        else if (message.event === 'hit') {
          const board = app.root?.querySelector('[data-bullethell-board]');
          board?.classList.add('hit'); host.setTimeout(() => board?.classList.remove('hit'), 460);
        } else if (message.event === 'petRogueResetInput') {
          resetPetRogueControlState(true, true);
          syncRealtimeWorkerInput();
        }
      } else if (message.type === 'stats') {
        app.performanceDiagnostics.workerStats[gameId] = { at: nowMs(), mode: app.realtimeWorker.mode, ...message.stats };
        if (app.performanceDiagnostics.activeSession?.gameId === gameId) {
          app.performanceDiagnostics.activeSession.stats.push({ at: nowMs(), ...message.stats });
          if (app.performanceDiagnostics.activeSession.stats.length > 120) app.performanceDiagnostics.activeSession.stats.splice(0, app.performanceDiagnostics.activeSession.stats.length - 120);
        }
      } else if (message.type === 'ended') {
        handleRealtimeWorkerState(gameId, message.state, { persist: false });
        const live = gameState(gameId);
        if (live) live.status = 'running';
        stopRealtimeGameWorker('game-over');
        finishGame(gameId, message.reason || '本局结束');
      } else if (message.type === 'error') {
        recordPerformanceError(`${gameId}-worker`, message.message);
      }
    };
    worker.onerror = (event) => {
      recordPerformanceError(`${gameId}-worker-error`, event?.message || event);
      app.realtimeWorker.disabledGames.add(gameId);
      stopRealtimeGameWorker('worker-error');
      app.message = `${GAME_DEFS[gameId]?.name || '小游戏'}的 Worker 不兼容当前环境，已自动切回兼容模式。`;
      queueGameRuntimeRefresh(true);
    };
    const state = gameState(gameId);
    const payload = {
      type: 'init', gameId, state,
      input: gameId === 'bulletHell' ? realtimeInputPayload() : gameId === 'petRogue' ? petRogueRealtimeInputPayload() : {},
      ...(gameId === 'petRogue' ? { visual: petRogueWorkerVisualPayload(), modifierSummary: petRogueModifierSummary() } : {}),
    };
    try {
      if (offscreen) worker.postMessage({ ...payload, canvas: offscreen }, [offscreen]);
      else worker.postMessage(payload);
      return true;
    } catch (error) {
      recordPerformanceError(`${gameId}-worker-init`, error);
      app.realtimeWorker.disabledGames.add(gameId);
      stopRealtimeGameWorker('worker-init-error');
      return false;
    }
  }

  function flushDeferredAssistantScans() {
    if (!app.deferredAssistantScans.size || shouldUseGameRuntime()) return;
    const queued = [...app.deferredAssistantScans.entries()];
    app.deferredAssistantScans.clear();
    queued.forEach(([id, options], index) => scheduleAssistantMessageScan(id, 80 + index * 60, options.showBanner));
  }

  function trackEventSubscription(subscription) {
    if (subscription && typeof subscription.stop === 'function') app.eventSubscriptions.push(subscription);
    return subscription;
  }

  function stopEventSubscriptions() {
    app.eventSubscriptions.splice(0).forEach((subscription) => {
      try { subscription.stop(); } catch (_) {}
    });
  }

  function gameRuntimeState() {
    const gameId = app.games?.selected;
    const state = gameState(gameId);
    return { gameId, state };
  }

  function shouldUseGameRuntime() {
    const { gameId, state } = gameRuntimeState();
    return Boolean(
      app.root?.classList.contains('ptg-open')
      && app.activeTab === 'games'
      && gameId
      && state
      && (state.status === 'running' || state.status === 'paused')
    );
  }

  function isolateHostForGame(active) {
    if (!doc?.body) return;
    if (active) {
      if (app.hostIsolation.length) return;
      [...doc.body.children].forEach((node) => {
        if (node === app.root || node === app.floatingHost || node === app.importInput) return;
        const style = node.style;
        if (!style) return;
        app.hostIsolation.push({
          node,
          contentVisibility: style.getPropertyValue('content-visibility'),
          contentVisibilityPriority: style.getPropertyPriority('content-visibility'),
          visibility: style.getPropertyValue('visibility'),
          visibilityPriority: style.getPropertyPriority('visibility'),
          pointerEvents: style.getPropertyValue('pointer-events'),
          pointerEventsPriority: style.getPropertyPriority('pointer-events'),
        });
        style.setProperty('content-visibility', 'hidden', 'important');
        style.setProperty('visibility', 'hidden', 'important');
        style.setProperty('pointer-events', 'none', 'important');
      });
      if (app.floatingHost) app.floatingHost.style.display = 'none';
      return;
    }
    app.hostIsolation.splice(0).forEach((entry) => {
      const { node } = entry;
      if (!node?.style) return;
      const restore = (name, value, priority) => {
        if (value) node.style.setProperty(name, value, priority || '');
        else node.style.removeProperty(name);
      };
      restore('content-visibility', entry.contentVisibility, entry.contentVisibilityPriority);
      restore('visibility', entry.visibility, entry.visibilityPriority);
      restore('pointer-events', entry.pointerEvents, entry.pointerEventsPriority);
    });
    updateFloatingButton();
  }

  function cancelGameRuntimeRefresh() {
    if (app.gameRuntime.refreshRaf !== null) {
      try { host.cancelAnimationFrame(app.gameRuntime.refreshRaf); } catch (_) {}
      app.gameRuntime.refreshRaf = null;
    }
  }


  function leaveGameRuntime() {
    cancelGameRuntimeRefresh();
    callOptionalGameHook(clearMatch3RuntimeAnimation, true);
    stopRealtimeGameWorker('leave-runtime');
    stopLogicGameWorker('leave-runtime');
    isolateHostForGame(false);
    app.root?.classList.remove('ptg-game-runtime-active');
    const device = app.root?.querySelector('.ptg-device');
    if (device) {
      delete device.dataset.ptgRuntimeKey;
      delete device.dataset.ptgRuntimeGame;
    }
    app.gameRuntime.active = false;
    app.gameRuntime.gameId = null;
    app.gameRuntime.status = null;
    app.gameRuntime.shellKey = '';
    app.gameRuntime.match3Signature = '';
    app.gameRuntime.match3VisualBoard = null;
    app.gameRuntime.collectHoneySignature = '';
    app.gameRuntime.zombieSignature = '';
    app.gameRuntime.tetrisNextType = '';
    host.setTimeout(flushDeferredAssistantScans, 0);
  }

  function canvasContext2d(canvas, logicalWidth, logicalHeight, alpha = false) {
    if (!canvas) return null;
    const rect = canvas.getBoundingClientRect();
    const cssWidth = Math.max(1, Number(rect.width) || logicalWidth);
    const cssHeight = Math.max(1, Number(rect.height) || logicalHeight);
    const dpr = Math.max(1, Math.min(GAME_CANVAS_DPR_CAP, Number(host.devicePixelRatio) || 1));
    const pixelWidth = Math.max(1, Math.round(cssWidth * dpr));
    const pixelHeight = Math.max(1, Math.round(cssHeight * dpr));
    if (canvas.width !== pixelWidth || canvas.height !== pixelHeight) {
      canvas.width = pixelWidth;
      canvas.height = pixelHeight;
    }
    const context = canvas.getContext('2d', { alpha, desynchronized: true });
    if (!context) return null;
    context.setTransform(pixelWidth / logicalWidth, 0, 0, pixelHeight / logicalHeight, 0, 0);
    context.imageSmoothingEnabled = false;
    return context;
  }












  function updateCommonGameRuntimeHud(gameId, state) {
    const root = app.root;
    if (!root || !state) return;
    const set = (selector, value) => { const element = root.querySelector(selector); if (element) element.textContent = String(value); };
    set('[data-runtime-score]', Math.max(0, Math.floor(Number(state.score) || 0)));
    set('[data-runtime-coins]', gameRewardPreview(gameId, state.score));
    if (gameId === 'tetris') set('[data-runtime-extra]', state.lines || 0);
    else if (gameId === 'snake') set('[data-runtime-extra]', Math.max(0, (state.snake?.length || 3) - 3));
    else if (gameId === '2048') set('[data-runtime-extra]', state.maxTile || 2);
    else if (gameId === 'pinball') set('[data-runtime-extra]', Math.max(0, Number(state.ballsRemaining) || 0));
    else if (gameId === 'petRogue') set('[data-runtime-extra]', Math.max(1, Number(state.wave) || 1));
  }

  function refreshGameRuntimeNow(force = false) {
    app.gameRuntime.refreshRaf = null;
    if (!shouldUseGameRuntime()) return;
    const { gameId, state } = gameRuntimeState();
    const device = app.root?.querySelector('.ptg-device');
    if (!device || !state) return;
    // 宠物奇旅的升级层在现有画布上增删，不再因 choosing 状态重建整台运行界面。
    // 这样选择强化后原有 RAF 会自然继续，避免画面停住但状态已经恢复。
    const runtimePhase = '';
    const statusKey = `${gameId}:${state.status}${runtimePhase ? `:${runtimePhase}` : ''}`;
    if (force || device.dataset.ptgRuntimeKey !== statusKey) {
      device.dataset.ptgRuntimeKey = statusKey;
      device.dataset.ptgRuntimeGame = gameId;
      // Worker 游戏仍然运行在独立场景中，但保留原掌机的外壳、标题栏和底部导航。
      // 这些静态结构只在进入游戏或暂停状态变化时创建一次，不参与逐帧刷新。
      const runtimeTitle = app.save?.lifecycle === 'alive' && app.save?.pet
        ? `${app.save.pet.name} · 游戏中`
        : '像素拓麻歌子';
      const runtimeSubtitle = GAME_DEFS[gameId]?.name || '小游戏';
      device.innerHTML = `${renderHeader(runtimeTitle, runtimeSubtitle)}<div class="ptg-scroll ptg-runtime-only" data-tab="games">${renderSelectedGame(gameId)}</div>${renderNav()}`;
      bindDeviceEvents();
      callOptionalGameHook(clearMatch3RuntimeAnimation, true);
      app.gameRuntime.match3Signature = '';
      app.gameRuntime.collectHoneySignature = '';
      app.gameRuntime.zombieSignature = '';
      app.gameRuntime.tetrisNextType = '';
    }
    updateCommonGameRuntimeHud(gameId, state);
    if (gameId === 'tetris') {
      refreshTetrisDomBoard(device, state);
      // 下一块由 Worker 状态直接驱动；预览节点固定存在并按真实 nextType 更新，避免停留在开局的 S/Z 方块。
      refreshTetrisPreview(device, state.nextType);
      app.gameRuntime.tetrisNextType = normalizedTetrominoType(state.nextType);
      const swapButton = device.querySelector('[data-action="game-tetris-swap"]');
      if (swapButton) swapButton.disabled = !(state.status === 'running' && state.current && state.nextType);
    }
    else if (gameId === 'snake') drawSnakeRuntime(device.querySelector('[data-snake-canvas]'), state);
    else if (gameId === '2048') refresh2048DomBoard(device, state);
    else if (gameId === 'match3') {
      refreshMatch3RuntimeBoard(device, state, force);
      refreshMatch3View(state);
    } else if (gameId === 'minesweeper') {
      updateMinesweeperLiveHud();
      drawMinesweeperCanvas(device.querySelector('[data-minesweeper-canvas]'), state, false);
    } else if (gameId === 'collectHoney') {
      const signature = JSON.stringify([state.score, state.jarProgress, state.jarsFilled, state.lastAction, state.board]);
      let slot = device.querySelector('[data-collect-honey-runtime-slot]');
      if (slot && signature !== app.gameRuntime.collectHoneySignature) {
        app.gameRuntime.collectHoneySignature = signature;
        slot.outerHTML = renderCollectHoneyGame(state);
        setupCollectHoneyInput(device);
        slot = device.querySelector('[data-collect-honey-runtime-slot]');
      }
      drawCollectHoneyCanvas(device.querySelector('[data-collect-honey-canvas]'), state);
    }
    else if (gameId === 'bulletHell') updateBulletHellHud(state);
    else if (gameId === 'zombieGarden') {
      const signature = JSON.stringify([state.score, state.turns, state.pot, state.flowers, state.zombies, state.selectedFlower, state.resolving, state.message]);
      const slot = device.querySelector('[data-zombie-garden]');
      if (slot && signature !== app.gameRuntime.zombieSignature && !state.resolving) {
        app.gameRuntime.zombieSignature = signature;
        slot.outerHTML = renderZombieGardenGame(state);
        setupZombieGardenInput(device);
      }
    }
    else if (gameId === 'watermelon') {
      drawWatermelonCanvas(device.querySelector('[data-watermelon-canvas]'), state);
      refreshWatermelonHud(state);
    } else if (gameId === 'pinball') {
      drawPinballCanvas(device.querySelector('[data-pinball-canvas]'), state);
      refreshPinballHud(state);
    } else if (gameId === 'petRogue') {
      syncPetRogueChoiceOverlay(device, state);
      drawPetRogueCanvas(device.querySelector('[data-petrogue-canvas]'), state);
      refreshPetRogueHud(state);
    } else if (gameId === 'kitchen') refreshKitchenView(state);
  }

  function queueGameRuntimeRefresh(force = false) {
    if (!shouldUseGameRuntime()) return false;
    if (force) {
      cancelGameRuntimeRefresh();
      refreshGameRuntimeNow(true);
      return true;
    }
    if (app.gameRuntime.refreshRaf !== null) return true;
    app.gameRuntime.refreshRaf = host.requestAnimationFrame(() => refreshGameRuntimeNow(false));
    return true;
