  function playToneSequence(notes = []) {
    const volume = audioSettingPercent('sfxVolume', DEFAULT_SFX_VOLUME) / 100;
    if (volume <= 0 || !Array.isArray(notes) || !notes.length) return;
    const context = ensureSoundContext();
    if (!context) return;
    const base = context.currentTime + 0.006;
    notes.forEach((note = {}) => {
      const frequency = Math.max(40, Number(note.frequency) || 440);
      const duration = Math.max(0.025, Number(note.duration) || 0.08);
      const offset = Math.max(0, Number(note.offset) || 0);
      const gainAmount = Math.max(0.01, Math.min(1, Number(note.gain) || 0.2)) * volume;
      const oscillator = context.createOscillator();
      const gain = context.createGain();
      oscillator.type = note.type || 'square';
      oscillator.frequency.setValueAtTime(frequency, base + offset);
      if (Number(note.endFrequency) > 0) {
        oscillator.frequency.exponentialRampToValueAtTime(Number(note.endFrequency), base + offset + duration);
      }
      gain.gain.setValueAtTime(0.0001, base + offset);
      gain.gain.exponentialRampToValueAtTime(Math.max(0.0002, gainAmount), base + offset + 0.006);
      gain.gain.exponentialRampToValueAtTime(0.0001, base + offset + duration);
      oscillator.connect(gain);
      gain.connect(context.destination);
      oscillator.start(base + offset);
      oscillator.stop(base + offset + duration + 0.025);
    });
  }

  function playScratchSound(force = false) {
    const now = nowMs();
    if (!force && now - app.audio.lastScratchAt < 85) return;
    app.audio.lastScratchAt = now;
    const volume = audioSettingPercent('sfxVolume', DEFAULT_SFX_VOLUME) / 100;
    if (volume <= 0) return;
    const context = ensureSoundContext();
    if (!context) return;
    if (!app.audio.noiseBuffer) {
      const length = Math.max(1, Math.floor(context.sampleRate * 0.09));
      const buffer = context.createBuffer(1, length, context.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < length; i += 1) data[i] = (Math.random() * 2 - 1) * (1 - i / length);
      app.audio.noiseBuffer = buffer;
    }
    const source = context.createBufferSource();
    const filter = context.createBiquadFilter();
    const gain = context.createGain();
    source.buffer = app.audio.noiseBuffer;
    filter.type = 'bandpass';
    filter.frequency.value = 1500;
    filter.Q.value = 0.75;
    gain.gain.value = volume * 0.075;
    source.connect(filter);
    filter.connect(gain);
    gain.connect(context.destination);
    source.start();
  }

