  function actionSoundKind(action = '', element = null) {
    if (!action || action === 'fortune-roll' || action === 'answer-book-open' || action === 'game-kitchen-serve') return null;
    if (action === 'close' || action === 'settings-back' || /(?:-close|-back|-cancel|-exit|-undo|-clear)$/.test(action)) return 'back';
    if (action.startsWith('tab-') || action.startsWith('records-view-') || action.startsWith('mystic-view-') || action === 'open-settings' || action.startsWith('game-select-')) return 'menu';
    if (action === 'pet') return 'pet';
    if (action.startsWith('use-item-')) {
      const item = ITEMS[action.slice('use-item-'.length)];
      if (item?.category === 'food') return 'feed';
      if (item?.category === 'clean') return 'clean';
      if (item?.category === 'toy') return 'pet';
      return 'confirm';
    }
    if (action.startsWith('item-picker-') || action.startsWith('event-') || action.startsWith('char-care-')) return 'confirm';
    if (/^(?:buy-|lottery-buy)/.test(action)) return 'coin';
    if (action === 'hatch' || action === 'revive-pet') return 'magic';
    if (action.startsWith('wardrobe-') || action.startsWith('skin-select-') || action.startsWith('toggle-') || action.endsWith('-reset')) return 'toggle';
    if (action.startsWith('game-start-')) return 'gameStart';
    if (action.startsWith('game-kitchen-grill-')) return 'grill';
    if (action.startsWith('game-kitchen-chop-')) return 'chop';
    if (action.startsWith('game-kitchen-juice-')) return 'juice';
    if (action.startsWith('game-kitchen-add-')) return 'feed';
    if (action.startsWith('game-')) return 'game';
    if (action.startsWith('schedule-')) return 'confirm';
    if (element?.classList?.contains('ptg-danger')) return 'back';
    if (element?.classList?.contains('ptg-primary')) return 'confirm';
    return 'ui';
  }

