  function getPetExtensionBus() {
    let bus = host[PET_EXTENSION_BUS_KEY];
    if (!bus || bus.protocol !== 1) {
      const pending = Array.isArray(bus?.pending) ? bus.pending.slice() : [];
      const definitions = Array.isArray(bus?.definitions) ? bus.definitions.slice() : [];
      bus = {
        protocol: 1,
        apiVersion: PET_EXTENSION_API_VERSION,
        api: null,
        pending,
        definitions,
        register(extension) {
          const id = String(extension?.id || '');
          if (id) {
            const index = this.definitions.findIndex((entry) => String(entry?.id || '') === id);
            if (index >= 0) this.definitions[index] = extension;
            else this.definitions.push(extension);
          }
          if (this.api) return this.api.registerPetExtension(extension);
          const queuedIndex = this.pending.findIndex((entry) => String(entry?.id || '') === id);
          if (queuedIndex >= 0) this.pending[queuedIndex] = extension;
          else this.pending.push(extension);
          return { ok: true, queued: true, message: '像素拓麻歌子尚未就绪，扩展已排队。' };
        },
        unregister(id) {
          const key = String(id || '');
          this.definitions = this.definitions.filter((entry) => String(entry?.id || '') !== key);
          if (this.api) return this.api.unregisterPetExtension(key);
          this.pending = this.pending.filter((entry) => String(entry?.id || '') !== key);
          return { ok: true, queued: true };
        },
        list() {
          if (this.api) return this.api.listPetExtensions();
          return this.definitions.map((entry) => ({ id: entry?.id || '', name: entry?.name || '', queued: true }));
        },
      };
    }
    host[PET_EXTENSION_BUS_KEY] = bus;
    try { window[PET_EXTENSION_BUS_KEY] = bus; } catch (_) {}
    return bus;
  }

  const petExtensionBus = getPetExtensionBus();

