      apiVersion: PET_EXTENSION_API_VERSION,
      coreVersion: CORE_VERSION,
      extensionId: extension?.id || '',
      character: getCharacterInfo(),
      save,
      pet,
      now: Number(extra.now) || nowMs(),
      action: extra.action || '',
      itemId: extra.itemId || '',
      item: extra.item || null,
      actor: extra.actor || 'player',
      result: extra.result || null,
      helpers: {
        clamp,
        round1,
        randomChoice,
        localDayKey,
        getAgeDays,
        getCompanionDays,
      },
    };
  }

  function callExtensionHook(extension, hookName, extra = {}, fallback = undefined) {
    const hook = extension?.hooks?.[hookName];
    if (typeof hook !== 'function') return fallback;
    try {
      const value = hook(extensionContext(extension, extra));
      return value === undefined ? fallback : value;
    } catch (error) {
      console.error(`[像素拓麻歌子] 宠物扩展 ${extension.id} 的 ${hookName} 钩子执行失败：`, error);
      return fallback;
    }
  }

  function extensionMatchesCharacter(extension, info = getCharacterInfo()) {
    if (!extension?.enabled || !info) return false;
    if (extension.matchCharacter) {
      try { if (extension.matchCharacter(extensionContext(extension, { save: app.save, pet: app.save?.pet || null }))) return true; }
      catch (error) { console.error(`[像素拓麻歌子] 宠物扩展 ${extension.id} 的角色匹配函数失败：`, error); }
    }
    return extension.match.characterNames.includes(String(info.name || '').trim());
  }

  function matchingExtensionForCharacter(info = getCharacterInfo()) {
    return [...petExtensions.values()]
      .filter((extension) => extensionMatchesCharacter(extension, info))
      .sort((a, b) => b.priority - a.priority || a.id.localeCompare(b.id))[0] || null;
  }

  function extensionForPet(pet) {
    if (!pet) return null;
    const direct = String(pet._ptgExtensionId || '');
    if (direct && petExtensions.has(direct)) return petExtensions.get(direct);
    const owner = extensionSpeciesOwners.get(String(pet.species || ''));
    return owner ? petExtensions.get(owner) || null : null;
  }

  function petPolicy(pet) {
    return extensionForPet(pet)?.policy || null;
  }

  function petStatMax(pet, key) {
    const configured = Number(petPolicy(pet)?.statCaps?.[key]);
    return Number.isFinite(configured) && configured > 0 ? configured : 100;
  }

  function clampPetStat(pet, key, value) {
    return clamp(value, 0, petStatMax(pet, key));
  }

  function petLossMultiplier(pet, key, source = 'passive') {
    const policy = petPolicy(pet);
    const table = source === 'activity' ? policy?.activityLossMultipliers : policy?.passiveLossMultipliers;
    const value = Number(table?.[key]);
    return Number.isFinite(value) && value >= 0 ? value : 1;
  }

  function petAlertThreshold(pet, key, fallback) {
    const value = Number(petPolicy(pet)?.alertThresholds?.[key]);
    return Number.isFinite(value) ? value : fallback;
  }

  function petIsImmortal(pet) {
    return Boolean(petPolicy(pet)?.immortal);
  }

  function petAllows(pet, policyKey, fallback = true) {
    const policy = petPolicy(pet);
    return policy && policy[policyKey] !== undefined ? Boolean(policy[policyKey]) : fallback;
  }

  function applyExtensionPetPolicy(pet, extension = extensionForPet(pet), atTimestamp = nowMs()) {
    if (!pet || !extension) return pet;
    const policy = extension.policy;
    pet._ptgExtensionId = extension.id;
    pet.species = extension.species.id;
    if (policy.fixedName) pet.name = policy.fixedName.slice(0, 16);
    if (policy.fixedColorId && extension.species.colors.some((color) => color.id === policy.fixedColorId)) pet.colorId = policy.fixedColorId;
    if (policy.fixedStage) {
      pet.stage = policy.fixedStage;
      pet.lastStage = policy.fixedStage;
    }
    if (policy.immortal) {
      pet.naturalDeathAt = IMMORTAL_DEATH_AT;
      pet.health = Math.max(policy.minimumHealth, Number(pet.health) || policy.minimumHealth);
    }
    ['hunger', 'happiness', 'health', 'cleanliness', 'energy', 'companionship'].forEach((key) => {
      if (pet[key] !== undefined) pet[key] = clampPetStat(pet, key, pet[key]);
    });
    const patch = callExtensionHook(extension, 'enforcePet', { pet, now: atTimestamp }, null);
    if (patch && typeof patch === 'object') Object.assign(pet, patch);
    if (policy.fixedName) pet.name = policy.fixedName.slice(0, 16);
    if (policy.fixedStage) pet.stage = pet.lastStage = policy.fixedStage;
    if (policy.immortal) {
      pet.naturalDeathAt = IMMORTAL_DEATH_AT;
      pet.health = Math.max(policy.minimumHealth, Number(pet.health) || policy.minimumHealth);
    }
    return pet;
  }

  function buildExtensionPet(extension, existingPet = null, atTimestamp = nowMs()) {
    const sameExtension = existingPet && (
      existingPet._ptgExtensionId === extension.id
      || extensionSpeciesOwners.get(String(existingPet.species || '')) === extension.id
    );
    const firstColor = extension.species.colors[0];
    const raw = {
      name: extension.policy.fixedName || extension.species.name,
      species: extension.species.id,
      colorId: extension.policy.fixedColorId || firstColor.id,
      stage: extension.policy.fixedStage || '幼崽期',
      lastStage: extension.policy.fixedStage || '幼崽期',
      birthdayAt: atTimestamp,
      naturalDeathAt: extension.policy.immortal
        ? IMMORTAL_DEATH_AT
        : atTimestamp + extension.species.lifespanDays * 86400000,
      lastUpdateAt: atTimestamp,
      hunger: Math.min(petStatMax({ _ptgExtensionId: extension.id }, 'hunger'), 86),
      happiness: 82,
      health: 100,
      cleanliness: 90,
      energy: 88,
      companionship: 12,
      weight: 3.2,
      sleeping: false,
      sick: false,
      mess: 0,
      wasteProgressHours: 0,
      _ptgExtensionId: extension.id,
      extensionData: {},
      ...extension.petDefaults,
      ...(sameExtension ? existingPet : {}),
    };
    if (extension.createPet) {
      try {
        const custom = extension.createPet(extensionContext(extension, { save: app.save, pet: existingPet, now: atTimestamp }));
        if (custom && typeof custom === 'object') Object.assign(raw, custom);
      } catch (error) {
        console.error(`[像素拓麻歌子] 宠物扩展 ${extension.id} 创建宠物失败：`, error);
      }
    }
    raw._ptgExtensionId = extension.id;
    raw.species = extension.species.id;
    const pet = normalizePet(raw);
    return applyExtensionPetPolicy(pet, extension, atTimestamp);
  }

  function ensureExtensionPetForCurrentCharacter(save, atTimestamp = nowMs()) {
    if (!save) return null;
    const extension = matchingExtensionForCharacter();
    if (!extension || !extension.policy.replacePet) return null;
    const currentExtension = extensionForPet(save.pet);
    if (!save.pet || currentExtension?.id !== extension.id) save.pet = buildExtensionPet(extension, null, atTimestamp);
    else applyExtensionPetPolicy(save.pet, extension, atTimestamp);
    save.lifecycle = 'alive';
    save.egg = null;
    if (!extension.policy.allowRandomEvents && save.events) save.events.current = null;
    callExtensionHook(extension, 'onEnsure', { save, pet: save.pet, now: atTimestamp }, null);
    return extension;
  }

  function extensionMetaChips(pet) {
    const extension = extensionForPet(pet);
    if (!extension) return [];
    const dynamic = callExtensionHook(extension, 'metaChips', { pet }, []);
    return [...extension.policy.metaChips, ...(Array.isArray(dynamic) ? dynamic : [])]
      .map((text) => String(text || '').trim()).filter(Boolean).slice(0, 8);
  }

  function extensionActionMessage(pet, action, extra = {}) {
    const extension = extensionForPet(pet);
    if (!extension) return '';
    return String(callExtensionHook(extension, 'actionMessage', { pet, action, ...extra }, '') || '');
  }

  function scheduleExtensionRuntimeRefresh() {
    if (!app.initialized) return;
    if (app.extensionReloadTimer) host.clearTimeout(app.extensionReloadTimer);
    app.extensionReloadTimer = host.setTimeout(() => {
      app.extensionReloadTimer = null;
      // 扩展可能在日程动画已经生成后才完成注册。先让旧演员签名失效，
      // 再重载当前角色，避免只刷新文字而继续复用默认宠物的旧 DOM。
      const activeStage = app.root?.querySelector?.('.ptgsa-stage');
      if (activeStage) activeStage.dataset.petVisual = '__extension_refresh__';
      beginCharacterTransition();
      loadCurrentCharacter(getCharacterInfo());
      if (app.root?.classList.contains('ptg-open')) render();
    }, 60);
  }

  function registerPetExtension(raw) {
    try {
      const extension = normalizeExtensionDefinition(raw);
      if (!/^1(?:\.|$)/.test(extension.apiVersion)) throw new Error(`扩展要求的 API ${extension.apiVersion} 与当前 API ${PET_EXTENSION_API_VERSION} 不兼容。`);
      const previous = petExtensions.get(extension.id);
      const owner = extensionSpeciesOwners.get(extension.species.id);
      if (owner && owner !== extension.id) throw new Error(`物种 id「${extension.species.id}」已被扩展 ${owner} 使用。`);
      if (SPECIES[extension.species.id] && !owner && previous?.species?.id !== extension.species.id) {
        throw new Error(`物种 id「${extension.species.id}」与主脚本内置物种冲突。`);
      }
      if (previous && previous.species.id !== extension.species.id) {
        delete SPECIES[previous.species.id];
        delete COLOR_VARIANTS[previous.species.id];
        extensionSpeciesOwners.delete(previous.species.id);
      }
      SPECIES[extension.species.id] = {
        name: extension.species.name,
        trait: extension.species.trait,
        lifespanDays: extension.species.lifespanDays,
        frames: extension.species.frames,
        ...(extension.species.adultFrames ? { adultFrames: extension.species.adultFrames } : {}),
      };
      COLOR_VARIANTS[extension.species.id] = extension.species.colors;
      extensionSpeciesOwners.set(extension.species.id, extension.id);
      petExtensions.set(extension.id, extension);
      if (extension.onRegistered) {
        try { extension.onRegistered(publicPetExtensionApi); } catch (error) { console.error(`[像素拓麻歌子] 宠物扩展 ${extension.id} 注册回调失败：`, error); }
      }
      scheduleExtensionRuntimeRefresh();
      console.info(`[像素拓麻歌子] 已注册宠物扩展：${extension.name} ${extension.version}`);
      return { ok: true, id: extension.id, name: extension.name, version: extension.version, apiVersion: PET_EXTENSION_API_VERSION };
    } catch (error) {
      console.error('[像素拓麻歌子] 宠物扩展注册失败：', error);
      return { ok: false, error: String(error?.message || error) };
    }
  }

  function unregisterPetExtension(id) {
    const key = String(id || '');
    const extension = petExtensions.get(key);
    if (!extension) return { ok: false, error: '未找到该扩展。' };
    petExtensions.delete(key);
    if (extensionSpeciesOwners.get(extension.species.id) === key) {
      extensionSpeciesOwners.delete(extension.species.id);
      delete SPECIES[extension.species.id];
      delete COLOR_VARIANTS[extension.species.id];
    }
    if (extension.onUnregistered) {
      try { extension.onUnregistered(publicPetExtensionApi); } catch (error) { console.error(`[像素拓麻歌子] 宠物扩展 ${key} 注销回调失败：`, error); }
    }
    scheduleExtensionRuntimeRefresh();
    return { ok: true };
  }

  function listPetExtensions() {
    return [...petExtensions.values()].map((extension) => ({
      id: extension.id,
      name: extension.name,
      version: extension.version,
      speciesId: extension.species.id,
      speciesName: extension.species.name,
      priority: extension.priority,
    }));
  }

  const publicPetExtensionApi = Object.freeze({
    apiVersion: PET_EXTENSION_API_VERSION,
    coreVersion: CORE_VERSION,
    registerPetExtension,
    unregisterPetExtension,
    listPetExtensions,
    getCurrentCharacter: () => ({ ...(getCharacterInfo() || {}) }),
    getCurrentPet: () => app.save?.pet ? deepClone(app.save.pet) : null,
    refresh: scheduleExtensionRuntimeRefresh,
  });

  petExtensionBus.api = publicPetExtensionApi;
  petExtensionBus.apiVersion = PET_EXTENSION_API_VERSION;
  host.PixelTamagotchiPetAPI = publicPetExtensionApi;
  try { window.PixelTamagotchiPetAPI = publicPetExtensionApi; } catch (_) {}
  const queuedPetExtensions = [
    ...(Array.isArray(petExtensionBus.definitions) ? petExtensionBus.definitions : []),
    ...(Array.isArray(petExtensionBus.pending) ? petExtensionBus.pending.splice(0) : []),
  ];
  const queuedById = new Map();
  queuedPetExtensions.forEach((extension) => {
    const id = String(extension?.id || '');
    if (id) queuedById.set(id, extension);
  });
  queuedById.forEach((extension) => registerPetExtension(extension));


  // ============================================================
  // 宠物奇旅运行时外挂扩展接口 v1
  // 外部补丁通过共享总线注册倍率与规则，不直接改写玩家存档。
  // ============================================================
  const petRogueRuntimeModifiers = new Map();

  function normalizePetRogueModifier(raw) {
    if (!raw || typeof raw !== 'object') throw new Error('宠物奇旅外挂定义必须是对象。');
    const id = String(raw.id || '').trim();
    if (!/^[a-zA-Z0-9][a-zA-Z0-9._-]{2,79}$/.test(id)) throw new Error('外挂 id 格式无效。');
    return {
      id,
      name: String(raw.name || id),
      version: String(raw.version || '1.0.0'),
      apiVersion: String(raw.apiVersion || '1'),
      enabled: raw.enabled !== false,
      damageMultiplier: Math.max(.01, Number(raw.damageMultiplier) || 1),
      attackSpeedMultiplier: Math.max(.01, Number(raw.attackSpeedMultiplier) || 1),
      uncappedStats: Boolean(raw.uncappedStats),
      description: String(raw.description || ''),
    };
  }

  function petRogueModifierSummary() {
    let damageMultiplier = 1;
    let attackSpeedMultiplier = 1;
    let uncappedStats = false;
    const active = [];
    for (const modifier of petRogueRuntimeModifiers.values()) {
      if (!modifier.enabled) continue;
      damageMultiplier *= modifier.damageMultiplier;
      attackSpeedMultiplier *= modifier.attackSpeedMultiplier;
      uncappedStats ||= modifier.uncappedStats;
      active.push({ id: modifier.id, name: modifier.name, version: modifier.version });
    }
    return {
      damageMultiplier: Math.max(.01, damageMultiplier),
      attackSpeedMultiplier: Math.max(.01, attackSpeedMultiplier),
      uncappedStats,
      active,
    };
  }

  function petRogueDamageMultiplier() { return petRogueModifierSummary().damageMultiplier; }
  function petRogueAttackSpeedMultiplier() { return petRogueModifierSummary().attackSpeedMultiplier; }
  function petRogueStatsAreUncapped() { return petRogueModifierSummary().uncappedStats; }
  function petRogueStatUpperBound(normalMax) { return petRogueStatsAreUncapped() ? Number.MAX_SAFE_INTEGER : normalMax; }
  function petRogueIntervalFloor(normalFloor) { return petRogueStatsAreUncapped() ? 16 : normalFloor; }

  function refreshPetRogueModifierRuntime() {
    const state = app.games?.petRogue;
    if (state) {
      state.attackTimers = {};
      const summary = petRogueModifierSummary();
      state.message = summary.active.length
        ? `外挂已启用：伤害 ×${summary.damageMultiplier.toFixed(2)}，攻速 ×${summary.attackSpeedMultiplier.toFixed(2)}${summary.uncappedStats ? '，属性无上限' : ''}。`
        : '宠物奇旅外挂已关闭，属性与倍率恢复正常规则。';
    }
    try { syncPetRogueWorkerModifiers(); } catch (_) {}
    try { queueGameRuntimeRefresh(false); } catch (_) {}
    if (app.root?.classList.contains('ptg-open')) {
      try { render(); } catch (_) {}
    }
  }

  function registerPetRogueModifier(raw) {
    try {
      const modifier = normalizePetRogueModifier(raw);
      if (!/^1(?:\.|$)/.test(modifier.apiVersion)) throw new Error(`外挂要求的 API ${modifier.apiVersion} 与当前 API ${PET_ROGUE_MOD_API_VERSION} 不兼容。`);
      petRogueRuntimeModifiers.set(modifier.id, modifier);
      refreshPetRogueModifierRuntime();
      console.info(`[像素拓麻歌子] 已启用宠物奇旅外挂：${modifier.name} ${modifier.version}`);
      return { ok: true, id: modifier.id, name: modifier.name, version: modifier.version, apiVersion: PET_ROGUE_MOD_API_VERSION };
    } catch (error) {
      console.error('[像素拓麻歌子] 宠物奇旅外挂注册失败：', error);
      return { ok: false, error: String(error?.message || error) };
    }
  }

  function unregisterPetRogueModifier(id) {
    const key = String(id || '');
    if (!petRogueRuntimeModifiers.has(key)) return { ok: false, error: '未找到该外挂。' };
    petRogueRuntimeModifiers.delete(key);
    refreshPetRogueModifierRuntime();
    return { ok: true };
  }

  function listPetRogueModifiers() {
    return [...petRogueRuntimeModifiers.values()].map((modifier) => ({
      id: modifier.id,
      name: modifier.name,
      version: modifier.version,
      enabled: modifier.enabled,
      damageMultiplier: modifier.damageMultiplier,
      attackSpeedMultiplier: modifier.attackSpeedMultiplier,
      uncappedStats: modifier.uncappedStats,
    }));
  }

  function getPetRogueModifierBus() {
    let bus = host[PET_ROGUE_MOD_BUS_KEY];
    if (!bus || bus.protocol !== 1) {
      const pending = Array.isArray(bus?.pending) ? bus.pending.slice() : [];
      const definitions = Array.isArray(bus?.definitions) ? bus.definitions.slice() : [];
      bus = {
        protocol: 1,
        apiVersion: PET_ROGUE_MOD_API_VERSION,
        api: null,
        pending,
        definitions,
        register(modifier) {
          const id = String(modifier?.id || '');
          if (id) {
            const index = this.definitions.findIndex((entry) => String(entry?.id || '') === id);
            if (index >= 0) this.definitions[index] = modifier;
            else this.definitions.push(modifier);
          }
          if (this.api) return this.api.register(modifier);
          const queuedIndex = this.pending.findIndex((entry) => String(entry?.id || '') === id);
          if (queuedIndex >= 0) this.pending[queuedIndex] = modifier;
          else this.pending.push(modifier);
          return { ok: true, queued: true, message: '主脚本尚未就绪，外挂已排队。' };
        },
        unregister(id) {
          const key = String(id || '');
          this.definitions = this.definitions.filter((entry) => String(entry?.id || '') !== key);
          this.pending = this.pending.filter((entry) => String(entry?.id || '') !== key);
          if (this.api) return this.api.unregister(key);
          return { ok: true, queued: true };
        },
        list() { return this.api ? this.api.list() : this.definitions.map((entry) => ({ id: entry?.id || '', name: entry?.name || '', queued: true })); },
      };
    }
    host[PET_ROGUE_MOD_BUS_KEY] = bus;
    try { window[PET_ROGUE_MOD_BUS_KEY] = bus; } catch (_) {}
    return bus;
  }

  const petRogueModBus = getPetRogueModifierBus();
  const publicPetRogueModApi = Object.freeze({
    apiVersion: PET_ROGUE_MOD_API_VERSION,
    coreVersion: CORE_VERSION,
    register: registerPetRogueModifier,
    unregister: unregisterPetRogueModifier,
    list: listPetRogueModifiers,
    summary: () => ({ ...petRogueModifierSummary() }),
  });
  petRogueModBus.api = publicPetRogueModApi;
  petRogueModBus.apiVersion = PET_ROGUE_MOD_API_VERSION;
  host.PixelTamagotchiPetRogueModAPI = publicPetRogueModApi;
  try { window.PixelTamagotchiPetRogueModAPI = publicPetRogueModApi; } catch (_) {}
  const queuedPetRogueModifiers = [
    ...(Array.isArray(petRogueModBus.definitions) ? petRogueModBus.definitions : []),
    ...(Array.isArray(petRogueModBus.pending) ? petRogueModBus.pending.splice(0) : []),
  ];
  const queuedPetRogueModifierById = new Map();
  queuedPetRogueModifiers.forEach((modifier) => {
    const id = String(modifier?.id || '');
    if (id) queuedPetRogueModifierById.set(id, modifier);
  });
  queuedPetRogueModifierById.forEach((modifier) => registerPetRogueModifier(modifier));

  function savePayloadSignature(save) {
    if (!save || typeof save !== 'object') return '';
    const pet = save.pet && typeof save.pet === 'object' ? save.pet : null;
    const egg = save.egg && typeof save.egg === 'object' ? save.egg : null;
    const cemetery = Array.isArray(save.cemetery) ? save.cemetery : [];
    const careLog = Array.isArray(save.careLog) ? save.careLog : [];
    const lastCemetery = cemetery[cemetery.length - 1] || null;
    const lastCare = careLog[careLog.length - 1] || null;
    return [
      String(save._ptgOwnerKey || ''), String(save.lifecycle || ''),
      String(pet?.petId || pet?._ptgPetId || ''), String(pet?.species || ''), String(pet?.colorId || ''),
      Number(pet?.birthdayAt) || 0, Number(pet?.lastUpdateAt) || 0,
      Number(egg?.boughtAt) || 0, Number(egg?.hatchAt) || 0,
      Number(save.createdAt) || 0, cemetery.length, Number(lastCemetery?.deathAt || lastCemetery?.diedAt) || 0,
      careLog.length, Number(lastCare?.at || lastCare?.createdAt) || 0,
      String(save.schedule?.dayKey || ''), Number(save.schedule?.today?.length) || 0, Number(save.schedule?.template?.length) || 0,
    ].join('|');
  }

  function saveOwnerKey(save) {
    return String(save?._ptgOwnerKey || '');
  }

  function stampSaveOwner(save, info) {
    if (!save || !info?.key) return save;
    save._ptgOwnerKey = info.key;
    save._ptgOwnerName = info.name || '';
    save._ptgOwnerVersion = 1;
    return save;
  }

  function beginCharacterTransition() {
    if (app.pendingSaveTimer && app.characterContextReady) {
      clearPendingSave();
      saveCurrent();
    }
    if (app.save && app.characterKey) {
      app.previousCharacterSnapshot = {
        key: app.characterKey,
        signature: savePayloadSignature(app.save),
        at: nowMs(),
      };
    }
    app.characterContextReady = false;
    app.saveRecheckToken += 1;
  }

  function refreshLiveCharacterName() {
    const info = getCharacterInfo();
    if (info && (!app.characterKey || info.key === app.characterKey)) {
      app.characterName = info.name;
    }
    return app.characterName || null;
  }

  function createEgg(now = nowMs(), starter = false) {
    return {
      boughtAt: now,
      hatchAt: starter ? now : now + CONFIG.eggHatchMinutes * 60000,
      shellColor: randomChoice(['mint', 'rose', 'honey', 'sky', 'lilac']),
      starter,
    };
  }

  function randomEventDelay(first = false) {
    const min = first ? CONFIG.firstEventMinMinutes : CONFIG.eventMinMinutes;
    const max = first ? CONFIG.firstEventMaxMinutes : CONFIG.eventMaxMinutes;
    return (min + Math.random() * Math.max(1, max - min)) * 60000;
  }



  function scheduleId(prefix = 'task') {
    return `${prefix}_${nowMs().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
  }

  function createEmptySchedule(now = nowMs()) {
    return {
      dayKey: localDayKey(now),
      template: [],
      today: [],
      todayTouched: false,
      planApplied: false,
      history: [],
      lastProcessedAt: now,
    };
  }

  function normalizeScheduleTemplateTask(task) {
    if (!task || typeof task !== 'object') return null;
    const category = ['study', 'fun', 'sleep', 'work'].includes(task.category) ? task.category : null;
    const definition = activityDefinition(category, task.activityId);
    const durationHours = Number(task.durationHours);
    if (!category || !definition || !Number.isFinite(durationHours) || durationHours <= 0 || durationHours > 10) return null;
    return {
      templateId: String(task.templateId || scheduleId('tpl')),
      category,
      activityId: String(task.activityId),
      durationHours,
    };
  }

  function cloneTemplateTaskForToday(task) {
    return {
      id: scheduleId('day'),
      templateId: task.templateId,
      category: task.category,
      activityId: task.activityId,
      durationHours: task.durationHours,
      progressHours: 0,
      status: 'queued',
      reward: 0,
      attributeRewardGranted: false,
      attributeReward: {},
    };
  }

  function normalizeSchedule(raw) {
    const base = createEmptySchedule();
    if (!raw || typeof raw !== 'object') return base;
    const template = Array.isArray(raw.template)
      ? raw.template.map(normalizeScheduleTemplateTask).filter(Boolean).slice(0, 20)
      : [];
    const today = Array.isArray(raw.today)
      ? raw.today.map((entry) => {
          const normalized = normalizeScheduleTemplateTask(entry);
          if (!normalized) return null;
          return {
            ...cloneTemplateTaskForToday(normalized),
            id: String(entry.id || scheduleId('day')),
            progressHours: clamp(Number(entry.progressHours) || 0, 0, normalized.durationHours),
            status: ['queued', 'active', 'done', 'skipped', 'blocked', 'blocked_energy', 'cancelled'].includes(entry.status) ? entry.status : 'queued',
            reward: Math.max(0, Math.floor(Number(entry.reward) || 0)),
            attributeRewardGranted: Boolean(entry.attributeRewardGranted) || entry.status === 'done',
            attributeReward: normalizeAttributeRewardMap(entry.attributeReward || {}),
          };
        }).filter(Boolean)
      : [];
    return {
      dayKey: String(raw.dayKey || localDayKey()),
      template,
      today,
      todayTouched: Boolean(raw.todayTouched),
      planApplied: Boolean(raw.planApplied),
      history: Array.isArray(raw.history) ? raw.history.slice(-14) : [],
      lastProcessedAt: Number(raw.lastProcessedAt) || nowMs(),
    };
  }

  function scheduleTemplateHours(schedule) {
    return round1((schedule?.template || []).reduce((total, task) => total + Number(task.durationHours || 0), 0));
  }

  function archiveScheduleDay(schedule) {
    if (!schedule?.dayKey || !Array.isArray(schedule.today) || schedule.today.length === 0) return;
    schedule.history.push({
      dayKey: schedule.dayKey,
      completed: schedule.today.filter((task) => task.status === 'done').length,
      missed: schedule.today.filter((task) => !['done', 'cancelled'].includes(task.status)).length,
      earned: schedule.today.reduce((sum, task) => sum + Number(task.reward || 0), 0),
    });
    schedule.history = schedule.history.slice(-14);
  }

  function ensureScheduleDay(save, dayKey) {
    if (!save.schedule) save.schedule = createEmptySchedule();
    if (save.schedule.dayKey === dayKey) return;
    archiveScheduleDay(save.schedule);
    save.schedule.dayKey = dayKey;
    // 新的一天：今日执行清空、等待玩家设定；若到 8 点仍未设定，再由 maybeApplyDailyPlan 套用每日计划。
    save.schedule.today = [];
    save.schedule.todayTouched = false;
    save.schedule.planApplied = false;
  }

  // 到达每日 8:00 时，如果玩家（或角色）当天还没有为“今日执行”设定任何日程，则自动套用“每日计划”；已设定则不覆盖。
  function maybeApplyDailyPlan(save, atTimestamp = nowMs()) {
    const schedule = save?.schedule;
    if (!schedule) return;
    if (schedule.todayTouched || schedule.planApplied) return;
    if (!Array.isArray(schedule.template) || schedule.template.length === 0) return;
    if (new Date(atTimestamp).getHours() < CONFIG.scheduleStartHour) return;
    schedule.today = schedule.template.map(cloneTemplateTaskForToday);
    schedule.planApplied = true;
  }

  function scheduleTodayHours(schedule) {
    return round1((schedule?.today || []).reduce((total, task) => total + Number(task.durationHours || 0), 0));
  }

  function normalizeAttributeDelta(amount) {
    const value = Number(amount);
    if (!Number.isFinite(value) || value === 0) return 0;
    const sign = value < 0 ? -1 : 1;
    return sign * clamp(Math.round(Math.abs(value)), 1, 5);
  }

  function normalizeAttributeRewardMap(changes = {}) {
    return Object.fromEntries(Object.entries(changes || {}).map(([key, amount]) => [key, normalizeAttributeDelta(amount)]).filter(([key, amount]) => ATTRIBUTE_DEFS[key] && amount !== 0));
  }

  function scheduleAttributeRewards(definition, durationHours) {
    if (!definition?.attributeRewards) return {};
    const key = String(Number(durationHours));
    return normalizeAttributeRewardMap(definition.attributeRewards[key] || {});
  }

  function formatAttributeChanges(changes = {}) {
    return Object.entries(changes).filter(([key, value]) => ATTRIBUTE_DEFS[key] && Number(value) !== 0).map(([key, value]) => `${ATTRIBUTE_DEFS[key].name} ${Number(value) > 0 ? '+' : ''}${Math.trunc(Number(value))}`).join('、');
  }

  function applyAttributeChanges(pet, changes = {}) {
    if (!pet) return {};
    if (!pet.attributes) pet.attributes = randomAttributes();
    const applied = {};
    Object.entries(normalizeAttributeRewardMap(changes)).forEach(([key, delta]) => {
      const before = clamp(Math.round(Number(pet.attributes[key] || 0)), 0, 100);
      const after = clamp(before + delta, 0, 100);
      pet.attributes[key] = after;
      const actual = after - before;
      if (actual !== 0) applied[key] = actual;
    });
    return applied;
  }

  function applyPassiveNeeds(pet, hours, sleeping = false) {
    if (!pet || hours <= 0) return;
    pet.hunger = clampPetStat(pet, 'hunger', pet.hunger - CONFIG.hungerLossPerHour * hours * petLossMultiplier(pet, 'hunger', 'passive'));
    pet.happiness = clampPetStat(pet, 'happiness', pet.happiness - CONFIG.happinessLossPerHour * hours * petLossMultiplier(pet, 'happiness', 'passive'));
    pet.cleanliness = clampPetStat(pet, 'cleanliness', pet.cleanliness - CONFIG.cleanlinessLossPerHour * hours * petLossMultiplier(pet, 'cleanliness', 'passive'));
    if (sleeping) {
      pet.energy = clampPetStat(pet, 'energy', pet.energy + CONFIG.sleepEnergyGainPerHour * hours);
      pet.hunger = clampPetStat(pet, 'hunger', pet.hunger - 1.0 * hours * petLossMultiplier(pet, 'hunger', 'passive'));
    } else {
      pet.energy = clampPetStat(pet, 'energy', pet.energy - CONFIG.energyLossPerHour * hours * petLossMultiplier(pet, 'energy', 'passive'));
    }
    pet.wasteProgressHours += hours;
    while (pet.wasteProgressHours >= CONFIG.wasteEveryHours && pet.mess < 4) {
      pet.mess += 1;
      pet.wasteProgressHours -= CONFIG.wasteEveryHours;
    }
  }

  function applyPassiveHealth(pet, hours, sleeping = false) {
    if (!pet || hours <= 0) return;
    let healthDelta = 0;
    const hungerMax = petStatMax(pet, 'hunger');
    if (pet.hunger <= hungerMax * 0.05) healthDelta -= 5 * hours;
    if (pet.cleanliness <= 15 || pet.mess >= 3) healthDelta -= 3.5 * hours;
    if (pet.energy <= 5 && !sleeping) healthDelta -= 2.5 * hours;
    if (pet.hunger >= hungerMax * 0.35 && pet.cleanliness >= 35 && pet.energy >= 25 && !pet.sick) healthDelta += 0.6 * hours;
    pet.health = clampPetStat(pet, 'health', pet.health + healthDelta);
    pet.sick = pet.health < 35 || (pet.sick && pet.health < 75);
  }

  function applyIdleProgress(save, hours, sleeping = false) {
    if (!save?.pet || hours <= 0) return;
    applyPassiveNeeds(save.pet, hours, sleeping);
    applyPassiveHealth(save.pet, hours, sleeping);
  }

  function applyScheduledProgress(save, task, hours) {
    const pet = save.pet;
    const definition = activityDefinition(task.category, task.activityId);
    if (!pet || !definition || hours <= 0) return;
    if (task.category === 'sleep') {
      applyIdleProgress(save, hours, true);
      return;
    }
    applyPassiveNeeds(pet, hours, false);
    Object.entries(definition.effectsPerHour || {}).forEach(([key, amount]) => {
      if (['hunger', 'happiness', 'health', 'cleanliness', 'energy'].includes(key)) {
        const strain = task.category === 'work' && ['hunger', 'cleanliness', 'energy'].includes(key) && Number(amount) < 0
          ? shiftStrainMultiplier(task.durationHours)
          : 1;
        const extensionMultiplier = Number(amount) < 0 ? petLossMultiplier(pet, key, 'activity') : 1;
        pet[key] = clampPetStat(pet, key, Number(pet[key] || 0) + Number(amount || 0) * hours * strain * extensionMultiplier);
      }
    });
    if (definition.companionshipPerHour) changeCompanionship(save, Number(definition.companionshipPerHour) * hours);
    applyPassiveHealth(pet, hours, false);
  }

  function completeScheduledTask(save, task) {
    const definition = activityDefinition(task.category, task.activityId);
    task.status = 'done';
    task.progressHours = task.durationHours;
    save.stats.totalScheduleTasks += 1;
    if (task.category === 'study') save.stats.totalStudyTasks += 1;

    let attributeText = '';
    if (!task.attributeRewardGranted && task.category !== 'sleep') {
      const plannedRewards = scheduleAttributeRewards(definition, task.durationHours);
      const appliedRewards = applyAttributeChanges(save.pet, plannedRewards);
      task.attributeRewardGranted = true;
      task.attributeReward = appliedRewards;
      attributeText = formatAttributeChanges(appliedRewards);
    }
    const attributeSuffix = attributeText ? ` 属性提升：${attributeText}。` : '';

    if (task.category === 'work') {
      save.stats.totalWorkTasks += 1;
      task.reward = calculateJobReward(definition, task.durationHours);
      addCoins(save, task.reward);
      app.message = `${save.pet.name}完成了「${definition.name}」${task.durationHours}小时班次，工资 +${task.reward}。${attributeSuffix}`;
    } else if (task.category === 'study') {
      app.message = `${save.pet.name}完成了「${definition.name}」。${attributeSuffix || '相关属性已经达到上限。'}`;
    } else if (task.category === 'sleep') {
      app.message = `${save.pet.name}完成了${formatHours(task.durationHours)}休息，恢复了最多 ${Math.round(task.durationHours * CONFIG.sleepEnergyGainPerHour)} 点精力。`;
    } else {
      app.message = `${save.pet.name}完成了「${definition.name}」，看起来心情不错。${attributeSuffix}`;
    }
  }

  function processScheduleHours(save, availableHours) {
    if (!save?.pet || availableHours <= 0) return;
    let remaining = availableHours;
    let guard = 0;
    while (remaining > 0.0001 && guard < 100) {
      guard += 1;
      const task = save.schedule.today.find((entry) => ['queued', 'active'].includes(entry.status));
      if (!task) {
        applyIdleProgress(save, remaining, false);
        remaining = 0;
        break;
      }
      const definition = activityDefinition(task.category, task.activityId);
      if (!definition) {
        task.status = 'skipped';
        continue;
      }
      const isStarting = Number(task.progressHours || 0) <= 0.0001 && task.status !== 'active';
      if (isStarting && ['study', 'work'].includes(task.category) && Number(save.pet.energy || 0) < CONFIG.minimumActivityEnergy) {
        task.status = 'blocked_energy';
        continue;
      }
      if (isStarting && task.category === 'work' && !jobRequirementsMet(save.pet, definition)) {
        task.status = 'blocked';
        continue;
      }
      task.status = 'active';
      const taskRemaining = Math.max(0, Number(task.durationHours) - Number(task.progressHours || 0));
      if (taskRemaining <= 0.0001) {
        completeScheduledTask(save, task);
        continue;
      }
      const delta = Math.min(remaining, taskRemaining);
      applyScheduledProgress(save, task, delta);
      task.progressHours = Math.min(task.durationHours, Number(task.progressHours || 0) + delta);
      remaining -= delta;
      if (task.progressHours >= task.durationHours - 0.0001) completeScheduledTask(save, task);
    }
    if (remaining > 0.0001) applyIdleProgress(save, remaining, false);
  }

  function localDayStart(timestamp) {
    const date = new Date(timestamp);
    date.setHours(0, 0, 0, 0);
    return date.getTime();
  }

  function localDayEnd(timestamp) {
    const date = new Date(timestamp);
    date.setHours(0, 0, 0, 0);
    date.setDate(date.getDate() + 1);
    return date.getTime();
  }

  function automaticWakeAt(timestamp) {
    const date = new Date(timestamp);
    date.setHours(CONFIG.scheduleStartHour, 0, 0, 0);
    return date.getTime();
  }

  function startAutomaticNightSleep(save, atTimestamp = nowMs()) {
    const pet = save?.pet;
    if (!pet) return false;
    const dayKey = localDayKey(atTimestamp);
    if (pet.nightSleepDayKey === dayKey) {
      if (pet.nightSleepActive && !pet.sleeping) {
        pet.sleeping = true;
        pet.sleepStartedAt = atTimestamp;
        pet.sleepStartEnergy = pet.energy;
      }
      return false;
    }
    pet.nightSleepDayKey = dayKey;
    pet.nightSleepActive = true;
    if (!pet.sleeping) {
      pet.sleeping = true;
      pet.sleepStartedAt = atTimestamp;
      pet.sleepStartEnergy = pet.energy;
    } else {
      if (!pet.sleepStartedAt) pet.sleepStartedAt = atTimestamp;
      if (pet.sleepStartEnergy === null || pet.sleepStartEnergy === undefined) pet.sleepStartEnergy = pet.energy;
    }
    return true;
  }

  function wakeFromAutomaticNightSleep(save, atTimestamp = nowMs()) {
    const pet = save?.pet;
    if (!pet?.nightSleepActive) return false;
    pet.nightSleepActive = false;
    if (pet.sleeping) {
      pet.sleeping = false;
      pet.sleepStartedAt = null;
      pet.sleepStartEnergy = null;
    }
    return true;
  }

  function syncAutomaticDailyState(save, atTimestamp = nowMs()) {
    if (!save?.pet || save.lifecycle !== 'alive') return;
    ensureScheduleDay(save, localDayKey(atTimestamp));
    const hour = new Date(atTimestamp).getHours();
    if (hour < CONFIG.scheduleStartHour) {
      startAutomaticNightSleep(save, atTimestamp);
    } else {
      wakeFromAutomaticNightSleep(save, atTimestamp);
      if (!save.pet.sleeping) maybeApplyDailyPlan(save, atTimestamp);
    }
  }

  function settleDailySchedule(save, fromTimestamp, toTimestamp) {
    if (!save?.pet || save.lifecycle !== 'alive' || !save.schedule || toTimestamp <= fromTimestamp) return;
    let cursor = Math.max(fromTimestamp, toTimestamp - CONFIG.maxOfflineHours * 3600000);
    while (cursor < toTimestamp) {
      const dayStart = localDayStart(cursor);
      const dayEnd = localDayEnd(cursor);
      const segmentEnd = Math.min(toTimestamp, dayEnd);
      const scheduleStart = automaticWakeAt(cursor);
      ensureScheduleDay(save, localDayKey(cursor));

      // 00:00～08:00：每天只触发一次自动入睡。玩家若夜间手动叫醒，本夜不会反复强制睡回去。
      if (cursor < Math.min(segmentEnd, scheduleStart)) {
        startAutomaticNightSleep(save, cursor);
        const nightEnd = Math.min(segmentEnd, scheduleStart);
        applyIdleProgress(save, (nightEnd - cursor) / 3600000, Boolean(save.pet.sleeping));
        cursor = nightEnd;
      }

      // 08:00：仅解除由夜间规则触发的睡眠；随后套用每日计划并立即开始结算今日执行。
      if (cursor < segmentEnd) {
        if (cursor >= scheduleStart) wakeFromAutomaticNightSleep(save, scheduleStart);
        if (!save.pet.sleeping) maybeApplyDailyPlan(save, Math.max(cursor, scheduleStart));
        const hours = (segmentEnd - cursor) / 3600000;
        if (save.pet.sleeping) applyIdleProgress(save, hours, true);
        else processScheduleHours(save, hours);
        cursor = segmentEnd;
      }

      if (cursor === dayEnd && cursor < toTimestamp) ensureScheduleDay(save, localDayKey(cursor));
    }
    syncAutomaticDailyState(save, toTimestamp);
    save.schedule.lastProcessedAt = toTimestamp;
  }


  function createFortuneHouseState(now = nowMs()) {
    return {
      dayKey: localDayKey(now),
      ticketsBoughtToday: 0,
      tickets: [],
      fortune: null,
      fortuneHistory: [],
      currentAnswer: null,
      answerHistory: [],
    };
  }

  function normalizeLotteryTicket(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const id = String(raw.id || '').trim();
    if (!id) return null;
    const prizeId = LOTTERY_PRIZES[raw.prizeId] ? raw.prizeId : null;
    return {
      id,
      boughtAt: Math.max(0, Number(raw.boughtAt) || nowMs()),
      boughtDayKey: String(raw.boughtDayKey || localDayKey(Number(raw.boughtAt) || nowMs())),
      prizeId,
      revealed: Boolean(raw.revealed && prizeId),
      revealedAt: Math.max(0, Number(raw.revealedAt) || 0),
      awarded: Boolean(raw.awarded && prizeId),
    };
  }

  function normalizeFortuneRecord(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const omen = FORTUNE_OMENS.find((entry) => entry.id === raw.omenId);
    if (!omen) return null;
    const dice = Array.isArray(raw.dice)
      ? raw.dice.map((id) => FORTUNE_DICE_FACES.some((face) => face.id === id) ? id : null).filter(Boolean).slice(0, 3)
      : [];
    while (dice.length < 3) dice.push(FORTUNE_DICE_FACES[dice.length % FORTUNE_DICE_FACES.length].id);
    return {
      dayKey: String(raw.dayKey || localDayKey(Number(raw.rolledAt) || nowMs())),
      omenId: omen.id,
      grade: omen.grade,
      dice,
      rolledAt: Math.max(0, Number(raw.rolledAt) || nowMs()),
    };
  }

  function normalizeFortuneHouse(raw) {
    const base = createFortuneHouseState();
    if (!raw || typeof raw !== 'object') return base;
    const tickets = Array.isArray(raw.tickets)
      ? raw.tickets
          .map(normalizeLotteryTicket)
          .filter(Boolean)
          .sort((a, b) => Number(a.boughtAt || 0) - Number(b.boughtAt || 0))
          .slice(-1)
      : [];
    const fortuneHistory = Array.isArray(raw.fortuneHistory)
      ? raw.fortuneHistory.map(normalizeFortuneRecord).filter(Boolean).slice(-30)
      : [];
    const answerHistory = Array.isArray(raw.answerHistory)
      ? raw.answerHistory.map((entry) => ({
          id: Math.max(0, Math.min(ANSWER_BOOK_TOTAL - 1, Math.floor(Number(entry?.id) || 0))),
          text: String(entry?.text || '').slice(0, 160),
          at: Math.max(0, Number(entry?.at) || 0),
        })).filter((entry) => entry.text).slice(-30)
      : [];
    const currentAnswer = raw.currentAnswer && typeof raw.currentAnswer === 'object'
      ? {
          id: Math.max(0, Math.min(ANSWER_BOOK_TOTAL - 1, Math.floor(Number(raw.currentAnswer.id) || 0))),
          text: String(raw.currentAnswer.text || '').slice(0, 160),
          at: Math.max(0, Number(raw.currentAnswer.at) || 0),
        }
      : null;
    return {
      dayKey: String(raw.dayKey || localDayKey()),
      ticketsBoughtToday: Math.max(0, Math.min(LOTTERY_DAILY_LIMIT, Math.floor(Number(raw.ticketsBoughtToday) || 0))),
      tickets,
      fortune: normalizeFortuneRecord(raw.fortune),
      fortuneHistory,
      currentAnswer: currentAnswer?.text ? currentAnswer : (answerHistory.at(-1) || null),
      answerHistory,
    };
  }

  function ensureFortuneHouseDay(save, atTimestamp = nowMs()) {
    if (!save) return false;
    if (!save.fortuneHouse) save.fortuneHouse = createFortuneHouseState(atTimestamp);
    const today = localDayKey(atTimestamp);
    if (save.fortuneHouse.dayKey === today) return false;
    const previous = normalizeFortuneRecord(save.fortuneHouse.fortune);
    if (previous && previous.dayKey !== today && !save.fortuneHouse.fortuneHistory.some((entry) => entry.dayKey === previous.dayKey)) {
      save.fortuneHouse.fortuneHistory.push(previous);
      save.fortuneHouse.fortuneHistory = save.fortuneHouse.fortuneHistory.slice(-30);
    }
    save.fortuneHouse.dayKey = today;
    save.fortuneHouse.ticketsBoughtToday = 0;
    save.fortuneHouse.fortune = null;
    app.fortuneDetailOpen = false;
    return true;
  }

  function fortuneOmen(record = app.save?.fortuneHouse?.fortune) {
    return record ? FORTUNE_OMENS.find((entry) => entry.id === record.omenId) || null : null;
  }

  function fortuneGradeMeta(record = app.save?.fortuneHouse?.fortune) {
    const omen = fortuneOmen(record);
    return FORTUNE_GRADE_META[omen?.grade] || FORTUNE_GRADE_META.success;
  }

  function weightedRandomKey(weightMap) {
    const entries = Object.entries(weightMap).filter(([, weight]) => Number(weight) > 0);
    const total = entries.reduce((sum, [, weight]) => sum + Number(weight), 0);
    if (total <= 0 || !entries.length) return entries[0]?.[0] || null;
    let cursor = Math.random() * total;
    for (const [key, weight] of entries) {
      cursor -= Number(weight);
      if (cursor < 0) return key;
    }
    return entries.at(-1)[0];
  }

  function lotteryWeightsForFortune(record = app.save?.fortuneHouse?.fortune) {
    const weights = { ...LOTTERY_BASE_WEIGHTS };
    const shift = Number(fortuneGradeMeta(record).luckShift || 0);
    if (shift === 0) return weights;
    const lowKeys = ['none', 'coin5', 'coin10'];
    const highKeys = ['coin20', 'coin50', 'coin100', 'coin200'];
    const lowRatios = { none: 0.6, coin5: 0.24, coin10: 0.16 };
    const highRatios = { coin20: 0.52, coin50: 0.22, coin100: 0.16, coin200: 0.10 };
    if (shift > 0) {
      lowKeys.forEach((key) => { weights[key] = Math.max(0.1, weights[key] - shift * lowRatios[key]); });
      highKeys.forEach((key) => { weights[key] += shift * highRatios[key]; });
    } else {
      const amount = Math.abs(shift);
      lowKeys.forEach((key) => { weights[key] += amount * lowRatios[key]; });
      highKeys.forEach((key) => { weights[key] = Math.max(0.1, weights[key] - amount * highRatios[key]); });
    }
    // 固定头奖精确为 1%，再将浮点误差补到 20 金币档。
    weights.coin500 = 1;
    const total = Object.values(weights).reduce((sum, value) => sum + value, 0);
    weights.coin20 += 100 - total;
    return weights;
  }

  function chooseLotteryPrize(record = app.save?.fortuneHouse?.fortune) {
    return weightedRandomKey(lotteryWeightsForFortune(record)) || 'none';
  }

  function buyLotteryTicket() {
    const save = app.save;
    if (!save) return;
    ensureFortuneHouseDay(save);
    const house = save.fortuneHouse;
    if (house.ticketsBoughtToday >= LOTTERY_DAILY_LIMIT) {
      app.message = `今天已经购买了 ${LOTTERY_DAILY_LIMIT} 张彩票，明天再来吧。`;
      render();
      return;
    }
    if (!spendCoins(save, LOTTERY_TICKET_PRICE)) {
      app.message = `购买一张彩票需要 ${LOTTERY_TICKET_PRICE} 金币。`;
      render();
      return;
    }
    // 彩票区只保留最新购买的一张。购买新票时直接替换旧票，
    // 无论旧票是否已经刮开，都不会继续出现在存档和界面中。
    house.tickets = [{
      id: scheduleId('ticket'),
      boughtAt: nowMs(),
      boughtDayKey: localDayKey(),
      prizeId: null,
      revealed: false,
      revealedAt: 0,
      awarded: false,
    }];
    house.ticketsBoughtToday += 1;
    app.message = `购买了一张刮刮乐，今天还可购买 ${LOTTERY_DAILY_LIMIT - house.ticketsBoughtToday} 张。`;
    saveCurrent();
    render();
  }

  function lotteryTicketById(ticketId) {
    return app.save?.fortuneHouse?.tickets?.find((ticket) => ticket.id === ticketId) || null;
  }

  function ensureLotteryTicketPrize(ticketId) {
    const ticket = lotteryTicketById(ticketId);
    if (!ticket || ticket.revealed) return ticket;
    if (!ticket.prizeId || !LOTTERY_PRIZES[ticket.prizeId]) {
      ticket.prizeId = chooseLotteryPrize();
      saveCurrent();
    }
    return ticket;
  }

  function revealLotteryTicket(ticketId) {
    const ticket = ensureLotteryTicketPrize(ticketId);
    if (!ticket || ticket.revealed) return false;
    ticket.revealed = true;
    ticket.revealedAt = nowMs();
    const prize = LOTTERY_PRIZES[ticket.prizeId] || LOTTERY_PRIZES.none;
    if (!ticket.awarded) {
      ticket.awarded = true;
      if (prize.coins > 0) addCoins(app.save, prize.coins);
    }
    app.message = prize.coins > 0 ? `刮出了「${prize.label}」！奖励已放入钱包。` : '这张彩票是「谢谢惠顾」。';
    playSfx(prize.coins >= 100 ? 'jackpot' : prize.coins > 0 ? 'coin' : 'fail');
    saveCurrent();
    notify(prize.coins >= 100 ? 'success' : 'info', prize.coins > 0 ? `刮刮乐获得 ${prize.coins} 金币` : '刮刮乐：谢谢惠顾');
    render();
    return true;
  }

  function pickFortuneGrade() {
    return weightedRandomKey(Object.fromEntries(Object.entries(FORTUNE_GRADE_META).map(([key, meta]) => [key, meta.weight]))) || 'success';
  }

  function fortuneDiceForGrade(grade) {
    const faceIds = FORTUNE_DICE_FACES.map((face) => face.id);
    const randomFace = () => randomChoice(faceIds);
    if (grade === 'supreme') {
      const face = randomFace();
      return [face, face, face];
    }
    if (grade === 'greater' || grade === 'fortune') {
      const face = randomFace();
      let other = randomFace();
      while (other === face) other = randomFace();
      const dice = [face, face, other];
      return dice.sort(() => Math.random() - 0.5);
    }
    const dice = [];
    while (dice.length < 3) {
      const face = randomFace();
      if (!dice.includes(face) || grade === 'success') dice.push(face);
    }
    return dice;
  }

  function rollDailyFortune() {
    const save = app.save;
    if (!save || app.fortuneRolling) return;
    ensureFortuneHouseDay(save);
    if (save.fortuneHouse.fortune) {
      app.fortuneDetailOpen = !app.fortuneDetailOpen;
      render();
      return;
    }
    app.fortuneRolling = true;
    playSfx('magic');
    app.message = '三枚卦骰正在滚动……';
    render();
    if (app.fortuneRollTimer) host.clearTimeout(app.fortuneRollTimer);
    app.fortuneRollTimer = host.setTimeout(() => {
      app.fortuneRollTimer = null;
      if (!app.save) return;
      ensureFortuneHouseDay(app.save);
      if (app.save.fortuneHouse.fortune) {
        app.fortuneRolling = false;
        render();
        return;
      }
      const grade = pickFortuneGrade();
      const candidates = FORTUNE_OMENS.filter((entry) => entry.grade === grade);
      const omen = randomChoice(candidates.length ? candidates : FORTUNE_OMENS);
      const record = {
        dayKey: localDayKey(),
        omenId: omen.id,
        grade: omen.grade,
        dice: fortuneDiceForGrade(omen.grade),
        rolledAt: nowMs(),
      };
      app.save.fortuneHouse.fortune = record;
      app.save.fortuneHouse.fortuneHistory.push(record);
      app.save.fortuneHouse.fortuneHistory = app.save.fortuneHouse.fortuneHistory.slice(-30);
      app.fortuneRolling = false;
      app.fortuneDetailOpen = false;
      const meta = FORTUNE_GRADE_META[omen.grade];
      app.message = `今日卦象：${meta.name} · ${omen.title}。`;
      playSfx('fortune');
      saveCurrent();
      render();
    }, 850);
  }

  function answerBookTextById(id) {
    const safe = Math.max(0, Math.min(ANSWER_BOOK_TOTAL - 1, Math.floor(Number(id) || 0)));
    const opening = ANSWER_BOOK_OPENINGS[Math.floor(safe / ANSWER_BOOK_ENDINGS.length)];
    const ending = ANSWER_BOOK_ENDINGS[safe % ANSWER_BOOK_ENDINGS.length];
    return `${opening}，${ending}`;
  }

  function openAnswerBookPage() {
    const house = app.save?.fortuneHouse;
    if (!house) return;
    const recentIds = new Set((house.answerHistory || []).slice(-20).map((entry) => entry.id));
    let id = Math.floor(Math.random() * ANSWER_BOOK_TOTAL);
    let guard = 0;
    while (recentIds.has(id) && guard < 40) {
      id = Math.floor(Math.random() * ANSWER_BOOK_TOTAL);
      guard += 1;
    }
    const entry = { id, text: answerBookTextById(id), at: nowMs() };
    house.currentAnswer = entry;
    house.answerHistory.push(entry);
    house.answerHistory = house.answerHistory.slice(-30);
    app.message = `答案之书翻到了第 ${id + 1} 页。`;
    playSfx('page');
    saveCurrent();
    render();
  }


  function createLeaderboardPlayerId() {
    try {
      const cryptoApi = host.crypto || globalThis.crypto;
      if (typeof cryptoApi?.randomUUID === 'function') return cryptoApi.randomUUID();
      const bytes = new Uint8Array(16);
      cryptoApi?.getRandomValues?.(bytes);
      if (!bytes.some((value) => value !== 0)) {
        for (let index = 0; index < bytes.length; index += 1) bytes[index] = Math.floor(Math.random() * 256);
      }
      bytes[6] = (bytes[6] & 0x0f) | 0x40;
      bytes[8] = (bytes[8] & 0x3f) | 0x80;
      const hex = [...bytes].map((value) => value.toString(16).padStart(2, '0'));
      return `${hex.slice(0, 4).join('')}-${hex.slice(4, 6).join('')}-${hex.slice(6, 8).join('')}-${hex.slice(8, 10).join('')}-${hex.slice(10).join('')}`;
    } catch (_) {
      const random = () => Math.floor(Math.random() * 0x10000).toString(16).padStart(4, '0');
      return `${random()}${random()}-${random()}-4${random().slice(1)}-${(8 + Math.floor(Math.random() * 4)).toString(16)}${random().slice(1)}-${random()}${random()}${random()}`;
    }
  }

  function validLeaderboardPlayerId(value) {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || ''));
