  function normalizeLeaderboardSnapshot(raw) {
    const source = raw && typeof raw === 'object' ? raw : {};
    // 旧版本可能已经把双表重复行写入本地快照；读取快照时也立即执行同一套去重。
    const rows = mergeLeaderboardRows([normalizeLeaderboardRows(source.rows)], LEADERBOARD_LIMIT);
    const ownRows = mergeLeaderboardRows([normalizeLeaderboardRows(source.own ? [source.own] : [])], 1);
    return {
      rows,
      own: ownRows[0] || null,
      fetchedAt: Math.max(0, Number(source.fetchedAt) || 0),
    };
  }

  function leaderboardSnapshotSignature(snapshot) {
