  function normalizeLeaderboardServerHighScoreRestore(raw) {
    const source = raw && typeof raw === 'object' ? raw : {};
    const completedGameIds = [...new Set((Array.isArray(source.completedGameIds) ? source.completedGameIds : [])
      .map((value) => String(value || '').trim())
      .filter((value) => /^[A-Za-z0-9_-]{1,64}$/.test(value)))]
      .slice(0, 512);
    const restoredScores = {};
    Object.entries(source.restoredScores && typeof source.restoredScores === 'object' ? source.restoredScores : {}).forEach(([gameId, score]) => {
      const id = String(gameId || '').trim();
      if (!/^[A-Za-z0-9_-]{1,64}$/.test(id)) return;
      restoredScores[id] = Math.max(0, Math.floor(Number(score) || 0));
    });
    return {
      version: 1,
      disabled: source.disabled === true,
      completedGameIds,
      restoredScores,
      lastAttemptAt: Math.max(0, Number(source.lastAttemptAt) || 0),
      completedAt: Math.max(0, Number(source.completedAt) || 0),
