  function normalizeLeaderboardProfile(raw) {
    const now = nowMs(); const source = raw && typeof raw === 'object' ? raw : {};
    const uploaded = {}, uploadedNicknames = {}, uploadedShowcaseSignatures = {}, snapshots = {};
    const gameIds = new Set([
      ...Object.keys(source.uploadedHighScores && typeof source.uploadedHighScores === 'object' ? source.uploadedHighScores : {}),
      ...Object.keys(source.uploadedNicknames && typeof source.uploadedNicknames === 'object' ? source.uploadedNicknames : {}),
      ...Object.keys(source.uploadedShowcaseSignatures && typeof source.uploadedShowcaseSignatures === 'object' ? source.uploadedShowcaseSignatures : {}),
      ...Object.keys(source.snapshots && typeof source.snapshots === 'object' ? source.snapshots : {}),
      ...Object.keys(GAME_DEFS),
    ]);
    gameIds.forEach((gameId) => {
      if (!/^[A-Za-z0-9_-]{1,64}$/.test(String(gameId))) return;
      uploaded[gameId] = Math.max(0, Math.floor(Number(source.uploadedHighScores?.[gameId]) || 0));
      uploadedNicknames[gameId] = [...String(source.uploadedNicknames?.[gameId] || '').trim()].slice(0, 20).join('');
      uploadedShowcaseSignatures[gameId] = String(source.uploadedShowcaseSignatures?.[gameId] || '');
      snapshots[gameId] = normalizeLeaderboardSnapshot(source.snapshots?.[gameId]);
    });
    const playerId = validLeaderboardPlayerId(source.playerId) ? String(source.playerId) : createLeaderboardPlayerId();
    const legacyPlayerIds = [...new Set((Array.isArray(source.legacyPlayerIds) ? source.legacyPlayerIds : [])
      .map((value) => String(value || '').trim())
      .filter((value) => validLeaderboardPlayerId(value) && value !== playerId))]
      .slice(0, 8);
    const nickname = [...String(source.nickname || '').trim()].slice(0, 20).join('');
    const nicknameAliases = [...new Set((Array.isArray(source.nicknameAliases) ? source.nicknameAliases : [])
      .map((value) => [...String(value || '').replace(/[\r\n\t]+/g, ' ').trim()].slice(0, 20).join(''))
      .filter((value) => value && value !== nickname))]
      .slice(-12);
    return {
      playerId,
      nickname,
      nicknameAliases,
      legacyPlayerIds,
      identityBoundAt: Math.max(0, Number(source.identityBoundAt) || 0),
      identityPreviousPlayerId: validLeaderboardPlayerId(source.identityPreviousPlayerId) ? String(source.identityPreviousPlayerId) : '',
      uploadedHighScores: uploaded, uploadedNicknames, uploadedShowcaseSignatures,
      backendVersion: Math.max(0, Math.floor(Number(source.backendVersion) || 0)), lastV2AttemptAt: Math.max(0, Number(source.lastV2AttemptAt) || 0),
      cosmetics: normalizeGachaState(source.cosmetics), snapshots,
      serverHighScoreRestore: normalizeLeaderboardServerHighScoreRestore(source.serverHighScoreRestore),
      createdAt: Math.max(0, Number(source.createdAt) || now), updatedAt: Math.max(0, Number(source.updatedAt) || now), lastSyncedAt: Math.max(0, Number(source.lastSyncedAt) || 0),
