  function normalizePet(rawPet) {
    if (!rawPet || typeof rawPet !== 'object') return null;
    const now = nowMs();
    const speciesId = SPECIES[rawPet.species] ? rawPet.species : 'leaf_blob';
    const variants = COLOR_VARIANTS[speciesId] || COLOR_VARIANTS.leaf_blob;
    const colorId = variants.some((item) => item.id === rawPet.colorId) ? rawPet.colorId : variants[0].id;
    const species = SPECIES[speciesId];
    const extensionId = String(rawPet._ptgExtensionId || extensionSpeciesOwners.get(speciesId) || '');
    const extension = extensionId ? petExtensions.get(extensionId) || null : null;
    const statCaps = extension?.policy?.statCaps || {};
    const statMax = (key) => {
      const configured = Number(statCaps[key]);
      return Number.isFinite(configured) && configured > 0 ? configured : 100;
    };
    const birthdayAt = Number(rawPet.birthdayAt) || now;
    const petId = String(rawPet.petId || rawPet._ptgPetId || createPetId()).slice(0, 96);
    const reviveCount = Math.max(0, Math.min(CONFIG.maxPetRevives, Math.floor(Number(rawPet.reviveCount) || 0)));
    const legacyCare = Math.max(0, Math.floor(Number(rawPet.careCount) || 0));
    const normalized = {
      petId,
      reviveCount,
      name: String(rawPet.name || species.name).slice(0, 16),
      species: speciesId,
      colorId,
      stage: String(rawPet.stage || '幼年期'),
      birthdayAt,
      naturalDeathAt: Number(rawPet.naturalDeathAt) || birthdayAt + (species.lifespanDays + Math.floor(Math.random() * 6)) * 86400000,
      lastUpdateAt: Number(rawPet.lastUpdateAt) || now,
      hunger: clamp(rawPet.hunger ?? 86, 0, statMax('hunger')),
      happiness: clamp(rawPet.happiness ?? 82, 0, statMax('happiness')),
      health: clamp(rawPet.health ?? 100, 0, statMax('health')),
      cleanliness: clamp(rawPet.cleanliness ?? 90, 0, statMax('cleanliness')),
      energy: clamp(rawPet.energy ?? 88, 0, statMax('energy')),
      companionship: clamp(rawPet.companionship ?? Math.min(100, 12 + legacyCare * 1.8), 0, statMax('companionship')),
      attributes: normalizeAttributes(rawPet.attributes),
      interactionCount: Math.max(0, Math.floor(Number(rawPet.interactionCount) || legacyCare)),
      touchCount: Math.max(0, Math.floor(Number(rawPet.touchCount) || 0)),
      lastCompanionTouchAt: Math.max(0, Number(rawPet.lastCompanionTouchAt) || 0),
      touchWindowStartedAt: Math.max(0, Number(rawPet.touchWindowStartedAt) || 0),
      touchWindowCount: Math.max(0, Math.floor(Number(rawPet.touchWindowCount) || 0)),
      touchAngryUntil: Math.max(0, Number(rawPet.touchAngryUntil) || 0),
      weight: Math.max(0.5, Number(rawPet.weight) || 3.2),
      sleeping: Boolean(rawPet.sleeping),
      sleepStartedAt: Boolean(rawPet.sleeping) ? (Number(rawPet.sleepStartedAt) || Number(rawPet.lastUpdateAt) || now) : null,
      sleepStartEnergy: Boolean(rawPet.sleeping) ? clamp(rawPet.sleepStartEnergy ?? rawPet.energy ?? 88, 0, statMax('energy')) : null,
      nightSleepActive: Boolean(rawPet.nightSleepActive),
      nightSleepDayKey: String(rawPet.nightSleepDayKey || ''),
      sick: Boolean(rawPet.sick),
      mess: Math.max(0, Math.min(4, Math.floor(Number(rawPet.mess) || 0))),
      wasteProgressHours: Math.max(0, Number(rawPet.wasteProgressHours) || 0),
      lastStage: String(rawPet.lastStage || rawPet.stage || '幼年期'),
      lastMovedAt: Math.max(0, Number(rawPet.lastMovedAt) || 0),
      lastMoveFrom: String(rawPet.lastMoveFrom || '').slice(0, 180),
      lastMoveTo: String(rawPet.lastMoveTo || '').slice(0, 180),
      _ptgExtensionId: extensionId || null,
      extensionData: rawPet.extensionData && typeof rawPet.extensionData === 'object' ? deepClone(rawPet.extensionData) : {},
    };
    const patch = callExtensionHook(extension, 'normalizePet', { pet: normalized, now }, null);
    if (patch && typeof patch === 'object') Object.assign(normalized, patch);
    return applyExtensionPetPolicy(normalized, extension, now);
  }

  function normalizeSave(raw) {
    const base = createDefaultSave();
    if (!raw || typeof raw !== 'object') {
      ensureExtensionPetForCurrentCharacter(base);
      return base;
    }

    const wasV1 = !raw.lifecycle && raw.pet;
    const oldStats = raw.stats || {};
    const oldEconomy = raw.economy || {};
    const merged = {
      ...base,
      ...deepClone(raw),
      economy: { ...base.economy, ...oldEconomy },
      inventory: { ...base.inventory, ...(raw.inventory || {}) },
      collection: {
        variants: { ...(raw.collection?.variants || {}) },
        species: { ...(raw.collection?.species || {}) },
      },
      achievements: { ...(raw.achievements || {}) },
      leaderboard: normalizeLeaderboardProfile(raw.leaderboard),
      fortuneHouse: normalizeFortuneHouse(raw.fortuneHouse),
      cemetery: Array.isArray(raw.cemetery) ? raw.cemetery.slice(-CONFIG.cemeteryLimit) : [],
      events: { ...base.events, ...(raw.events || {}) },
      stats: { ...base.stats, ...oldStats },
      schedule: normalizeSchedule(raw.schedule),
      gameRecords: {
        ...base.gameRecords,
        ...(raw.gameRecords || {}),
        highScores: { ...base.gameRecords.highScores, ...(raw.gameRecords?.highScores || {}) },
        suspended: normalizeSuspendedGame(raw.gameRecords?.suspended),
      },
      settings: { ...base.settings, ...(raw.settings || {}) },
      charCare: { ...base.charCare, ...(raw.charCare || {}), history: Array.isArray(raw.charCare?.history) ? raw.charCare.history.slice(-30) : [] },
      careLog: Array.isArray(raw.careLog) ? raw.careLog.slice(-CARE_LOG_LIMIT) : [],
      wardrobe: {
        owned: (raw.wardrobe && typeof raw.wardrobe.owned === 'object' && raw.wardrobe.owned) ? { ...raw.wardrobe.owned } : {},
        equipped: {
          head: raw.wardrobe?.equipped?.head && ACCESSORY_DEFS[raw.wardrobe.equipped.head]?.slot === 'head' ? raw.wardrobe.equipped.head : null,
          eyes: raw.wardrobe?.equipped?.eyes && ACCESSORY_DEFS[raw.wardrobe.equipped.eyes]?.slot === 'eyes' ? raw.wardrobe.equipped.eyes : null,
        },
      },
    };

    if (oldEconomy.companionCoinsToday === undefined) merged.economy.companionCoinsToday = Math.max(0, Number(oldEconomy.careCoinsToday) || 0);
    if (oldStats.totalCompanionActions === undefined) merged.stats.totalCompanionActions = Math.max(0, Number(oldStats.totalCare) || 0);
    if (oldStats.totalEvents === undefined) merged.stats.totalEvents = Math.max(0, Number(raw.events?.completed) || 0);
    if (merged.achievements.care_10 && !merged.achievements.bond_40) merged.achievements.bond_40 = merged.achievements.care_10;

    if (wasV1) merged.lifecycle = 'alive';
    merged.pet = normalizePet(raw.pet);
    if (merged.lifecycle === 'alive' && !merged.pet) merged.lifecycle = 'empty';
    if (merged.lifecycle === 'egg') {
      merged.egg = raw.egg && typeof raw.egg === 'object'
        ? { ...createEgg(), ...raw.egg, boughtAt: Number(raw.egg.boughtAt) || nowMs(), hatchAt: Number(raw.egg.hatchAt) || nowMs() }
        : createEgg(nowMs(), true);
    } else {
      merged.egg = null;
    }

    merged.economy.coins = Math.max(0, Math.floor(Number(merged.economy.coins) || 0));
    ['chatCoinsToday', 'companionCoinsToday', 'gameCoinsToday'].forEach((key) => {
      merged.economy[key] = Math.max(0, Math.floor(Number(merged.economy[key]) || 0));
    });
    const normalizedHighScores = {};
    const rawHighScores = merged.gameRecords.highScores && typeof merged.gameRecords.highScores === 'object'
      ? merged.gameRecords.highScores
      : {};
    // 先读取真实本地游戏 ID。v0.42 使用 collectHoney / bulletHell / zombieGarden / petRogue，
    // 不能把上传接口使用的小写 game_id 当成另一份本地成绩。
    Object.entries(rawHighScores).forEach(([gameId, score]) => {
      const id = String(gameId || '').trim();
      if (!/^[A-Za-z0-9_-]{1,64}$/.test(id)) return;
      if (Object.prototype.hasOwnProperty.call(OFFICIAL_REMOTE_GAME_ID_TO_LOCAL, id) && OFFICIAL_REMOTE_GAME_ID_TO_LOCAL[id] !== id) return;
      normalizedHighScores[id] = Math.max(0, Math.floor(Number(score) || 0));
    });
    // 仅当旧的驼峰键确实不存在时，才兼容曾被错误写入的小写官方键；绝不让别名覆盖真实本地记录。
    Object.entries(rawHighScores).forEach(([gameId, score]) => {
      const id = String(gameId || '').trim();
      const canonicalId = canonicalStoredGameId(id);
      if (canonicalId === id || normalizedHighScores[canonicalId] != null) return;
      normalizedHighScores[canonicalId] = Math.max(0, Math.floor(Number(score) || 0));
    });
    GAME_IDS.forEach((gameId) => {
      if (normalizedHighScores[gameId] == null) normalizedHighScores[gameId] = 0;
    });
    merged.gameRecords.highScores = normalizedHighScores;
    if (!SKINS[merged.settings.skin]) merged.settings.skin = 'honey';
    merged.settings.charCareIntegration = merged.settings.charCareIntegration !== false;
    merged.settings.deviceScale = Math.max(0.7, Math.min(1.3, Number(merged.settings.deviceScale) || 1));
    merged.settings.bgmEnabled = merged.settings.bgmEnabled !== false;
    merged.settings.bgmVolume = Math.round(clamp(Number(merged.settings.bgmVolume ?? DEFAULT_BGM_VOLUME), 0, 100));
    merged.settings.sfxVolume = Math.round(clamp(Number(merged.settings.sfxVolume ?? DEFAULT_SFX_VOLUME), 0, 100));
    merged.settings.bulletJoystickSensitivity = Math.max(0.25, Math.min(2, Number(merged.settings.bulletJoystickSensitivity) || 1));
    merged.settings.bulletKeyboardSensitivity = Math.max(0.25, Math.min(2, Number(merged.settings.bulletKeyboardSensitivity) || 1));
    merged.settings.installedGames = normalizeInstalledGames(merged.settings.installedGames);
    delete merged[['rhy', 'thmGame'].join('')];
    // 不再按当前已加载组件重建 highScores。脚本关闭、尚未注册或临时加载失败时，历史高分仍完整保留。
    merged.gameRecords.suspended = normalizeSuspendedGame(merged.gameRecords.suspended);
    if (merged.gameRecords.suspended && !isGameInstalled(merged.gameRecords.suspended.gameId, merged)) merged.gameRecords.suspended = null;
    Object.keys(ITEMS).forEach((key) => {
      merged.inventory[key] = Math.max(0, Math.floor(Number(merged.inventory[key]) || 0));
    });
    Object.keys(merged.stats).forEach((key) => {
      merged.stats[key] = Math.max(0, Math.floor(Number(merged.stats[key]) || 0));
    });
    merged.events.completed = Math.max(0, Math.floor(Number(merged.events.completed) || 0));
    merged.events.positive = Math.max(0, Math.floor(Number(merged.events.positive) || 0));
    merged.events.negative = Math.max(0, Math.floor(Number(merged.events.negative) || 0));
    merged.events.nextAt = Number(merged.events.nextAt) || nowMs() + randomEventDelay(true);
    merged.events.lastTouchEventAt = Math.max(0, Number(merged.events.lastTouchEventAt) || 0);
    merged.events.history = Array.isArray(merged.events.history) ? merged.events.history.slice(-20) : [];
    if (merged.events.current && !RANDOM_EVENTS.some((event) => event && event.id === merged.events.current.id)) merged.events.current = null;

    merged.cemetery = merged.cemetery.map((record) => {
      const ageDays = Math.max(0, Math.floor(Number(record.ageDays) || 0));
      const snapshot = record.petSnapshot && typeof record.petSnapshot === 'object' ? deepClone(record.petSnapshot) : null;
      const petId = String(record.petId || snapshot?.petId || snapshot?._ptgPetId || createPetId()).slice(0, 96);
      const reviveCount = Math.max(0, Math.min(CONFIG.maxPetRevives, Math.floor(Number(record.reviveCount ?? snapshot?.reviveCount) || 0)));
      if (snapshot) {
        snapshot.petId = petId;
        snapshot.reviveCount = reviveCount;
      }
      return {
        ...record,
        petId,
        reviveCount,
        revivedAt: Math.max(0, Number(record.revivedAt) || 0) || null,
        petSnapshot: snapshot,
        ageDays,
        companionDays: Math.max(1, Math.floor(Number(record.companionDays) || ageDays + 1)),
        companionship: clamp(record.companionship ?? Math.min(100, 12 + (Number(record.careCount) || 0) * 1.8)),
        interactionCount: Math.max(0, Math.floor(Number(record.interactionCount) || Number(record.careCount) || 0)),
      };
    });

    ensureExtensionPetForCurrentCharacter(merged);
    if (merged.pet) discoverVariant(merged, merged.pet.species, merged.pet.colorId, false);
    merged.version = SAVE_VERSION;
    return merged;
  }


  // ============================================================
  // v0.25.3 分层存档
  // 角色卡变量只保存宠物本身及其生活记录；金币、背包、设置、图鉴、
  // 成就、小游戏、占卜等统一写入酒馆全局变量，切换角色卡时继续共享。
  // ============================================================
  function createGlobalMigrationMeta(raw = null) {
    const source = raw && typeof raw === 'object' ? raw : {};
    return {
      schema: SPLIT_SAVE_SCHEMA_VERSION,
      initializedAt: Math.max(0, Number(source.initializedAt) || nowMs()),
      initializedFrom: String(source.initializedFrom || 'default'),
      migratedCharacterKeys: Array.isArray(source.migratedCharacterKeys)
        ? [...new Set(source.migratedCharacterKeys.map((key) => String(key || '')).filter(Boolean))].slice(-200)
        : [],
    };
  }

  function normalizeWardrobeOwned(raw) {
    const source = raw && typeof raw === 'object' ? raw : {};
    const result = {};
    Object.entries(source).forEach(([key, value]) => {
      if (!ACCESSORY_DEFS[key]) return;
      if (typeof value === 'boolean') result[key] = value;
      else result[key] = Math.max(0, Math.floor(Number(value) || 0));
    });
    return result;
  }

  function extractGlobalSave(save) {
    const source = save && typeof save === 'object' ? save : createDefaultSave();
    const createdAt = Math.max(0, Number(source._ptgGlobalCreatedAt || source.createdAt) || nowMs());
    return {
      version: SAVE_VERSION,
      _ptgGlobalSaveSchema: SPLIT_SAVE_SCHEMA_VERSION,
      _ptgGlobalMigration: createGlobalMigrationMeta(source._ptgGlobalMigration),
      _ptgHighScoreRecoveryV109: source._ptgHighScoreRecoveryV109 && typeof source._ptgHighScoreRecoveryV109 === 'object'
        ? deepClone(source._ptgHighScoreRecoveryV109)
        : null,
      _ptgHighScoreReadV110: source._ptgHighScoreReadV110 && typeof source._ptgHighScoreReadV110 === 'object'
        ? deepClone(source._ptgHighScoreReadV110)
        : null,
      economy: deepClone(source.economy || createDefaultSave().economy),
      inventory: deepClone(source.inventory || createDefaultSave().inventory),
      collection: deepClone(source.collection || { variants: {}, species: {} }),
      fortuneHouse: deepClone(source.fortuneHouse || createFortuneHouseState()),
      achievements: deepClone(source.achievements || {}),
      leaderboard: deepClone(normalizeLeaderboardProfile(source.leaderboard)),
      wardrobe: { owned: normalizeWardrobeOwned(source.wardrobe?.owned) },
      stats: deepClone(source.stats || createDefaultSave().stats),
      gameRecords: deepClone(source.gameRecords || createDefaultSave().gameRecords),
      settings: deepClone(source.settings || createDefaultSave().settings),
      createdAt,
      updatedAt: Math.max(createdAt, Number(source.updatedAt) || nowMs()),
    };
  }

  function extractCharacterSave(save, info = getCharacterInfo()) {
    const source = save && typeof save === 'object' ? save : createDefaultSave();
    const createdAt = Math.max(0, Number(source._ptgCharacterCreatedAt || source.createdAt) || nowMs());
    const payload = {
      version: SAVE_VERSION,
      _ptgSplitSaveSchema: SPLIT_SAVE_SCHEMA_VERSION,
      lifecycle: source.lifecycle,
      pet: source.pet ? deepClone(source.pet) : null,
      egg: source.egg ? deepClone(source.egg) : null,
      cemetery: Array.isArray(source.cemetery) ? deepClone(source.cemetery) : [],
      events: deepClone(source.events || createDefaultSave().events),
      charCare: deepClone(source.charCare || { history: [] }),
      careLog: Array.isArray(source.careLog) ? deepClone(source.careLog) : [],
      schedule: deepClone(source.schedule || createEmptySchedule()),
      wardrobe: {
        equipped: {
          head: source.wardrobe?.equipped?.head || null,
          eyes: source.wardrobe?.equipped?.eyes || null,
        },
      },
      createdAt,
      updatedAt: Math.max(createdAt, Number(source.updatedAt) || nowMs()),
    };
    stampSaveOwner(payload, info);
    return payload;
  }

  function normalizeGlobalSave(raw) {
    // normalizeSave 能继续兼容旧版完整存档；这里只抽出应全局共享的字段。
    const normalized = normalizeSave(raw && typeof raw === 'object' ? raw : {});
    const result = extractGlobalSave(normalized);
    result._ptgGlobalMigration = createGlobalMigrationMeta(raw?._ptgGlobalMigration || normalized._ptgGlobalMigration);
    result._ptgGlobalCreatedAt = result.createdAt;
    return result;
  }

  function combineCharacterAndGlobalSave(characterRaw, globalRaw, info = getCharacterInfo()) {
    const combined = normalizeSave(characterRaw && typeof characterRaw === 'object' ? characterRaw : null);
    const globalSave = normalizeGlobalSave(globalRaw);
    const equipped = {
      head: combined.wardrobe?.equipped?.head || null,
      eyes: combined.wardrobe?.equipped?.eyes || null,
    };

    combined.economy = deepClone(globalSave.economy);
    combined.inventory = deepClone(globalSave.inventory);
    combined.collection = deepClone(globalSave.collection);
    combined.fortuneHouse = deepClone(globalSave.fortuneHouse);
    combined.achievements = deepClone(globalSave.achievements);
    combined.leaderboard = deepClone(normalizeLeaderboardProfile(globalSave.leaderboard));
    combined.stats = deepClone(globalSave.stats);
    combined.gameRecords = deepClone(globalSave.gameRecords);
    combined.settings = deepClone(globalSave.settings);
    combined.wardrobe = {
      owned: normalizeWardrobeOwned(globalSave.wardrobe?.owned),
      equipped,
    };
    combined._ptgCharacterCreatedAt = Math.max(0, Number(characterRaw?.createdAt || combined.createdAt) || nowMs());
    combined._ptgGlobalCreatedAt = Math.max(0, Number(globalSave.createdAt) || nowMs());
    combined._ptgGlobalMigration = createGlobalMigrationMeta(globalSave._ptgGlobalMigration);
    combined._ptgHighScoreRecoveryV109 = globalSave._ptgHighScoreRecoveryV109 && typeof globalSave._ptgHighScoreRecoveryV109 === 'object'
      ? deepClone(globalSave._ptgHighScoreRecoveryV109)
      : null;
    combined._ptgHighScoreReadV110 = globalSave._ptgHighScoreReadV110 && typeof globalSave._ptgHighScoreReadV110 === 'object'
      ? deepClone(globalSave._ptgHighScoreReadV110)
      : null;
    combined.createdAt = combined._ptgCharacterCreatedAt;
    combined.updatedAt = Math.max(Number(characterRaw?.updatedAt) || 0, Number(globalSave.updatedAt) || 0, nowMs());
    combined.version = SAVE_VERSION;
    stampSaveOwner(combined, info);

    // 当前宠物的外观发现仍写入共享图鉴，但不会把宠物本体变成全局数据。
    if (combined.pet) discoverVariant(combined, combined.pet.species, combined.pet.colorId, false);
    return combined;
  }

  function globalMirrorKey() {
    return `${GLOBAL_ROOT_KEY}::mirror_v1`;
  }

  function readGlobalMirror() {
    try {
      const raw = host.localStorage?.getItem(globalMirrorKey());
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      const save = parsed && typeof parsed === 'object' ? parsed.save : null;
      return save && typeof save === 'object' ? save : null;
    } catch (_) {
      return null;
    }
  }

  function writeGlobalMirror(save) {
    if (!save) return;
    try {
      const key = globalMirrorKey();
      const next = JSON.stringify({ save, at: nowMs() });
      const storage = host.localStorage;
      const previous = storage?.getItem(key);
      if (previous && previous !== next) {
        const backupAtKey = `${key}::backup_at`;
        const lastBackupAt = Number(storage?.getItem(backupAtKey)) || 0;
        if (nowMs() - lastBackupAt >= MIRROR_BACKUP_INTERVAL_MS) {
          storage?.setItem(`${key}::backup`, previous);
          storage?.setItem(backupAtKey, String(nowMs()));
        }
      }
      storage?.setItem(key, next);
    } catch (_) {}
  }

  function isLegacyFullSave(raw) {
    if (!raw || typeof raw !== 'object' || raw._ptgSplitSaveSchema) return false;
    return Boolean(raw.economy || raw.inventory || raw.collection || raw.achievements || raw.gameRecords || raw.settings || raw.fortuneHouse);
  }

  function legacySaveTimestamp(raw) {
    return Math.max(0, Number(raw?.updatedAt) || Number(raw?.createdAt) || 0);
  }

  function newestLegacyGlobalCandidate(currentRaw = null) {
    let best = isLegacyFullSave(currentRaw) ? currentRaw : null;
    let bestAt = legacySaveTimestamp(best);
    try {
      const storage = host.localStorage;
      if (!storage) return best;
      for (let index = 0; index < storage.length; index += 1) {
        const key = String(storage.key(index) || '');
        if (!key.startsWith(`${ROOT_KEY}::mirror_v2::`) && !key.startsWith(`${ROOT_KEY}::mirror::`)) continue;
        try {
          const parsed = JSON.parse(storage.getItem(key) || '');
          const candidate = parsed && typeof parsed === 'object' ? parsed.save : null;
          if (!isLegacyFullSave(candidate)) continue;
          const at = Math.max(Number(parsed.at) || 0, legacySaveTimestamp(candidate));
          if (!best || at > bestAt) {
            best = candidate;
            bestAt = at;
          }
        } catch (_) {}
      }
    } catch (_) {}
    return best;
  }

  function mergeLegacyProgressIntoGlobal(globalSave, legacyRaw) {
    if (!isLegacyFullSave(legacyRaw)) return globalSave;
    const legacy = normalizeGlobalSave(legacyRaw);

    globalSave.collection.variants = {
      ...(legacy.collection?.variants || {}),
      ...(globalSave.collection?.variants || {}),
    };
    globalSave.collection.species = {
      ...(legacy.collection?.species || {}),
      ...(globalSave.collection?.species || {}),
    };
    globalSave.achievements = {
      ...(legacy.achievements || {}),
      ...(globalSave.achievements || {}),
    };

    const scoreIds = new Set([
      ...Object.keys(globalSave.gameRecords?.highScores || {}),
      ...Object.keys(legacy.gameRecords?.highScores || {}),
    ]);
    scoreIds.forEach((gameId) => {
      globalSave.gameRecords.highScores[gameId] = Math.max(
        Number(globalSave.gameRecords.highScores?.[gameId]) || 0,
        Number(legacy.gameRecords.highScores?.[gameId]) || 0,
      );
    });
    if (!globalSave.gameRecords.suspended && legacy.gameRecords.suspended) {
      globalSave.gameRecords.suspended = deepClone(legacy.gameRecords.suspended);
    }

    const owned = normalizeWardrobeOwned(globalSave.wardrobe?.owned);
    Object.entries(normalizeWardrobeOwned(legacy.wardrobe?.owned)).forEach(([key, value]) => {
      if (typeof value === 'boolean') owned[key] = Boolean(owned[key]) || value;
      else owned[key] = Math.max(Number(owned[key]) || 0, Number(value) || 0);
    });
    globalSave.wardrobe.owned = owned;

    Object.keys(globalSave.stats || {}).forEach((key) => {
      globalSave.stats[key] = Math.max(Number(globalSave.stats[key]) || 0, Number(legacy.stats?.[key]) || 0);
    });
    return globalSave;
  }

  function storedSavePayload(raw) {
    if (!raw || typeof raw !== 'object') return null;
    return raw.save && typeof raw.save === 'object' ? raw.save : raw;
  }

  function readStoredSaveEnvelope(key) {
    try {
      const raw = host.localStorage?.getItem(String(key || ''));
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      const save = storedSavePayload(parsed);
      if (!save || typeof save !== 'object') return null;
      return {
        save,
        at: Math.max(0, Number(parsed?.at) || Number(save.updatedAt) || Number(save.createdAt) || 0),
      };
    } catch (_) {
      return null;
    }
  }

  function v42LocalHighScoreCandidate(raw, source, priority = 0) {
    const save = storedSavePayload(raw);
    if (!save || typeof save !== 'object') return null;
    const version = Math.max(0, Math.floor(Number(save.version) || 0));
    if (version > V42_MAX_SAVE_VERSION) return null;
    const highScores = save.gameRecords?.highScores;
    if (!highScores || typeof highScores !== 'object') return null;
    return {
      source: String(source || 'unknown'),
      priority: Number(priority) || 0,
      at: Math.max(0, Number(raw?.at) || Number(save.updatedAt) || Number(save.createdAt) || 0),
      highScores,
    };
  }

  function newestV42LocalHighScoreCandidate(variableRaw, mirrorRaw, currentCharacterRaw, info) {
    const candidates = [];
    const add = (raw, source, priority) => {
      const candidate = v42LocalHighScoreCandidate(raw, source, priority);
      if (candidate) candidates.push(candidate);
    };

    add(variableRaw, 'global-variable-v42', 100);
    add(mirrorRaw, 'global-mirror-v42', 90);
    add(readStoredSaveEnvelope(`${globalMirrorKey()}::backup`), 'global-mirror-backup-v42', 85);
    add(currentCharacterRaw, 'current-character-v42', 80);

    const exactKey = info?.key ? localMirrorKey(info.key) : '';
    if (exactKey) {
      add(readStoredSaveEnvelope(exactKey), 'current-character-mirror-v42', 75);
      add(readStoredSaveEnvelope(`${exactKey}::backup`), 'current-character-mirror-backup-v42', 70);
    }
    if (info?.legacyKey) {
      const legacyKey = `${ROOT_KEY}::mirror::${info.legacyKey}`;
      add(readStoredSaveEnvelope(legacyKey), 'current-character-legacy-mirror-v42', 65);
      add(readStoredSaveEnvelope(`${legacyKey}::backup`), 'current-character-legacy-mirror-backup-v42', 60);
    }

    // 与 v0.42 的旧档迁移保持一致：只有在精确来源都没有可用旧档时，
    // 才扫描当时使用的角色镜像键，并且只接受 v0.42 及更早的 gameRecords.highScores。
    // 不读取 uploadedHighScores，也不会把服务器成绩当成本地成绩。
    if (!candidates.length) {
      try {
        const storage = host.localStorage;
        if (storage) {
          for (let index = 0; index < storage.length; index += 1) {
            const key = String(storage.key(index) || '');
            if (!key.startsWith(`${ROOT_KEY}::mirror_v2::`) && !key.startsWith(`${ROOT_KEY}::mirror::`)) continue;
            add(readStoredSaveEnvelope(key), 'latest-legacy-mirror-v42', 10);
            add(readStoredSaveEnvelope(`${key}::backup`), 'latest-legacy-mirror-backup-v42', 5);
          }
        }
      } catch (_) {}
    }

    candidates.sort((left, right) => (right.at - left.at) || (right.priority - left.priority));
    return candidates[0] || null;
  }

  function restoreV42LocalHighScores(targetSave, variableRaw, mirrorRaw, currentCharacterRaw, info) {
    if (!targetSave || typeof targetSave !== 'object') return false;
    if (targetSave._ptgHighScoreReadV110 && typeof targetSave._ptgHighScoreReadV110 === 'object') return false;

    const candidate = newestV42LocalHighScoreCandidate(variableRaw, mirrorRaw, currentCharacterRaw, info);
    const hadBroadV109Recovery = Boolean(targetSave._ptgHighScoreRecoveryV109);
    let changed = false;

    if (candidate && hadBroadV109Recovery) {
      if (!targetSave.gameRecords || typeof targetSave.gameRecords !== 'object') targetSave.gameRecords = { highScores: {}, suspended: null };
      if (!targetSave.gameRecords.highScores || typeof targetSave.gameRecords.highScores !== 'object') targetSave.gameRecords.highScores = {};
      const sourceScores = candidate.highScores;

      OFFICIAL_LOCAL_GAME_IDS.forEach((gameId) => {
        const remoteAlias = leaderboardRemoteGameId(gameId);
        const restored = Math.max(
          0,
          Math.floor(Number(sourceScores?.[gameId] ?? sourceScores?.[remoteAlias]) || 0),
        );
        const current = Math.max(0, Math.floor(Number(targetSave.gameRecords.highScores?.[gameId]) || 0));
        if (restored !== current) {
          targetSave.gameRecords.highScores[gameId] = restored;
          changed = true;
        }
      });

      OFFICIAL_REMOTE_ALIAS_IDS.forEach((aliasId) => {
        if (Object.prototype.hasOwnProperty.call(targetSave.gameRecords.highScores, aliasId)) {
          delete targetSave.gameRecords.highScores[aliasId];
          changed = true;
        }
      });
    }

    targetSave._ptgHighScoreReadV110 = {
      completedAt: nowMs(),
      restored: Boolean(candidate && hadBroadV109Recovery),
      source: candidate?.source || 'no-v42-source',
      sourceAt: Math.max(0, Number(candidate?.at) || 0),
    };
    if (changed) console.info(`[像素拓麻歌子] 已从 ${candidate?.source || 'v0.42 本地存档'} 恢复官方小游戏本地最高分。`);
    return changed;
  }

  function resolveGlobalSave(currentCharacterRaw = null, info = getCharacterInfo()) {
    let variableRaw = null;
    try {
      const variables = getVariables({ type: 'global' });
      variableRaw = variables && typeof variables === 'object' && variables[GLOBAL_ROOT_KEY] && typeof variables[GLOBAL_ROOT_KEY] === 'object'
        ? variables[GLOBAL_ROOT_KEY]
        : null;
    } catch (_) {}
    const mirrorRaw = readGlobalMirror();
    let chosen = variableRaw;
    if (!chosen || (mirrorRaw && legacySaveTimestamp(mirrorRaw) > legacySaveTimestamp(chosen))) chosen = mirrorRaw;

    const characterKey = String(info?.key || '');
    const currentIsLegacy = isLegacyFullSave(currentCharacterRaw);
    let result;

    if (!chosen) {
      const candidate = newestLegacyGlobalCandidate(currentCharacterRaw);
      result = normalizeGlobalSave(candidate || {});
      result._ptgGlobalMigration = createGlobalMigrationMeta({
        initializedAt: nowMs(),
        initializedFrom: candidate ? 'legacy-character-save' : 'default',
        migratedCharacterKeys: currentIsLegacy && characterKey ? [characterKey] : [],
      });
    } else {
      result = normalizeGlobalSave(chosen);
      const meta = createGlobalMigrationMeta(result._ptgGlobalMigration);
      const alreadyMigrated = characterKey && meta.migratedCharacterKeys.includes(characterKey);
      if (currentIsLegacy && !alreadyMigrated) {
        // 如果全局档只是空白默认档，首次遇到真正的旧档时直接继承完整资源；
        // 否则只合并图鉴、成就、高分等不会造成金币/道具复制的进度。
        if (meta.initializedFrom === 'default' && meta.migratedCharacterKeys.length === 0) {
          const replacement = normalizeGlobalSave(currentCharacterRaw);
          replacement._ptgGlobalMigration = meta;
          result = replacement;
          result._ptgGlobalMigration.initializedFrom = 'legacy-character-save';
        } else {
          result = mergeLegacyProgressIntoGlobal(result, currentCharacterRaw);
        }
        if (characterKey) result._ptgGlobalMigration.migratedCharacterKeys.push(characterKey);
        result._ptgGlobalMigration.migratedCharacterKeys = [...new Set(result._ptgGlobalMigration.migratedCharacterKeys)].slice(-200);
      }
    }

    // 恢复 v0.42 的本地最高分读取来源：全局变量 / 全局镜像 / 当前角色精确旧镜像。
    // 不再扫描所有角色镜像，也不再把 uploadedHighScores 当成本地成绩。
    restoreV42LocalHighScores(result, variableRaw, mirrorRaw, currentCharacterRaw, info);
    result.updatedAt = Math.max(Number(result.updatedAt) || 0, nowMs());
    return result;
  }

  function extensionVisualSpecies(speciesId, pet = null) {
    const requestedId = String(speciesId || pet?.species || '');
    const directExtensionId = String(pet?._ptgExtensionId || '');
    const ownerExtensionId = extensionSpeciesOwners.get(requestedId) || '';
    const extension = (directExtensionId && petExtensions.get(directExtensionId))
      || (ownerExtensionId && petExtensions.get(ownerExtensionId))
      || null;
    if (extension?.species?.id === requestedId) return { extension, species: extension.species };
    return { extension: null, species: null };
  }

  function speciesColor(speciesId, colorId, pet = null) {
    const visual = extensionVisualSpecies(speciesId, pet);
    const list = Array.isArray(visual.species?.colors) && visual.species.colors.length
      ? visual.species.colors
      : (COLOR_VARIANTS[speciesId] || COLOR_VARIANTS.leaf_blob);
    return list.find((item) => item.id === colorId) || list[0] || COLOR_VARIANTS.leaf_blob[0];
  }

  function petVisualDefinition(pet) {
    const speciesId = String(pet?.species || 'leaf_blob');
    const visual = extensionVisualSpecies(speciesId, pet);
    const species = visual.species || SPECIES[speciesId] || SPECIES.leaf_blob;
    const color = speciesColor(speciesId, pet?.colorId, pet);
    return { speciesId, species, color, extension: visual.extension };
  }

  function petVisualSignature(pet) {
    if (!pet) return 'none';
    const visual = petVisualDefinition(pet);
    const extensionVersion = String(visual.extension?.version || 'core');
    const frameCount = Array.isArray(visual.species?.frames) ? visual.species.frames.length : 0;
    const adultFrameCount = Array.isArray(visual.species?.adultFrames) ? visual.species.adultFrames.length : 0;
    return [
      visual.speciesId,
      String(visual.color?.id || pet.colorId || ''),
      String(pet.stage || ''),
      String(pet._ptgExtensionId || ''),
      extensionVersion,
      frameCount,
      adultFrameCount,
    ].join('|');
  }

  function discoverVariant(save, speciesId, colorId, checkAchievements = true) {
    if (!save.collection) save.collection = { variants: {}, species: {} };
    save.collection.variants[`${speciesId}:${colorId}`] = true;
    save.collection.species[speciesId] = true;
    if (checkAchievements) checkAchievementsNow(save);
  }

  function hatchEgg(save) {
    if (save.lifecycle !== 'egg' || !save.egg || nowMs() < Number(save.egg.hatchAt || 0)) return false;
    const now = nowMs();
    const hatchableSpecies = Object.keys(SPECIES).filter((id) => {
      const owner = extensionSpeciesOwners.get(id);
      return !owner || petExtensions.get(owner)?.policy?.includeInRandomHatch === true;
    });
    const speciesId = randomChoice(hatchableSpecies.length ? hatchableSpecies : ['leaf_blob']);
    const color = randomChoice(COLOR_VARIANTS[speciesId]);
    const species = SPECIES[speciesId];
    save.pet = normalizePet({
      name: species.name,
      species: speciesId,
      colorId: color.id,
      stage: '幼崽期',
      birthdayAt: now,
      naturalDeathAt: now + (species.lifespanDays + Math.floor(Math.random() * 6)) * 86400000,
      lastUpdateAt: now,
      hunger: 90,
      happiness: 90,
      health: 100,
      cleanliness: 100,
      energy: 95,
      companionship: 10,
      attributes: randomAttributes(),
      interactionCount: 0,
      touchCount: 0,
      weight: 1.2,
      sleeping: false,
      sick: false,
      mess: 0,
      wasteProgressHours: 0,
      lastStage: '幼崽期',
    });
    save.lifecycle = 'alive';
    save.egg = null;
    save.events.current = null;
    save.events.nextAt = now + randomEventDelay(true);
    save.schedule = createEmptySchedule(now);
    syncAutomaticDailyState(save, now);
    save.stats.totalHatches += 1;
    discoverVariant(save, speciesId, color.id, false);
    unlockAchievement(save, 'first_hatch');
    checkAchievementsNow(save);
    app.message = `蛋壳裂开了！孵出了${color.name}的${species.name}。它正在小心地认识你。`;
    return true;
  }

  function killPet(save, reason, deathAt = nowMs()) {
    if (save.lifecycle !== 'alive' || !save.pet) return false;
    const pet = save.pet;
    if (petIsImmortal(pet)) {
      applyExtensionPetPolicy(pet, extensionForPet(pet), deathAt);
      const message = extensionActionMessage(pet, 'preventDeath', { save });
      app.message = message || '它并没有因此离开。';
      return false;
    }
    if (!pet.petId) pet.petId = createPetId();
    pet.reviveCount = Math.max(0, Math.min(CONFIG.maxPetRevives, Math.floor(Number(pet.reviveCount) || 0)));
    const visual = petVisualDefinition(pet);
    const color = visual.color || speciesColor(pet.species, pet.colorId, pet);
    const ageDays = getAgeDays(pet, deathAt);
    const companionDays = getCompanionDays(pet, deathAt);
    save.cemetery.push({
      petId: pet.petId,
      reviveCount: pet.reviveCount,
      revivedAt: null,
      petSnapshot: deepClone(pet),
      name: pet.name,
      species: pet.species,
      speciesName: visual.species?.name || SPECIES[pet.species]?.name || pet.species,
      colorId: pet.colorId,
      colorName: color?.name || pet.colorId,
      birthdayAt: pet.birthdayAt,
      deathAt,
      ageDays,
      companionDays,
      reason,
      companionship: pet.companionship,
      interactionCount: pet.interactionCount,
      attributes: deepClone(pet.attributes || {}),
    });
    save.cemetery = save.cemetery.slice(-CONFIG.cemeteryLimit);
    save.stats.totalDeaths += 1;
    save.lifecycle = 'dead';
    save.pet = null;
    save.egg = null;
    save.events.current = null;
    save.schedule = createEmptySchedule(deathAt);
    unlockAchievement(save, 'first_death');
    app.message = `它因「${reason}」离开了。你们之间的陪伴会一直留在记录里。`;
    return true;
  }

  function latestReviveRecord(save = app.save) {
    if (!save || save.lifecycle !== 'dead' || !Array.isArray(save.cemetery) || !save.cemetery.length) return null;
    return save.cemetery[save.cemetery.length - 1] || null;
  }

  function reviveCountForRecord(record) {
    return Math.max(0, Math.min(CONFIG.maxPetRevives, Math.floor(Number(record?.reviveCount ?? record?.petSnapshot?.reviveCount) || 0)));
  }

  function reviveBlockedReason(save = app.save) {
    if (!save || save.lifecycle !== 'dead') return '只有死亡的宠物才能使用复活药。';
    const record = latestReviveRecord(save);
    if (!record) return '没有可以复活的宠物记录。';
    if (reviveCountForRecord(record) >= CONFIG.maxPetRevives) return `这只宠物已经复活过 ${CONFIG.maxPetRevives} 次，无法再次复活。`;
    if (Number(save.inventory?.revival_potion || 0) <= 0) return '背包里没有复活药。';
    return '';
  }

  function buildPetFromDeathRecord(record, reviveAt = nowMs()) {
    const raw = record?.petSnapshot && typeof record.petSnapshot === 'object'
      ? deepClone(record.petSnapshot)
      : {
          petId: record?.petId,
          reviveCount: record?.reviveCount,
          name: record?.name,
          species: record?.species,
          colorId: record?.colorId,
          birthdayAt: record?.birthdayAt,
          stage: record?.stage || '成年期',
          lastStage: record?.stage || '成年期',
          companionship: record?.companionship,
          interactionCount: record?.interactionCount,
          attributes: deepClone(record?.attributes || {}),
          weight: Number(record?.weight) || 3.2,
        };
    raw.petId = String(raw.petId || record?.petId || createPetId());
    raw.reviveCount = reviveCountForRecord(record) + 1;
    raw.lastUpdateAt = reviveAt;
    raw.health = 100;
    raw.hunger = Math.max(70, Number(raw.hunger) || 0);
    raw.happiness = Math.max(60, Number(raw.happiness) || 0);
    raw.cleanliness = Math.max(70, Number(raw.cleanliness) || 0);
    raw.energy = Math.max(70, Number(raw.energy) || 0);
    raw.sleeping = false;
    raw.sleepStartedAt = null;
    raw.sleepStartEnergy = null;
    raw.nightSleepActive = false;
    raw.nightSleepDayKey = '';
    raw.sick = false;
    raw.mess = 0;
    raw.wasteProgressHours = 0;
    const restored = normalizePet(raw);
    if (!restored) return null;
    const visual = petVisualDefinition(restored);
    const lifespanDays = Math.max(1, Number(visual.species?.lifespanDays || SPECIES[restored.species]?.lifespanDays) || 30);
    restored.naturalDeathAt = reviveAt + lifespanDays * 86400000;
    restored.lastUpdateAt = reviveAt;
    restored.reviveCount = raw.reviveCount;
    restored.petId = raw.petId;
    restored.health = petStatMax(restored, 'health');
    restored.hunger = clampPetStat(restored, 'hunger', Math.max(restored.hunger, petStatMax(restored, 'hunger') * 0.7));
    restored.happiness = clampPetStat(restored, 'happiness', Math.max(restored.happiness, petStatMax(restored, 'happiness') * 0.6));
    restored.cleanliness = clampPetStat(restored, 'cleanliness', Math.max(restored.cleanliness, petStatMax(restored, 'cleanliness') * 0.7));
    restored.energy = clampPetStat(restored, 'energy', Math.max(restored.energy, petStatMax(restored, 'energy') * 0.7));
    restored.sick = false;
    return applyExtensionPetPolicy(restored, extensionForPet(restored), reviveAt);
  }

  function useRevivalPotion() {
    const save = app.save;
    const blocked = reviveBlockedReason(save);
    if (blocked) {
      app.message = blocked;
      render();
      return false;
    }
    const record = latestReviveRecord(save);
    const reviveAt = nowMs();
    const restored = buildPetFromDeathRecord(record, reviveAt);
    if (!restored) {
      app.message = '复活失败：宠物记录不完整。复活药没有被消耗。';
      render();
      return false;
    }
    save.inventory.revival_potion = Math.max(0, Number(save.inventory.revival_potion || 0) - 1);
    record.petId = restored.petId;
    record.reviveCount = restored.reviveCount;
    record.revivedAt = reviveAt;
    if (record.petSnapshot && typeof record.petSnapshot === 'object') {
      record.petSnapshot.petId = restored.petId;
      record.petSnapshot.reviveCount = restored.reviveCount;
    }
    save.pet = restored;
    save.lifecycle = 'alive';
    save.egg = null;
    save.events.current = null;
    save.events.nextAt = reviveAt + randomEventDelay(true);
    save.schedule = createEmptySchedule(reviveAt);
    syncAutomaticDailyState(save, reviveAt);
    discoverVariant(save, restored.species, restored.colorId, false);
    app.activeTab = 'home';
    app.itemPickerCategory = null;
    app.message = `${restored.name}重新睁开了眼睛。原有陪伴值 ${Math.round(restored.companionship || 0)} 已保留；这是第 ${restored.reviveCount}/${CONFIG.maxPetRevives} 次复活。`;
    pushCareLog('player', 'revive', `使用复活药复活${restored.name}（${restored.reviveCount}/${CONFIG.maxPetRevives}）`);
    saveCurrent();
    playTransient('hug', app.message, 2200);
    return true;
  }

  function getAgeHours(pet, atTimestamp = nowMs()) {
    if (!pet) return 0;
    return Math.max(0, (Number(atTimestamp) - Number(pet.birthdayAt || atTimestamp)) / 3600000);
  }

  // 年龄按本地自然日计算：孵化当天为 0 天，每经过一次本地 00:00 增加 1 天。
  function localCalendarDayNumber(timestamp = nowMs()) {
    const date = new Date(Number(timestamp) || nowMs());
    return Math.floor(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()) / 86400000);
  }

  function getAgeDays(pet = app.save?.pet, atTimestamp = nowMs()) {
    if (!pet) return 0;
    return Math.max(0, localCalendarDayNumber(atTimestamp) - localCalendarDayNumber(pet.birthdayAt));
  }

  function getCompanionDays(pet = app.save?.pet, atTimestamp = nowMs()) {
    return pet ? getAgeDays(pet, atTimestamp) + 1 : 0;
  }

  function computeStage(pet, atTimestamp = nowMs()) {
    const fixedStage = petPolicy(pet)?.fixedStage;
    if (fixedStage) return fixedStage;
    const ageDays = getAgeDays(pet, atTimestamp);
    if (ageDays < 1) return '幼崽期';
    if (ageDays < 4) return '幼年期';
    if (ageDays < 10) return '成长期';
    return '成年期';
  }

  function updateStage(save, atTimestamp = nowMs()) {
    const pet = save.pet;
    if (!pet) return;
    const fixedStage = petPolicy(pet)?.fixedStage;
    if (fixedStage) {
      pet.stage = fixedStage;
      pet.lastStage = fixedStage;
      applyExtensionPetPolicy(pet, extensionForPet(pet), atTimestamp);
      return;
    }
    const next = computeStage(pet, atTimestamp);
    if (next !== pet.stage) {
      pet.stage = next;
      pet.lastStage = next;
      app.message = next === '成年期' ? `${pet.name}在第 10 天进化成了成年形态！` : `${pet.name}成长到了${next}！`;
    }
    if (next === '成年期') unlockAchievement(save, 'adult');
  }

  function getLifePeriod() {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 8) return '清晨';
    if (hour >= 8 && hour < 17) return '白天';
    if (hour >= 17 && hour < 20) return '傍晚';
    return '夜晚';
  }

  function resetDailyCounters(save) {
    const today = localDayKey();
    if (save.economy.lastDailyKey === today) return false;
    save.economy.lastDailyKey = today;
    save.economy.chatCoinsToday = 0;
    save.economy.companionCoinsToday = 0;
    save.economy.gameCoinsToday = 0;
    addCoins(save, CONFIG.dailyGiftCoins, false);
    app.message = `今日补给已送达：金币 +${CONFIG.dailyGiftCoins}。`;
    return true;
  }

  function addCoins(save, amount, countAsEarned = true) {
    const value = Math.max(0, Math.floor(Number(amount) || 0));
    save.economy.coins += value;
    if (countAsEarned) save.stats.totalCoinsEarned += value;
    checkAchievementsNow(save);
  }

  function spendCoins(save, amount) {
    const value = Math.max(0, Math.floor(Number(amount) || 0));
    if (save.economy.coins < value) return false;
    save.economy.coins -= value;
    return true;
  }

  function unlockAchievement(save, id) {
    const definition = ACHIEVEMENTS[id];
    if (!definition || save.achievements[id]) return false;
    save.achievements[id] = { unlockedAt: nowMs() };
    if (definition.reward) {
      save.economy.coins += definition.reward;
      save.stats.totalCoinsEarned += definition.reward;
    }
    notify('success', `成就解锁：${definition.name}${definition.reward ? `，金币 +${definition.reward}` : ''}`);
    return true;
  }

  function checkAchievementsNow(save) {
    if (!save) return;
    if (save.pet?.companionship >= 40) unlockAchievement(save, 'bond_40');
    if (save.pet?.companionship >= 80) unlockAchievement(save, 'bond_80');
    if (save.events?.completed >= 5) unlockAchievement(save, 'event_5');
    if (Object.keys(save.collection.variants || {}).length >= 3) unlockAchievement(save, 'discover_3');
    const achievementSpecies = Object.keys(SPECIES).filter((speciesId) => {
      const owner = extensionSpeciesOwners.get(speciesId);
      return !owner || petExtensions.get(owner)?.policy?.countTowardSpeciesAchievement === true;
    });
    if (achievementSpecies.every((speciesId) => save.collection.species?.[speciesId])) unlockAchievement(save, 'discover_all_species');
    if (save.economy.coins >= 200) unlockAchievement(save, 'rich');
  }

  function inferDeathReason(pet) {
    if (pet.hunger <= 1) return '长期饥饿';
    if (pet.cleanliness <= 5 || pet.mess >= 4) return '长期处于肮脏环境';
    if (pet.energy <= 1 && !pet.sleeping) return '过度疲劳';
    if (pet.sick) return '病情恶化';
    return '健康耗尽';
  }

  function settleTime(save, currentTime = nowMs()) {
    if (!save) return 0;
    ensureExtensionPetForCurrentCharacter(save, currentTime);
    resetDailyCounters(save);
    ensureFortuneHouseDay(save, currentTime);
    if (save.lifecycle !== 'alive' || !save.pet) {
      save.updatedAt = currentTime;
      return 0;
    }

    const pet = save.pet;
    const previous = Number(pet.lastUpdateAt) || currentTime;
    if (currentTime <= previous) {
      syncAutomaticDailyState(save, currentTime);
      pet.lastUpdateAt = currentTime;
      save.updatedAt = currentTime;
      updateStage(save, currentTime);
      applyExtensionPetPolicy(pet, extensionForPet(pet), currentTime);
      return 0;
    }

    if (!petIsImmortal(pet) && Number(pet.naturalDeathAt) <= currentTime) {
      pet.lastUpdateAt = currentTime;
      killPet(save, '寿命走到了尽头', Number(pet.naturalDeathAt) || currentTime);
      save.updatedAt = currentTime;
      return (currentTime - previous) / 3600000;
    }

    const rawHours = (currentTime - previous) / 3600000;
    settleDailySchedule(save, previous, currentTime);
    pet.lastUpdateAt = currentTime;
    save.updatedAt = currentTime;

    updateStage(save, currentTime);
    applyExtensionPetPolicy(pet, extensionForPet(pet), currentTime);
    if (!petIsImmortal(pet) && pet.health <= 0) killPet(save, inferDeathReason(pet), currentTime);
    else maybeTriggerRandomEvent(save, currentTime);
    return rawHours;
  }

  function localMirrorKey(characterKey) {
    return `${ROOT_KEY}::mirror_v2::${encodeURIComponent(String(characterKey || ''))}`;
  }

  function readLocalMirror(infoOrKey) {
    const info = typeof infoOrKey === 'object' && infoOrKey
      ? infoOrKey
      : { key: String(infoOrKey || ''), legacyKey: '' };
    if (!info.key) return null;

    const parse = (raw) => {
      try {
        const parsed = JSON.parse(raw);
        const save = parsed && typeof parsed === 'object' ? parsed.save : null;
        if (save && typeof save === 'object') {
          return { save, at: Number(parsed.at) || Number(save.updatedAt) || 0 };
        }
      } catch (_) {}
      return null;
    };

    const accept = (candidate) => {
      if (!candidate?.save) return null;
      const owner = saveOwnerKey(candidate.save);
      if (owner && owner !== info.key) return null;
      const save = deepClone(candidate.save);
      stampSaveOwner(save, info);
      return { save, at: candidate.at };
    };

    try {
      // 新镜像使用角色卡稳定身份，彻底与 characterId 解耦。
      const exact = host.localStorage?.getItem(localMirrorKey(info.key));
      const exactParsed = accept(exact ? parse(exact) : null);
      if (exactParsed) return exactParsed.save;

      // 只迁移当前角色“精确旧键”，绝不再扫描同一 rawId 下的其他镜像。
      // 原先按 rawId 扫描最新镜像，会在切卡期间把另一张卡的死亡存档误认成当前卡。
      if (info.legacyKey) {
        const legacyKey = `${ROOT_KEY}::mirror::${info.legacyKey}`;
        const legacy = host.localStorage?.getItem(legacyKey);
        const legacyParsed = accept(legacy ? parse(legacy) : null);
        if (legacyParsed) return legacyParsed.save;
      }
      return null;
    } catch (_) {
      return null;
    }
  }

  function writeLocalMirror(characterKey, save) {
    if (!characterKey || !save) return;
    try {
      const key = localMirrorKey(characterKey);
      const next = JSON.stringify({ save, at: nowMs() });
      const storage = host.localStorage;
      const previous = storage?.getItem(key);
      if (previous && previous !== next) {
        const backupAtKey = `${key}::backup_at`;
        const lastBackupAt = Number(storage?.getItem(backupAtKey)) || 0;
        if (nowMs() - lastBackupAt >= MIRROR_BACKUP_INTERVAL_MS) {
          storage?.setItem(`${key}::backup`, previous);
          storage?.setItem(backupAtKey, String(nowMs()));
        }
      }
      storage?.setItem(key, next);
    } catch (_) {}
  }

  function saveCurrent() {
    // 切换角色卡期间禁止任何落盘，避免宠物档写进错误角色变量域。
    if (!app.characterContextReady) return false;
    if (app.savePlaceholder) return false;
    if (!app.save || !app.characterKey) return false;
    const info = getCharacterInfo();
    if (!info || info.key !== app.characterKey) return false;
    clearPendingSave();

    try {
      let variables = null;
      try { variables = getVariables({ type: 'character' }); } catch (_) { variables = null; }
      const existing = variables && typeof variables === 'object' ? variables[ROOT_KEY] : null;
      const existingOwner = saveOwnerKey(existing);
      if (existingOwner && existingOwner !== app.characterKey) {
        app.characterContextReady = false;
        scheduleCharacterReload(140);
        return false;
      }

      persistGameSnapshot(false);
      const characterPayload = extractCharacterSave(app.save, info);
      const globalPayload = extractGlobalSave(app.save);
      const characterSignature = saveDomainSignature(characterPayload);
      const globalSignature = saveDomainSignature(globalPayload);
      const characterChanged = app.saveWriteCache.characterKey !== app.characterKey
        || app.saveWriteCache.characterSignature !== characterSignature;
      const globalChanged = app.saveWriteCache.globalSignature !== globalSignature;
      const savedAt = nowMs();

      if (characterChanged) {
        characterPayload.updatedAt = savedAt;
        writeLocalMirror(app.characterKey, characterPayload);
        insertOrAssignVariables({ [ROOT_KEY]: deepClone(characterPayload) }, { type: 'character' });
        app.saveWriteCache.characterKey = app.characterKey;
        app.saveWriteCache.characterSignature = characterSignature;
      }
      if (globalChanged) {
        globalPayload.updatedAt = savedAt;
        writeGlobalMirror(globalPayload);
        insertOrAssignVariables({ [GLOBAL_ROOT_KEY]: deepClone(globalPayload) }, { type: 'global' });
        app.saveWriteCache.globalSignature = globalSignature;
      }
      if (characterChanged || globalChanged) {
        app.save.updatedAt = savedAt;
        queueWorldbookSync();
      }
      updateFloatingButton();
      return true;
    } catch (error) {
      console.error('[像素拓麻歌子] 保存失败：', error);
      notify('error', '拓麻歌子存档失败，请查看控制台。');
      return false;
    }
  }

  let characterReloadToken = 0;

  // 刷新酒馆时本脚本可能早于角色变量加载完成，首屏读到空数据会落到“占位新蛋”。
  // 该函数在占位状态下反复重读：一旦真实存档出现就立刻恢复并落盘；只有在等待窗口结束、
  // 确认两个数据源都确实没有本插件存档时，才把占位新蛋提交保存（视为真正的新角色）。
  function scheduleSaveRecheck() {
    // 新版由 loadCurrentCharacter 自己等待角色变量域稳定；保留此入口仅用于兼容旧调用。
    scheduleCharacterReload(180);
  }

  function scheduleCharacterReload(delay = 80) {
    const token = ++characterReloadToken;
    const startedAt = nowMs();
    let previousSignature = '';
    let stableReads = 0;
    let attempts = 0;

    const check = () => {
      if (token !== characterReloadToken) return;
      attempts += 1;
      const info = getCharacterInfo();
      const signature = info ? `${info.key}::${info.rawId}::${String(SillyTavern?.chatId || '')}` : '';
      stableReads = signature && signature === previousSignature ? stableReads + 1 : 0;
      previousSignature = signature;

      // 至少等待约 400ms，并连续确认角色对象稳定，避免角色名、avatar 与变量域分步切换。
      if ((stableReads >= 3 && nowMs() - startedAt >= 400) || attempts >= 30) {
        loadCurrentCharacter(info);
        return;
      }
      host.setTimeout(check, 100);
    };

    host.setTimeout(check, delay);
  }

  function loadCurrentCharacter(expectedInfo = null) {
    const token = ++app.characterLoadToken;
    app.saveRecheckToken += 1;

    const info = expectedInfo || getCharacterInfo();
    if (app.save && app.characterKey && info?.key && info.key !== app.characterKey) {
      app.previousCharacterSnapshot = {
        key: app.characterKey,
        signature: savePayloadSignature(app.save),
        at: nowMs(),
      };
    }

    app.characterContextReady = false;
    app.petResidence = { open: false, loading: false, moving: false, targets: [], error: '' };
    app.characterKey = info?.key || null;
    app.characterName = info?.name || null;
    app.activeTab = 'home';
    resetGameRuntime();

    if (!info) {
      app.save = null;
      app.savePlaceholder = false;
      app.message = '请先打开一张角色卡。';
      queueWorldbookSync(0, true);
      render();
      return;
    }

    // 加载完成前不保留上一张卡的 app.save，所有定时结算和交互都会自然停止。
    app.save = null;
    app.savePlaceholder = true;
    app.message = `正在读取「${info.name}」的宠物档与全局共享档……`;
    render();

    const previousSnapshot = app.previousCharacterSnapshot;
    const startedAt = nowMs();
    let attempts = 0;
    let legacySignature = '';
    let legacyStableReads = 0;

    const finalize = (chosenRaw, hadSave) => {
      if (token !== app.characterLoadToken) return;
      const live = getCharacterInfo();
      if (!live || live.key !== info.key) {
        scheduleCharacterReload(80);
        return;
      }

      app.savePlaceholder = !hadSave;
      const globalSave = resolveGlobalSave(chosenRaw, info);
      app.save = combineCharacterAndGlobalSave(chosenRaw, globalSave, info);
      stampSaveOwner(app.save, info);
      const elapsedHours = settleTime(app.save);
      const restoredGame = restoreGameRuntimeFromSave();

      if (!hadSave) {
        const extension = extensionForPet(app.save?.pet);
        const customMessage = extension ? callExtensionHook(extension, 'initialMessage', { save: app.save, pet: app.save.pet }, '') : '';
        app.message = customMessage || (extension
          ? `${app.save.pet.name}已经来到「${info.name}」身边。`
          : `「${info.name}」获得了一枚免费新手蛋，已经可以孵化。`);
      } else if (app.save.lifecycle === 'dead') {
        const latest = app.save.cemetery.at(-1);
        app.message = latest ? `${latest.name}已经离开。购买新蛋可以再次开始。` : '购买新蛋可以再次开始。';
      } else if (elapsedHours >= 1 && app.save.lifecycle === 'alive') {
        app.message = `你离开了 ${formatDuration(elapsedHours)}，状态已经按设备时间结算。`;
      } else if (restoredGame) {
        app.message = `${GAME_DEFS[app.games.selected].name}保存在暂停状态，进入游戏页即可继续。`;
      } else {
        app.message = getStatusMessage();
      }

      app.characterContextReady = true;
      processPendingExclusiveCosmeticGrants();
      processPendingRewardGiftGrants();
      app.savePlaceholder = false;
      app.saveRecheckAttempts = 0;
      app.previousCharacterSnapshot = null;
      render();
      // 离线结算与迁移结果稍后落盘，避免角色卡切换完成瞬间被大对象序列化和变量写入阻塞。
      queueSaveCurrent(hadSave ? 420 : 80);
      host.setTimeout(() => {
        void restoreLocalHighScoresFromLeaderboardOnce()
          .finally(() => scheduleLeaderboardSync(180));
      }, 260);
    };

    const attemptLoad = () => {
      if (token !== app.characterLoadToken) return;
      const live = getCharacterInfo();
      if (!live || live.key !== info.key) {
        scheduleCharacterReload(80);
        return;
      }

      attempts += 1;
      let variables = null;
      try { variables = getVariables({ type: 'character' }); } catch (_) { variables = null; }
      const bagReady = variables && typeof variables === 'object';
      const varSaveRaw = bagReady && variables[ROOT_KEY] && typeof variables[ROOT_KEY] === 'object'
        ? variables[ROOT_KEY]
        : null;
      const mirrorRaw = readLocalMirror(info);

      let validVariableSave = null;
      let variableContextSafe = false;
      if (bagReady && !varSaveRaw) {
        // 已经读到当前角色变量对象且其中没有宠物存档；稍等片刻后可判定为当前卡的空变量域。
        variableContextSafe = nowMs() - startedAt >= 600;
      } else if (varSaveRaw) {
        const owner = saveOwnerKey(varSaveRaw);
        if (owner) {
          if (owner === info.key) {
            validVariableSave = varSaveRaw;
            variableContextSafe = true;
          }
        } else {
          // 旧存档尚无所有者标记：必须稳定读取多次，并排除“与刚切走角色完全相同”的数据。
          const signature = savePayloadSignature(varSaveRaw);
          if (signature && signature === legacySignature) legacyStableReads += 1;
          else {
            legacySignature = signature;
            legacyStableReads = 1;
          }
          const copiedFromPrevious = Boolean(
            previousSnapshot
            && previousSnapshot.key !== info.key
            && signature
            && signature === previousSnapshot.signature
          );
          if (!copiedFromPrevious && legacyStableReads >= 4 && nowMs() - startedAt >= 750) {
            validVariableSave = varSaveRaw;
            variableContextSafe = true;
          }
        }
      }

      let chosenRaw = mirrorRaw || null;
      if (validVariableSave) {
        const variableAt = Number(validVariableSave.updatedAt) || 0;
        const mirrorAt = Number(chosenRaw?.updatedAt) || 0;
        if (!chosenRaw || variableAt > mirrorAt) chosenRaw = validVariableSave;
      }

      // 即使已经找到目标角色的本地镜像，也要等角色变量域确认切换完成后再落盘。
      // 否则会把目标角色的健康存档反向写进刚切走的角色卡。
      if (chosenRaw && variableContextSafe) {
        finalize(chosenRaw, true);
        return;
      }

      // 变量域为空时继续等待约 5 秒，以区分“新角色”与“酒馆变量尚未完成切换”。
      if (attempts < 42) {
        host.setTimeout(attemptLoad, 120);
        return;
      }

      // 如果仍能读到一份明显属于上一张卡或其他卡的存档，保持隔离并继续等待，绝不覆盖。
      if (varSaveRaw) {
        app.message = `正在等待「${info.name}」的角色变量完成切换，请稍候……`;
        render();
        host.setTimeout(attemptLoad, 300);
        return;
      }

      finalize(null, false);
    };

    host.setTimeout(attemptLoad, 120);
  }

  function formatDuration(hours) {
    if (hours < 1) return `${Math.max(1, Math.round(hours * 60))} 分钟`;
    if (hours < 24) return `${Math.round(hours)} 小时`;
    return `${Math.round(hours / 24)} 天`;
  }

  function formatCountdown(milliseconds) {
    const totalSeconds = Math.max(0, Math.ceil(milliseconds / 1000));
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
  }

  function getCompanionTier(value = app.save?.pet?.companionship ?? 0) {
    const amount = clamp(value);
    if (amount < 20) return { id: 'first', name: '初识' };
    if (amount < 40) return { id: 'familiar', name: '熟悉' };
    if (amount < 60) return { id: 'close', name: '亲近' };
    if (amount < 80) return { id: 'attached', name: '依恋' };
    return { id: 'beloved', name: '挚爱' };
  }

