  function scheduleVisualForTask(task) {
    if (!task) return null;
    const direct = SCHEDULE_ACTIVITY_VISUALS[task.activityId];
    if (direct) return direct;
    const fallback = {
      study: { motion: 'reading', prop: '▤', particleA: 'A', particleB: '?' },
      fun: { motion: 'playing', prop: '●', particleA: '♥', particleB: '✦' },
