      sleep: { motion: 'scheduled-sleep', prop: '▱', particleA: 'Z', particleB: 'z' },
    };
    return fallback[task.category] || null;
  }

  function scheduleTaskCanRunNow(save, task) {
    const pet = save?.pet;
    const definition = activityDefinition(task?.category, task?.activityId);
    if (!pet || !definition || task?.status !== 'queued') return false;
    if (pet.sleeping) return false;
    if (new Date().getHours() < CONFIG.scheduleStartHour) return false;
    if (['study', 'work'].includes(task.category) && Number(pet.energy || 0) < CONFIG.minimumActivityEnergy) return false;
    if (task.category === 'work' && !jobRequirementsMet(pet, definition)) return false;
    return true;
  }

  function currentScheduleTask(save = app.save) {
    if (!save || save.lifecycle !== 'alive' || !save.pet || !Array.isArray(save.schedule?.today)) return null;
    const active = save.schedule.today.find((entry) => entry?.status === 'active' && activityDefinition(entry.category, entry.activityId));
    if (active) {
      if (save.pet.sleeping && active.category !== 'sleep') return null;
      return active;
    }
    return save.schedule.today.find((entry) => scheduleTaskCanRunNow(save, entry)) || null;
  }

  function scheduleTaskProgressPercent(task) {
    if (!task) return 0;
    return clamp(Math.round((Number(task.progressHours || 0) / Math.max(0.01, Number(task.durationHours || 1))) * 100), 0, 100);
  }

  function scheduleTaskRemainingText(task) {
    if (!task) return '';
    const remaining = Math.max(0, Number(task.durationHours || 0) - Number(task.progressHours || 0));
    return remaining <= 0.01 ? '即将完成' : `剩余 ${formatDuration(remaining)}`;
  }

