  function schedulePixelArtSvg(rows, colors, className = '', label = '') {
    const width = Math.max(1, ...rows.map((row) => String(row || '').length));
    const height = Math.max(1, rows.length);
    let rects = '';
    rows.forEach((row, y) => {
      [...String(row || '').padEnd(width, '.')].forEach((ch, x) => {
        if (ch !== '.' && colors[ch]) rects += `<rect x="${x}" y="${y}" width="1" height="1" fill="${colors[ch]}"/>`;
      });
    });
    return `<svg class="ptgsa-pixel-prop ${escapeHtml(className)}" viewBox="0 0 ${width} ${height}" shape-rendering="crispEdges" aria-label="${escapeHtml(label)}">${rects}</svg>`;
  }

