  function scheduleAnimatedPetSpriteHtml(pet) {
    const visual = petVisualDefinition(pet);
    const { species, color } = visual;
    const frameSet = pet?.stage === '成年期' && Array.isArray(species.adultFrames) && species.adultFrames.length
      ? species.adultFrames
      : species.frames;
    const frames = [frameSet?.[0], frameSet?.[1] || frameSet?.[0]].filter(Boolean);
    if (!frames.length) return '';
    const countW = (frame) => frame.reduce((sum, row) => sum + (String(row).split('W').length - 1), 0);
    const eyeFrame = frames.reduce((best, frame) => countW(frame) > countW(best) ? frame : best, frames[0]);
    const svgs = frames.map((frame, index) => matrixToSvg(
      frame,
      `${color.name}${species.name}`,
      color,
      buildAccessoryRects(frame, eyeFrame),
    ).replace('class="ptg-sprite"', `class="ptg-sprite ptgsa-frame ptgsa-frame-${index}"`)).join('');
    return `<span class="ptgsa-sprite is-auto">${svgs}</span>`;
  }

  function scheduleActivityPetHtml(def, pet) {
    const { color } = petVisualDefinition(pet);
    return `<div class="ptgsa-pet-actor ptgsa-actor-${escapeHtml(def.id)} ptgsa-pose-${escapeHtml(def.pose || 'front')}" data-pet-visual="${escapeHtml(petVisualSignature(pet))}" style="--pet-primary:${color.primary};--pet-secondary:${color.secondary};--pet-accent:${color.accent}">
      <span class="ptgsa-pet-sprite">${scheduleAnimatedPetSpriteHtml(pet)}</span>
      <i class="ptgsa-action-paw"></i><i class="ptgsa-action-foot"></i>
    </div>`;
  }

  function scheduleInteractionDomMatches(task = currentScheduleTask(app.save)) {
    if (!task || !app.root || !app.save?.pet) return false;
    const stage = app.root.querySelector('.ptgsa-stage');
    if (!stage || stage.dataset.activity !== String(task.activityId || '')) return false;
    return stage.dataset.petVisual === petVisualSignature(app.save.pet);
  }

  function homeScheduleInteractionIsActive() {
    if (app.activeTab !== 'home' || !app.save?.pet) return false;
    if (app.transientAnimation && nowMs() < app.transientUntil) return false;
    const task = currentScheduleTask(app.save);
    return Boolean(task && SCHEDULE_INTERACTION_DEFS[task.activityId]);
  }

  function refreshHomeScheduleLiveText() {
    if (!app.root || app.activeTab !== 'home') return;
    const task = currentScheduleTask(app.save);
    if (!task || !scheduleInteractionDomMatches(task)) return;
    const definition = activityDefinition(task.category, task.activityId);
    const meta = SCHEDULE_CATEGORY_META[task.category];
    const badge = app.root.querySelector('.ptg-schedule-now');
    if (badge && definition && meta) {
      const strong = badge.querySelector('strong');
      const small = badge.querySelector('small');
      if (strong) strong.textContent = `${meta.name}中 · ${definition.name}`;
      if (small) small.textContent = `${scheduleTaskProgressPercent(task)}% · ${scheduleTaskRemainingText(task)}`;
    }
    const clock = app.root.querySelector('.ptg-screen-head span:last-child');
    if (clock) clock.textContent = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const bubble = app.root.querySelector('.ptg-screen .ptg-bubble');
    if (bubble && !app.transientAnimation) bubble.textContent = scheduleStatusMessage(task, app.save.pet) || app.message || '';
  }

  function renderScheduleActivityOverlay(task, pet = app.save?.pet) {
    const def = SCHEDULE_INTERACTION_DEFS[task?.activityId];
    if (!def || !pet) return '';
    return `<div class="ptgsa-stage ptgsa-stage-${escapeHtml(def.id)}" data-activity="${escapeHtml(def.id)}" data-pet-visual="${escapeHtml(petVisualSignature(pet))}" aria-hidden="true">
      <div class="ptgsa-interaction-world">
        <div class="ptgsa-floor-shadow"></div>
        ${scheduleInteractionObjectMarkup(def)}
        ${scheduleActivityPetHtml(def, pet)}
      </div>
    </div>`;
  }

  function renderCurrentScheduleBadge(task) {
    const definition = activityDefinition(task?.category, task?.activityId);
    const meta = SCHEDULE_CATEGORY_META[task?.category];
    if (!definition || !meta) return '';
    const progress = scheduleTaskProgressPercent(task);
    return `<div class="ptg-schedule-now">${pixelIcon(meta.icon || 'calendar')}<span><strong>${escapeHtml(meta.name)}中 · ${escapeHtml(definition.name)}</strong><small>${progress}% · ${escapeHtml(scheduleTaskRemainingText(task))}</small></span></div>`;
  }

  function getStatusMessage() {
    if (!app.save) return '请先打开一张角色卡。';
    if (app.save.lifecycle === 'egg') {
      const remain = Number(app.save.egg?.hatchAt || 0) - nowMs();
      return remain <= 0 ? '蛋壳里传来了轻轻的敲击声，可以孵化了！' : `蛋正在孵化，还需要 ${formatCountdown(remain)}。`;
    }
    if (app.save.lifecycle === 'dead') return '纪念碑旁边很安静。新的蛋会带来新的相遇。';
    if (app.save.lifecycle !== 'alive' || !app.save.pet) return '还没有宠物，先购买一枚蛋吧。';
    const pet = app.save.pet;
    const extension = extensionForPet(pet);
    const customStatus = extension ? callExtensionHook(extension, 'statusMessage', { pet }, '') : '';
    if (customStatus) return String(customStatus);
    const tier = getCompanionTier(pet.companionship);
    const lifeEndHint = imminentNaturalDeathHint(pet);
    if (lifeEndHint) return lifeEndHint;
    const scheduleTask = currentScheduleTask(app.save);
    const scheduledMessage = scheduleStatusMessage(scheduleTask, pet);
    if (scheduledMessage) return scheduledMessage;
    if (pet.sick) return tier.id === 'beloved' ? '我有点难受……可以留在我身边吗？' : '身体有些不舒服……可以给我治疗吗？';
    if (pet.sleeping) return tier.id === 'beloved' ? 'Zzz……梦里你也没有离开。' : 'Zzz……正在做方块形状的梦。';
    if (pet.mess > 0 || pet.cleanliness < 25) return tier.id === 'first' ? '房间有点乱，它不好意思地躲开了。' : '房间有点乱……我们一起收拾，好不好？';
    if (pet.hunger < 25) return tier.id === 'beloved' ? '肚子饿了，但看到你就先开心了一点。' : '肚子咕噜咕噜叫了。';
    if (pet.energy < 20) return tier.id === 'attached' || tier.id === 'beloved' ? '我想靠着你睡一会儿。' : '眼皮快要合起来啦。';
    if (pet.happiness < 25) return tier.id === 'first' ? '它看起来有点孤单，却没有主动开口。' : '陪我玩一会儿嘛，我想和你待在一起。';
    return companionLine(pet);
  }

  function currentPetMode(scheduleTask = currentScheduleTask()) {
    if (!app.save?.pet) return 'idle';
    if (app.transientAnimation && nowMs() < app.transientUntil) return app.transientAnimation;
    const visual = scheduleVisualForTask(scheduleTask);
    if (visual) return `schedule-${visual.motion}`;
    const pet = app.save.pet;
    if (pet.sleeping) return 'sleep';
    if (pet.sick) return 'sick';
    if (pet.mess > 0 || pet.cleanliness < 25) return 'dirty';
    return 'idle';
  }

  function matrixToSvg(matrix, label = '像素图案', paletteOverride = {}, extraRects = '') {
    const palette = {
      K: '#24312f',
      A: paletteOverride.primary || '#73c2a3',
      B: paletteOverride.secondary || '#a9e3c9',
      P: paletteOverride.accent || '#ef8f9d',
      W: '#fff9e9',
      Z: '#617f91',
      M: '#705747',
      E: paletteOverride.shell || '#73c2a3',
    };
    const rects = [];
    matrix.forEach((row, y) => {
      [...row].forEach((cell, x) => {
        const fill = palette[cell];
        if (fill) rects.push(`<rect x="${x}" y="${y}" width="1" height="1" fill="${fill}"/>`);
      });
    });
    return `<svg class="ptg-sprite" viewBox="0 0 16 16" shape-rendering="crispEdges" style="overflow:visible" role="img" aria-label="${escapeHtml(label)}">${rects.join('')}${extraRects || ''}</svg>`;
  }

  function petSvg(pet, scheduleTask = null) {
    const visual = petVisualDefinition(pet);
    const { species, color } = visual;
    const frameSet = pet.stage === '成年期' && Array.isArray(species.adultFrames) && species.adultFrames.length
      ? species.adultFrames
      : species.frames;
    const frame = frameSet[app.frame % frameSet.length];
    const mode = currentPetMode(scheduleTask);
    const overlays = {
      happy: '<span class="ptg-overlay ptg-heart">♥</span>',
      eat: '<span class="ptg-overlay ptg-food-dot">◆</span>',
      sleep: '<span class="ptg-overlay ptg-z">Z</span>',
      sick: '<span class="ptg-overlay ptg-sick-mark">+</span>',
      dirty: '<span class="ptg-overlay ptg-dirty-mark">≋</span>',
      pat: '<span class="ptg-overlay ptg-touch-star">✦</span>',
      poke: '<span class="ptg-overlay ptg-touch-question">?</span>',
      tickle: '<span class="ptg-overlay ptg-touch-wave">≋</span>',
      hug: '<span class="ptg-overlay ptg-touch-hearts">♥♥</span>',
      highfive: '<span class="ptg-overlay ptg-touch-star">★</span>',
      shy: '<span class="ptg-overlay ptg-touch-shy">///</span>',
      surprise: '<span class="ptg-overlay ptg-touch-question">!</span>',
      sad: '<span class="ptg-overlay ptg-touch-sad">·</span>',
    };
    const countW = (f) => f.reduce((n, row) => n + (row.split('W').length - 1), 0);
    const eyeFrame = frameSet.reduce((best, f) => (countW(f) > countW(best) ? f : best), frameSet[0]);
    const phase = Math.abs(Number(app.frame) || 0) % 4;
    const showScheduleOverlay = !(app.transientAnimation && nowMs() < app.transientUntil);
    if (showScheduleOverlay && scheduleTask && SCHEDULE_INTERACTION_DEFS[scheduleTask.activityId]) return renderScheduleActivityOverlay(scheduleTask, pet);
    return `<div class="ptg-pet-sprite ptg-stage-${escapeHtml(pet.stage)} ptg-mode-${escapeHtml(mode)} ptg-schedule-phase-${phase}">${matrixToSvg(frame, `${color.name}${species.name}`, color, buildAccessoryRects(frame, eyeFrame))}${overlays[mode] || ''}</div>`;
  }



  // ============================================================
  // 陪伴小游戏：不进入像素游戏厅，不使用默认宠物副本。
  // 所有预览与游戏演员都直接调用 petSvg(app.save.pet)，因此扩展物种、颜色与配饰会原样显示。
  // 实时物体统一由单个 requestAnimationFrame + Canvas 绘制，避免逐帧修改大量 DOM 导致卡顿。
  // ============================================================
  const COMPANION_PLAY_DEFS = Object.freeze({
    bubbles: { name: '戳泡泡', symbol: '○', description: '泡泡会越来越小、越来越快，漏掉 7 个就会提前结束。', durationMs: 30000 },
    keepup: { name: '轮流顶球', symbol: '◆', description: '宠物在上方回球，轮到你时及时顶回去。', durationMs: 30000 },
    hideSeek: { name: '纸箱捉迷藏', symbol: '▣', description: '盯住宠物躲藏的纸箱，跟随连续换位后把它找出来。', durationMs: 0 },
  });

  function freshCompanionPlayState(open = false) {
    return {
      open: Boolean(open),
      gameId: '',
      status: 'menu',
      score: 0,
      popped: 0,
      combo: 0,
      bestCombo: 0,
      misses: 0,
      maxMisses: 7,
      startedAt: 0,
      endsAt: 0,
      durationMs: 30000,
      lastFrameAt: 0,
      nextSpawnAt: 0,
      nextObjectId: 1,
      objects: [],
      effects: [],
      ball: null,
      round: 1,
      maxRounds: 5,
      correct: 0,
      phase: 'show',
      targetBox: 0,
      selectedBox: null,
      boxOrder: [0, 1, 2],
      lastSwapKey: '',
      phaseToken: 0,
      scheduledKey: '',
      resultText: '',
      rewardApplied: false,
      rafId: null,
      timeoutIds: [],
      loopToken: 0,
      nextHudAt: 0,
      hudCache: {},
      lastHint: '',
    };
  }

  function companionPlayState() {
    if (!app.companionPlay || typeof app.companionPlay !== 'object') app.companionPlay = freshCompanionPlayState(false);
    if (!Array.isArray(app.companionPlay.objects)) app.companionPlay.objects = [];
    if (!Array.isArray(app.companionPlay.effects)) app.companionPlay.effects = [];
    if (!Array.isArray(app.companionPlay.timeoutIds)) app.companionPlay.timeoutIds = [];
    if (!Array.isArray(app.companionPlay.boxOrder) || app.companionPlay.boxOrder.length !== 3) app.companionPlay.boxOrder = [0, 1, 2];
    if (!app.companionPlay.hudCache || typeof app.companionPlay.hudCache !== 'object') app.companionPlay.hudCache = {};
    return app.companionPlay;
  }

  function companionPlayIsOpen() {
    return Boolean(app.activeTab === 'home' && companionPlayState().open);
  }

  function clearCompanionPlayRuntime() {
    const state = companionPlayState();
    state.loopToken = (Number(state.loopToken) || 0) + 1;
    if (state.rafId != null) {
      try { host.cancelAnimationFrame(state.rafId); } catch (_) {}
      state.rafId = null;
    }
    (state.timeoutIds || []).forEach((id) => host.clearTimeout(id));
    state.timeoutIds = [];
    state.scheduledKey = '';
  }

  function resetCompanionPlay(open = false) {
    clearCompanionPlayRuntime();
    app.companionPlay = freshCompanionPlayState(open);
    return app.companionPlay;
  }

  function companionPlayTimeout(callback, delay) {
    const state = companionPlayState();
    const token = Number(state.loopToken) || 0;
    const id = host.setTimeout(() => {
      state.timeoutIds = (state.timeoutIds || []).filter((entry) => entry !== id);
      if (token !== (Number(state.loopToken) || 0)) return;
      callback();
    }, Math.max(0, Number(delay) || 0));
    state.timeoutIds.push(id);
    return id;
  }

  function openCompanionPlay() {
    const pet = app.save?.pet;
    if (!pet || app.save?.lifecycle !== 'alive') {
      app.message = '孵化宠物后才能一起玩。';
      render();
      return;
    }
    if (pet.sleeping) {
      app.message = '它正在睡觉，先叫醒它再一起玩吧。';
      render();
      return;
    }
    resetCompanionPlay(true);
    app.message = `今天想和${pet.name}玩什么？`;
    app.scrollPositions.home = 0;
    render();
  }

  function closeCompanionPlay(shouldRender = true) {
    resetCompanionPlay(false);
    if (shouldRender) {
      app.message = getStatusMessage();
      app.scrollPositions.home = 0;
      render();
    }
  }

  function startCompanionPlay(gameId) {
    const definition = COMPANION_PLAY_DEFS[gameId];
    const pet = app.save?.pet;
    if (!definition || !pet || app.save?.lifecycle !== 'alive') return;
    if (pet.sleeping) {
      app.message = '它正在睡觉，先叫醒它再一起玩吧。';
      closeCompanionPlay(true);
      return;
    }
    clearCompanionPlayRuntime();
    const now = nowMs();
    const state = freshCompanionPlayState(true);
    state.gameId = gameId;
    state.status = 'running';
    state.startedAt = now;
    state.durationMs = definition.durationMs || 0;
    state.endsAt = definition.durationMs ? now + definition.durationMs : 0;
    state.lastFrameAt = now;
    state.nextSpawnAt = now + 180;
    if (gameId === 'bubbles') {
      state.maxMisses = 7;
      state.lastHint = '泡泡会越来越快，漏掉 7 个就会结束。';
    }
    if (gameId === 'keepup') {
      state.ball = { x: 50, y: 37, vy: 38, turn: 'player', spin: 0 };
      state.lastHint = '轮到你时，点击场地或“顶回去”按钮。';
    }
    if (gameId === 'hideSeek') {
      state.round = 1;
      state.maxRounds = 5;
      state.correct = 0;
      state.phase = 'show';
      state.targetBox = Math.floor(Math.random() * 3);
      state.selectedBox = null;
      state.boxOrder = [0, 1, 2];
      state.phaseToken = 1;
      state.lastHint = '先盯住宠物躲进去的纸箱。';
    }
    app.companionPlay = state;
    app.message = `开始和${pet.name}玩「${definition.name}」。`;
    playSfx('gameStart');
    app.scrollPositions.home = 0;
    render();
  }

  function companionPlayScoreLabel(state = companionPlayState()) {
    if (state.gameId === 'bubbles') return `得分 ${Math.max(0, Math.floor(state.score || 0))} · 漏 ${Math.max(0, Math.floor(state.misses || 0))}/${Math.max(1, Math.floor(state.maxMisses || 7))}`;
    if (state.gameId === 'keepup') return `回击 ${Math.max(0, Math.floor(state.score || 0))} 次`;
    if (state.gameId === 'hideSeek') return `找对 ${Math.max(0, Math.floor(state.correct || 0))}/${Math.max(1, Math.floor(state.maxRounds || 5))}`;
    return `得分 ${Math.max(0, Math.floor(state.score || 0))}`;
  }

  function companionPlayResultText(state, reason = '') {
    const petName = app.save?.pet?.name || '宠物';
    if (state.gameId === 'bubbles') {
      const ending = reason === 'escaped' ? '漏掉的泡泡太多，本局提前结束。' : '时间到！';
      return `${ending}${petName}一共吹出了好多泡泡，你戳破了 ${Math.floor(state.popped || 0)} 个，得到 ${Math.floor(state.score || 0)} 分。`;
    }
    if (state.gameId === 'keepup') {
      if (reason === 'dropped') return `球落地了，不过你和${petName}已经连续回击了 ${Math.floor(state.score || 0)} 次。`;
      return `时间到！你和${petName}一共完成了 ${Math.floor(state.score || 0)} 次漂亮回击。`;
    }
    if (state.gameId === 'hideSeek') return `${petName}躲了 ${Math.floor(state.maxRounds || 5)} 回合，你找对了 ${Math.floor(state.correct || 0)} 次。`;
    return `你和${petName}玩得很开心。`;
  }

  function finishCompanionPlay(reason = 'completed') {
    const state = companionPlayState();
    if (!state.open || state.status !== 'running') return;
    clearCompanionPlayRuntime();
    state.status = 'finished';
    state.resultText = companionPlayResultText(state, reason);
    if (!state.rewardApplied && app.save?.lifecycle === 'alive' && app.save.pet) {
      const pet = app.save.pet;
      const rawScore = state.gameId === 'hideSeek' ? Number(state.correct || 0) * 4 : Number(state.score || 0);
      const happinessGain = Math.min(15, 6 + Math.floor(rawScore / 5));
      const energyCost = Math.min(9, 3 + Math.floor(rawScore / 18));
      pet.happiness = clampPetStat(pet, 'happiness', Number(pet.happiness || 0) + happinessGain);
      pet.energy = clampPetStat(pet, 'energy', Number(pet.energy || 0) - energyCost);
      pet.hunger = clampPetStat(pet, 'hunger', Number(pet.hunger || 0) - Math.min(5, 2 + Math.floor(rawScore / 24)) * petLossMultiplier(pet, 'hunger', 'activity'));
      rewardCompanionAction(app.save, 4 + Math.min(4, rawScore / 10));
      const definition = COMPANION_PLAY_DEFS[state.gameId];
      pushCareLog('player', 'play', `一起玩「${definition?.name || '陪伴游戏'}」：${companionPlayScoreLabel(state)}`, { companionGameId: state.gameId, score: Math.floor(Number(state.score) || 0) });
      maybeTriggerRandomEvent(app.save);
      state.rewardApplied = true;
      const extensionText = extensionActionMessage(pet, 'companionPlay', { result: { gameId: state.gameId, score: Number(state.score) || 0, correct: Number(state.correct) || 0, reason } });
      app.message = extensionText || state.resultText;
      saveCurrent();
    }
    playSfx(reason === 'dropped' || reason === 'escaped' ? 'fail' : 'confirm');
    render();
  }

  function renderCompanionPlayMenu() {
    const pet = app.save?.pet;
    const cards = Object.entries(COMPANION_PLAY_DEFS).map(([id, definition]) => `
      <button type="button" class="ptg-companion-game-card" data-action="companion-play-start-${id}">
        <span class="ptg-companion-game-symbol">${escapeHtml(definition.symbol)}</span>
        <strong>${escapeHtml(definition.name)}</strong>
        <small>${escapeHtml(definition.description)}</small>
      </button>`).join('');
    return `<div class="ptg-panel ptg-companion-play-panel">
      <div class="ptg-companion-play-head"><button type="button" class="ptg-wizard-back" data-action="companion-play-close">‹ 返回陪伴</button><div><h3>一起玩</h3><small>这些是陪伴互动，不消耗玩具，也不进入游戏排行榜。</small></div></div>
      <div class="ptg-companion-menu-preview"><div class="ptg-companion-menu-pet">${pet ? petSvg(pet) : ''}</div><div><strong>${escapeHtml(pet?.name || '宠物')}</strong><span>正在等你选一个游戏</span></div></div>
      <div class="ptg-companion-game-grid">${cards}</div>
    </div>`;
  }

  function renderCompanionBubbleStage(state, pet) {
    return `<div class="ptg-companion-stage ptg-companion-stage-bubbles" data-companion-stage="bubbles">
      <div class="ptg-companion-sky-decor" aria-hidden="true">·　✦　·　✧　·</div>
      <canvas class="ptg-companion-canvas" data-companion-canvas aria-label="戳泡泡游戏画布"></canvas>
      <div class="ptg-companion-actor ptg-companion-actor-bubbles" data-companion-pet>${petSvg(pet)}</div>
      <span class="ptg-companion-blow-bubble" aria-hidden="true"></span>
      <div class="ptg-companion-help">小泡泡分更高，漏掉 7 个会结束</div>
    </div>`;
  }

  function renderCompanionKeepupStage(state, pet) {
    return `<div class="ptg-companion-stage ptg-companion-stage-keepup" data-companion-stage="keepup">
      <canvas class="ptg-companion-canvas" data-companion-canvas aria-label="轮流顶球游戏画布"></canvas>
      <div class="ptg-companion-actor ptg-companion-actor-keepup" data-companion-pet>${petSvg(pet)}</div>
      <div class="ptg-companion-player-zone"><span>你的回球区</span></div>
      <div class="ptg-companion-help">球落进下方亮区时点击</div>
    </div>
    <button type="button" class="ptg-primary ptg-wide ptg-companion-hit-button" data-action="companion-play-keepup-hit">◆ 顶回去！</button>`;
  }

  function renderCompanionHideSeekStage(state, pet) {
    const phase = String(state.phase || 'show');
    const order = Array.isArray(state.boxOrder) ? state.boxOrder : [0, 1, 2];
    const phaseText = phase === 'show' ? '看清楚它躲进了哪个纸箱' : phase === 'shuffle' ? '盯紧纸箱，它们正在连续换位……' : phase === 'guess' ? '现在，它在哪个纸箱里？' : (state.selectedBox === state.targetBox ? '找到了！' : '差一点，它躲在这里');
    const boxes = [0, 1, 2].map((id) => {
      const classes = [
        'ptg-hide-box',
        id === state.targetBox ? 'target' : '',
        state.selectedBox === id ? 'selected' : '',
        phase === 'result' && id === state.targetBox ? 'correct' : '',
        phase === 'result' && state.selectedBox === id && id !== state.targetBox ? 'wrong' : '',
      ].filter(Boolean).join(' ');
      const disabled = phase === 'guess' ? '' : 'disabled';
      return `<button type="button" class="${classes}" data-action="companion-play-hide-box-${id}" data-box-id="${id}" style="order:${order.indexOf(id)}" aria-label="选择纸箱" ${disabled}>
        <span class="ptg-hide-pet">${id === state.targetBox ? petSvg(pet) : ''}</span>
        <span class="ptg-hide-carton"><i></i><b>▦</b></span>
      </button>`;
    }).join('');
    return `<div class="ptg-companion-stage ptg-companion-stage-hide" data-companion-stage="hideSeek" data-phase="${escapeHtml(phase)}">
      <div class="ptg-hide-instruction" data-companion-hide-instruction>${escapeHtml(phaseText)}</div>
      <div class="ptg-hide-box-row">${boxes}</div>
    </div>`;
  }

  function renderCompanionPlayGame() {
    const state = companionPlayState();
    const pet = app.save?.pet;
    const definition = COMPANION_PLAY_DEFS[state.gameId];
    if (!pet || !definition) return renderCompanionPlayMenu();
    if (state.status === 'finished') {
      return `<div class="ptg-panel ptg-companion-play-panel">
        <div class="ptg-companion-play-head"><button type="button" class="ptg-wizard-back" data-action="companion-play-menu">‹ 选择别的游戏</button><div><h3>${escapeHtml(definition.name)}</h3><small>一起玩的结果</small></div></div>
        <div class="ptg-companion-result"><div class="ptg-companion-result-pet">${petSvg(pet)}</div><strong>${escapeHtml(companionPlayScoreLabel(state))}</strong><p>${escapeHtml(state.resultText || companionPlayResultText(state))}</p></div>
        <div class="ptg-tools"><button type="button" class="ptg-primary" data-action="companion-play-retry">再玩一次</button><button type="button" class="ptg-secondary" data-action="companion-play-close">回到陪伴</button></div>
      </div>`;
    }
    const remaining = state.endsAt ? Math.max(0, Math.ceil((state.endsAt - nowMs()) / 1000)) : 0;
    const stage = state.gameId === 'bubbles' ? renderCompanionBubbleStage(state, pet)
      : state.gameId === 'keepup' ? renderCompanionKeepupStage(state, pet)
      : renderCompanionHideSeekStage(state, pet);
    const timeLabel = state.gameId === 'hideSeek' ? `第 ${state.round}/${state.maxRounds} 回合` : `${remaining} 秒`;
    return `<div class="ptg-panel ptg-companion-play-panel">
      <div class="ptg-companion-play-head"><button type="button" class="ptg-wizard-back" data-action="companion-play-menu">‹ 退出本局</button><div><h3>${escapeHtml(definition.name)}</h3><small>${escapeHtml(definition.description)}</small></div></div>
      <div class="ptg-companion-hud"><span data-companion-score>${escapeHtml(companionPlayScoreLabel(state))}</span><span data-companion-time>${escapeHtml(timeLabel)}</span><span data-companion-combo>${state.gameId === 'hideSeek' ? `记忆 ${state.correct}` : `连击 ${state.combo}`}</span></div>
      ${stage}
      <div class="ptg-companion-status" data-companion-status>${escapeHtml(state.lastHint || (state.gameId === 'hideSeek' ? '先记住宠物的位置。' : '和宠物配合，争取更高分。'))}</div>
    </div>`;
  }

  function renderCompanionPlay() {
    const state = companionPlayState();
    return !state.gameId || state.status === 'menu' ? renderCompanionPlayMenu() : renderCompanionPlayGame();
  }

  function updateCompanionPlayHud(force = false) {
    const state = companionPlayState();
    const now = nowMs();
    if (!force && now < Number(state.nextHudAt || 0)) return;
    state.nextHudAt = now + 100;
    const device = app.root?.querySelector('.ptg-device');
    if (!device) return;
    const scoreText = companionPlayScoreLabel(state);
    const timeText = state.gameId === 'hideSeek'
      ? `第 ${Math.min(state.round, state.maxRounds)}/${state.maxRounds} 回合`
      : `${Math.max(0, Math.ceil((state.endsAt - now) / 1000))} 秒`;
    const comboText = state.gameId === 'hideSeek' ? `记忆 ${state.correct}` : `连击 ${state.combo}`;
    const values = { score: scoreText, time: timeText, combo: comboText, status: state.lastHint || '' };
    const selectors = {
      score: '[data-companion-score]',
      time: '[data-companion-time]',
      combo: '[data-companion-combo]',
      status: '[data-companion-status]',
    };
    Object.entries(values).forEach(([key, value]) => {
      if (state.hudCache[key] === value) return;
      state.hudCache[key] = value;
      const node = device.querySelector(selectors[key]);
      if (node && (key !== 'status' || value)) node.textContent = value;
    });
  }

  function companionCanvasContext(stage) {
    const canvas = stage?.querySelector?.('[data-companion-canvas]');
    if (!canvas) return null;
    const rect = canvas.getBoundingClientRect();
    const width = Math.max(1, rect.width || stage.clientWidth || 1);
    const height = Math.max(1, rect.height || stage.clientHeight || 1);
    const dpr = Math.min(1.5, Math.max(1, Number(host.devicePixelRatio) || 1));
    const pixelWidth = Math.max(1, Math.round(width * dpr));
    const pixelHeight = Math.max(1, Math.round(height * dpr));
    if (canvas.width !== pixelWidth || canvas.height !== pixelHeight) {
      canvas.width = pixelWidth;
      canvas.height = pixelHeight;
    }
    const ctx = canvas.getContext('2d', { alpha: true, desynchronized: true });
    if (!ctx) return null;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, width, height);
    return { canvas, ctx, width, height };
  }

  function drawCompanionBubble(ctx, bubble, width, height) {
    const x = width * bubble.x / 100;
    const y = height * bubble.y / 100;
    const radius = Math.max(7, Number(bubble.size || 24) / 2);
    ctx.save();
    ctx.translate(x, y);
    ctx.globalAlpha = 0.92;
    ctx.fillStyle = bubble.isChild ? 'rgba(187,227,255,.58)' : 'rgba(157,220,241,.48)';
    ctx.strokeStyle = bubble.isChild ? '#6f8ed0' : '#477b92';
    ctx.lineWidth = radius < 11 ? 2 : 3;
    ctx.beginPath();
    ctx.arc(0, 0, radius, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();
    ctx.globalAlpha = 0.9;
    ctx.fillStyle = '#ffffff';
    ctx.beginPath();
    ctx.ellipse(-radius * 0.3, -radius * 0.32, Math.max(2, radius * 0.23), Math.max(1.5, radius * 0.12), -0.45, 0, Math.PI * 2);
    ctx.fill();
    if (bubble.split && !bubble.isChild) {
      ctx.globalAlpha = 0.5;
      ctx.strokeStyle = '#9d75c7';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.arc(0, 0, Math.max(3, radius * 0.42), 0, Math.PI * 2);
      ctx.stroke();
    }
    ctx.restore();
  }

  function drawCompanionBubbleCanvas(stage, state, now) {
    const surface = companionCanvasContext(stage);
    if (!surface) return;
    const { ctx, width, height } = surface;
    state.objects.forEach((bubble) => drawCompanionBubble(ctx, bubble, width, height));
    state.effects.forEach((effect) => {
      const life = clamp((now - effect.startedAt) / 260, 0, 1);
      const x = width * effect.x / 100;
      const y = height * effect.y / 100;
      const radius = 8 + life * 24;
      ctx.save();
      ctx.globalAlpha = 1 - life;
      ctx.strokeStyle = effect.color || '#fff4a8';
      ctx.lineWidth = 3 - life * 1.5;
      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.stroke();
      for (let i = 0; i < 6; i += 1) {
        const angle = i * Math.PI / 3 + effect.phase;
        const distance = 10 + life * 22;
        ctx.fillStyle = i % 2 ? '#ffffff' : '#f4d35e';
        ctx.fillRect(x + Math.cos(angle) * distance - 2, y + Math.sin(angle) * distance - 2, 4, 4);
      }
      ctx.restore();
    });
  }

  function spawnCompanionBubble(state, now, override = null) {
    const progress = state.durationMs ? clamp((now - state.startedAt) / state.durationMs, 0, 1) : 0;
    const capacity = Math.max(0, 22 - state.objects.length);
    if (capacity <= 0) {
      state.nextSpawnAt = now + 90;
      return;
    }
    const burst = override ? 1 : Math.min(capacity, 1 + (Math.random() < 0.18 + progress * 0.62 ? 1 : 0) + (progress > 0.68 && Math.random() < 0.38 ? 1 : 0));
    for (let i = 0; i < burst; i += 1) {
      const size = override?.size ?? Math.round(38 - progress * 12 + Math.random() * 14);
      state.objects.push({
        id: state.nextObjectId++,
        x: override?.x ?? (35 + Math.random() * 30),
        y: override?.y ?? (80 + Math.random() * 5),
        size: clamp(size, 15, 48),
        speed: override?.speed ?? (28 + progress * 42 + Math.random() * 16),
        vx: override?.vx ?? ((Math.random() - 0.5) * (14 + progress * 20)),
        wobble: override?.wobble ?? (2.5 + Math.random() * (4 + progress * 3)),
        phase: Math.random() * Math.PI * 2,
        split: override?.split ?? (progress > 0.3 && size > 28 && Math.random() < 0.12 + progress * 0.16),
        isChild: Boolean(override?.isChild),
      });
    }
    if (!override) state.nextSpawnAt = now + Math.max(125, 500 - progress * 330) + Math.random() * 110;
  }

  function popCompanionBubble(id) {
    const state = companionPlayState();
    if (state.status !== 'running' || state.gameId !== 'bubbles') return;
    const index = state.objects.findIndex((bubble) => String(bubble.id) === String(id));
    if (index < 0) return;
    const [bubble] = state.objects.splice(index, 1);
    const basePoints = bubble.size <= 21 ? 3 : bubble.size <= 30 ? 2 : 1;
    state.combo += 1;
    const comboBonus = Math.min(3, Math.floor(state.combo / 6));
    state.score += basePoints + comboBonus;
    state.popped += 1;
    state.bestCombo = Math.max(state.bestCombo, state.combo);
    state.effects.push({ x: bubble.x, y: bubble.y, startedAt: nowMs(), phase: Math.random() * Math.PI * 2, color: bubble.isChild ? '#9fb8ff' : '#fff4a8' });
    if (bubble.split && !bubble.isChild && state.objects.length <= 19) {
      [-1, 1].forEach((direction) => spawnCompanionBubble(state, nowMs(), {
        x: clamp(bubble.x + direction * 2.2, 4, 96),
        y: bubble.y,
        size: Math.max(15, bubble.size * 0.48),
        speed: bubble.speed * 1.22,
        vx: direction * (15 + Math.random() * 8),
        wobble: 5,
        split: false,
        isChild: true,
      }));
      state.lastHint = '大泡泡分裂成了两个小泡泡！';
    } else {
      state.lastHint = state.combo >= 6 ? `${state.combo} 连击！小泡泡和连击都会获得额外分数。` : `啪！+${basePoints + comboBonus} 分。`;
    }
    playSfx(state.combo % 6 === 0 ? 'confirm' : 'game');
    updateCompanionPlayHud(true);
  }

  function popCompanionBubbleAt(event, stage) {
    const state = companionPlayState();
    const canvas = stage?.querySelector?.('[data-companion-canvas]');
    if (!canvas || !state.objects.length) return false;
    const rect = canvas.getBoundingClientRect();
    const px = event.clientX - rect.left;
    const py = event.clientY - rect.top;
    let hit = null;
    for (let i = state.objects.length - 1; i >= 0; i -= 1) {
      const bubble = state.objects[i];
      const bx = rect.width * bubble.x / 100;
      const by = rect.height * bubble.y / 100;
      const radius = Math.max(12, Number(bubble.size || 24) / 2 + 5);
      if (Math.hypot(px - bx, py - by) <= radius) {
        hit = bubble;
        break;
      }
    }
    if (!hit) return false;
    popCompanionBubble(hit.id);
    return true;
  }

  function companionKeepupHit() {
    const state = companionPlayState();
    const ball = state.ball;
    if (state.status !== 'running' || state.gameId !== 'keepup' || !ball) return;
    if (ball.vy > 0 && ball.y >= 66 && ball.y <= 93 && ball.turn === 'player') {
      const speed = Math.min(66, 46 + state.score * 0.82);
      ball.vy = -speed;
      ball.turn = 'pet';
      state.score += 1;
      state.combo += 1;
      state.bestCombo = Math.max(state.bestCombo, state.combo);
      state.lastHint = state.combo >= 4 ? `${state.combo} 次连续回击，配合得越来越好了！` : '漂亮！球回到宠物那边了。';
      playSfx(state.combo % 4 === 0 ? 'confirm' : 'game');
    } else {
      state.lastHint = ball.vy < 0 ? '球正在飞向宠物，等它顶回来。' : '再等一下，球进入下方亮区时再顶。';
    }
    updateCompanionPlayHud(true);
  }

  function stepCompanionBubbles(state, stage, now, dt) {
    if (now >= state.nextSpawnAt) spawnCompanionBubble(state, now);
    state.objects.forEach((bubble) => {
      bubble.y -= bubble.speed * dt;
      bubble.x += (bubble.vx + Math.sin(now / 260 + bubble.phase) * bubble.wobble) * dt;
      if (bubble.x < 3.5) {
        bubble.x = 3.5;
        bubble.vx = Math.abs(bubble.vx);
      } else if (bubble.x > 96.5) {
        bubble.x = 96.5;
        bubble.vx = -Math.abs(bubble.vx);
      }
    });
    const escaped = state.objects.filter((bubble) => bubble.y < -10).length;
    if (escaped) {
      state.objects = state.objects.filter((bubble) => bubble.y >= -10);
      state.misses += escaped;
      state.combo = 0;
      state.lastHint = `有 ${escaped} 个泡泡飘走了！还可以漏 ${Math.max(0, state.maxMisses - state.misses)} 个。`;
      updateCompanionPlayHud(true);
      if (state.misses >= state.maxMisses) {
        finishCompanionPlay('escaped');
        return;
      }
    }
    state.effects = state.effects.filter((effect) => now - effect.startedAt < 280);
    drawCompanionBubbleCanvas(stage, state, now);
  }

  function drawCompanionKeepupCanvas(stage, state) {
    const surface = companionCanvasContext(stage);
    const ball = state.ball;
    if (!surface || !ball) return;
    const { ctx, width, height } = surface;
    const x = width * ball.x / 100;
    const y = height * ball.y / 100;
    const radius = Math.max(15, Math.min(width, height) * 0.052);
    const ready = ball.vy > 0 && ball.y >= 66 && ball.turn === 'player';
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate(ball.spin || 0);
    if (ready) {
      ctx.globalAlpha = 0.35 + Math.sin(nowMs() / 90) * 0.08;
      ctx.fillStyle = '#fff0a8';
      ctx.beginPath();
      ctx.arc(0, 0, radius + 8, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }
    const colors = ['#ef718c', '#f4d35e', '#67c2a3', '#65bde0'];
    colors.forEach((color, index) => {
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.arc(0, 0, radius, index * Math.PI / 2, (index + 1) * Math.PI / 2);
      ctx.closePath();
      ctx.fill();
    });
    ctx.strokeStyle = '#30262d';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(0, 0, radius, 0, Math.PI * 2);
    ctx.stroke();
    ctx.fillStyle = 'rgba(255,255,255,.75)';
    ctx.beginPath();
    ctx.arc(-radius * 0.32, -radius * 0.34, radius * 0.18, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }

  function animateCompanionPetHit(stage) {
    const petNode = stage?.querySelector?.('[data-companion-pet]');
    if (!petNode) return;
    if (typeof petNode.animate === 'function') {
      petNode.animate([
        { transform: 'translateX(-50%) translateY(0) scale(1)' },
        { transform: 'translateX(-50%) translateY(8px) scale(1.08,.88)', offset: 0.46 },
        { transform: 'translateX(-50%) translateY(0) scale(1)' },
      ], { duration: 280, easing: 'steps(3,end)' });
    } else {
      petNode.classList.add('is-hitting');
      companionPlayTimeout(() => petNode.classList.remove('is-hitting'), 320);
    }
  }

  function stepCompanionKeepup(state, stage, now, dt) {
    const ball = state.ball;
    if (!ball) return;
    ball.y += ball.vy * dt;
    ball.x = 50 + Math.sin((now - state.startedAt) / 510) * Math.min(18, 7 + state.score * 0.28);
    ball.spin = Number(ball.spin || 0) + dt * (ball.vy > 0 ? 6.8 : -6.8);
    if (ball.vy < 0 && ball.y <= 22 && ball.turn === 'pet') {
      ball.y = 22;
      ball.vy = Math.min(62, 40 + state.score * 0.72);
      ball.turn = 'player';
      state.lastHint = `${app.save?.pet?.name || '宠物'}把球顶回来了，准备！`;
      animateCompanionPetHit(stage);
      playSfx('pet');
      updateCompanionPlayHud(true);
    }
    if (ball.y >= 95) {
      ball.y = 95;
      drawCompanionKeepupCanvas(stage, state);
      finishCompanionPlay('dropped');
      return;
    }
    drawCompanionKeepupCanvas(stage, state);
  }

  function companionPlayFrame() {
    const state = companionPlayState();
    if (!companionPlayIsOpen() || state.status !== 'running' || !['bubbles', 'keepup'].includes(state.gameId)) {
      state.rafId = null;
      return;
    }
    const stage = app.root?.querySelector(`[data-companion-stage="${state.gameId}"]`);
    if (!stage) {
      state.rafId = null;
      return;
    }
    const now = nowMs();
    const dt = Math.min(0.04, Math.max(0.001, (now - (Number(state.lastFrameAt) || now)) / 1000));
    state.lastFrameAt = now;
    if (state.gameId === 'bubbles') stepCompanionBubbles(state, stage, now, dt);
    else stepCompanionKeepup(state, stage, now, dt);
    updateCompanionPlayHud(false);
    if (state.status === 'running' && state.endsAt && now >= state.endsAt) {
      finishCompanionPlay('time');
      return;
    }
    if (state.status === 'running') state.rafId = host.requestAnimationFrame(companionPlayFrame);
  }

  function updateHideSeekDom(stage, state) {
    stage.dataset.phase = state.phase;
    stage.querySelectorAll('[data-box-id]').forEach((box) => {
      const id = Number(box.dataset.boxId);
      box.style.order = String(state.boxOrder.indexOf(id));
      box.disabled = state.phase !== 'guess';
    });
    const instruction = stage.querySelector('[data-companion-hide-instruction]');
    if (instruction) instruction.textContent = state.phase === 'shuffle' ? '盯紧纸箱，它们正在连续换位……' : state.phase === 'guess' ? '现在，它在哪个纸箱里？' : '看清楚它躲进了哪个纸箱';
    updateCompanionPlayHud(true);
  }

  function animateHideSeekSwap(stage, state, slotA, slotB, duration, step) {
    const boxes = [...stage.querySelectorAll('[data-box-id]')];
    const movingIds = [state.boxOrder[slotA], state.boxOrder[slotB]];
    const before = new Map(boxes.map((box) => [Number(box.dataset.boxId), box.getBoundingClientRect()]));
    const temp = state.boxOrder[slotA];
    state.boxOrder[slotA] = state.boxOrder[slotB];
    state.boxOrder[slotB] = temp;
    boxes.forEach((box) => {
      const id = Number(box.dataset.boxId);
      box.style.order = String(state.boxOrder.indexOf(id));
    });
    const after = new Map(boxes.map((box) => [Number(box.dataset.boxId), box.getBoundingClientRect()]));
    movingIds.forEach((id, index) => {
      const box = boxes.find((entry) => Number(entry.dataset.boxId) === id);
      const oldRect = before.get(id);
      const newRect = after.get(id);
      if (!box || !oldRect || !newRect) return;
      const deltaX = oldRect.left - newRect.left;
      const arcY = (index === 0 ? -1 : 1) * (16 + Math.min(10, step * 1.5));
      box.style.zIndex = index === 0 ? '5' : '4';
      if (typeof box.animate === 'function') {
        const animation = box.animate([
          { transform: `translate3d(${deltaX}px,0,0) scale(1)`, filter: 'brightness(1)' },
          { transform: `translate3d(${deltaX * 0.52}px,${arcY}px,0) scale(1.06)`, filter: 'brightness(1.08)', offset: 0.5 },
          { transform: 'translate3d(0,0,0) scale(1)', filter: 'brightness(1)' },
        ], { duration, easing: 'cubic-bezier(.35,.05,.2,1)', fill: 'none' });
        animation.finished.catch(() => {}).finally(() => { box.style.zIndex = ''; });
      } else {
        box.style.transform = `translate3d(${deltaX}px,0,0)`;
        host.requestAnimationFrame(() => {
          box.style.transition = `transform ${duration}ms ease`;
          box.style.transform = 'translate3d(0,0,0)';
          companionPlayTimeout(() => {
            box.style.transition = '';
            box.style.transform = '';
            box.style.zIndex = '';
          }, duration + 20);
        });
      }
    });
  }

  function beginHideSeekShuffle(stage, state) {
    if (state.status !== 'running' || state.gameId !== 'hideSeek') return;
    state.phase = 'shuffle';
    updateHideSeekDom(stage, state);
    const swaps = 3 + Math.min(5, state.round);
    const duration = Math.max(300, 520 - state.round * 38);
    let step = 0;
    const doSwap = () => {
      if (state.status !== 'running' || state.phase !== 'shuffle') return;
      let a = Math.floor(Math.random() * 3);
      let b = Math.floor(Math.random() * 3);
      while (b === a) b = Math.floor(Math.random() * 3);
      let key = [a, b].sort().join(':');
      let guard = 0;
      while (key === state.lastSwapKey && guard < 8) {
        a = Math.floor(Math.random() * 3);
        b = Math.floor(Math.random() * 3);
        while (b === a) b = Math.floor(Math.random() * 3);
        key = [a, b].sort().join(':');
        guard += 1;
      }
      state.lastSwapKey = key;
      animateHideSeekSwap(stage, state, a, b, duration, step);
      playSfx('menu');
      step += 1;
      if (step < swaps) companionPlayTimeout(doSwap, duration + 70);
      else companionPlayTimeout(() => {
        state.phase = 'guess';
        state.lastHint = '换位结束，选出宠物所在的那个纸箱。';
        updateHideSeekDom(stage, state);
      }, duration + 180);
    };
    companionPlayTimeout(doSwap, 430);
  }

  function guessHideSeekBox(boxId) {
    const state = companionPlayState();
    if (state.status !== 'running' || state.gameId !== 'hideSeek' || state.phase !== 'guess') return;
    const id = Math.max(0, Math.min(2, Math.floor(Number(boxId) || 0)));
    state.selectedBox = id;
    state.phase = 'result';
    state.phaseToken += 1;
    state.scheduledKey = '';
    if (id === state.targetBox) {
      state.correct += 1;
      state.score += 10;
      state.combo += 1;
      state.bestCombo = Math.max(state.bestCombo, state.combo);
      state.lastHint = '找到了！宠物开心地从纸箱里探出头。';
      playSfx('confirm');
    } else {
      state.combo = 0;
      state.lastHint = '差一点，它其实躲在另一个纸箱。';
      playSfx('fail');
    }
    render();
  }

  function setupHideSeekRuntime(device, state) {
    const stage = device.querySelector('[data-companion-stage="hideSeek"]');
    if (!stage || state.status !== 'running') return;
    const key = `${state.round}:${state.phase}:${state.phaseToken}`;
    if (state.scheduledKey === key) return;
    state.scheduledKey = key;
    if (state.phase === 'show') {
      state.lastHint = '先盯住宠物躲进去的纸箱。';
      updateCompanionPlayHud(true);
      companionPlayTimeout(() => beginHideSeekShuffle(stage, state), Math.max(1100, 1450 - state.round * 45));
    } else if (state.phase === 'result') {
      companionPlayTimeout(() => {
        if (state.round >= state.maxRounds) {
          finishCompanionPlay('completed');
          return;
        }
        state.round += 1;
        state.phase = 'show';
        state.targetBox = Math.floor(Math.random() * 3);
        state.selectedBox = null;
        state.boxOrder = [0, 1, 2];
        state.lastSwapKey = '';
        state.phaseToken += 1;
        state.scheduledKey = '';
        state.lastHint = '新一回合，继续盯住宠物的位置。';
        render();
      }, 1250);
    }
  }

  function setupCompanionPlayRuntime(device) {
    const state = companionPlayState();
    if (!state.open || state.status !== 'running' || app.activeTab !== 'home') return;
    if (state.gameId === 'hideSeek') {
      setupHideSeekRuntime(device, state);
      return;
    }
    const stage = device.querySelector(`[data-companion-stage="${state.gameId}"]`);
    if (!stage) return;
    if (!stage.dataset.companionBound) {
      stage.dataset.companionBound = '1';
      stage.addEventListener('pointerdown', (event) => {
        if (state.gameId === 'bubbles') {
          event.preventDefault();
          event.stopPropagation();
          popCompanionBubbleAt(event, stage);
          return;
        }
        if (state.gameId === 'keepup' && !event.target?.closest?.('[data-action]')) {
          event.preventDefault();
          event.stopPropagation();
          companionKeepupHit();
        }
      }, { passive: false });
    }
    if (state.rafId == null) {
      state.lastFrameAt = nowMs();
      state.rafId = host.requestAnimationFrame(companionPlayFrame);
    }
  }

  function eggSvg(shellColor = 'mint') {
    const shells = {
      mint: '#79c9ad',
      rose: '#e998b0',
      honey: '#e4bd62',
      sky: '#79b8d2',
      lilac: '#aa98ce',
    };
    const matrix = [
      '................','.......KK.......','......KEEK......','.....KEEEEK.....',
      '....KEEEEEEK....','....KEEEEEEK....','...KEEBEEEEEK...','...KEEEEBEEEK...',
      '...KEEEEEEEEK...','...KEEEEEEEEK...','....KEEEEEEK....','....KEEEEEEK....',
      '.....KEEEEK.....','......KKKK......','................','................',
    ];
    return matrixToSvg(matrix, '像素宠物蛋', {
      shell: shells[shellColor] || shells.mint,
      secondary: '#fff3c8',
    });
  }

  function tombstoneSvg() {
    const matrix = [
      '................','.....KKKKKK.....','....KAAAAAAK....','...KAAAAAAAAK...',
      '...KAAAKKAAAK...','...KAAAKKAAAK...','...KAKKKKKKAK...','...KAAAAAAAAK...',
      '...KAAAKKAAAK...','...KAAAAAAAAK...','...KAAAAAAAAK...','..KKAAAAAAAAKK..',
      '.KKKKKKKKKKKKKK.','..MMMMMMMMMMMM..','.MMMMMMMMMMMMMM.','................',
    ];
    return matrixToSvg(matrix, '纪念碑', {
      primary: '#8e9a97',
      secondary: '#b9c2bf',
      accent: '#73817e',
