  }

  function wasteSvg(count) {
    if (!count) return '';
    const item = `<svg viewBox="0 0 8 8" shape-rendering="crispEdges" aria-hidden="true"><rect x="2" y="4" width="4" height="2" fill="#705747"/><rect x="3" y="2" width="2" height="2" fill="#705747"/><rect x="1" y="6" width="6" height="1" fill="#24312f"/></svg>`;
    return Array.from({ length: count }, (_, index) => `<span class="ptg-waste ptg-waste-${index + 1}">${item}</span>`).join('');
  }

  function pixelIcon(kind) {
    const icons = {
      food: ['.RR.', 'RRRR', '.GG.', '.GG.'], play: ['.YY.', 'YYYY', 'YWWY', '.YY.'],
      clean: ['W..W', '.WW.', 'WWWW', '.WW.'], sleep: ['ZZZ.', '..Z.', '.Z..', 'ZZZZ'],
      heal: ['.RR.', 'RRRR', '.RR.', '....'], edit: ['...K', '..KK', '.KK.', 'KK..'],
      reset: ['.KK.', 'K..K', '...K', '.KK.'], coin: ['.YY.', 'YWWY', 'YWWY', '.YY.'],
      egg: ['.KK.', 'KYYK', 'KYYK', '.KK.'], book: ['K..K', 'KKKK', 'K..K', 'KKKK'],
      grave: ['.KK.', 'KWWK', 'KWWK', 'KKKK'], home: ['.KK.', 'KKKK', 'KWWK', 'KKKK'],
      shop: ['KKKK', 'KYYK', 'KWWK', 'KKKK'], game: ['K..K', '.KK.', 'K..K', '.KK.'],
      data: ['KKKK', 'K..K', 'K..K', 'KKKK'], settings: ['K.K.', '.KKK', 'KKK.', '.K.K'],
      wardrobe: ['.YY.', 'KYYK', '.KK.', '.KK.'],
      light: ['.YY.', 'YYYY', '.YY.', '.YY.'], dice: ['KKKK', 'KW.K', 'K.WK', 'KKKK'], gacha: ['.YY.', 'YYYY', 'KYYK', '.KK.'],
      back: ['..K.', '.KKK', 'KKKK', '.KKK'], calendar: ['K.K.', 'KKKK', 'K.KK', 'KKKK'],
      study: ['K..K', 'KKKK', 'K..K', 'KKKK'], work: ['.KK.', 'KKKK', 'K..K', 'KKKK'],
      fun: ['Y..Y', '.YY.', 'Y..Y', '.YY.'], attribute: ['K.KK', 'KKK.', '.KKK', 'KK.K'],
    };
    const palette = { R: '#e36f74', G: '#6fa35f', Y: '#e5ba55', W: '#dff8ef', Z: '#7692a8', K: '#33413f' };
    const matrix = icons[kind] || icons.home;
    const rects = [];
    matrix.forEach((row, y) => [...row].forEach((cell, x) => {
      if (palette[cell]) rects.push(`<rect x="${x}" y="${y}" width="1" height="1" fill="${palette[cell]}"/>`);
    }));
    return `<svg class="ptg-icon" viewBox="0 0 4 4" shape-rendering="crispEdges" aria-hidden="true">${rects.join('')}</svg>`;
  }

