      @media(max-width:430px){#${APP_ID} .ptg-leaderboard-row{grid-template-columns:30px 38px minmax(0,1fr);padding:8px}.ptg-leaderboard-row>strong{grid-column:3;text-align:left}.ptg-leaderboard-badge{width:36px;height:36px}.ptg-leaderboard-badge .ptg-gacha-pixel-art{width:34px;height:34px}.ptg-gacha-collection-grid{grid-template-columns:1fr}.ptg-gacha-preview-row{grid-template-columns:28px 38px minmax(0,1fr);padding:9px}.ptg-gacha-preview-row>strong{grid-column:3;text-align:left}.ptg-gacha-preview-slots{grid-template-columns:1fr}.ptg-gacha-preview-actions{grid-template-columns:repeat(2,minmax(0,1fr))}.ptg-gacha-preview-actions button.ptg-save{grid-column:span 1}.ptg-leaderboard-equipped{grid-template-columns:1fr}}

    `;
  }

  const ITEM_CATEGORY_META = {
    food: { name: '食物', action: '喂食', icon: 'food' },
    toy: { name: '玩具', action: '玩耍', icon: 'play' },
    clean: { name: '清洁用品', action: '清洁', icon: 'clean' },
    medicine: { name: '药品', action: '治疗', icon: 'heal' },
    revival: { name: '特殊药剂', action: '复活', icon: 'heal' },
  };

  function itemsByCategory(category) {
    return Object.entries(ITEMS).filter(([, item]) => item.category === category);
  }

  function inventoryCategoryCount(category, save = app.save) {
    return itemsByCategory(category).reduce((sum, [id]) => sum + Math.max(0, Number(save?.inventory?.[id] || 0)), 0);
  }

  function applyItemEffects(pet, effects = {}) {
    ['hunger', 'happiness', 'health', 'cleanliness', 'energy'].forEach((key) => {
      if (effects[key] !== undefined) pet[key] = clampPetStat(pet, key, Number(pet[key] || 0) + Number(effects[key] || 0));
    });
    if (effects.hungerSet !== undefined) pet.hunger = clampPetStat(pet, 'hunger', effects.hungerSet);
    if (effects.happinessSet !== undefined) pet.happiness = clampPetStat(pet, 'happiness', effects.happinessSet);
    if (effects.healthSet !== undefined) pet.health = clampPetStat(pet, 'health', effects.healthSet);
    if (effects.cleanlinessSet !== undefined) pet.cleanliness = clampPetStat(pet, 'cleanliness', effects.cleanlinessSet);
    if (effects.energySet !== undefined) pet.energy = clampPetStat(pet, 'energy', effects.energySet);
    if (effects.weight !== undefined) pet.weight = Math.max(0.5, Number(pet.weight || 0) + Number(effects.weight || 0));
    if (effects.lifespanDays !== undefined) pet.naturalDeathAt = Number(pet.naturalDeathAt || nowMs()) + Number(effects.lifespanDays || 0) * 86400000;
    if (effects.messSet !== undefined) pet.mess = Math.max(0, Math.min(4, Math.floor(Number(effects.messSet) || 0)));
    if (effects.mess !== undefined) pet.mess = Math.max(0, Math.min(4, Math.floor(Number(pet.mess || 0) + Number(effects.mess || 0))));
    if (pet.mess <= 0) pet.wasteProgressHours = 0;
    const appliedAttributes = effects.attributes ? applyAttributeChanges(pet, effects.attributes) : {};
    pet.sick = pet.health < 35;
    return appliedAttributes;
  }

  function itemUseBlocked(category, pet = app.save?.pet, item = null, itemId = '') {
    if (!pet) return '当前没有宠物。';
    if (itemId === 'revival_potion') return '复活药只能在宠物死亡后从主页使用。';
    const extension = extensionForPet(pet);
    const customBlocked = extension ? callExtensionHook(extension, 'itemUseBlocked', { pet, item, itemId, action: category }, '') : '';
    if (customBlocked) return String(customBlocked);
    if (itemId === 'longevity_pill' && !petAllows(pet, 'allowLongevityItems', true)) return '这种宠物无法使用延寿类物品。';
    if (category === 'food' && pet.hunger >= petStatMax(pet, 'hunger') && !item?.allowWhenFull) return '已经吃得饱饱的，普通食物暂时不能继续喂食。';
    if (category === 'clean' && pet.cleanliness >= petStatMax(pet, 'cleanliness')) return '清洁已经是满值，不需要继续清洁。';
    if (category === 'medicine' && pet.health >= petStatMax(pet, 'health')) return '健康已经是满值，不需要继续治疗。';
    if (pet.sleeping && ['food', 'toy', 'medicine'].includes(category)) return '它正在睡觉，先叫醒它吧。';
    return '';
  }

  function pushCareLog(actor, type, text, extra = {}) {
    const save = app.save;
    if (!save || !text) return;
    if (!Array.isArray(save.careLog)) save.careLog = [];
    save.careLog.push({
      at: nowMs(),
      actor: actor === 'char' ? 'char' : 'player',
      actorName: actor === 'char' ? (refreshLiveCharacterName() || '角色') : '你',
      type: type || 'other',
      text: String(text),
      ...extra,
    });
    if (save.careLog.length > CARE_LOG_LIMIT) save.careLog = save.careLog.slice(-CARE_LOG_LIMIT);
  }

  function useCareItem(itemId, actor = 'player', requestedCount = 1) {
    const save = app.save;
    const pet = save?.pet;
    const item = ITEMS[itemId];
    if (itemId === 'revival_potion') return { ok: false, text: '复活药只能在宠物死亡后从主页使用。' };
    if (!save || save.lifecycle !== 'alive' || !pet || !item) return { ok: false, text: '当前无法使用这个物品。' };
    const blocked = itemUseBlocked(item.category, pet, item, itemId);
    if (blocked) return { ok: false, text: blocked };
    const have = Number(save.inventory[itemId] || 0);
    if (have <= 0) return { ok: false, text: `背包里没有「${item.name}」。` };
    let count = Math.floor(Number(requestedCount) || 1);
    if (!Number.isFinite(count) || count < 1) count = 1;
    count = Math.min(count, have, CONFIG.maxCareItemBatch);
    let appliedAttributes = {};
    const lifeBefore = Number(pet.naturalDeathAt || 0);
    for (let i = 0; i < count; i += 1) {
      save.inventory[itemId] -= 1;
      appliedAttributes = applyItemEffects(pet, item.effects || {});
      const baseCompanion = item.category === 'toy' ? 4 : item.category === 'medicine' ? 3 : 2;
      rewardCompanionAction(save, actor === 'char' ? Math.max(0.5, baseCompanion * 0.45) : baseCompanion);
    }
    const verb = ITEM_CATEGORY_META[item.category]?.action || '使用';
    const countText = count > 1 ? ` ×${count}` : '';
    const attributeText = formatAttributeChanges(appliedAttributes);
    const extendedDays = Math.max(0, Math.round((Number(pet.naturalDeathAt || 0) - lifeBefore) / 86400000));
    const lifespanText = extendedDays > 0 ? `寿命延长 ${extendedDays} 天。` : '';
    const result = {
      ok: true,
      mode: item.mode || 'pat',
      text: `${verb}使用了「${item.name}」${countText}。${lifespanText}${attributeText ? `属性提升：${attributeText}。` : ''}${actor === 'char' ? `${refreshLiveCharacterName() || '角色'}照顾了它。` : ''}`,
      itemId, item, appliedAttributes, count,
      logType: item.category === 'food' ? 'feed' : item.category === 'toy' ? 'play' : item.category === 'clean' ? 'clean' : 'heal',
      logText: `${verb}「${item.name}」${countText}`,
    };
    const extension = extensionForPet(pet);
    const extensionResult = extension ? callExtensionHook(extension, 'afterItemUse', { pet, itemId, item, actor, result }, null) : null;
    if (typeof extensionResult === 'string') result.text = extensionResult;
    else if (extensionResult && typeof extensionResult === 'object') Object.assign(result, extensionResult);
    applyExtensionPetPolicy(pet, extension);
    return result;
  }

  function renderItemPickerModal() {
    const category = app.itemPickerCategory;
    if (!category || !ITEM_CATEGORY_META[category] || app.save?.lifecycle !== 'alive') return '';
    const meta = ITEM_CATEGORY_META[category];
    const generalBlocked = itemUseBlocked(category, app.save?.pet, { allowWhenFull: category === 'food' });
    const cards = itemsByCategory(category).map(([id, item]) => {
      const count = Number(app.save.inventory[id] || 0);
      const blocked = itemUseBlocked(category, app.save?.pet, item, id);
      return `<button type="button" class="ptg-picker-item" data-action="use-item-${id}" ${(blocked || count <= 0) ? 'disabled' : ''}><span class="ptg-picker-icon">${pixelIcon(item.icon)}</span><span><strong>${escapeHtml(item.name)}</strong><small>${escapeHtml(item.description)} · 持有 ${count}${blocked ? ` · ${escapeHtml(blocked)}` : ''}</small></span></button>`;
    }).join('');
    return `<div class="ptg-runtime-overlay"><div class="ptg-runtime-card"><div class="ptg-runtime-head"><strong>${escapeHtml(meta.action)} · 选择${escapeHtml(meta.name)}</strong><button type="button" data-action="item-picker-close">×</button></div>${generalBlocked ? `<div class="ptg-runtime-note negative">${escapeHtml(generalBlocked)}</div>` : ''}<div class="ptg-picker-list">${cards}</div><button type="button" class="ptg-secondary ptg-wide" data-action="item-picker-close">取消</button></div></div>`;
  }

  function renderStat(label, value, max = 100) {
    const safeMax = Math.max(1, Number(max) || 100);
    const safe = clamp(value, 0, safeMax);
    const display = safeMax === 100 ? `${Math.round(safe)}` : `${Math.round(safe)}/${Math.round(safeMax)}`;
    return `<div class="ptg-stat"><div class="ptg-stat-head"><span>${escapeHtml(label)}</span><span>${display}</span></div><div class="ptg-meter"><i style="width:${clamp((safe / safeMax) * 100)}%"></i></div></div>`;
  }



  function renderAttributes(pet) {
    if (!pet) return '';
    return `<div class="ptg-attributes">${Object.entries(ATTRIBUTE_DEFS).map(([key, definition]) => `<div class="ptg-attribute" title="${escapeHtml(definition.description)}"><strong>${Math.round(Number(pet.attributes?.[key] || 0))}</strong><small>${escapeHtml(definition.name)}</small></div>`).join('')}</div>`;
  }

  function formatHours(hours) {
    const value = Number(hours) || 0;
    return Number.isInteger(value) ? `${value}小时` : `${round1(value)}小时`;
  }

  function scheduleStatusLabel(status) {
    return ({ queued: '等待中', active: '进行中', done: '已完成', skipped: '已跳过', blocked: '属性不足', blocked_energy: '精力不足，未能开始', cancelled: '已取消' })[status] || status;
  }

  function renderScheduleTask(task, kind = 'today') {
    const definition = activityDefinition(task.category, task.activityId);
    if (!definition) return '';
    const isTemplate = kind === 'template';
    const progress = clamp((Number(task.progressHours || 0) / Number(task.durationHours || 1)) * 100);
    const rewardText = task.category === 'work' ? ` · 工资 ${calculateJobReward(definition, task.durationHours)}` : '';
    const removeBtn = isTemplate
      ? `<button type="button" class="ptg-schedule-remove" data-action="schedule-remove-${escapeHtml(task.templateId)}">删除</button>`
      : (['done', 'cancelled'].includes(task.status) ? '' : `<button type="button" class="ptg-schedule-remove" data-action="schedule-today-remove-${escapeHtml(task.id)}">删除</button>`);
    return `<div class="ptg-schedule-row ${escapeHtml(task.status || '')}"><div><strong>${escapeHtml(definition.name)} · ${formatHours(task.durationHours)}${rewardText}</strong><small>${isTemplate ? '每日计划' : scheduleStatusLabel(task.status)}${task.status === 'active' ? ` · ${round1(task.progressHours)}/${task.durationHours}小时` : ''}</small>${isTemplate ? '' : `<div class="ptg-schedule-progress"><i style="width:${progress}%"></i></div>`}</div>${removeBtn}</div>`;
  }

  function renderRequirementText(pet, requirements = {}) {
    const entries = Object.entries(requirements);
    if (!entries.length) return '无属性要求';
    return entries.map(([key, required]) => {
      const current = Math.round(Number(pet?.attributes?.[key] || 0));
      const okay = current >= required;
      return `<span class="${okay ? '' : 'miss'}">${escapeHtml(ATTRIBUTE_DEFS[key]?.name || key)} ${current}/${required}</span>`;
    }).join(' · ');
  }

  const SCHEDULE_CATEGORY_META = {
    study: { name: '学习', icon: 'study', description: '选择课程，提升宠物的不同属性。' },
    fun: { name: '娱乐', icon: 'fun', description: '选择陪伴活动，恢复心情并积累少量属性。' },
    work: { name: '打工', icon: 'work', description: '选择符合属性要求的工作，完成后获得金币。' },
    sleep: { name: '睡觉', icon: 'sleep', description: '安排中途休息，每小时恢复10点精力。' },
  };

  function scheduleDefinitions(category) {
    return category === 'study' ? COURSE_DEFS
      : category === 'fun' ? ENTERTAINMENT_DEFS
      : category === 'work' ? JOB_DEFS
      : category === 'sleep' ? REST_DEFS
      : {};
  }

  function getScheduleBuilder() {
    if (!app.scheduleBuilder || typeof app.scheduleBuilder !== 'object') {
      app.scheduleBuilder = { open: false, step: 1, category: null, activityId: null, target: 'today' };
    }
    if (app.scheduleBuilder.target !== 'today' && app.scheduleBuilder.target !== 'template') app.scheduleBuilder.target = 'today';
    return app.scheduleBuilder;
  }

  function resetScheduleBuilder(open = false, target = 'today') {
    app.scheduleBuilder = { open, step: 1, category: null, activityId: null, target: target === 'template' ? 'template' : 'today' };
  }

  function scheduleBuilderSteps(step) {
    return `<div class="ptg-wizard-steps">
      <div class="ptg-wizard-step ${step === 1 ? 'active' : step > 1 ? 'done' : ''}">1<br>选择行动</div>
      <div class="ptg-wizard-step ${step === 2 ? 'active' : step > 2 ? 'done' : ''}">2<br>具体行动</div>
      <div class="ptg-wizard-step ${step === 3 ? 'active' : ''}">3<br>选择时间</div>
    </div>`;
  }

  function scheduleActivityDetail(category, definition, pet) {
    if (category === 'study') return `${definition.description} · 完成后按时长获得整数属性，单项 +1～5`;
    if (category === 'fun') return `${definition.description} · 心情满值时也可以继续安排 · 完成后可获得整数属性`;
    if (category === 'sleep') return `${definition.description} · 10小时最多恢复100精力`;
    if (category === 'work') {
      const requirementText = Object.entries(definition.requirements || {})
        .map(([key, required]) => `${ATTRIBUTE_DEFS[key]?.name || key}${Math.round(Number(pet?.attributes?.[key] || 0))}/${required}`).join('、') || '无属性要求';
      return `${definition.description} · ${definition.hourlyWage}币/时 · 完成后获得整数属性 · 要求：${requirementText}`;
    }
    return definition.description || '';
  }

  function renderScheduleBuilder(save, pet, totalHours) {
    const builder = getScheduleBuilder();
    const step = clamp(Number(builder.step) || 1, 1, 3);
    const remainingHours = Math.max(0, round1(CONFIG.maxDailyScheduleHours - totalHours));
    const targetLabel = builder.target === 'template' ? '每日计划' : '今日执行';
    let body = '';

    if (step === 1) {
      body = `<div class="ptg-wizard-tip">先选择要安排的行动类型。之后只会显示对应的课程、娱乐、工作或睡眠选项。</div>
        <div class="ptg-wizard-list">${Object.entries(SCHEDULE_CATEGORY_META).map(([category, meta]) => `<button type="button" class="ptg-wizard-option" data-action="schedule-builder-category-${category}">${pixelIcon(meta.icon)}<span class="ptg-wizard-option-main"><strong>${escapeHtml(meta.name)}</strong><small>${escapeHtml(meta.description)}</small></span><span class="ptg-wizard-arrow">›</span></button>`).join('')}</div>`;
    } else if (step === 2) {
      const category = builder.category;
      const meta = SCHEDULE_CATEGORY_META[category];
      const definitions = scheduleDefinitions(category);
      const options = Object.entries(definitions).map(([id, definition]) => {
        const locked = category === 'work' && !jobRequirementsMet(pet, definition);
        const lockedText = locked ? ' · 当前属性不足' : '';
        return `<button type="button" class="ptg-wizard-option" data-action="schedule-builder-activity-${id}" ${locked ? 'disabled' : ''}>${pixelIcon(meta?.icon || 'calendar')}<span class="ptg-wizard-option-main"><strong>${escapeHtml(definition.name)}${escapeHtml(lockedText)}</strong><small>${escapeHtml(scheduleActivityDetail(category, definition, pet))}</small></span><span class="ptg-wizard-arrow">›</span></button>`;
      }).join('');
      body = `<div class="ptg-wizard-tip">已选择「${escapeHtml(meta?.name || '')}」。现在选择具体要做的事情。</div><div class="ptg-wizard-list">${options}</div>`;
    } else {
      const category = builder.category;
      const definition = activityDefinition(category, builder.activityId);
      const meta = SCHEDULE_CATEGORY_META[category];
      if (!definition) {
        resetScheduleBuilder(true);
        return renderScheduleBuilder(save, pet, totalHours);
      }
      const availableDurations = Array.isArray(definition.durations) && definition.durations.length
        ? definition.durations
        : category === 'work' ? [1, 2, 4, 8] : [];
      const durationButtons = availableDurations.map((duration) => {
        const exceeds = totalHours + Number(duration) > CONFIG.maxDailyScheduleHours + 0.0001;
        const token = String(duration).replace('.', '_');
        const attributeText = formatAttributeChanges(scheduleAttributeRewards(definition, duration));
        const details = [category === 'work' ? `预计工资 ${calculateJobReward(definition, duration)} 币` : '', attributeText ? `属性：${attributeText}` : ''].filter(Boolean).join(' · ');
        const reward = details ? `<small>${escapeHtml(details)}</small>` : '';
        return `<button type="button" class="ptg-wizard-duration" data-action="schedule-builder-duration-${token}" ${exceeds ? 'disabled' : ''}>${formatHours(duration)}${reward}</button>`;
      }).join('');
      const durationArea = durationButtons || '<div class="ptg-wizard-tip">当前行动没有可用时长，请返回上一步重新选择。</div>';
      body = `<div class="ptg-wizard-summary"><div class="ptg-wizard-summary-title">${pixelIcon(meta?.icon || 'calendar')}<strong>${escapeHtml(meta?.name || '')} · ${escapeHtml(definition.name)}</strong></div><p>${escapeHtml(scheduleActivityDetail(category, definition, pet))}</p><p>当前${targetLabel} ${totalHours}/${CONFIG.maxDailyScheduleHours} 小时，还可安排 ${remainingHours} 小时。</p></div><div class="ptg-wizard-tip">最后选择持续时间。点击时间后会立即加入${targetLabel}。</div><div class="ptg-wizard-durations">${durationArea}</div>`;
    }

    return `<div class="ptg-panel ptg-wizard"><div class="ptg-wizard-head"><h3>添加到${targetLabel}</h3><button type="button" class="ptg-wizard-close" data-action="schedule-builder-close">取消</button></div>${scheduleBuilderSteps(step)}${body}${step > 1 ? '<button type="button" class="ptg-wizard-back" data-action="schedule-builder-back">‹ 返回上一步</button>' : ''}</div>`;
  }

  function renderSchedule() {
    const save = app.save;
    if (!save || save.lifecycle !== 'alive' || !save.pet) return `<div class="ptg-panel"><div class="ptg-empty">孵化宠物后才能安排睡觉、课程、娱乐和打工。</div></div>`;
    ensureScheduleDay(save, localDayKey());
    maybeApplyDailyPlan(save);
    const pet = save.pet;
    const schedule = save.schedule;
    const totalHours = scheduleTemplateHours(schedule);
    const builder = getScheduleBuilder();
    if (builder.open) return renderScheduleBuilder(save, pet, builder.target === 'template' ? scheduleTemplateHours(schedule) : scheduleTodayHours(schedule));

    const currentTask = schedule.today.find((task) => task.status === 'active') || schedule.today.find((task) => task.status === 'queued');
    const completed = schedule.today.filter((task) => task.status === 'done').length;
    const earned = schedule.today.reduce((sum, task) => sum + Number(task.reward || 0), 0);
    const todayHours = scheduleTodayHours(schedule);
    const energyWarning = pet.energy < CONFIG.minimumActivityEnergy ? `<div class="ptg-event-feedback negative">当前精力 ${Math.round(pet.energy)}：低于20，尚未开始的学习与打工会无法执行。可以在它们前面添加睡觉。</div>` : '';
    const templateHtml = schedule.template.length ? schedule.template.map((task) => renderScheduleTask(task, 'template')).join('') : '<div class="ptg-empty" style="padding:18px">还没有每日计划。可在下方“添加到每日计划”里安排，每天 08:00 若没单独设定今日执行就会自动套用。</div>';
    const todayHtml = schedule.today.length ? schedule.today.map((task) => renderScheduleTask(task, 'today')).join('') : '<div class="ptg-empty" style="padding:18px">今天还没有安排。可“添加到今日执行”，或等 08:00 自动套用每日计划。</div>';
    const planStatus = schedule.todayTouched
      ? '今日执行由你单独设定，今天不会被每日计划覆盖。'
      : schedule.planApplied
        ? '今日执行已自动套用每日计划。'
        : `今日执行尚未设定，将在每天 ${String(CONFIG.scheduleStartHour).padStart(2, '0')}:00 自动套用每日计划。`;

    return `<div class="ptg-panel"><div class="ptg-section-title"><h3>每日日程表</h3><span class="ptg-chip">今日 ${todayHours}/${CONFIG.maxDailyScheduleHours}h</span></div>
