  function createGameStateById(gameId) {
    const module = gameModule(gameId);
    if (module && !module.legacy && typeof module.createState === 'function') {
      try { return module.createState(gameExtensionApi(gameId)); }
      catch (error) { console.error(`[像素拓麻歌子] 小游戏 ${gameId} 创建状态失败：`, error); return null; }
    }
    if (gameId === 'tetris') return createTetrisState();
    if (gameId === 'snake') return createSnakeState();
    if (gameId === '2048') return create2048State();
    if (gameId === 'match3') return createMatch3State();
    if (gameId === 'watermelon') return createWatermelonState();
    if (gameId === 'pinball') return createPinballState();
    if (gameId === 'petRogue') return createPetRogueState(app.games.petRogueStartWeapon);
    if (gameId === 'minesweeper') return createMinesweeperState();
    if (gameId === 'collectHoney') return createCollectHoneyState();
    if (gameId === 'bulletHell') return createBulletHellState();
    if (gameId === 'zombieGarden') return createZombieGardenState();
    if (gameId === 'kitchen') return createKitchenState();
    return null;
  }

  function assignGameState(gameId, state) {
    const property = GAME_STATE_PROPERTY[gameId];
    if (property) app.games[property] = state;
    return state;
  }

  function gameState(gameId, createIfMissing = true) {
    const property = GAME_STATE_PROPERTY[gameId];
    if (!property || !GAME_DEFS[gameId]) return null;
    if (!isGameInstalled(gameId)) return null;
    const current = app.games[property];
    if (current || !createIfMissing) return current || null;
    return assignGameState(gameId, createGameStateById(gameId));
  }

  function releaseGameState(gameId) {
    const property = GAME_STATE_PROPERTY[gameId];
    if (!property) return;
    if (app.games.selected === gameId) {
      clearGameTimer();
      app.games.selected = null;
      app.games.leaderboardOpen = false;
      syncBackgroundMusicForCurrentView();
    }
    if (app.save?.gameRecords?.suspended?.gameId === gameId) app.save.gameRecords.suspended = null;
    app.games[property] = null;
  }


function gameIconSvg(gameId) {
  const module = gameModule(gameId) || {};
  const icon = module.icon || {};
  const pattern = Array.isArray(icon.pattern) && icon.pattern.length ? icon.pattern.slice(0, 8) : [
    '........', '..AAAA..', '.A....A.', '.A.BB.A.', '.A.BB.A.', '.A....A.', '..AAAA..', '........',
  ];
  const palette = icon.palette && typeof icon.palette === 'object' ? icon.palette : { A: '#6f8f7d', B: '#f2c96b' };
  const background = /^#[0-9a-f]{3,8}$/i.test(String(icon.background || '')) ? icon.background : '#9caf89';
  let rects = `<rect width="8" height="8" fill="${background}"/>`;
  pattern.forEach((rawRow, y) => [...String(rawRow || '').padEnd(8, '.').slice(0, 8)].forEach((char, x) => {
    if (char !== '.') rects += `<rect x="${x}" y="${y}" width="1" height="1" fill="${escapeHtml(palette[char] || '#263238')}" stroke="#263238" stroke-width=".12"/>`;
  }));
  const lines = Array.isArray(icon.textLines) ? icon.textLines.slice(0, 2) : [];
  lines.forEach((line, index) => {
    const y = lines.length === 1 ? 4.8 : (index === 0 ? 3.25 : 6.15);
    rects += `<text x="4" y="${y}" text-anchor="middle" font-size="1.45" font-weight="900" fill="#263238">${escapeHtml(String(line).slice(0, 4))}</text>`;
  });
  return `<svg class="ptg-game-icon" viewBox="0 0 8 8" shape-rendering="crispEdges" aria-hidden="true">${rects}</svg>`;
}

  function gameRewardPreview(gameId, score) {
