  function setGameInstalled(gameId, installed) {
    if (!app.save || !GAME_DEFS[gameId]) return false;
    app.save.settings.installedGames = normalizeInstalledGames(app.save.settings.installedGames);
    const next = Boolean(installed);
    if (app.save.settings.installedGames[gameId] === next) return false;
    app.save.settings.installedGames[gameId] = next;
    if (!next) releaseGameState(gameId);
    else scheduleLeaderboardSync(350);
    app.message = `${GAME_DEFS[gameId].name}已${next ? '启用' : '停用'}。`;
    saveCurrent();
    return true;
  }






















































