    if (!definition || !state) {
      app.games.selected = null;
      return renderGameGallery();
    }
    app.games.leaderboardGameId = gameId;
    const highScore = app.save.gameRecords.highScores[gameId] || 0;
    const running = state.status === 'running';
    const paused = state.status === 'paused';
    const loading = false;
    const finished = state.status === 'over';
    if (app.games.leaderboardOpen && !running && !paused && !loading) return renderGameLeaderboard(gameId);
    const score = Math.max(0, Math.floor(Number(state.score) || 0));
    let extraLabel = '';
    let extraValue = 0;
    let board = '';
    let customSetup = '';
    const module = gameModule(gameId);
    if (module && !module.legacy && typeof module.render === 'function') {
      try {
        const output = module.render(state, gameExtensionApi(gameId));
        if (typeof output === 'string') board = output;
        else if (output && typeof output === 'object') {
          board = String(output.board || '');
          extraLabel = String(output.extraLabel || '');
          extraValue = output.extraValue ?? 0;
          customSetup = String(output.setup || '');
        }
      } catch (error) {
        console.error(`[像素拓麻歌子] 小游戏 ${gameId} 渲染失败：`, error);
        board = `<div class="ptg-empty">小游戏渲染失败，请检查该组件脚本。</div>`;
      }
    } else if (gameId === 'tetris') {
      extraLabel = '消行'; extraValue = state.lines || 0; board = renderTetrisGame(state);
    } else if (gameId === 'snake') {
      extraLabel = '吃到果实'; extraValue = Math.max(0, (state.snake?.length || 3) - 3); board = renderSnakeGame(state);
    } else if (gameId === '2048') {
      extraLabel = '最大数字'; extraValue = state.maxTile || 2; board = render2048Game(state);
    } else if (gameId === 'match3') {
      extraLabel = '消除'; extraValue = `${Math.max(0, Number(state.cleared) || 0)}格`; board = renderMatch3Game(state);
    } else if (gameId === 'watermelon') {
      extraLabel = '最大水果'; extraValue = WATERMELON_FRUITS[Math.max(0, Number(state.maxLevel) || 0)]?.name || '樱桃'; board = renderWatermelonGame(state);
    } else if (gameId === 'pinball') {
      extraLabel = '剩余球'; extraValue = Math.max(0, Number(state.ballsRemaining) || 0); board = renderPinballGame(state);
    } else if (gameId === 'petRogue') {
      extraLabel = '波次'; extraValue = `${Math.max(1, Number(state.wave) || 1)}`; board = renderPetRogueGame(state);
    } else if (gameId === 'minesweeper') {
      extraLabel = '雷数'; extraValue = state.mineCount || 10; board = renderMinesweeperGame(state);
    } else if (gameId === 'collectHoney') {
      extraLabel = '蜂蜜罐'; extraValue = `${Math.max(0, Number(state.jarsFilled) || 0)}瓶`; board = renderCollectHoneyGame(state);
    } else if (gameId === 'bulletHell') {
      extraLabel = '击破'; extraValue = Math.max(0, Number(state.kills) || 0); board = renderBulletHellGame(state);
    } else if (gameId === 'zombieGarden') {
      extraLabel = '击破'; extraValue = Math.max(0, Number(state.kills) || 0); board = renderZombieGardenGame(state);
    } else if (gameId === 'kitchen') {
      extraLabel = '余心'; extraValue = kitchenHearts(state); board = renderKitchenGame(state);
    } else if (!module || module.legacy) {
      app.games.selected = null;
      return renderGameGallery();
    }
    const setup = customSetup || (gameId === 'minesweeper' ? renderMinesweeperSetup(state) : gameId === 'bulletHell' ? renderBulletHellSensitivityControls() : gameId === 'petRogue' ? renderPetRogueSetup() : '');
    const resultTitle = gameId === 'minesweeper' ? (state.won ? '通关' : '本局结束') : gameId === 'kitchen' ? '本局结束' : '本局结算';
    const leaderboardEnabled = definition.leaderboard !== false;
    const rankCache = leaderboardEnabled ? leaderboardCacheFor(gameId) : null;
    const authorization = rankCache?.authorization || null;
    const rankText = leaderboardEnabled
      ? (authorization?.approved ? leaderboardOwnRankText(rankCache) : leaderboardAuthorizationMessage(authorization))
      : '本地记录';
    const displayPlayerName = leaderboardEnabled
      ? (authorization?.approved ? leaderboardDisplayNickname(leaderboardProfile()) : '未获后端授权时只记录本地最高分')
      : '该小游戏仅记录本地成绩';
    const rankCard = leaderboardEnabled
      ? `<div class="ptg-game-rank-card"><div class="ptg-game-rank-main"><span>${authorization?.approved ? '我的全服排名' : '全服榜状态'}</span><strong>${escapeHtml(rankText)}</strong><small>${escapeHtml(displayPlayerName)}</small></div><button type="button" data-action="game-open-leaderboard">${authorization?.approved ? '查看排行榜' : '查看授权状态'}</button></div>`
      : `<div class="ptg-game-rank-card"><div class="ptg-game-rank-main"><span>成绩记录</span><strong>仅保存在本地</strong><small>该小游戏不会上传全服排行榜</small></div></div>`;
    return `<div class="ptg-panel"><div class="ptg-game-shell">
      <div class="ptg-game-top"><button data-action="game-exit">${running || paused ? '结束' : '退出'}</button><h4>${escapeHtml(definition.name)}</h4><span class="ptg-chip">最高 ${highScore}</span></div>
      <div class="ptg-game-scorebar"><div class="ptg-game-scorebox">当前分<strong data-runtime-score ${gameId === 'minesweeper' ? 'data-minesweeper-score' : gameId === 'bulletHell' ? 'data-bullethell-score' : gameId === 'kitchen' ? 'data-kitchen-score' : gameId === 'match3' ? 'data-match3-score' : gameId === 'watermelon' ? 'data-watermelon-score' : ''}>${score}</strong></div><div class="ptg-game-scorebox">${escapeHtml(extraLabel)}<strong data-runtime-extra ${gameId === 'bulletHell' ? 'data-bullethell-kills' : gameId === 'kitchen' ? 'data-kitchen-hearts class="hearts"' : gameId === 'match3' ? 'data-match3-cleared' : gameId === 'watermelon' ? 'data-watermelon-max' : ''}>${extraValue}</strong></div><div class="ptg-game-scorebox">${definition.noCoins ? `余心<strong class="hearts">${kitchenHearts(state)}</strong>` : `预计金币<strong data-runtime-coins ${gameId === 'bulletHell' ? 'data-bullethell-coins' : gameId === 'kitchen' ? 'data-kitchen-coins' : gameId === 'match3' ? 'data-match3-coins' : gameId === 'watermelon' ? 'data-watermelon-coins' : ''}>${gameRewardPreview(gameId, score)}</strong>`}</div></div>
      ${finished ? `<div class="ptg-game-result"><span>${escapeHtml(resultTitle)}</span><strong>${score} 分</strong><span>${escapeHtml(state.message || '')}</span><span>${gameId === 'kitchen' ? `获得 ${state.reward || 0} 金币 · 出餐 ${state.served || 0} 次 · 最佳连击 ${state.bestCombo || 0} · 历史最高 ${highScore}` : gameId === 'match3' ? `获得 ${state.reward || 0} 金币 · 消除 ${state.cleared || 0} 格 · 最长连锁 ${state.bestCombo || 0} · 历史最高 ${highScore}` : gameId === 'watermelon' ? `获得 ${state.reward || 0} 金币 · 合成 ${state.mergeCount || 0} 次 · 最大 ${WATERMELON_FRUITS[Math.max(0, Number(state.maxLevel) || 0)]?.name || '樱桃'} · 历史最高 ${highScore}` : gameId === 'petRogue' ? `获得 ${state.reward || 0} 金币 · Lv.${Math.max(1, Number(state.level) || 1)} · 到达第 ${Math.max(1, Number(state.wave) || 1)} 波 · 击破 ${Math.max(0, Number(state.kills) || 0)} 只怪物 · 历史最高 ${highScore}` : definition.noCoins ? `历史最高 ${highScore}` : `获得 ${state.reward || 0} 金币 · 历史最高 ${highScore}`}</span></div>` : ''}
      ${paused ? '<div class="ptg-game-paused">游戏已暂停并保存。切换同一角色卡的聊天档或重新打开酒馆后仍可继续。</div>' : ''}
      ${running || paused ? board : `<div class="ptg-game-menu">${gameIconSvg(gameId)}<p>${escapeHtml(definition.description)}</p>${setup}<p>历史最高分：<strong>${highScore}</strong></p>${rankCard}<div class="ptg-game-menu-actions"><button data-action="game-exit">退出</button><button class="ptg-game-start" data-action="game-start-${gameId}">${finished ? '再来一局' : '开始游戏'}</button></div></div>`}
      ${paused ? '<div class="ptg-game-menu-actions"><button data-action="game-exit">结束并结算</button><button class="ptg-game-start" data-action="game-resume">继续游戏</button></div>' : ''}
      ${running ? '<div class="ptg-game-menu-actions"><button data-action="game-pause">暂停</button><button data-action="game-exit">结束并结算</button></div>' : ''}
      ${!definition.noCoins && app.save.economy.gameCoinsToday >= CONFIG.maxGameCoinsPerDay ? '<div class="ptg-game-cap">今日金币已满，本局仍会记录最高分，但结算金币为 0。</div>' : ''}
    </div></div>`;
  }

  function renderGames() {
    if (app.games.managerOpen) return renderGameManager();
    if (app.games.selected) return renderSelectedGame(app.games.selected);
    return renderGameGallery();
  }

  function leaderboardProfile() {
    if (!app.save) return null;
    if (!app.save.leaderboard || typeof app.save.leaderboard !== 'object') app.save.leaderboard = createLeaderboardProfile();
    const profile = app.save.leaderboard;
    if (!validLeaderboardPlayerId(profile.playerId)) profile.playerId = createLeaderboardPlayerId();
    profile.nickname = [...String(profile.nickname || '').trim()].slice(0, 20).join('');
    if (!profile.uploadedHighScores || typeof profile.uploadedHighScores !== 'object') profile.uploadedHighScores = {};
    if (!profile.uploadedNicknames || typeof profile.uploadedNicknames !== 'object') profile.uploadedNicknames = {};
    if (!profile.uploadedShowcaseSignatures || typeof profile.uploadedShowcaseSignatures !== 'object') profile.uploadedShowcaseSignatures = {};
    if (!profile.snapshots || typeof profile.snapshots !== 'object') profile.snapshots = {};
    profile.cosmetics = normalizeGachaState(profile.cosmetics);
    profile.serverHighScoreRestore = normalizeLeaderboardServerHighScoreRestore(profile.serverHighScoreRestore);
    Object.keys(GAME_DEFS).forEach((gameId) => {
      profile.uploadedHighScores[gameId] = Math.max(0, Math.floor(Number(profile.uploadedHighScores[gameId]) || 0));
      profile.uploadedNicknames[gameId] = [...String(profile.uploadedNicknames[gameId] || '').trim()].slice(0, 20).join('');
      profile.uploadedShowcaseSignatures[gameId] = String(profile.uploadedShowcaseSignatures[gameId] || '');
      profile.snapshots[gameId] = normalizeLeaderboardSnapshot(profile.snapshots[gameId]);
    });
    profile.backendVersion = Math.max(0, Math.floor(Number(profile.backendVersion) || 0)); profile.lastV2AttemptAt = Math.max(0, Number(profile.lastV2AttemptAt) || 0);
    profile.identityBoundAt = Math.max(0, Number(profile.identityBoundAt) || 0);
    profile.identityPreviousPlayerId = validLeaderboardPlayerId(profile.identityPreviousPlayerId) ? String(profile.identityPreviousPlayerId) : '';
    profile.createdAt = Math.max(0, Number(profile.createdAt) || nowMs()); profile.updatedAt = Math.max(0, Number(profile.updatedAt) || nowMs()); profile.lastSyncedAt = Math.max(0, Number(profile.lastSyncedAt) || 0);
    return profile;
  }

  // ============================================================
  // 排行榜专属装扮发放接口 v1
  // 主脚本仅内置显示定义；限定装扮不会进入扭蛋池或碎片兑换。
  // 额外补丁通过共享总线 grant() 发放，导入顺序前后均可。
  // ============================================================
  function getCosmeticGiftBus() {
    let bus = host[COSMETIC_GIFT_BUS_KEY];
    if (!bus || bus.protocol !== 1) {
      const pending = Array.isArray(bus?.pending) ? bus.pending.slice() : [];
      bus = {
        protocol: 1,
        apiVersion: COSMETIC_GIFT_API_VERSION,
        api: null,
        pending,
        grant(request) {
          if (this.api) return this.api.grantExclusiveCosmetic(request);
          const id = String(request?.id || '');
          const key = String(request?.grantKey || '');
          if (!this.pending.some((entry) => String(entry?.id || '') === id && String(entry?.grantKey || '') === key)) this.pending.push(request);
          return { ok: true, queued: true, message: '像素拓麻歌子尚未就绪，专属装扮发放请求已排队。' };
        },
      };
    }
    host[COSMETIC_GIFT_BUS_KEY] = bus;
    try { window[COSMETIC_GIFT_BUS_KEY] = bus; } catch (_) {}
    return bus;
  }

  const cosmeticGiftBus = getCosmeticGiftBus();

  function queueExclusiveCosmeticGrant(request) {
    const id = String(request?.id || '');
    const key = String(request?.grantKey || '');
    if (!id) return;
    if (!cosmeticGiftBus.pending.some((entry) => String(entry?.id || '') === id && String(entry?.grantKey || '') === key)) cosmeticGiftBus.pending.push(request);
  }

  function grantExclusiveCosmetic(raw) {
    try {
      const id = String(raw?.id || '').trim();
      const grantKey = String(raw?.grantKey || '').trim();
      const reward = GACHA_REWARDS[id];
      if (!reward || !reward.exclusive) throw new Error('该装扮不是可由补丁发放的专属限定。');
      if (!grantKey || grantKey !== String(reward.grantKey || '')) throw new Error('专属装扮发放密钥不匹配。');
      if (!app.save || !app.characterContextReady) {
        queueExclusiveCosmeticGrant({ id, grantKey, source: String(raw?.source || '') });
        return { ok: true, queued: true, id, name: reward.name };
      }
      const profile = leaderboardProfile();
      const previous = Math.max(0, Number(profile.cosmetics.collection[id]) || 0);
      if (previous <= 0) {
        profile.cosmetics.collection[id] = 1;
        profile.cosmetics.updatedAt = nowMs();
        profile.updatedAt = nowMs();
        queueSaveCurrent(40);
        app.message = `已获得专属幻彩套装「${reward.name}」。前往占卜屋 → 扭蛋机 → 佩戴装扮进行预览与保存。`;
        try { notify('success', `获得专属幻彩：${reward.name}`); } catch (_) {}
        if (app.root?.classList.contains('ptg-open')) render();
      }
      return { ok: true, granted: previous <= 0, alreadyOwned: previous > 0, id, name: reward.name };
    } catch (error) {
      console.error('[像素拓麻歌子] 专属装扮发放失败：', error);
      return { ok: false, error: String(error?.message || error) };
    }
  }

  function processPendingExclusiveCosmeticGrants() {
    if (!app.save || !app.characterContextReady || !cosmeticGiftBus.pending.length) return false;
    const queued = cosmeticGiftBus.pending.splice(0);
    const unique = new Map();
    queued.forEach((request) => unique.set(`${String(request?.id || '')}::${String(request?.grantKey || '')}`, request));
    unique.forEach((request) => grantExclusiveCosmetic(request));
    return true;
  }

  const publicCosmeticGiftApi = Object.freeze({
    apiVersion: COSMETIC_GIFT_API_VERSION,
    coreVersion: CORE_VERSION,
    grantExclusiveCosmetic,
    hasCosmetic: (id) => gachaOwnedCount(String(id || '')) > 0,
  });
  cosmeticGiftBus.api = publicCosmeticGiftApi;
  cosmeticGiftBus.apiVersion = COSMETIC_GIFT_API_VERSION;
  host.PixelTamagotchiCosmeticAPI = publicCosmeticGiftApi;
  try { window.PixelTamagotchiCosmeticAPI = publicCosmeticGiftApi; } catch (_) {}
  if (cosmeticGiftBus.pending.length && app.save && app.characterContextReady) processPendingExclusiveCosmeticGrants();

  // ============================================================
  // 一次性奖励礼包接口 v1
  // 奖励定义由主脚本白名单校验，补丁只能领取已登记礼包。
  // 领取标记保存在全局经济存档中，重复导入、开关或刷新不会重复发放。
  // ============================================================
  const REWARD_GIFT_DEFS = Object.freeze({
    coin_gift_888: Object.freeze({
      name: '888 金币礼包',
      amount: 888,
      grantKey: 'ptg-reward-gift-888-coins-2026-v1',
    }),
  });

  function getRewardGiftBus() {
    let bus = host[REWARD_GIFT_BUS_KEY];
    if (!bus || bus.protocol !== 1) {
      const pending = Array.isArray(bus?.pending) ? bus.pending.slice() : [];
      bus = {
        protocol: 1,
        apiVersion: REWARD_GIFT_API_VERSION,
        api: null,
        pending,
        grant(request) {
          if (this.api && typeof this.api.grantRewardGift === 'function') return this.api.grantRewardGift(request);
          const id = String(request?.id || '');
          const key = String(request?.grantKey || '');
          if (!this.pending.some((entry) => String(entry?.id || '') === id && String(entry?.grantKey || '') === key)) this.pending.push(request);
          return { ok: true, queued: true, message: '像素拓麻歌子尚未就绪，金币礼包领取请求已排队。' };
        },
      };
    }
    host[REWARD_GIFT_BUS_KEY] = bus;
    try { window[REWARD_GIFT_BUS_KEY] = bus; } catch (_) {}
    return bus;
  }

  const rewardGiftBus = getRewardGiftBus();

  function queueRewardGiftGrant(request) {
    const id = String(request?.id || '');
    const key = String(request?.grantKey || '');
    if (!id) return;
    if (!rewardGiftBus.pending.some((entry) => String(entry?.id || '') === id && String(entry?.grantKey || '') === key)) rewardGiftBus.pending.push(request);
  }

  function grantRewardGift(raw) {
    try {
      const id = String(raw?.id || '').trim();
      const grantKey = String(raw?.grantKey || '').trim();
      const definition = REWARD_GIFT_DEFS[id];
      if (!definition) throw new Error('该奖励礼包未在主脚本中登记。');
      if (!grantKey || grantKey !== definition.grantKey) throw new Error('奖励礼包发放密钥不匹配。');
      if (!app.save || !app.characterContextReady) {
        queueRewardGiftGrant({ id, grantKey, source: String(raw?.source || '') });
        return { ok: true, queued: true, id, name: definition.name };
      }
      const economy = app.save.economy || (app.save.economy = {});
      const claims = economy.giftClaims && typeof economy.giftClaims === 'object' ? economy.giftClaims : {};
      if (claims[id]) return { ok: true, granted: false, alreadyClaimed: true, id, name: definition.name, amount: definition.amount };

      const amount = Math.max(0, Math.floor(Number(definition.amount) || 0));
      economy.coins = Math.max(0, Math.floor(Number(economy.coins) || 0)) + amount;
      if (!app.save.stats || typeof app.save.stats !== 'object') app.save.stats = {};
      app.save.stats.totalCoinsEarned = Math.max(0, Math.floor(Number(app.save.stats.totalCoinsEarned) || 0)) + amount;
      claims[id] = {
        amount,
        claimedAt: nowMs(),
        source: String(raw?.source || '').slice(0, 120),
      };
      economy.giftClaims = claims;
      app.save.updatedAt = nowMs();
      queueSaveCurrent(30);
      app.message = `已领取「${definition.name}」，金币 +${amount}。`;
      try { notify('success', `礼包领取成功：金币 +${amount}`); } catch (_) {}
      if (app.root?.classList.contains('ptg-open')) render();
      return { ok: true, granted: true, alreadyClaimed: false, id, name: definition.name, amount };
    } catch (error) {
      console.error('[像素拓麻歌子] 奖励礼包发放失败：', error);
      return { ok: false, error: String(error?.message || error) };
    }
  }

  function processPendingRewardGiftGrants() {
    if (!app.save || !app.characterContextReady || !rewardGiftBus.pending.length) return false;
    const queued = rewardGiftBus.pending.splice(0);
    const unique = new Map();
    queued.forEach((request) => unique.set(`${String(request?.id || '')}::${String(request?.grantKey || '')}`, request));
    unique.forEach((request) => grantRewardGift(request));
    return true;
  }

  const publicRewardGiftApi = Object.freeze({
    apiVersion: REWARD_GIFT_API_VERSION,
    coreVersion: CORE_VERSION,
    grantRewardGift,
    hasClaimed: (id) => Boolean(app.save?.economy?.giftClaims?.[String(id || '')]),
  });
  rewardGiftBus.api = publicRewardGiftApi;
  rewardGiftBus.apiVersion = REWARD_GIFT_API_VERSION;
  host.PixelTamagotchiRewardAPI = publicRewardGiftApi;
  try { window.PixelTamagotchiRewardAPI = publicRewardGiftApi; } catch (_) {}
  if (rewardGiftBus.pending.length && app.save && app.characterContextReady) processPendingRewardGiftGrants();

  function leaderboardDefaultIdentity(profile = leaderboardProfile()) {
    const compact = String(profile?.playerId || '').replace(/[^0-9a-f]/gi, '').toLowerCase();
    if (compact.length < 12) return 'PTG-ANON00000000';
    return `PTG-${compact.slice(0, 8)}${compact.slice(-4)}`;
  }

  function leaderboardSubmissionNickname(profile = leaderboardProfile()) {
    const custom = [...String(profile?.nickname || '').trim()].slice(0, 20).join('');
    return custom || leaderboardDefaultIdentity(profile);
  }

  function leaderboardDisplayName(value) {
    const text = String(value || '').trim();
    const compactId = text.match(/^PTG-([0-9a-f]{8})([0-9a-f]{4})$/i);
    if (compactId) return `PTG-${compactId[1].slice(0, 4)}****${compactId[2]}`;
    const uuid = text.match(/^([0-9a-f]{4})[0-9a-f-]+([0-9a-f]{4})$/i);
    if (uuid && text.includes('-')) return `ID-${uuid[1]}****${uuid[2]}`;
    return text;
  }

  function leaderboardDisplayNickname(profile = leaderboardProfile()) {
    return leaderboardDisplayName(leaderboardSubmissionNickname(profile));
  }

  function leaderboardOwnRankText(cache) {
    const rank = Math.max(0, Math.floor(Number(cache?.own?.rank) || 0));
    return rank > 0 && rank <= LEADERBOARD_LIMIT ? `第 ${rank} 名` : `${LEADERBOARD_LIMIT}+`;
  }

  function leaderboardRemoteGameId(gameId) {
    return String(gameId || '').trim().toLowerCase();
  }

  function leaderboardCacheFor(gameId) {
    if (!app.leaderboard.cache[gameId]) {
      const profile = leaderboardProfile();
      const snapshot = normalizeLeaderboardSnapshot(profile?.snapshots?.[gameId]);
      const mergeOptions = leaderboardMergeOptionsForProfile(profile, gameId, snapshot.own ? [snapshot.own] : []);
      const snapshotRows = mergeLeaderboardRows([snapshot.rows], LEADERBOARD_LIMIT, mergeOptions);
      const snapshotOwnRows = mergeLeaderboardRows([snapshot.own ? [snapshot.own] : []], 1, mergeOptions);
      const hasSnapshot = snapshot.fetchedAt > 0;
      app.leaderboard.cache[gameId] = {
        status: hasSnapshot ? 'ready' : 'idle',
        rows: deepClone(snapshotRows),
        own: snapshotOwnRows[0] ? deepClone(snapshotOwnRows[0]) : null,
        error: '',
        uploadError: '',
        fetchedAt: snapshot.fetchedAt,
        refreshing: false,
        authorization: {
          status: 'unknown',
          approved: false,
          displayName: '',
          authorName: '',
          notes: '',
          maxScore: null,
          fetchedAt: 0,
          error: '',
        },
        authorizationPromise: null,
      };
    }
    return app.leaderboard.cache[gameId];
  }

  function persistLeaderboardSnapshot(gameId, cache = leaderboardCacheFor(gameId)) {
    const profile = leaderboardProfile();
    if (!profile || !GAME_DEFS[gameId]) return false;
    if (!profile.snapshots || typeof profile.snapshots !== 'object') profile.snapshots = {};
    const previous = normalizeLeaderboardSnapshot(profile.snapshots[gameId]);
    const next = normalizeLeaderboardSnapshot({
      rows: cache?.rows,
      own: cache?.own,
      fetchedAt: cache?.fetchedAt,
    });
    if (leaderboardSnapshotSignature(previous) === leaderboardSnapshotSignature(next)) return false;
    profile.snapshots[gameId] = next;
    profile.updatedAt = nowMs();
    saveCurrent();
    return true;
  }

  function leaderboardShouldRender() {
    const gameId = app.games.selected;
    const state = gameState(gameId);
    return Boolean(
      app.root?.classList.contains('ptg-open')
      && app.activeTab === 'games'
      && gameId
      && state
      && !['running', 'paused'].includes(state.status)
    );
  }

  function renderLeaderboardIfVisible() {
    if (leaderboardShouldRender()) render();
  }

  async function leaderboardFetchJson(url, body) {
    const Controller = host.AbortController || globalThis.AbortController;
    const controller = Controller ? new Controller() : null;
    const timeoutId = controller
      ? host.setTimeout(() => controller.abort(), LEADERBOARD_REQUEST_TIMEOUT_MS)
      : null;
    try {
      const fetchFn = typeof host.fetch === 'function'
        ? host.fetch.bind(host)
        : globalThis.fetch.bind(globalThis);
      const response = await fetchFn(url, {
        method: 'POST',
        headers: {
          apikey: LEADERBOARD_PUBLISHABLE_KEY,
          'Content-Type': 'application/json',
          Accept: 'application/json',
        },
        body: JSON.stringify(body || {}),
        ...(controller ? { signal: controller.signal } : {}),
      });
      let payload = null;
      try { payload = await response.json(); } catch (_) {}
      if (!response.ok) {
        const detail = payload?.error || payload?.message || payload?.hint || `${response.status} ${response.statusText}`;
        throw new Error(String(detail || '排行榜请求失败'));
      }
      return payload;
    } catch (error) {
      if (error?.name === 'AbortError') throw new Error('排行榜连接超时，请检查网络或代理。');
      throw error;
    } finally {
      if (timeoutId !== null) host.clearTimeout(timeoutId);
    }
  }

  function normalizeLeaderboardGameAuthorization(payload, gameId) {
    const row = Array.isArray(payload) ? payload[0] : payload;
    const status = String(row?.status || 'unregistered').trim().toLowerCase();
    return {
      gameId: leaderboardRemoteGameId(row?.game_id || gameId),
      status: ['approved', 'pending', 'revoked', 'unregistered'].includes(status) ? status : 'unregistered',
      approved: row?.approved === true || status === 'approved',
      displayName: String(row?.display_name || '').trim(),
      authorName: String(row?.author_name || '').trim(),
      notes: String(row?.notes || '').trim(),
      maxScore: Number.isFinite(Number(row?.max_score)) ? Math.max(0, Math.floor(Number(row.max_score))) : null,
      fetchedAt: nowMs(),
      error: '',
    };
  }

  function leaderboardAuthorizationMessage(auth) {
    const status = String(auth?.status || 'unknown');
    if (status === 'approved') return '社区排行榜已授权';
    if (status === 'pending') return '全服榜正在等待管理员审核';
    if (status === 'revoked') return '全服榜授权已被撤销';
    if (status === 'unregistered') return '该小游戏尚未获得全服榜授权';
    if (auth?.error) return '暂时无法确认全服榜授权';
    return '正在确认全服榜授权';
  }

  function leaderboardAuthorizationFromError(message, gameId) {
    const text = String(message || '').toUpperCase();
    let status = '';
    if (text.includes('GAME_PENDING')) status = 'pending';
    else if (text.includes('GAME_AUTHORIZATION_REVOKED') || text.includes('GAME_REVOKED')) status = 'revoked';
    else if (text.includes('GAME_NOT_REGISTERED') || text.includes('GAME_NOT_APPROVED')) status = 'unregistered';
    if (!status) return null;
    return {
      gameId: leaderboardRemoteGameId(gameId),
      status,
      approved: false,
      displayName: '',
      authorName: '',
      notes: '',
      maxScore: null,
      fetchedAt: nowMs(),
      error: '',
    };
  }

  async function getLeaderboardGameAuthorization(gameId, force = false) {
    const cache = leaderboardCacheFor(gameId);
    if (GAME_DEFS[gameId]?.leaderboard === false) {
      cache.authorization = {
        gameId: leaderboardRemoteGameId(gameId),
        status: 'disabled',
        approved: false,
        displayName: '',
        authorName: '',
        notes: '',
        maxScore: null,
        fetchedAt: nowMs(),
        error: '',
      };
      return cache.authorization;
    }

    const current = cache.authorization || {};
    if (!force && Number(current.fetchedAt || 0) > 0 && nowMs() - Number(current.fetchedAt || 0) < LEADERBOARD_AUTH_CACHE_MS) return current;
    if (cache.authorizationPromise) return cache.authorizationPromise;

    cache.authorizationPromise = (async () => {
      try {
        const payload = await leaderboardFetchJson(LEADERBOARD_GAME_STATUS_RPC_URL, {
          p_game_id: leaderboardRemoteGameId(gameId),
        });
        cache.authorization = normalizeLeaderboardGameAuthorization(payload, gameId);
      } catch (error) {
        cache.authorization = {
          ...current,
          gameId: leaderboardRemoteGameId(gameId),
          status: 'unknown',
          approved: false,
          fetchedAt: nowMs(),
          error: String(error?.message || error || '授权状态读取失败'),
        };
      } finally {
        cache.authorizationPromise = null;
      }
      renderLeaderboardIfVisible();
      return cache.authorization;
    })();

    return cache.authorizationPromise;
  }

  function leaderboardRestorePlayerIds(profile) {
    return [...new Set([
      profile?.playerId,
      profile?.identityPreviousPlayerId,
      ...(Array.isArray(profile?.legacyPlayerIds) ? profile.legacyPlayerIds : []),
    ].map((value) => String(value || '').trim().toLowerCase())
      .filter((value) => validLeaderboardPlayerId(value)))]
      .slice(0, 10);
  }

  function leaderboardOwnedScoreFromPayload(payload) {
    const rows = Array.isArray(payload) ? payload : (payload && typeof payload === 'object' ? [payload] : []);
    return rows.reduce((highest, row) => Math.max(
      highest,
      Math.max(0, Math.floor(Number(row?.score ?? row?.high_score ?? row?.highScore) || 0)),
    ), 0);
  }

  async function readOwnedLeaderboardScoreV2(gameId, profile) {
    const playerIds = leaderboardRestorePlayerIds(profile);
    if (!playerIds.length) return { ok: true, score: 0, playerIds: [] };
    const remoteGameId = leaderboardRemoteGameId(gameId);
    const requests = await Promise.allSettled(playerIds.map((playerId) => leaderboardFetchJson(
      LEADERBOARD_RANK_V2_RPC_URL,
      { p_game_id: remoteGameId, p_player_id: playerId },
    )));
    const fulfilled = requests.filter((result) => result.status === 'fulfilled');
    if (!fulfilled.length) {
      const reason = requests.find((result) => result.status === 'rejected')?.reason;
      throw reason instanceof Error ? reason : new Error(String(reason || '排行榜个人成绩读取失败'));
    }
    return {
      ok: true,
      score: fulfilled.reduce((highest, result) => Math.max(highest, leaderboardOwnedScoreFromPayload(result.value)), 0),
      playerIds,
    };
  }

  async function restoreLocalHighScoresFromLeaderboardOnce(force = false) {
    if (!app.characterContextReady || !app.save) return false;
    if (app.leaderboard.scoreRestorePromise) return app.leaderboard.scoreRestorePromise;

    const profile = leaderboardProfile();
    if (!profile) return false;
    const restoreState = normalizeLeaderboardServerHighScoreRestore(profile.serverHighScoreRestore);
    profile.serverHighScoreRestore = restoreState;
    if (restoreState.disabled && !force) return false;

    const completed = new Set(force ? [] : restoreState.completedGameIds);
    const targets = Object.keys(GAME_DEFS).filter((gameId) => (
      GAME_DEFS[gameId]?.leaderboard !== false
      && (force || !completed.has(gameId))
    ));
    if (!targets.length) return false;

    app.leaderboard.scoreRestorePromise = (async () => {
      restoreState.lastAttemptAt = nowMs();
      let restoredCount = 0;
      let completedCount = 0;
      let changed = false;

      const results = await Promise.allSettled(targets.map(async (gameId) => {
        const authorization = await getLeaderboardGameAuthorization(gameId);
        // 未登记、待审核或被撤销的社区游戏不能读取全服榜；保留为未完成，授权后会自动补读一次。
        if (!authorization?.approved) return { gameId, skipped: true };
        const result = await readOwnedLeaderboardScoreV2(gameId, profile);
        return { gameId, skipped: false, score: Math.max(0, Math.floor(Number(result.score) || 0)) };
      }));

      results.forEach((result, index) => {
        const gameId = targets[index];
        if (result.status !== 'fulfilled') {
          console.warn(`[像素拓麻歌子] ${GAME_DEFS[gameId]?.name || gameId}从全服榜恢复本地最高分失败：`, result.reason);
          return;
        }
        const value = result.value || {};
        if (value.skipped) return;
        const serverScore = Math.max(0, Math.floor(Number(value.score) || 0));
        const localScore = Math.max(0, Math.floor(Number(app.save?.gameRecords?.highScores?.[gameId]) || 0));
        if (!app.save.gameRecords || typeof app.save.gameRecords !== 'object') app.save.gameRecords = { highScores: {}, suspended: null };
        if (!app.save.gameRecords.highScores || typeof app.save.gameRecords.highScores !== 'object') app.save.gameRecords.highScores = {};
        if (serverScore > localScore) {
          app.save.gameRecords.highScores[gameId] = serverScore;
          restoredCount += 1;
          changed = true;
        }
        profile.uploadedHighScores[gameId] = Math.max(
          Math.max(0, Math.floor(Number(profile.uploadedHighScores?.[gameId]) || 0)),
          serverScore,
        );
        restoreState.restoredScores[gameId] = serverScore;
        completed.add(gameId);
        completedCount += 1;
      });

      restoreState.completedGameIds = [...completed];
      const remainingApprovedTargets = Object.keys(GAME_DEFS).filter((gameId) => (
        GAME_DEFS[gameId]?.leaderboard !== false
        && !completed.has(gameId)
        && leaderboardCacheFor(gameId).authorization?.approved
      ));
      if (!remainingApprovedTargets.length) restoreState.completedAt = nowMs();
      profile.serverHighScoreRestore = restoreState;
      profile.updatedAt = nowMs();

      if (changed || completedCount > 0) {
        saveCurrent();
        if (restoredCount > 0) {
          app.message = `已从新版全服排行榜恢复 ${restoredCount} 项本地最高分。`;
          try { notify('success', `已恢复 ${restoredCount} 项小游戏最高分`); } catch (_) {}
          if (app.root?.classList.contains('ptg-open')) render();
        }
      }
      return restoredCount > 0;
    })().finally(() => {
      app.leaderboard.scoreRestorePromise = null;
    });

    return app.leaderboard.scoreRestorePromise;
  }

  async function syncLeaderboardScore(gameId) {
    const profile = leaderboardProfile();
    if (!profile || GAME_DEFS[gameId]?.leaderboard === false) return false;
    const localScore = Math.max(0, Math.floor(Number(app.save?.gameRecords?.highScores?.[gameId]) || 0));
    const uploaded = Math.max(0, Math.floor(Number(profile.uploadedHighScores?.[gameId]) || 0));
    const score = Math.max(localScore, uploaded, leaderboardKnownScore(profile, gameId));
    if (score <= 0) return false;
    const submissionNickname = leaderboardSubmissionNickname(profile);
    const uploadedNickname = String(profile.uploadedNicknames?.[gameId] || '');
    const showcaseSignature = gachaShowcaseSignature(profile);
    const uploadedShowcase = String(profile.uploadedShowcaseSignatures?.[gameId] || '');
    const v2ProbeDue = profile.backendVersion < 2 && nowMs() - Number(profile.lastV2AttemptAt || 0) >= 6 * 60 * 60 * 1000;
    const scoreNeedsSync = localScore > uploaded || v2ProbeDue;
    const nicknameNeedsSync = uploadedNickname !== submissionNickname;
    const showcaseNeedsSync = uploadedShowcase !== showcaseSignature;
    if (!scoreNeedsSync && !nicknameNeedsSync && !showcaseNeedsSync) return false;

    const cache = leaderboardCacheFor(gameId);
    const authorization = await getLeaderboardGameAuthorization(gameId);
    if (!authorization?.approved) {
      delete app.leaderboard.uploadErrors[gameId];
      cache.uploadError = '';
      return false;
    }

    if (app.leaderboard.uploading.has(gameId)) return false;
    app.leaderboard.uploading.add(gameId);
    delete app.leaderboard.uploadErrors[gameId];
    cache.uploadError = '';
    renderLeaderboardIfVisible();
    let synced = false;

    try {
      profile.lastV2AttemptAt = nowMs();
      const payload = await leaderboardFetchJson(LEADERBOARD_SUBMIT_V2_RPC_URL, {
        p_player_id: profile.playerId,
        p_nickname: submissionNickname,
        p_game_id: leaderboardRemoteGameId(gameId),
        p_score: score,
        p_client_version: CORE_VERSION,
        p_showcase: gachaPublicShowcase(profile),
      });
      const result = Array.isArray(payload) ? payload[0] : payload;
      if (!result || result.ok !== true) throw new Error(result?.error || '排行榜没有确认本次成绩');
      const serverScore = Math.max(0, Math.floor(Number(result.score) || 0));
      profile.uploadedHighScores[gameId] = Math.max(localScore, uploaded, score, serverScore);
      profile.uploadedNicknames[gameId] = submissionNickname;
      profile.uploadedShowcaseSignatures[gameId] = showcaseSignature;
      profile.backendVersion = 2;
      cache.supportsShowcase = true;
      profile.lastSyncedAt = nowMs();
      profile.updatedAt = nowMs();
      delete app.leaderboard.uploadErrors[gameId];
      cache.uploadError = '';
      saveCurrent();
      synced = true;
    } catch (error) {
      const message = String(error?.message || error || '同步失败');
      const denied = leaderboardAuthorizationFromError(message, gameId);
      if (denied) {
        cache.authorization = denied;
        delete app.leaderboard.uploadErrors[gameId];
        cache.uploadError = '';
      } else {
        console.warn(`[像素拓麻歌子] ${GAME_DEFS[gameId]?.name || gameId}最高分同步失败：`, error);
        app.leaderboard.uploadErrors[gameId] = message;
        cache.uploadError = message;
      }
    } finally {
      app.leaderboard.uploading.delete(gameId);
      renderLeaderboardIfVisible();
      const newest = Math.max(0, Math.floor(Number(app.save?.gameRecords?.highScores?.[gameId]) || 0));
      const newestUploaded = Math.max(0, Math.floor(Number(profile.uploadedHighScores?.[gameId]) || 0));
      if (cache.authorization?.approved && newest > newestUploaded && newest > score) {
        host.setTimeout(() => { void syncLeaderboardScore(gameId); }, 80);
      }
    }
    return synced;
  }

  async function syncAllPendingLeaderboardScores() {
    const profile = leaderboardProfile();
    if (!profile) return { attempted: 0, synced: 0 };
    const showcaseSignature = gachaShowcaseSignature(profile);
    const submissionNickname = leaderboardSubmissionNickname(profile);
    const targets = leaderboardKnownGameIds(profile).filter((gameId) => {
      const score = leaderboardKnownScore(profile, gameId);
      const uploaded = Math.max(0, Math.floor(Number(profile.uploadedHighScores?.[gameId]) || 0));
      const nicknameChanged = String(profile.uploadedNicknames?.[gameId] || '') !== submissionNickname;
      const showcaseChanged = String(profile.uploadedShowcaseSignatures?.[gameId] || '') !== showcaseSignature;
      const v2ProbeDue = profile.backendVersion < 2 && nowMs() - Number(profile.lastV2AttemptAt || 0) >= 6 * 60 * 60 * 1000;
      return score > 0 && (score > uploaded || nicknameChanged || showcaseChanged || v2ProbeDue);
    });
    const results = await Promise.allSettled(targets.map((gameId) => syncLeaderboardScore(gameId)));
    return {
      attempted: targets.length,
      synced: results.filter((result) => result.status === 'fulfilled' && result.value === true).length,
    };
  }

  function scheduleLeaderboardSync(delay = 500) {
    if (app.leaderboard.syncTimer) host.clearTimeout(app.leaderboard.syncTimer);
    app.leaderboard.syncTimer = host.setTimeout(() => {
      app.leaderboard.syncTimer = null;
      if (!app.characterContextReady || !leaderboardProfile()) return;
      void syncAllPendingLeaderboardScores();
    }, Math.max(0, Number(delay) || 0));
  }

  function resetLeaderboardRuntime() {
    app.games.gachaDraftEquipped = null;
    app.games.gachaDraftTouched = false;
    if (app.leaderboard.syncTimer) {
      host.clearTimeout(app.leaderboard.syncTimer);
      app.leaderboard.syncTimer = null;
    }
    app.leaderboard.requestToken += 1;
    app.leaderboard.cache = {};
    app.leaderboard.uploadErrors = {};
    app.leaderboard.uploading.clear();
    app.leaderboard.scoreRestorePromise = null;
  }

function normalizeLeaderboardRows(payload, source = '') {
    const normalizedSource = source === 'v2' || source === 'legacy' ? source : '';
    return (Array.isArray(payload) ? payload : []).map((row) => {
      const rawPlayerId = row?.player_id ?? row?.playerId ?? row?.player_uuid ?? row?.playerUuid ?? '';
      const playerId = validLeaderboardPlayerId(rawPlayerId) ? String(rawPlayerId).toLowerCase() : '';
      return {
        rank: Math.max(1, Math.floor(Number(row?.rank) || 0)),
        playerId,
        nickname: String(row?.nickname || '').slice(0, 60),
        score: Math.max(0, Math.floor(Number(row?.score) || 0)),
        updatedAt: String(row?.updated_at ?? row?.updatedAt ?? ''),
        showcase: normalizePublicShowcase(row?.showcase),
        source: normalizedSource || (row?.source === 'v2' || row?.source === 'legacy' ? row.source : ''),
      };
    }).filter((row) => row.rank > 0 && row.nickname).slice(0, LEADERBOARD_LIMIT);
  }

  function leaderboardShowcaseHasContent(showcase) {
    const equipped = normalizePublicShowcase(showcase).equipped;
    return Boolean(equipped.badge || equipped.title || equipped.frame || equipped.gradient);
  }

  function leaderboardNicknameKey(value) {
    return String(value || '')
      .normalize?.('NFKC')
      .replace(/[\u200B-\u200D\uFEFF]/g, '')
      .replace(/\s+/g, ' ')
      .trim()
      .toLowerCase() || String(value || '').replace(/\s+/g, ' ').trim().toLowerCase();
  }

function leaderboardRowKey(row, aliasMap = null) {
    const playerId = validLeaderboardPlayerId(row?.playerId) ? String(row.playerId).toLowerCase() : '';
    const aliasTarget = playerId && aliasMap?.get(playerId) ? String(aliasMap.get(playerId)).toLowerCase() : '';
    const canonicalId = aliasTarget || playerId;
    return canonicalId ? `id:${canonicalId}` : '';
  }

  function leaderboardKnownScore(profile, gameId, extraRows = []) {
    const values = [
      app.save?.gameRecords?.highScores?.[gameId],
      profile?.uploadedHighScores?.[gameId],
      profile?.snapshots?.[gameId]?.own?.score,
      ...(Array.isArray(extraRows) ? extraRows.map((row) => row?.score) : []),
    ];
    return values.reduce((highest, value) => Math.max(highest, Math.max(0, Math.floor(Number(value) || 0))), 0);
  }

  function leaderboardKnownGameIds(profile = leaderboardProfile()) {
    const ids = new Set([
      ...GAME_IDS,
      ...Object.keys(GAME_DEFS),
      ...Object.keys(profile?.uploadedHighScores && typeof profile.uploadedHighScores === 'object' ? profile.uploadedHighScores : {}),
      ...Object.keys(profile?.uploadedNicknames && typeof profile.uploadedNicknames === 'object' ? profile.uploadedNicknames : {}),
      ...Object.keys(profile?.snapshots && typeof profile.snapshots === 'object' ? profile.snapshots : {}),
      ...Object.keys(app.save?.gameRecords?.highScores && typeof app.save.gameRecords.highScores === 'object' ? app.save.gameRecords.highScores : {}),
    ].map(canonicalStoredGameId));
    return [...ids].filter((gameId) => (
      /^[A-Za-z0-9_-]{1,64}$/.test(String(gameId || ''))
      && GAME_DEFS[gameId]?.leaderboard !== false
      && leaderboardKnownScore(profile, gameId) > 0
    ));
  }

  function leaderboardMergeOptionsForProfile(profile, gameId, extraRows = []) {
    const aliases = new Set([
      ...(Array.isArray(profile?.nicknameAliases) ? profile.nicknameAliases : []),
      ...Object.values(profile?.uploadedNicknames && typeof profile.uploadedNicknames === 'object' ? profile.uploadedNicknames : {}),
    ].map((value) => leaderboardNicknameKey(value)).filter(Boolean));
    const canonicalScore = leaderboardKnownScore(profile, gameId, extraRows);
    const extraScores = (Array.isArray(extraRows) ? extraRows : [])
      .map((row) => Math.max(0, Math.floor(Number(row?.score) || 0)))
      .filter((score) => score > 0);
    return {
      canonicalPlayerId: profile?.playerId,
      identityAliases: profile?.legacyPlayerIds,
      canonicalNickname: leaderboardSubmissionNickname(profile),
      nicknameAliases: [...aliases],
      canonicalScores: [...new Set([canonicalScore, ...extraScores].filter((score) => score > 0))],
    };
  }

function leaderboardRowCompare(a, b) {
    const scoreDiff = Math.max(0, Number(b?.score) || 0) - Math.max(0, Number(a?.score) || 0);
    if (scoreDiff) return scoreDiff;
    const aTime = Date.parse(String(a?.updatedAt || '')) || Number.MAX_SAFE_INTEGER;
    const bTime = Date.parse(String(b?.updatedAt || '')) || Number.MAX_SAFE_INTEGER;
    if (aTime !== bTime) return aTime - bTime;
    const aKey = validLeaderboardPlayerId(a?.playerId) ? String(a.playerId).toLowerCase() : `${leaderboardNicknameKey(a?.nickname)}:${a?.rank || 0}`;
    const bKey = validLeaderboardPlayerId(b?.playerId) ? String(b.playerId).toLowerCase() : `${leaderboardNicknameKey(b?.nickname)}:${b?.rank || 0}`;
    return aKey.localeCompare(bKey);
  }

function leaderboardRowUpdatedMs(row) {
    const parsed = Date.parse(String(row?.updatedAt || ''));
    return Number.isFinite(parsed) ? parsed : 0;
  }

  function leaderboardLatestRow(a, b) {
    const aTime = leaderboardRowUpdatedMs(a);
    const bTime = leaderboardRowUpdatedMs(b);
    if (aTime !== bTime) return bTime > aTime ? b : a;
    if (a?.source !== b?.source) {
      if (b?.source === 'v2') return b;
      if (a?.source === 'v2') return a;
    }
    return b;
  }

  function leaderboardMergePair(previous, row, canonicalPlayerId = '') {
    const latest = leaderboardLatestRow(previous, row);
    const older = latest === row ? previous : row;
    const latestShowcase = normalizePublicShowcase(latest?.showcase);
    const olderShowcase = normalizePublicShowcase(older?.showcase);
    const showcase = leaderboardShowcaseHasContent(latestShowcase)
      || latestShowcase.identityAliases.length >= olderShowcase.identityAliases.length
      ? latestShowcase
      : olderShowcase;
    return {
      ...latest,
      playerId: (canonicalPlayerId || latest.playerId || older.playerId || '').toLowerCase(),
      nickname: String(latest.nickname || older.nickname || '').slice(0, 60),
      // 排行榜仍保留历史最高分，但昵称、装扮和更新时间使用最新记录。
      score: Math.max(Number(previous.score) || 0, Number(row.score) || 0),
      showcase,
      updatedAt: latest.updatedAt || older.updatedAt || '',
      source: previous.source === row.source ? previous.source : 'mixed',
    };
  }

function mergeLeaderboardRows(groups, limit = LEADERBOARD_LIMIT, options = {}) {
    const rows = [];
    (Array.isArray(groups) ? groups : []).forEach((group) => {
      (Array.isArray(group) ? group : []).forEach((row) => rows.push({
        ...row,
        playerId: validLeaderboardPlayerId(row?.playerId) ? String(row.playerId).toLowerCase() : '',
        showcase: normalizePublicShowcase(row?.showcase),
      }));
    });

    const aliasMap = new Map();
    rows.forEach((row) => {
      if (!validLeaderboardPlayerId(row?.playerId)) return;
      const canonical = String(row.playerId).toLowerCase();
      normalizePublicShowcase(row?.showcase).identityAliases.forEach((aliasId) => {
        const alias = validLeaderboardPlayerId(aliasId) ? String(aliasId).toLowerCase() : '';
        if (alias && alias !== canonical) aliasMap.set(alias, canonical);
      });
    });
    const canonicalPlayerId = validLeaderboardPlayerId(options?.canonicalPlayerId)
      ? String(options.canonicalPlayerId).toLowerCase()
      : '';
    (Array.isArray(options?.identityAliases) ? options.identityAliases : []).forEach((aliasId) => {
      const alias = validLeaderboardPlayerId(aliasId) ? String(aliasId).toLowerCase() : '';
      if (canonicalPlayerId && alias && alias !== canonicalPlayerId) aliasMap.set(alias, canonicalPlayerId);
    });
    const canonicalNickname = String(options?.canonicalNickname || '').slice(0, 60);
    const nicknameAliases = new Set((Array.isArray(options?.nicknameAliases) ? options.nicknameAliases : [])
      .map((value) => leaderboardNicknameKey(value))
      .filter(Boolean));
    const canonicalScores = new Set((Array.isArray(options?.canonicalScores) ? options.canonicalScores : [])
      .map((value) => Math.max(0, Math.floor(Number(value) || 0)))
      .filter((value) => value > 0));

    // 旧 RPC 的部分版本不会返回 player_id。先按跨表同昵称同分数找唯一 ID；
    // 修改昵称后旧 RPC 可能短暂返回旧名称，此时再以“同排名 + 同分数”的唯一记录补回 ID。
    // 对当前玩家还会结合历史昵称和已知最高分收拢旧客户端残留，避免同一个 UUID 显示成两个人。
    const identifiedRows = rows.filter((row) => validLeaderboardPlayerId(row.playerId));
    rows.forEach((row) => {
      if (validLeaderboardPlayerId(row.playerId)) return;
      const nicknameKey = leaderboardNicknameKey(row.nickname);
      const score = Math.max(0, Math.floor(Number(row.score) || 0));
      const crossSource = identifiedRows.filter((candidate) => (
        (candidate.source !== row.source || !candidate.source || !row.source)
        && Math.max(0, Math.floor(Number(candidate.score) || 0)) === score
      ));
      const resolveCandidateIds = (candidates) => [...new Set(candidates.map((candidate) => {
        const id = String(candidate.playerId || '').toLowerCase();
        return aliasMap.get(id) || id;
      }).filter(validLeaderboardPlayerId))];

      const sameNicknameIds = resolveCandidateIds(crossSource.filter((candidate) => (
        leaderboardNicknameKey(candidate.nickname) === nicknameKey
      )));
      if (sameNicknameIds.length === 1) {
        row.playerId = sameNicknameIds[0];
        return;
      }
      if (canonicalPlayerId && sameNicknameIds.includes(canonicalPlayerId)) {
        row.playerId = canonicalPlayerId;
        return;
      }

      const samePositionIds = resolveCandidateIds(crossSource.filter((candidate) => (
        Math.max(1, Math.floor(Number(candidate.rank) || 0)) === Math.max(1, Math.floor(Number(row.rank) || 0))
      )));
      if (samePositionIds.length === 1) {
        row.playerId = samePositionIds[0];
        return;
      }

      if (canonicalPlayerId && canonicalScores.has(score) && nicknameAliases.has(nicknameKey)) {
        const canonicalCandidates = identifiedRows.filter((candidate) => {
          const id = String(candidate.playerId || '').toLowerCase();
          return Math.max(0, Math.floor(Number(candidate.score) || 0)) === score
            && (aliasMap.get(id) || id) === canonicalPlayerId;
        });
        if (canonicalCandidates.length) row.playerId = canonicalPlayerId;
      }
    });

    const merged = new Map();
    rows.forEach((row, index) => {
      const idKey = leaderboardRowKey(row, aliasMap);
      // 没有 ID 且无法唯一对应到另一张表时保持独立，不能仅按昵称合并真正重名的玩家。
      const key = idKey || `anon:${row.source || 'unknown'}:${row.rank || index + 1}:${leaderboardNicknameKey(row.nickname)}:${Math.max(0, Number(row.score) || 0)}`;
      const canonicalId = idKey.startsWith('id:') ? idKey.slice(3) : '';
      const previous = merged.get(key);
      if (!previous) {
        merged.set(key, { ...row, playerId: canonicalId || row.playerId || '' });
        return;
      }
      merged.set(key, leaderboardMergePair(previous, row, canonicalId));
    });

    return [...merged.values()]
      .map((row) => {
        const rowId = validLeaderboardPlayerId(row?.playerId) ? String(row.playerId).toLowerCase() : '';
        const canonicalId = rowId ? (aliasMap.get(rowId) || rowId) : '';
        return canonicalPlayerId && canonicalId === canonicalPlayerId && canonicalNickname
          ? { ...row, playerId: canonicalPlayerId, nickname: canonicalNickname }
          : row;
      })
      .sort(leaderboardRowCompare)
      .slice(0, Math.max(1, Math.floor(Number(limit) || LEADERBOARD_LIMIT)))
      .map((row, index) => ({ ...row, rank: index + 1 }));
  }

  function leaderboardIdentityReferenceScores(profile, gameId, v2Rows = [], legacyRows = []) {
    const currentId = String(profile?.playerId || '');
    const values = [
      app.save?.gameRecords?.highScores?.[gameId],
      profile?.uploadedHighScores?.[gameId],
    ];
    [...(Array.isArray(v2Rows) ? v2Rows : []), ...(Array.isArray(legacyRows) ? legacyRows : [])]
      .filter((row) => row?.playerId === currentId)
      .forEach((row) => values.push(row.score));
    return new Set(values
      .map((value) => Math.max(0, Math.floor(Number(value) || 0)))
      .filter((value) => value > 0));
  }

  function bindLeaderboardIdentityBackToLegacy(profile, gameId, v2Rows, legacyRows) {
    if (!profile || !validLeaderboardPlayerId(profile.playerId) || Number(profile.identityBoundAt) > 0) return null;
    const currentId = String(profile.playerId);
    const nicknameKey = leaderboardNicknameKey(leaderboardSubmissionNickname(profile));
    if (!nicknameKey) return null;
    const allRows = [
      ...(Array.isArray(v2Rows) ? v2Rows : []),
      ...(Array.isArray(legacyRows) ? legacyRows : []),
    ];
    const currentRows = allRows.filter((row) => row?.playerId === currentId);
    if (!currentRows.length) return null;
    const referenceScores = leaderboardIdentityReferenceScores(profile, gameId, v2Rows, legacyRows);
    if (!referenceScores.size) return null;

    const knownAliases = new Set((Array.isArray(profile.legacyPlayerIds) ? profile.legacyPlayerIds : [])
      .filter((value) => validLeaderboardPlayerId(value) && value !== currentId));
    const candidatesById = new Map();
    allRows.forEach((row) => {
      const id = validLeaderboardPlayerId(row?.playerId) ? String(row.playerId) : '';
      if (!id || id === currentId) return;
      if (leaderboardNicknameKey(row.nickname) !== nicknameKey) return;
      const score = Math.max(0, Math.floor(Number(row.score) || 0));
      if (!referenceScores.has(score)) return;
      const old = candidatesById.get(id);
      const candidate = {
        ...row,
        playerId: id,
        knownAlias: knownAliases.has(id),
        legacySource: row.source === 'legacy',
        time: Date.parse(String(row.updatedAt || '')) || Number.MAX_SAFE_INTEGER,
      };
      if (!old || (candidate.legacySource && !old.legacySource) || candidate.time < old.time) candidatesById.set(id, candidate);
    });
    const candidates = [...candidatesById.values()].sort((a, b) => {
      if (a.knownAlias !== b.knownAlias) return a.knownAlias ? -1 : 1;
      if (a.legacySource !== b.legacySource) return a.legacySource ? -1 : 1;
      if (a.time !== b.time) return a.time - b.time;
      return a.playerId.localeCompare(b.playerId);
    });
    if (!candidates.length) return null;

    const canonicalId = candidates[0].playerId;
    const aliases = new Set([
      currentId,
      ...(Array.isArray(profile.legacyPlayerIds) ? profile.legacyPlayerIds : []),
      ...candidates.slice(1).map((row) => row.playerId),
    ]);
    aliases.delete(canonicalId);
    profile.playerId = canonicalId;
    profile.legacyPlayerIds = [...aliases].filter(validLeaderboardPlayerId).slice(0, 8);
    profile.identityPreviousPlayerId = currentId;
    profile.identityBoundAt = nowMs();
    profile.backendVersion = 0;
    profile.lastV2AttemptAt = 0;
    Object.keys(GAME_DEFS).forEach((id) => {
      profile.uploadedHighScores[id] = 0;
      profile.uploadedNicknames[id] = '';
      profile.uploadedShowcaseSignatures[id] = '';
    });
    profile.updatedAt = nowMs();
    saveCurrent();
    app.message = '已将排行榜身份绑定回旧版本记录，之后会继续使用原来的玩家 ID。';
    return { canonicalId, previousId: currentId };
  }

  function learnLegacyLeaderboardAliases(profile, gameId, v2Rows, legacyRows) {
    if (!profile || !validLeaderboardPlayerId(profile.playerId)) return false;
    const currentNickname = leaderboardNicknameKey(leaderboardSubmissionNickname(profile));
    if (!currentNickname) return false;
    const referenceScores = leaderboardIdentityReferenceScores(profile, gameId, v2Rows, legacyRows);
    if (!referenceScores.size) return false;
    const existing = new Set(Array.isArray(profile.legacyPlayerIds) ? profile.legacyPlayerIds : []);
    let changed = false;
    [...(Array.isArray(v2Rows) ? v2Rows : []), ...(Array.isArray(legacyRows) ? legacyRows : [])].forEach((row) => {
      if (!validLeaderboardPlayerId(row?.playerId) || row.playerId === profile.playerId) return;
      if (leaderboardNicknameKey(row.nickname) !== currentNickname) return;
      if (!referenceScores.has(Math.max(0, Math.floor(Number(row.score) || 0)))) return;
      if (!existing.has(row.playerId) && existing.size < 8) {
        existing.add(row.playerId);
        changed = true;
      }
    });
    if (!changed) return false;
    profile.legacyPlayerIds = [...existing];
    profile.updatedAt = nowMs();
    saveCurrent();
    return true;
  }

  async function loadLeaderboard(gameId = app.games.leaderboardGameId, force = false) {
    if (!GAME_DEFS[gameId]) gameId = GAME_IDS[0] || 'match3'; if (GAME_DEFS[gameId]?.leaderboard === false) return;
    app.games.leaderboardGameId = gameId; const profile = leaderboardProfile(); const cache = leaderboardCacheFor(gameId); if (!profile || cache.refreshing) return;
    if (!force && cache.status === 'ready' && nowMs() - Number(cache.fetchedAt || 0) < 30000) return;
    const requestToken = ++app.leaderboard.requestToken; const hadSnapshot = cache.status === 'ready' || Number(cache.fetchedAt || 0) > 0; cache.refreshing = true; cache.error = '';
    try {
      const authorization = await getLeaderboardGameAuthorization(gameId, force);
      if (requestToken !== app.leaderboard.requestToken || gameId !== app.games.leaderboardGameId) return;
      if (!authorization?.approved) {
        cache.rows = [];
        cache.own = null;
        cache.status = 'authorization';
        cache.error = '';
        cache.uploadError = '';
        cache.fetchedAt = nowMs();
        return;
      }
      await syncLeaderboardScore(gameId);
      cache.uploadError = String(app.leaderboard.uploadErrors[gameId] || cache.uploadError || '');
      const remoteGameId = leaderboardRemoteGameId(gameId);
      const requests = await Promise.allSettled([
        leaderboardFetchJson(LEADERBOARD_LIST_V2_RPC_URL, { p_game_id: remoteGameId, p_limit: LEADERBOARD_LIMIT }),
        leaderboardFetchJson(LEADERBOARD_RANK_V2_RPC_URL, { p_game_id: remoteGameId, p_player_id: profile.playerId }),
        leaderboardFetchJson(`${LEADERBOARD_RPC_URL}/get_leaderboard`, { p_game_id: remoteGameId, p_limit: LEADERBOARD_LIMIT }),
        leaderboardFetchJson(`${LEADERBOARD_RPC_URL}/get_player_rank`, { p_game_id: remoteGameId, p_player_id: profile.playerId }),
      ]);
      if (requestToken !== app.leaderboard.requestToken || gameId !== app.games.leaderboardGameId) return;

      const [v2RowsResult, v2OwnResult, legacyRowsResult, legacyOwnResult] = requests;
      const v2RowsOk = v2RowsResult.status === 'fulfilled';
      const legacyRowsOk = legacyRowsResult.status === 'fulfilled';
      if (!v2RowsOk && !legacyRowsOk) {
        const reason = v2RowsResult.reason || legacyRowsResult.reason || '新旧排行榜均读取失败';
        throw reason instanceof Error ? reason : new Error(String(reason));
      }

      if (!v2RowsOk) console.debug('[像素拓麻歌子] 装扮排行榜读取失败，仅显示旧排行榜：', v2RowsResult.reason);
      if (!legacyRowsOk) console.debug('[像素拓麻歌子] 旧排行榜读取失败，仅显示装扮排行榜：', legacyRowsResult.reason);

      const v2Rows = v2RowsOk ? normalizeLeaderboardRows(v2RowsResult.value, 'v2') : [];
      const legacyRows = legacyRowsOk ? normalizeLeaderboardRows(legacyRowsResult.value, 'legacy') : [];
      const v2Own = v2OwnResult.status === 'fulfilled' ? normalizeLeaderboardRows(v2OwnResult.value, 'v2') : [];
      const legacyOwn = legacyOwnResult.status === 'fulfilled' ? normalizeLeaderboardRows(legacyOwnResult.value, 'legacy') : [];

      // 两张表使用相同 player_id 时直接合并；旧 RPC 未返回 ID 时，按唯一的同昵称/同分数记录匹配。
      // 昵称刚修改时，再结合相同排名、历史昵称与当前玩家已知分数收拢旧名称，避免客户端重复显示同一玩家。
      const mergeOptions = leaderboardMergeOptionsForProfile(profile, gameId, [
        ...v2Own,
        ...legacyOwn,
        ...v2Rows.filter((row) => row.playerId === String(profile.playerId || '').toLowerCase()),
        ...legacyRows.filter((row) => row.playerId === String(profile.playerId || '').toLowerCase()),
      ]);
      const mergedPool = mergeLeaderboardRows([v2Rows, legacyRows], LEADERBOARD_LIMIT * 2, mergeOptions);
      const nextRows = mergedPool.slice(0, LEADERBOARD_LIMIT).map((row, index) => ({ ...row, rank: index + 1 }));

      const ownCandidates = mergeLeaderboardRows([
        v2Own,
        legacyOwn,
        mergedPool.filter((row) => row.playerId === String(profile.playerId || '').toLowerCase()),
      ], 4, mergeOptions);
      let nextOwn = ownCandidates[0] || null;
      if (nextOwn) {
        const rankPool = mergeLeaderboardRows([v2Rows, legacyRows, [nextOwn]], LEADERBOARD_LIMIT * 2 + 1, mergeOptions);
        const rankedOwn = rankPool.find((row) => row.playerId === String(profile.playerId || '').toLowerCase());
        nextOwn = { ...nextOwn, rank: rankedOwn?.rank || LEADERBOARD_LIMIT + 1 };
      }

      if (JSON.stringify({rows:cache.rows,own:cache.own}) !== JSON.stringify({rows:nextRows,own:nextOwn})) { cache.rows = nextRows; cache.own = nextOwn; }
      cache.supportsShowcase = v2RowsOk || v2OwnResult.status === 'fulfilled'; cache.status = 'ready'; cache.error = ''; cache.uploadError = String(app.leaderboard.uploadErrors[gameId] || cache.uploadError || ''); cache.fetchedAt = nowMs(); persistLeaderboardSnapshot(gameId, cache);
    } catch (error) {
      if (requestToken !== app.leaderboard.requestToken) return; cache.status = hadSnapshot ? 'ready' : 'error'; cache.error = String(error?.message || error || '排行榜读取失败'); console.warn('[像素拓麻歌子] 排行榜读取失败：', error);
    } finally { cache.refreshing = false; if (requestToken === app.leaderboard.requestToken) renderLeaderboardIfVisible(); }
  }

  function defaultLeaderboardNickname() {
    try {
      if (typeof substitudeMacros === 'function') {
        const value = String(substitudeMacros('{{user}}') || '').trim();
        if (value && value !== '{{user}}') return [...value].slice(0, 20).join('');
      }
    } catch (_) {}
    return [...String(SillyTavern?.name1 || '').trim()].slice(0, 20).join('');
  }

  function reconcileLeaderboardCachesForProfile(profile) {
    if (!profile) return;
    Object.entries(app.leaderboard.cache || {}).forEach(([gameId, cache]) => {
      if (!cache || typeof cache !== 'object') return;
      const options = leaderboardMergeOptionsForProfile(profile, gameId, cache.own ? [cache.own] : []);
      cache.rows = mergeLeaderboardRows([cache.rows], LEADERBOARD_LIMIT, options);
      const ownRows = mergeLeaderboardRows([cache.own ? [cache.own] : []], 1, options);
      cache.own = ownRows[0] || null;
    });
    Object.entries(profile.snapshots && typeof profile.snapshots === 'object' ? profile.snapshots : {}).forEach(([gameId, snapshot]) => {
      const normalized = normalizeLeaderboardSnapshot(snapshot);
      const options = leaderboardMergeOptionsForProfile(profile, gameId, normalized.own ? [normalized.own] : []);
      profile.snapshots[gameId] = {
        rows: mergeLeaderboardRows([normalized.rows], LEADERBOARD_LIMIT, options),
        own: mergeLeaderboardRows([normalized.own ? [normalized.own] : []], 1, options)[0] || null,
        fetchedAt: normalized.fetchedAt,
      };
    });
  }

  function setLeaderboardNickname() {
    const profile = leaderboardProfile();
    if (!profile) return;
    const currentCustom = String(profile.nickname || '').trim();
    const previousSubmissionNickname = leaderboardSubmissionNickname(profile);
    const value = host.prompt(
      '设置全服排行榜昵称（1～20个字符，所有小游戏共用）。留空会恢复为匿名玩家 ID：',
      currentCustom || defaultLeaderboardNickname(),
    );
    if (value === null) return;
    const nickname = [...String(value).replace(/[\r\n\t]+/g, ' ').trim()].slice(0, 20).join('');
    profile.nickname = nickname;
    const nextSubmissionNickname = leaderboardSubmissionNickname(profile);
    const aliases = [...new Set([
      ...(Array.isArray(profile.nicknameAliases) ? profile.nicknameAliases : []),
      previousSubmissionNickname,
    ].map((entry) => [...String(entry || '').replace(/[\r\n\t]+/g, ' ').trim()].slice(0, 20).join(''))
      .filter((entry) => entry && leaderboardNicknameKey(entry) !== leaderboardNicknameKey(nextSubmissionNickname)))];
    profile.nicknameAliases = aliases.slice(-12);
    profile.updatedAt = nowMs();
    app.leaderboard.uploadErrors = {};
    reconcileLeaderboardCachesForProfile(profile);
    const targetCount = leaderboardKnownGameIds(profile).length;
    app.message = nickname
      ? `排行榜统一昵称已设置为「${nickname}」，正在同步到 ${targetCount} 个已有成绩的榜单。`
      : `已恢复使用匿名玩家 ID「${leaderboardDisplayNickname(profile)}」，正在同步到 ${targetCount} 个已有成绩的榜单。`;
    saveCurrent();
    render();
    const gameId = app.games.selected || app.games.leaderboardGameId;
    void (async () => {
      await syncAllPendingLeaderboardScores();
      if (GAME_DEFS[gameId]) await loadLeaderboard(gameId, true);
    })();
  }

