    const uploadError = String(cache.uploadError || app.leaderboard.uploadErrors[gameId] || '');
    const own = cache.own;
    const ownRankText = leaderboardOwnRankText(cache);
    const hasSnapshot = cache.status === 'ready' || Number(cache.fetchedAt || 0) > 0;
    let boardHtml = '';
