    else if (!cache.rows.length && uploadError) boardHtml = `<div class="ptg-leaderboard-empty ptg-leaderboard-error"><strong>最高分没有上传成功</strong><span>${escapeHtml(uploadError)}</span><button data-action="leaderboard-refresh">重新同步</button></div>`;
    else if (!cache.rows.length) boardHtml = '<div class="ptg-leaderboard-empty"><strong>这个排行榜还没有成绩</strong><span>刷新非零最高分后，你可能会成为第一名。</span></div>';
    else boardHtml = `<div class="ptg-leaderboard-list">${cache.rows.map((row) => {
