      const badge = gachaEquippedPart('badge',row.showcase), title = gachaEquippedPart('title',row.showcase), frame = gachaEquippedPart('frame',row.showcase); const gradient = gachaHasGradient(row.showcase); const frameArt = frame ? gachaFrameDecorationHtml(frame.id) : '';
      return `<article class="ptg-leaderboard-row ${isOwn?'ptg-own':''} ${frame?'has-frame frame-'+escapeHtml(frame.id):''} ${gradient?'has-holo-name':''}" style="${gachaGradientStyle(row.showcase)}">${frameArt}<span class="ptg-leaderboard-rank">${escapeHtml(leaderboardRankLabel(row.rank))}</span><span class="ptg-leaderboard-badge">${badge?gachaRewardIconHtml(badge.id,'is-rank'):'◇'}</span><span class="ptg-leaderboard-player"><b class="ptg-leaderboard-name">${escapeHtml(leaderboardDisplayName(row.nickname))}${isOwn?'<small>你</small>':''}</b><em class="ptg-leaderboard-player-title">${escapeHtml(title?.name || '尚未佩戴称号')}</em></span><strong>${row.score}</strong></article>`;
    }).join('')}</div>`;
    const ownShowcase = gachaPublicShowcase(profile); const ownBadge=gachaEquippedPart('badge',ownShowcase), ownTitle=gachaEquippedPart('title',ownShowcase), ownFrame=gachaEquippedPart('frame',ownShowcase), ownGradient=gachaEquippedPart('gradient',ownShowcase);
