      <div class="ptg-leaderboard-profile"><span>玩家名称</span><strong>${escapeHtml(leaderboardDisplayNickname(profile))}</strong><button data-action="leaderboard-set-nickname">${profile?.nickname?'修改昵称':'设置昵称'}</button></div>
      <div class="ptg-leaderboard-equipped"><span>徽章：<b>${escapeHtml(ownBadge?.name||'未佩戴')}</b></span><span>称号：<b>${escapeHtml(ownTitle?.name||'未佩戴')}</b></span><span>边框：<b>${escapeHtml(ownFrame?.name||'未佩戴')}</b></span><span>字体：<b>${escapeHtml(ownGradient?.name||'未佩戴')}</b></span></div>
      <div class="ptg-leaderboard-summary"><div><span>本地最高</span><strong>${localHigh}</strong></div><div><span>${authorizationApproved ? '我的名次' : '全服榜状态'}</span><strong>${escapeHtml(authorizationApproved ? ownRankText : leaderboardAuthorizationMessage(authorization))}</strong></div></div>
