  function renderCollection() {
    const save = app.save;
    const cards = [];
    Object.entries(SPECIES).forEach(([speciesId, species]) => {
      const owner = extensionSpeciesOwners.get(speciesId);
      if (owner) {
        const extension = petExtensions.get(owner);
        const visible = extension?.policy?.showInCollectionGlobally || extensionMatchesCharacter(extension);
        if (!visible) return;
      }
      COLOR_VARIANTS[speciesId].forEach((color) => {
        const unlocked = Boolean(save.collection.variants[`${speciesId}:${color.id}`]);
        const frame = species.frames[0];
        cards.push(`<div class="ptg-collection-card ${unlocked ? '' : 'locked'}"><div class="ptg-mini-sprite">${unlocked ? matrixToSvg(frame, `${color.name}${species.name}`, color) : matrixToSvg(frame, '未发现', { primary: '#68716f', secondary: '#68716f', accent: '#68716f' })}</div><div class="ptg-mini-label">${unlocked ? `${escapeHtml(color.name)}<br>${escapeHtml(species.name)}<div class="ptg-species-trait">${escapeHtml(species.trait)}</div>` : '???'}</div></div>`);
      });
    });
    const unlockedCount = Object.keys(save.collection.variants).length;
    return `<div class="ptg-panel"><h3>成长图鉴 · ${unlockedCount}/${cards.length}</h3><div class="ptg-collection-grid">${cards.join('')}</div><div class="ptg-section"><h3>成就</h3>${Object.entries(ACHIEVEMENTS).map(([id, achievement]) => { const unlocked = Boolean(save.achievements[id]); return `<div class="ptg-achievement ${unlocked ? '' : 'locked'}"><div><strong>${unlocked ? '◆' : '◇'} ${escapeHtml(achievement.name)}</strong><small>${escapeHtml(achievement.description)}</small></div><small>${unlocked ? '已完成' : `奖励 ${achievement.reward}`}</small></div>`; }).join('')}</div></div>`;
  }

