  function formatLogTime(at) {
    const date = new Date(Number(at) || 0);
    if (Number.isNaN(date.getTime())) return '';
    const pad = (n) => String(n).padStart(2, '0');
    return `${date.getMonth() + 1}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
  }

  function renderCareLogSection(save) {
    const log = Array.isArray(save.careLog) ? [...save.careLog].reverse() : [];
    const body = log.length
      ? log.map((entry) => {
          const actor = entry.actor === 'char' ? 'char' : 'player';
          return `<div class="ptg-log-row ptg-log-${actor}"><span class="ptg-log-actor">${escapeHtml(entry.actorName || (actor === 'char' ? '角色' : '你'))}</span><div class="ptg-log-body"><div class="ptg-log-line"><span class="ptg-log-text">${escapeHtml(entry.text || '')}</span><span class="ptg-log-time">${escapeHtml(formatLogTime(entry.at))}</span></div>${entry.thought ? `<em class="ptg-log-thought">“${escapeHtml(entry.thought)}”</em>` : ''}</div></div>`;
        }).join('')
      : '<div class="ptg-empty" style="padding:26px 18px">还没有照顾记录。<br>你和角色的喂食、陪玩、日程安排都会记在这里。</div>';
    return `<div class="ptg-section"><div class="ptg-section-title"><h4>照顾事件记录</h4><span class="ptg-chip">${log.length}/${CARE_LOG_LIMIT}</span></div><div class="ptg-log-list">${body}</div></div>`;
