    const save = app.save;
    ensureFortuneHouseDay(save);
    const house = save.fortuneHouse;
    const remaining = Math.max(0, LOTTERY_DAILY_LIMIT - house.ticketsBoughtToday);
    const fortune = fortuneOmen();
    const grade = fortune ? fortuneGradeMeta() : null;
    const shift = Number(grade?.luckShift || 0);
    const luckText = fortune
      ? `今日「${grade.name} · ${fortune.title}」：${shift > 0 ? `中高奖组概率 +${shift} 个百分点` : shift < 0 ? `中高奖组概率 ${shift} 个百分点` : '运势不额外调整奖池'}。`
