  function characterInfoFromCard(characterName, character) {
    const fallbackName = normalizeCharacterName(characterName) || normalizeCharacterName(character?.name || character?.data?.name) || '未命名角色卡';
    const cardName = normalizeCharacterName(character?.name || character?.data?.name) || fallbackName;
    const rawAvatar = character?.avatar || character?.data?.avatar || '';
    const avatar = typeof rawAvatar === 'string' ? rawAvatar : '';
    return {
      name: fallbackName,
      key: avatar ? `avatar:${avatar}` : `name:${cardName}`,
      legacyKey: '',
      rawId: '',
      avatar,
    };
  }

  function characterVariablesFromCard(character, create = false) {
    if (!character || typeof character !== 'object') return null;
    if (create) {
      if (!character.extensions || typeof character.extensions !== 'object') character.extensions = {};
      if (!character.extensions.tavern_helper || typeof character.extensions.tavern_helper !== 'object') character.extensions.tavern_helper = {};
      if (!character.extensions.tavern_helper.variables || typeof character.extensions.tavern_helper.variables !== 'object') character.extensions.tavern_helper.variables = {};
    }
    return character.extensions?.tavern_helper?.variables || null;
  }

  function petMoveCooldownRemaining(pet = app.save?.pet, at = nowMs()) {
    if (!pet) return 0;
    return Math.max(0, PET_MOVE_COOLDOWN_MS - (at - Math.max(0, Number(pet.lastMovedAt) || 0)));
  }

  function formatPetMoveCooldown(milliseconds) {
    const totalMinutes = Math.max(1, Math.ceil(Number(milliseconds || 0) / 60000));
    const days = Math.floor(totalMinutes / 1440);
    const hours = Math.floor((totalMinutes % 1440) / 60);
    const minutes = totalMinutes % 60;
    return [days ? `${days}天` : '', hours ? `${hours}小时` : '', !days && minutes ? `${minutes}分钟` : ''].filter(Boolean).join('');
  }

  function clearActivePetForResidence(save, at = nowMs()) {
    if (!save) return;
    save.lifecycle = 'empty';
    save.pet = null;
    save.egg = null;
    save.events = { current: null, nextAt: at + randomEventDelay(true), lastTouchEventAt: 0, completed: 0, positive: 0, negative: 0, history: [] };
    save.charCare = { history: [] };
    save.careLog = [];
    save.schedule = createEmptySchedule(at);
    if (!save.wardrobe || typeof save.wardrobe !== 'object') save.wardrobe = { owned: {}, equipped: { head: null, eyes: null } };
    save.wardrobe.equipped = { head: null, eyes: null };
  }

  function residenceTransferBundle(save = app.save) {
    return {
      pet: deepClone(save?.pet),
      events: deepClone(save?.events || createDefaultSave().events),
      charCare: deepClone(save?.charCare || { history: [] }),
      careLog: deepClone(Array.isArray(save?.careLog) ? save.careLog : []),
      schedule: deepClone(save?.schedule || createEmptySchedule()),
      equipped: {
        head: save?.wardrobe?.equipped?.head || null,
        eyes: save?.wardrobe?.equipped?.eyes || null,
      },
    };
  }

  function normalizeResidenceCharacterSave(raw) {
    const now = nowMs();
    const base = createDefaultSave();
    const source = raw && typeof raw === 'object' ? raw : {};
    const pet = source.lifecycle === 'alive' ? normalizePet(source.pet) : null;
    const lifecycle = pet ? 'alive' : source.lifecycle === 'egg' ? 'egg' : source.lifecycle === 'dead' ? 'dead' : 'empty';
    return {
      ...base,
      lifecycle,
      pet,
      egg: lifecycle === 'egg' && source.egg && typeof source.egg === 'object' ? deepClone(source.egg) : null,
      cemetery: Array.isArray(source.cemetery) ? deepClone(source.cemetery.slice(-CONFIG.cemeteryLimit)) : [],
      events: { ...base.events, ...(source.events && typeof source.events === 'object' ? deepClone(source.events) : {}) },
      charCare: { history: Array.isArray(source.charCare?.history) ? deepClone(source.charCare.history.slice(-30)) : [] },
      careLog: Array.isArray(source.careLog) ? deepClone(source.careLog.slice(-CARE_LOG_LIMIT)) : [],
      schedule: normalizeSchedule(source.schedule),
      wardrobe: {
        owned: {},
        equipped: {
          head: source.wardrobe?.equipped?.head && ACCESSORY_DEFS[source.wardrobe.equipped.head]?.slot === 'head' ? source.wardrobe.equipped.head : null,
          eyes: source.wardrobe?.equipped?.eyes && ACCESSORY_DEFS[source.wardrobe.equipped.eyes]?.slot === 'eyes' ? source.wardrobe.equipped.eyes : null,
        },
      },
      createdAt: Math.max(0, Number(source.createdAt) || now),
      updatedAt: Math.max(0, Number(source.updatedAt) || now),
    };
  }

  async function readPetResidenceTargets() {
    const currentInfo = getCharacterInfo();
    if (typeof getCharacterNames !== 'function' || typeof getCharacter !== 'function') throw new Error('当前酒馆助手版本不支持读取角色卡列表。');
    const names = [...new Set((getCharacterNames() || []).map((name) => String(name || '').trim()).filter(Boolean))];
    const settled = await Promise.allSettled(names.map(async (name) => {
      const character = await getCharacter(name);
      const info = characterInfoFromCard(name, character);
      if (currentInfo?.key && info.key === currentInfo.key) return null;
      const variables = characterVariablesFromCard(character, false);
      const raw = variables?.[ROOT_KEY] && typeof variables[ROOT_KEY] === 'object' ? variables[ROOT_KEY] : null;
      const normalized = raw ? normalizeResidenceCharacterSave(raw) : null;
      const pet = normalized?.lifecycle === 'alive' ? normalized.pet : null;
      return {
        token: '',
        name,
        key: info.key,
        avatar: info.avatar,
        hasSave: Boolean(raw),
        hasPet: Boolean(pet),
        petName: pet?.name || '',
        petSpecies: pet ? (SPECIES[pet.species]?.name || pet.species || '') : '',
      };
    }));
    return settled
      .filter((item) => item.status === 'fulfilled' && item.value)
      .map((item) => item.value)
      .sort((a, b) => a.name.localeCompare(b.name, 'zh-CN'))
      .map((item, index) => ({ ...item, token: String(index) }));
  }

  async function loadPetResidenceTargets() {
    const state = app.petResidence;
    state.loading = true;
    state.error = '';
    render();
    try {
      state.targets = await readPetResidenceTargets();
    } catch (error) {
      console.error('[像素拓麻歌子] 读取角色卡列表失败：', error);
      state.targets = [];
      state.error = error?.message || String(error);
    } finally {
      state.loading = false;
      if (state.open && app.root?.classList.contains('ptg-open')) render();
    }
  }

  async function mutateCharacterPetSave(characterName, mutator) {
    if (typeof updateCharacterWith === 'function') {
      let resultMeta = null;
      const updated = await updateCharacterWith(characterName, (character) => {
        const info = characterInfoFromCard(characterName, character);
        const variables = characterVariablesFromCard(character, true);
        const previousRaw = variables[ROOT_KEY] && typeof variables[ROOT_KEY] === 'object' ? deepClone(variables[ROOT_KEY]) : null;
        const next = mutator({ character, info, variables, previousRaw });
        resultMeta = { info, previousRaw, ...(next?.meta || {}) };
        if (next?.remove) delete variables[ROOT_KEY];
        else if (next?.payload) variables[ROOT_KEY] = deepClone(next.payload);
        return character;
      });
      if (updated && resultMeta) resultMeta.info = characterInfoFromCard(characterName, updated);
      return resultMeta;
    }
    if (typeof getCharacter !== 'function' || typeof replaceCharacter !== 'function') throw new Error('当前酒馆助手版本不支持修改目标角色卡。');
    const character = await getCharacter(characterName);
    const info = characterInfoFromCard(characterName, character);
    const variables = characterVariablesFromCard(character, true);
    const previousRaw = variables[ROOT_KEY] && typeof variables[ROOT_KEY] === 'object' ? deepClone(variables[ROOT_KEY]) : null;
    const next = mutator({ character, info, variables, previousRaw });
    if (next?.remove) delete variables[ROOT_KEY];
    else if (next?.payload) variables[ROOT_KEY] = deepClone(next.payload);
    await replaceCharacter(characterName, character, { render: 'none' });
    return { info, previousRaw, ...(next?.meta || {}) };
  }

  async function restoreCharacterPetSave(characterName, previousRaw, info = null) {
    await mutateCharacterPetSave(characterName, ({ info: liveInfo }) => ({ remove: !previousRaw, payload: previousRaw, meta: { info: info || liveInfo } }));
    const key = (info || {}).key;
    if (key) {
      if (previousRaw) writeLocalMirror(key, previousRaw);
      else {
        try { host.localStorage?.removeItem(localMirrorKey(key)); } catch (_) {}
      }
    }
  }

  function releaseCurrentPetFromResidence() {
    const save = app.save;
    if (!save || save.lifecycle !== 'alive' || !save.pet) return;
    const petName = save.pet.name || '当前宠物';
    if (!host.confirm(`确定放生「${petName}」吗？\n放生不会记入生命纪念册，也无法使用复活药恢复。`)) return;
    const snapshot = deepClone(save);
    clearActivePetForResidence(save);
    app.message = `已经放生「${petName}」。当前角色卡现在没有宠物，可以之后购买新的宠物蛋。`;
    if (!saveCurrent()) {
      app.save = snapshot;
      notify('error', '放生失败：当前角色卡存档没有成功写入。');
      render();
      return;
    }
    app.petResidence.open = false;
    queueWorldbookSync(0, true);
    notify('success', `已经放生「${petName}」。`);
    render();
  }

  async function moveCurrentPetToResidenceTarget(token) {
    const state = app.petResidence;
    if (state.moving) return;
    const target = state.targets.find((item) => item.token === String(token));
    const sourceInfo = getCharacterInfo();
    const save = app.save;
    if (!target || !sourceInfo || !save || save.lifecycle !== 'alive' || !save.pet) return;
    const remaining = petMoveCooldownRemaining(save.pet);
    if (remaining > 0) {
      notify('warning', `这只宠物刚搬过家，还需等待 ${formatPetMoveCooldown(remaining)} 才能再次搬家。`);
      return;
    }
    const petName = save.pet.name || '当前宠物';
    const replacement = target.hasPet ? `\n「${target.name}」原有的宠物「${target.petName || '未命名宠物'}」会被自动放生。` : '';
    if (!host.confirm(`确定把「${petName}」搬到角色卡「${target.name}」吗？${replacement}\n同一只宠物搬家后 3 天内不能再次搬家。`)) return;

    state.moving = true;
    state.error = '';
    render();
    const now = nowMs();
    const sourceSnapshot = deepClone(save);
    const bundle = residenceTransferBundle(save);
    bundle.pet.lastMovedAt = now;
    bundle.pet.lastMoveFrom = sourceInfo.key;
    bundle.pet.lastMoveTo = target.key;
    bundle.pet.lastUpdateAt = now;
    let targetMeta = null;
    try {
      targetMeta = await mutateCharacterPetSave(target.name, ({ info, previousRaw }) => {
        const targetSave = normalizeResidenceCharacterSave(previousRaw);
        const displacedPetName = targetSave.lifecycle === 'alive' && targetSave.pet ? targetSave.pet.name : '';
        const targetCemetery = Array.isArray(targetSave.cemetery) ? deepClone(targetSave.cemetery) : [];
        targetSave.lifecycle = 'alive';
        targetSave.pet = deepClone(bundle.pet);
        targetSave.egg = null;
        targetSave.events = deepClone(bundle.events);
        targetSave.charCare = deepClone(bundle.charCare);
        targetSave.careLog = deepClone(bundle.careLog);
        targetSave.schedule = deepClone(bundle.schedule);
        targetSave.cemetery = targetCemetery;
        targetSave.wardrobe = targetSave.wardrobe && typeof targetSave.wardrobe === 'object' ? targetSave.wardrobe : { owned: {}, equipped: {} };
        targetSave.wardrobe.equipped = deepClone(bundle.equipped);
        targetSave.updatedAt = now;
        const payload = extractCharacterSave(targetSave, info);
        return { payload, meta: { displacedPetName, payload } };
      });
      if (!targetMeta?.info?.key || !targetMeta?.payload) throw new Error('目标角色卡存档写入失败。');
      writeLocalMirror(targetMeta.info.key, targetMeta.payload);

      clearActivePetForResidence(save, now);
      app.message = `「${petName}」已经搬到角色卡「${target.name}」。${targetMeta.displacedPetName ? `原来的宠物「${targetMeta.displacedPetName}」已自动放生。` : ''}`;
      if (!saveCurrent()) throw new Error('源角色卡存档保存失败，搬家已回滚。');
      app.petResidence.open = false;
      queueWorldbookSync(0, true);
      notify('success', `宠物已经搬到「${target.name}」。`);
      render();
    } catch (error) {
      console.error('[像素拓麻歌子] 宠物搬家失败：', error);
      app.save = sourceSnapshot;
      stampSaveOwner(app.save, sourceInfo);
      try { saveCurrent(); } catch (_) {}
      if (targetMeta) {
        try { await restoreCharacterPetSave(target.name, targetMeta.previousRaw, targetMeta.info); } catch (rollbackError) { console.error('[像素拓麻歌子] 搬家回滚目标角色卡失败：', rollbackError); }
      }
      state.error = error?.message || String(error);
      notify('error', `宠物搬家失败：${state.error}`);
      render();
    } finally {
      state.moving = false;
      if (state.open && app.root?.classList.contains('ptg-open')) render();
    }
  }

  function renderPetResidence() {
    const save = app.save;
    const state = app.petResidence;
    const pet = save?.lifecycle === 'alive' ? save.pet : null;
    const remaining = petMoveCooldownRemaining(pet);
    const cooldownText = remaining > 0
      ? `<div class="ptg-residence-note warning">这只宠物还需等待 ${escapeHtml(formatPetMoveCooldown(remaining))} 才能再次搬家。</div>`
      : '<div class="ptg-residence-note">搬家成功后，同一只宠物 3 天内不能再次搬家。</div>';
    const targetList = state.loading
      ? '<div class="ptg-empty">正在读取全部角色卡……</div>'
      : state.error
        ? `<div class="ptg-residence-note warning">${escapeHtml(state.error)}</div><button type="button" class="ptg-tool" data-action="pet-residence-refresh">重新读取</button>`
        : state.targets.length
          ? `<div class="ptg-residence-list">${state.targets.map((target) => `<button type="button" class="ptg-residence-target" data-action="pet-residence-move-${target.token}" ${!pet || remaining > 0 || state.moving ? 'disabled' : ''}><span><strong>${escapeHtml(target.name)}</strong><small>${target.hasPet ? `已有宠物：${escapeHtml(target.petName || target.petSpecies || '未命名宠物')}；搬入后会自动放生` : target.hasSave ? '当前没有宠物' : '尚未建立拓麻歌子存档'}</small></span><b>搬到这里</b></button>`).join('')}</div>`
          : '<div class="ptg-empty">没有可搬入的其他角色卡。</div>';
    return `<div class="ptg-panel"><div class="ptg-section-title"><h3>宠物安置</h3><button class="ptg-tool" data-action="pet-residence-back">${pixelIcon('back')}返回设置</button></div>
      <div class="ptg-setting-card"><strong>当前角色卡的宠物</strong>${pet ? `<div class="ptg-residence-current"><span>${petSvg(pet)}</span><div><b>${escapeHtml(pet.name)}</b><small>${escapeHtml(SPECIES[pet.species]?.name || pet.species || '')} · 陪伴 ${Math.round(Number(pet.companionship) || 0)}</small></div></div>${cooldownText}<button type="button" class="ptg-tool ptg-danger ptg-wide" data-action="pet-residence-release" ${state.moving ? 'disabled' : ''}>放生当前宠物</button>` : '<div class="ptg-empty">当前角色卡没有可以放生或搬家的宠物。</div>'}</div>
      <div class="ptg-setting-card"><strong>搬到其他角色卡</strong><p>宠物本体、当前日程、互动记录与已佩戴配饰会一起搬走；目标角色卡原有的宠物会自动放生，目标角色卡的生命纪念册不会被覆盖。</p>${targetList}</div>
    </div>`;
  }

  function renderSettings() {
    if (app.petResidence.open) return renderPetResidence();
    const save = app.save;
    const canRename = save.lifecycle === 'alive' && Boolean(save.pet) && petAllows(save.pet, 'allowRename', true);
