  function effectiveDeviceScale() {
    const requested = currentDeviceScale();
    const device = app.root?.querySelector('.ptg-device');
    const viewportWidth = host.visualViewport?.width || host.innerWidth || 0;
    const viewportHeight = host.visualViewport?.height || host.innerHeight || 0;
    if (!device || !viewportWidth || !viewportHeight) return requested;
    const baseWidth = Math.max(1, device.offsetWidth || 560);
    const baseHeight = Math.max(1, device.offsetHeight || 850);
    const fitScale = Math.min((viewportWidth - 8) / baseWidth, (viewportHeight - 8) / baseHeight);
    // 100% 始终是手机端的安全上限；较大的屏幕可以继续放大到玩家选择的比例。
    const safeMax = Math.max(1, Math.min(1.3, fitScale));
    return Math.max(0.7, Math.min(requested, safeMax));
  }

