  const SCROLL_RENDER_IDLE_MS = 420;

  function markScrollActivity(scroller) {
    const guard = app.scrollRenderGuard;
    if (!guard) return;
    guard.lastScrollAt = nowMs();
    const tab = scroller?.dataset?.tab || app.activeTab;
    if (scroller && tab) app.scrollPositions[tab] = scroller.scrollTop;
    if (guard.pending) scheduleRenderAfterScroll();
  }

  function renderIsBlockedByScroll() {
    const guard = app.scrollRenderGuard;
    if (!guard || !app.root?.classList.contains('ptg-open')) return false;
    if (nowMs() <= Number(guard.urgentUntil || 0)) return false;
    return nowMs() - Number(guard.lastScrollAt || 0) < SCROLL_RENDER_IDLE_MS;
  }

  function scheduleRenderAfterScroll() {
    const guard = app.scrollRenderGuard;
    if (!guard) return;
    guard.pending = true;
    if (guard.timer) host.clearTimeout(guard.timer);
    const elapsed = nowMs() - Number(guard.lastScrollAt || 0);
    const delay = Math.max(70, SCROLL_RENDER_IDLE_MS - elapsed + 24);
    guard.timer = host.setTimeout(() => {
      guard.timer = null;
      if (!guard.pending) return;
      if (renderIsBlockedByScroll()) { scheduleRenderAfterScroll(); return; }
      guard.pending = false;
      render(true);
    }, delay);
  }

