  function setupLotteryScratchCards(device) {
    device.querySelectorAll('[data-scratch-ticket]').forEach((canvas) => {
      if (canvas.dataset.scratchBound) return;
      canvas.dataset.scratchBound = '1';
      const ticketId = String(canvas.dataset.scratchTicket || '');
      const rect = canvas.getBoundingClientRect();
      const ratio = Math.max(1, Math.min(2, Number(host.devicePixelRatio) || 1));
      const width = Math.max(220, Math.round(rect.width || 300));
      const height = Math.max(70, Math.round(rect.height || 92));
      canvas.width = Math.round(width * ratio);
      canvas.height = Math.round(height * ratio);
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (!ctx) return;
      ctx.setTransform(ratio, 0, 0, ratio, 0, 0);
      const gradient = ctx.createLinearGradient(0, 0, width, height);
      gradient.addColorStop(0, '#8f9797');
      gradient.addColorStop(0.5, '#d9dddd');
      gradient.addColorStop(1, '#7c8585');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, width, height);
      ctx.fillStyle = '#35403f';
      ctx.font = '900 14px ui-monospace, monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('滑动刮开', width / 2, height / 2);
      ctx.globalCompositeOperation = 'destination-out';
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.lineWidth = Math.max(24, Math.min(width, height) * 0.34);
      let activePointer = null;
      let lastX = 0;
      let lastY = 0;
      let moveCount = 0;
      let revealed = false;

      const point = (event) => {
        const bounds = canvas.getBoundingClientRect();
        return {
          x: (event.clientX - bounds.left) * (width / Math.max(1, bounds.width)),
          y: (event.clientY - bounds.top) * (height / Math.max(1, bounds.height)),
        };
      };
      const erase = (x, y, fromX = x, fromY = y) => {
        ctx.beginPath();
        ctx.moveTo(fromX, fromY);
        ctx.lineTo(x, y);
        ctx.stroke();
      };
      const updateUnderlyingPrize = () => {
        const ticket = ensureLotteryTicketPrize(ticketId);
        const prize = LOTTERY_PRIZES[ticket?.prizeId] || LOTTERY_PRIZES.none;
        const label = device.querySelector(`[data-ticket-prize="${ticketId}"] strong`);
        if (label) label.textContent = prize.label;
      };
      const scratchedRatio = () => {
        const image = ctx.getImageData(0, 0, canvas.width, canvas.height).data;
        const step = Math.max(4, Math.round(8 * ratio));
        let transparent = 0;
        let sampled = 0;
        for (let y = 0; y < canvas.height; y += step) {
          for (let x = 0; x < canvas.width; x += step) {
            sampled += 1;
            if (image[(y * canvas.width + x) * 4 + 3] < 42) transparent += 1;
          }
        }
        return sampled ? transparent / sampled : 0;
      };
      const finish = (event) => {
        if (activePointer !== event.pointerId) return;
        activePointer = null;
        try { canvas.releasePointerCapture(event.pointerId); } catch (_) {}
        event.preventDefault();
        event.stopPropagation();
      };
      canvas.addEventListener('pointerdown', (event) => {
        if (revealed) return;
        updateUnderlyingPrize();
        playScratchSound(true);
        activePointer = event.pointerId;
        const p = point(event);
        lastX = p.x;
        lastY = p.y;
        erase(p.x, p.y);
        try { canvas.setPointerCapture(event.pointerId); } catch (_) {}
        event.preventDefault();
        event.stopPropagation();
      });
      canvas.addEventListener('pointermove', (event) => {
        if (revealed || activePointer !== event.pointerId) return;
        const p = point(event);
        erase(p.x, p.y, lastX, lastY);
        playScratchSound(false);
        lastX = p.x;
        lastY = p.y;
        moveCount += 1;
        if (moveCount % 5 === 0 && scratchedRatio() >= LOTTERY_REVEAL_THRESHOLD) {
          revealed = true;
          canvas.style.transition = 'opacity .22s ease';
          canvas.style.opacity = '0';
          host.setTimeout(() => revealLotteryTicket(ticketId), 180);
        }
        event.preventDefault();
        event.stopPropagation();
      });
      canvas.addEventListener('pointerup', finish);
      canvas.addEventListener('pointercancel', finish);
    });
  }

  function fortuneMotionSupported() {
    return typeof host.DeviceMotionEvent !== 'undefined';
  }

  function attachFortuneMotionListener() {
    if (!fortuneMotionSupported() || app.fortuneMotionHandler) return false;
    app.fortuneMotionHandler = (event) => {
      if (!app.root?.classList.contains('ptg-open') || app.activeTab !== 'mystic' || app.mysticView !== 'fortune') return;
      if (app.save?.fortuneHouse?.fortune || app.fortuneRolling) return;
      const a = event.accelerationIncludingGravity || event.acceleration;
      if (!a) return;
      const magnitude = Math.hypot(Number(a.x) || 0, Number(a.y) || 0, Number(a.z) || 0);
      const previous = app.fortuneMotionLastMagnitude;
      app.fortuneMotionLastMagnitude = magnitude;
      if (previous == null) return;
      const delta = Math.abs(magnitude - previous);
      if (delta < 8.5 || nowMs() - app.fortuneMotionLastTriggerAt < 1600) return;
      app.fortuneMotionLastTriggerAt = nowMs();
      try { host.navigator?.vibrate?.([30, 45, 30]); } catch (_) {}
      rollDailyFortune();
    };
    host.addEventListener('devicemotion', app.fortuneMotionHandler, true);
    return true;
  }

  async function requestFortuneMotionPermission() {
    try {
      if (!fortuneMotionSupported()) {
        app.message = '当前设备不支持动作感应，请使用滑动或直接掷骰。';
        render();
        return;
      }
      const request = host.DeviceMotionEvent?.requestPermission;
      if (typeof request === 'function') {
        const result = await request.call(host.DeviceMotionEvent);
        if (result !== 'granted') {
          app.message = '没有获得动作感应权限，仍可在骰盘上滑动。';
          render();
          return;
        }
      }
      attachFortuneMotionListener();
