  function setupFortuneInteraction(device) {
    const surface = device.querySelector('[data-fortune-shake]');
    if (!surface || surface.dataset.fortuneBound) return;
    surface.dataset.fortuneBound = '1';
    if (fortuneMotionSupported() && typeof host.DeviceMotionEvent?.requestPermission !== 'function') attachFortuneMotionListener();
    let pointerId = null;
    let lastX = 0;
    let lastY = 0;
    let distance = 0;
    surface.addEventListener('pointerdown', (event) => {
      if (app.save?.fortuneHouse?.fortune || app.fortuneRolling) return;
      pointerId = event.pointerId;
      lastX = event.clientX;
      lastY = event.clientY;
      distance = 0;
      try { surface.setPointerCapture(event.pointerId); } catch (_) {}
      event.preventDefault();
      event.stopPropagation();
    });
    surface.addEventListener('pointermove', (event) => {
      if (pointerId !== event.pointerId || app.fortuneRolling) return;
      const dx = event.clientX - lastX;
      const dy = event.clientY - lastY;
      distance += Math.hypot(dx, dy);
      lastX = event.clientX;
      lastY = event.clientY;
      if (distance >= 135) {
        pointerId = null;
        try { host.navigator?.vibrate?.(35); } catch (_) {}
        rollDailyFortune();
      }
      event.preventDefault();
      event.stopPropagation();
    });
    const finish = (event) => {
      if (pointerId !== event.pointerId) return;
      pointerId = null;
      try { surface.releasePointerCapture(event.pointerId); } catch (_) {}
      event.preventDefault();
      event.stopPropagation();
    };
    surface.addEventListener('pointerup', finish);
    surface.addEventListener('pointercancel', finish);
  }


