  const PET_TEXT_EXTRA_MS = 3000;

  function playTransient(mode, message, duration = 1500) {
    const displayDuration = Math.max(0, Number(duration) || 0) + PET_TEXT_EXTRA_MS;
    app.transientAnimation = mode;
    app.transientUntil = nowMs() + displayDuration;
    app.message = message;
    render();
    host.setTimeout(() => {
      if (nowMs() >= app.transientUntil) {
        app.transientAnimation = null;
