  function changeCompanionship(save, amount) {
    if (!save?.pet || save.lifecycle !== 'alive') return 0;
    const before = Number(save.pet.companionship) || 0;
    const rawAmount = Number(amount || 0);
    const adjustedAmount = rawAmount > 0 ? rawAmount * CONFIG.companionshipGainMultiplier : rawAmount;
    save.pet.companionship = clamp(before + adjustedAmount);
    checkAchievementsNow(save);
    return save.pet.companionship - before;
  }

  function rewardCompanionAction(save, bondGain = 1) {
    if (!save?.pet) return;
    save.pet.interactionCount += 1;
    save.stats.totalCompanionActions += 1;
    changeCompanionship(save, bondGain);
    if (save.economy.companionCoinsToday < CONFIG.maxCompanionCoinsPerDay) {
