  function maybeTriggerRandomEvent(save, currentTime = nowMs()) {
    if (!save || save.lifecycle !== 'alive' || !save.pet || save.events.current) return false;
    if (!petAllows(save.pet, 'allowRandomEvents', true)) return false;
    if (currentTime < Number(save.events.nextAt || 0)) return false;
    const pool = RANDOM_EVENTS.filter((event) => event && event.trigger !== 'touch');
    const recent = new Set((save.events.history || []).slice(-4).map((entry) => entry.id));
    const candidates = pool.filter((event) => event && !recent.has(event.id));
    const selected = randomChoice(candidates.length ? candidates : pool);
    save.events.current = { id: selected.id, source: 'regular', startedAt: currentTime };
    app.message = `${save.pet.name}好像遇到了一件事，正在等你回应。`;
    return true;
  }

  function applyEventEffects(save, effects = {}) {
    const pet = save.pet;
    if (!pet) return {};
    ['hunger', 'happiness', 'health', 'cleanliness', 'energy'].forEach((key) => {
      if (effects[key] !== undefined) {
        const raw = Number(effects[key] || 0);
        const multiplier = raw < 0 ? petLossMultiplier(pet, key, 'activity') : 1;
        pet[key] = clampPetStat(pet, key, pet[key] + raw * multiplier);
      }
    });
    const appliedAttributes = effects.attributes && typeof effects.attributes === 'object'
      ? applyAttributeChanges(pet, effects.attributes)
      : {};
    if (effects.companionship !== undefined) changeCompanionship(save, Number(effects.companionship || 0));
    if (effects.coins > 0) addCoins(save, effects.coins);
    if (effects.coins < 0) spendCoins(save, Math.abs(effects.coins));
    return appliedAttributes;
  }

  function resolveRandomEvent(eventId, choiceId) {
    const save = app.save;
    const current = save?.events?.current;
    if (!current || current.id !== eventId || save.lifecycle !== 'alive' || !save.pet) return;
    const event = RANDOM_EVENTS.find((item) => item && item.id === eventId);
    const choice = event?.choices.find((item) => item.id === choiceId);
    if (!choice) return;
    const appliedAttributes = applyEventEffects(save, choice.effects);
    const attributeText = formatAttributeChanges(appliedAttributes);
    const resultText = attributeText ? `${choice.result} 属性提升：${attributeText}。` : choice.result;
    pushCareLog('player', 'event', `事件「${event.title}」·${choice.label}${attributeText ? ` · 属性 ${attributeText}` : ''}`);
    const positive = choice.tone === 'positive';
    save.events.completed += 1;
    save.events[positive ? 'positive' : 'negative'] += 1;
    save.stats.totalEvents += 1;
    save.events.history.push({ id: eventId, choiceId, tone: choice.tone, at: nowMs() });
    save.events.history = save.events.history.slice(-20);
    save.events.current = null;
    save.events.nextAt = nowMs() + randomEventDelay(false);
    app.eventFeedback = { type: positive ? 'positive' : 'negative', text: resultText, until: nowMs() + 2600 + PET_TEXT_EXTRA_MS };
    app.transientAnimation = choice.mode || (positive ? 'happy' : 'sad');
    app.transientUntil = nowMs() + 1700 + PET_TEXT_EXTRA_MS;
    app.message = resultText;
    checkAchievementsNow(save);
    saveCurrent();
    render();
    host.setTimeout(() => {
      if (app.eventFeedback && nowMs() >= app.eventFeedback.until) app.eventFeedback = null;
      if (nowMs() >= app.transientUntil) app.transientAnimation = null;
      app.message = getStatusMessage();
      render();
    }, 2650 + PET_TEXT_EXTRA_MS);
  }

