  function normalizeSavedGameState(gameId, rawState) {
    if (!rawState || typeof rawState !== 'object') return null;
    const module = gameModule(gameId);
    if (module && !module.legacy && typeof module.normalizeState === 'function') {
      try { return module.normalizeState(rawState, gameExtensionApi(gameId)); }
      catch (error) { console.error(`[像素拓麻歌子] 小游戏 ${gameId} 存档恢复失败：`, error); return null; }
    }
    if (gameId === 'tetris') {
