  function scheduleGameTick() {
    const gameId = app.games.selected;
    const state = gameState(gameId);
    // 2048 无自动循环；扫雷的实时计时由独立 HUD 定时器负责。
    // 这里不能调用 clearGameTimer，否则会把刚绑定好的扫雷 HUD 计时器一并清除。
    const module = gameModule(gameId);
    const customTick = module && !module.legacy && typeof module.tick === 'function';
    if ((app.logicWorker.worker && app.logicWorker.gameId === gameId) || !gameId || !state || state.status !== 'running' || (!customTick && (gameId === '2048' || gameId === 'minesweeper' || gameId === 'collectHoney' || gameId === 'bulletHell' || gameId === 'zombieGarden' || gameId === 'watermelon' || gameId === 'pinball' || gameId === 'petRogue'))) {
      clearGameLoopTimer();
      return;
    }
    clearGameLoopTimer();
    const customDelay = customTick && typeof module.tickDelay === 'function' ? Number(module.tickDelay(state, gameExtensionApi(gameId))) : Number(module?.tickDelay);
    const delay = customTick && Number.isFinite(customDelay) ? Math.max(16, customDelay) : gameId === 'match3' ? MATCH3_TICK_MS : gameId === 'kitchen' ? KITCHEN_TICK_MS : gameId === 'tetris' ? tetrisDropDelay(state.lines) : Math.max(85, 190 - Math.floor(state.score / 50) * 8);
    app.games.timer = host.setTimeout(gameTick, delay);
  }

