    const module = gameModule(app.games.selected);
    if (module && !module.legacy && typeof module.resume === 'function') {
      try { module.resume(state, gameExtensionApi(app.games.selected)); }
      catch (error) { console.error(`[像素拓麻歌子] 小游戏 ${app.games.selected} 恢复失败：`, error); }
    }
    if (app.games.selected === 'minesweeper') resumeMinesweeperClock(state);
    if (app.games.selected === 'watermelon') {
      state.lastFrameAt = nowMs();
      state.effects = [];
    }
    if (app.games.selected === 'petRogue') {
      state.particles = []; state.popups = []; state.effects = []; state.projectiles = []; state.enemyBullets = []; state.zones = [];
