      if (state.choosing) { if (Math.max(0, Number(state.pendingLevelUps) || 0) <= 0 && Math.max(0, Number(state.pendingAttachmentPicks) || 0) <= 0) state.pendingLevelUps = 1; state.choiceMode = petRogueResolveChoiceMode(state) || 'upgrade'; if (!Array.isArray(state.pendingChoices) || !state.pendingChoices.length) state.pendingChoices = petRogueGenerateActiveChoices(state); }
