  function awardGameCoins(baseReward) {
    const save = app.save;
    const remaining = Math.max(0, CONFIG.maxGameCoinsPerDay - save.economy.gameCoinsToday);
    const reward = Math.min(remaining, Math.max(0, Math.floor(baseReward)));
    save.stats.totalGames += 1;
    if (reward > 0) {
      save.economy.gameCoinsToday += reward;
      addCoins(save, reward);
    }
    return reward;
  }

  function finishGame(gameId, reason = '本局结束') {
    if (app.logicWorker.worker && app.logicWorker.gameId === gameId) stopLogicGameWorker('finish');
    const state = gameState(gameId);
    if (!state || state.status === 'over' || state.status === 'idle') return;
    if (gameId === 'match3') {
      syncMatch3Clock(state);
      state.animationNonce += 1;
      state.resolving = false;
      state.popCells = [];
      clearMatch3Falls(state);
      state.lastTickAt = null;
    }
    if (gameId === 'watermelon') {
      state.lastFrameAt = null;
      state.effects = [];
    }
    if (gameId === 'zombieGarden') {
      state.resolving = false;
      state.animationNonce = Math.max(0, Number(state.animationNonce) || 0) + 1;
      if (app.games.zombieGardenAnimationFrame !== null) {
        try { host.cancelAnimationFrame(app.games.zombieGardenAnimationFrame); } catch (_) {}
        app.games.zombieGardenAnimationFrame = null;
      }
    }
    clearGameTimer();
    if (gameId === 'minesweeper') pauseMinesweeperClock(state);
    state.status = 'over';
    clearSuspendedGame();
    const score = Math.max(0, Math.floor(Number(state.score) || 0));
    state.score = score;
    if (gameId === 'petRogue') state.survivalScoreCarry = 0;
    const previousHigh = app.save.gameRecords.highScores[gameId] || 0;
    const isNewHighScore = score > previousHigh;
    app.save.gameRecords.highScores[gameId] = Math.max(previousHigh, score);
    state.reward = awardGameCoins(gameRewardPreview(gameId, score));
    state.message = reason;
    app.message = GAME_DEFS[gameId].noCoins
      ? `${GAME_DEFS[gameId].name}结束：${score} 分。`
      : `${GAME_DEFS[gameId].name}结束：${score} 分，金币 +${state.reward}。`;
    saveCurrent();
    if (isNewHighScore && score > 0 && GAME_DEFS[gameId]?.leaderboard !== false) {
      void loadLeaderboard(gameId, true);
    }
    if (app.root?.classList.contains('ptg-open') && app.activeTab === 'games') render();
  }

