      const payload = {
        format: 'pixel_tamagotchi_split_save',
        version: SAVE_VERSION,
        characterName: refreshLiveCharacterName(),
        exportedAt: new Date().toISOString(),
        characterSave: extractCharacterSave(app.save, info),
        globalSave: extractGlobalSave(app.save),
      };
      const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const anchor = doc.createElement('a');
      anchor.href = url;
      anchor.download = `像素拓麻歌子_全局与${refreshLiveCharacterName() || '当前宠物'}_${localDayKey()}.json`;
      doc.body.appendChild(anchor);
      anchor.click();
      anchor.remove();
      host.setTimeout(() => URL.revokeObjectURL(url), 1000);
      app.message = '当前角色的宠物档、全局共享档与排行榜身份已一起导出。';
      render();
    } catch (error) {
