  function handleImportedFile(file) {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const parsed = JSON.parse(String(reader.result || ''));
        const isSplit = parsed?.format === 'pixel_tamagotchi_split_save';
        const oldRawSave = parsed?.format === 'pixel_tamagotchi_save' ? parsed.save : (!isSplit ? parsed : null);
        if (isSplit) {
          if (!parsed.characterSave || typeof parsed.characterSave !== 'object' || !parsed.globalSave || typeof parsed.globalSave !== 'object') {
            throw new Error('文件不包含完整的宠物档和全局档');
          }
        } else if (!oldRawSave || typeof oldRawSave !== 'object') {
          throw new Error('文件不包含有效存档');
        }
        if (!host.confirm(`确定导入该存档吗？\n当前角色「${refreshLiveCharacterName() || '当前角色卡'}」的宠物档，以及所有角色共享的金币、背包、设置、图鉴、成就、小游戏和排行榜身份都会被覆盖。`)) return;

        const info = getCharacterInfo();
        if (isSplit) {
          app.save = combineCharacterAndGlobalSave(parsed.characterSave, parsed.globalSave, info);
        } else {
          // 兼容 v0.25.2 及更早版本的完整单角色存档，导入后自动拆分。
          const normalized = normalizeSave(oldRawSave);
          normalized._ptgGlobalMigration = createGlobalMigrationMeta({
            initializedAt: nowMs(),
            initializedFrom: 'imported-legacy-save',
            migratedCharacterKeys: info?.key ? [info.key] : [],
          });
          app.save = combineCharacterAndGlobalSave(
            extractCharacterSave(normalized, info),
            extractGlobalSave(normalized),
            info,
          );
        }
        resetLeaderboardRuntime();
        settleTime(app.save);
        const restoredGame = restoreGameRuntimeFromSave();
        app.activeTab = 'home';
        app.message = restoredGame ? '存档导入成功，全局小游戏进度也已恢复。' : '宠物档与全局共享档导入成功。';
        saveCurrent();
        render();
        scheduleLeaderboardSync(700);
      } catch (error) {
        console.error('[像素拓麻歌子] 导入失败：', error);
        notify('error', `导入失败：${error.message || error}`);
      } finally {
        if (app.importInput) app.importInput.value = '';
      }
    };
    reader.readAsText(file, 'utf-8');
  }



  function addScheduleTask(category, activityId, durationHours) {
    const save = app.save;
    const pet = save?.pet;
    const definition = activityDefinition(category, activityId);
    if (!save || save.lifecycle !== 'alive' || !pet || !definition) return;
    const duration = Number(durationHours);
    ensureScheduleDay(save, localDayKey());
    const target = getScheduleBuilder().target === 'template' ? 'template' : 'today';
    if (category === 'work' && !jobRequirementsMet(pet, definition)) {
      app.message = `属性不足，暂时无法安排「${definition.name}」。`;
      render();
      return;
    }
    const currentHours = target === 'template' ? scheduleTemplateHours(save.schedule) : scheduleTodayHours(save.schedule);
    if (currentHours + duration > CONFIG.maxDailyScheduleHours + 0.0001) {
      app.message = `${target === 'template' ? '每日计划' : '今日执行'}最多安排 ${CONFIG.maxDailyScheduleHours} 小时。`;
      render();
      return;
    }
    if (target === 'template') {
      const templateTask = { templateId: scheduleId('tpl'), category, activityId, durationHours: duration };
      save.schedule.template.push(templateTask);
      app.message = `已把「${definition.name}」${formatHours(duration)}加入每日计划。`;
    } else {
      save.schedule.today.push(cloneTemplateTaskForToday({ templateId: scheduleId('tpl'), category, activityId, durationHours: duration }));
      save.schedule.todayTouched = true;
      save.schedule.planApplied = true;
      app.message = `已把「${definition.name}」${formatHours(duration)}加入今日执行。`;
    }
    pushCareLog('player', 'schedule_add', `${target === 'template' ? '每日计划' : '今日执行'}：「${definition.name}」${formatHours(duration)}`);
    resetScheduleBuilder(false);
    saveCurrent();
    render();
  }

  function removeScheduleTask(templateId) {
    const schedule = app.save?.schedule;
    if (!schedule) return;
    const target = schedule.template.find((task) => task.templateId === templateId);
    schedule.template = schedule.template.filter((task) => task.templateId !== templateId);
    app.message = target ? `已从每日计划移除「${activityDefinition(target.category, target.activityId)?.name || '该活动'}」。` : '该计划已经不存在。';
    if (target) pushCareLog('player', 'schedule_delete', `每日计划删除「${activityDefinition(target.category, target.activityId)?.name || '该活动'}」`);
    saveCurrent();
    render();
  }

  function removeTodayTask(id) {
    const schedule = app.save?.schedule;
    if (!schedule) return;
    const target = schedule.today.find((task) => task.id === id);
    schedule.today = schedule.today.filter((task) => task.id !== id);
    schedule.todayTouched = true;
    schedule.planApplied = true;
    if (target) {
      app.message = `已从今日执行移除「${activityDefinition(target.category, target.activityId)?.name || '该活动'}」。`;
      pushCareLog('player', 'schedule_delete', `今日执行删除「${activityDefinition(target.category, target.activityId)?.name || '该活动'}」`);
    }
    saveCurrent();
    render();
  }

  function skipCurrentScheduleTask() {
    const task = app.save?.schedule?.today?.find((entry) => ['active', 'queued'].includes(entry.status));
    if (!task) {
      app.message = '当前没有可以跳过的日程。';
    } else {
      task.status = 'skipped';
      app.message = `已跳过「${activityDefinition(task.category, task.activityId)?.name || '当前日程'}」。`;
    }
    saveCurrent();
    render();
  }


  function handleAction(action) {
    if (action === 'close') return closePanel();
    if (!app.save) return;
    const hotGameAction = action.startsWith('game-')
      && !action.startsWith('game-start-')
      && !['game-exit', 'game-pause', 'game-resume', 'game-open-leaderboard', 'game-leaderboard-back'].includes(action);
    if (!hotGameAction) {
      settleTime(app.save);
      saveCurrent();
    }

    if (action.startsWith('tab-')) {
      let next = action.slice(4);
      if (companionPlayState().open) resetCompanionPlay(false);
      if (next === 'collection') { app.recordsView = 'collection'; next = 'records'; }
      if (next === 'gacha') {
        next = 'mystic';
        app.mysticView = 'gacha';
        app.mysticGachaView = 'machine';
        if (!GAME_DEFS[app.games.leaderboardGameId]) app.games.leaderboardGameId = GAME_IDS[0] || 'match3';
      }
      if (app.activeTab === 'games' && next !== 'games') pauseActiveGame(false);
      app.previousTab = app.activeTab === 'settings' ? app.previousTab : app.activeTab;
      app.activeTab = next;
      app.itemPickerCategory = null;
      if (next !== 'schedule') resetScheduleBuilder(false);
      if (app.scrollPositions[next] === undefined) app.scrollPositions[next] = 0;
      syncBackgroundMusicForCurrentView();
      render();
      if (next === 'games' && app.games.selected) {
        const state = selectedGameState();
        if (state && !['running', 'paused'].includes(state.status)) {
          app.games.leaderboardGameId = app.games.selected;
          void loadLeaderboard(app.games.selected, true);
        }
      }
      return;
    }

    if (action === 'leaderboard-view-ranking') {
      app.games.leaderboardView = 'ranking';
      app.scrollPositions.games = 0;
      render();
      const gameId = app.games.selected || app.games.leaderboardGameId;
      if (GAME_DEFS[gameId]) void loadLeaderboard(gameId, true);
      return;
    }
    if (action === 'mystic-gacha-view-machine' || action === 'mystic-gacha-view-collection' || action === 'mystic-gacha-view-exchange') {
      app.mysticGachaView = action.endsWith('-collection') ? 'collection' : action.endsWith('-exchange') ? 'exchange' : 'machine';
      if (app.mysticGachaView === 'collection') ensureGachaShowcaseDraft();
      app.scrollPositions.mystic = 0;
      render();
      return;
    }
    if (action === 'gacha-draw-1' || action === 'gacha-draw-10') { startGachaDraw(action.endsWith('-10') ? 10 : 1); return; }
    if (action.startsWith('gacha-filter-')) { const filter = action.slice('gacha-filter-'.length); if (['all','badge','title','frame','set'].includes(filter)) { app.games.gachaFilter = filter; render(); } return; }
    if (action.startsWith('gacha-preview-part-')) {
      const matched = action.match(/^gacha-preview-part-(badge|title|frame|gradient)-(.+)$/);
      if (matched) previewGachaReward(matched[2], matched[1]);
      render(); return;
    }
    if (action.startsWith('gacha-preview-')) { previewGachaReward(action.slice('gacha-preview-'.length)); render(); return; }
    if (action.startsWith('gacha-equip-')) { previewGachaReward(action.slice('gacha-equip-'.length)); render(); return; }
    if (action === 'gacha-clear-badge' || action === 'gacha-clear-title' || action === 'gacha-clear-frame' || action === 'gacha-clear-gradient') { clearGachaShowcaseDraft(action.slice('gacha-clear-'.length)); render(); return; }
    if (action === 'gacha-clear-all') { clearGachaShowcaseDraft('all'); render(); return; }
    if (action === 'gacha-preview-cancel') { cancelGachaShowcaseDraft(); render(); return; }
    if (action === 'gacha-showcase-save') { saveGachaShowcaseDraft(); return; }
    if (action.startsWith('gacha-redeem-')) { redeemGachaReward(action.slice('gacha-redeem-'.length)); return; }

    if (action === 'leaderboard-set-nickname') {
      setLeaderboardNickname();
      return;
    }
    if (action === 'leaderboard-refresh') {
      const profile = leaderboardProfile(); if (profile && profile.backendVersion < 2) profile.lastV2AttemptAt = 0;
      const gameId = app.games.selected || app.games.leaderboardGameId;
      if (GAME_DEFS[gameId]) void loadLeaderboard(gameId, true);
      return;
    }
    if (action === 'game-open-leaderboard') {
      const gameId = app.games.selected;
      if (GAME_DEFS[gameId]?.leaderboard === false) return;
      const state = gameState(gameId);
      if (GAME_DEFS[gameId] && state && !['running', 'paused'].includes(state.status)) {
        app.games.leaderboardOpen = true;
        app.games.leaderboardView = 'ranking';
        app.games.leaderboardGameId = gameId;
        app.scrollPositions.games = 0;
        render();
            if (GAME_DEFS[gameId]?.leaderboard !== false) void loadLeaderboard(gameId, true);
