    }
    if (action === 'game-leaderboard-back') {
      app.games.leaderboardOpen = false;
      app.games.leaderboardView = 'ranking';
      app.scrollPositions.games = 0;
      render();
      return;
    }

    if (action === 'records-view-records' || action === 'records-view-collection') {
      app.recordsView = action.endsWith('collection') ? 'collection' : 'records';
      app.scrollPositions.records = 0;
      render();
      return;
    }
    if (action.startsWith('mystic-view-')) {
      const view = action.slice('mystic-view-'.length);
      if (['lottery', 'fortune', 'answers', 'gacha'].includes(view)) {
        app.mysticView = view;
        app.scrollPositions.mystic = 0;
        render();
      }
      return;
    }
    if (action === 'lottery-buy') {
      buyLotteryTicket();
      return;
    }
    if (action === 'fortune-roll') {
      rollDailyFortune();
      return;
    }
    if (action === 'fortune-enable-motion') {
      void requestFortuneMotionPermission();
      return;
    }
    if (action === 'fortune-detail-toggle') {
      app.fortuneDetailOpen = !app.fortuneDetailOpen;
      render();
      return;
    }
    if (action === 'answer-book-open') {
      openAnswerBookPage();
      return;
    }
    if (action === 'open-settings') {
      if (companionPlayState().open) resetCompanionPlay(false);
      if (app.activeTab === 'games') pauseActiveGame(false);
      if (app.activeTab === 'settings') {
        app.activeTab = app.previousTab || 'home';
      } else {
        app.previousTab = app.activeTab;
        app.activeTab = 'settings';
      }
      syncBackgroundMusicForCurrentView();
      render();
      return;
    }
    if (action === 'pet-residence-open') {
      app.petResidence.open = true;
      app.petResidence.targets = [];
      app.petResidence.error = '';
      app.scrollPositions.settings = 0;
      render();
      void loadPetResidenceTargets();
      return;
    }
    if (action === 'pet-residence-back') {
      app.petResidence.open = false;
      app.petResidence.error = '';
      render();
      return;
    }
    if (action === 'pet-residence-refresh') {
      void loadPetResidenceTargets();
      return;
    }
    if (action === 'pet-residence-release') {
      releaseCurrentPetFromResidence();
      return;
    }
    if (action.startsWith('pet-residence-move-')) {
      void moveCurrentPetToResidenceTarget(action.slice('pet-residence-move-'.length));
      return;
    }
    if (action === 'settings-back') {
      app.activeTab = app.previousTab || 'home';
      syncBackgroundMusicForCurrentView();
      render();
      return;
    }
    if (action === 'schedule-builder-open' || action === 'schedule-builder-open-today') {
      resetScheduleBuilder(true, 'today');
      app.scrollPositions.schedule = 0;
      render();
      return;
    }
    if (action === 'schedule-builder-open-template') {
      resetScheduleBuilder(true, 'template');
      app.scrollPositions.schedule = 0;
      render();
      return;
    }
    if (action === 'schedule-builder-close') {
      resetScheduleBuilder(false);
      render();
      return;
    }
    if (action === 'schedule-builder-back') {
      const builder = getScheduleBuilder();
      if (builder.step >= 3) {
        builder.step = 2;
        builder.activityId = null;
      } else {
        builder.step = 1;
        builder.category = null;
        builder.activityId = null;
      }
      render();
      return;
    }
    if (action.startsWith('schedule-builder-category-')) {
      const category = action.slice('schedule-builder-category-'.length);
      if (SCHEDULE_CATEGORY_META[category]) {
        app.scheduleBuilder = { open: true, step: 2, category, activityId: null, target: getScheduleBuilder().target };
        app.scrollPositions.schedule = 0;
        render();
      }
      return;
    }
    if (action.startsWith('schedule-builder-activity-')) {
      const builder = getScheduleBuilder();
      const activityId = action.slice('schedule-builder-activity-'.length);
      const definition = activityDefinition(builder.category, activityId);
      if (!definition) return;
      if (builder.category === 'work' && !jobRequirementsMet(app.save.pet, definition)) {
        app.message = `属性不足，暂时无法选择「${definition.name}」。`;
        render();
        return;
      }
      builder.activityId = activityId;
      builder.step = 3;
      app.scrollPositions.schedule = 0;
      render();
      return;
    }
    if (action.startsWith('schedule-builder-duration-')) {
      const builder = getScheduleBuilder();
      const duration = Number(action.slice('schedule-builder-duration-'.length).replace('_', '.'));
      if (builder.category && builder.activityId && Number.isFinite(duration)) {
        addScheduleTask(builder.category, builder.activityId, duration);
      }
      return;
    }
    const scheduleAddMatch = action.match(/^schedule-add-(study|fun|sleep|work)-([a-z0-9_]+)-([0-9_]+)$/);
    if (scheduleAddMatch) {
      addScheduleTask(scheduleAddMatch[1], scheduleAddMatch[2], Number(scheduleAddMatch[3].replace('_', '.')));
      return;
    }
    if (action.startsWith('schedule-today-remove-')) {
      removeTodayTask(action.slice('schedule-today-remove-'.length));
      return;
    }
    if (action.startsWith('schedule-remove-')) {
      removeScheduleTask(action.slice('schedule-remove-'.length));
      return;
    }
    if (action === 'schedule-skip') {
      skipCurrentScheduleTask();
      return;
    }
    if (action === 'schedule-today-clear') {
      const sc = app.save.schedule;
      const pending = sc.today.filter((task) => !['done', 'cancelled'].includes(task.status)).length;
      if (!sc.today.length) { app.message = '今日执行本来就是空的。'; render(); return; }
      if (host.confirm('确定清空今日执行吗？尚未完成的安排会被移除（每日计划模板不受影响）。')) {
        sc.today = sc.today.filter((task) => task.status === 'done');
        sc.todayTouched = true;
        sc.planApplied = true;
        if (pending) pushCareLog('player', 'schedule_clear', `清空今日执行（${pending}项）`);
        app.message = '今日执行已清空。';
        saveCurrent();
        render();
      }
      return;
    }
    if (action === 'schedule-clear') {
      if (host.confirm('确定清空每日计划模板吗？只影响模板，不会改动今天已经在执行的安排。')) {
        const clearedCount = app.save.schedule.template.length;
        app.save.schedule.template = [];
        if (clearedCount) pushCareLog('player', 'schedule_clear', `清空每日计划模板（${clearedCount}项）`);
        app.message = '每日计划模板已清空。';
        saveCurrent();
        render();
      }
      return;
    }
    if (action === 'item-picker-close') { app.itemPickerCategory = null; render(); return; }
    if (action.startsWith('item-picker-')) {
      const category = action.slice('item-picker-'.length);
      if (ITEM_CATEGORY_META[category]) { app.itemPickerCategory = category; render(); }
      return;
    }
    if (action.startsWith('use-item-')) {
      const itemId = action.slice('use-item-'.length);
      const result = useCareItem(itemId, 'player');
      if (!result.ok) { app.message = result.text; render(); return; }
      pushCareLog('player', result.logType, result.logText);
      app.itemPickerCategory = null;
      maybeTriggerRandomEvent(app.save);
      saveCurrent();
      playTransient(result.mode, result.text, 1500);
      return;
    }
    if (action.startsWith('char-care-count-')) {
      const stepperMatch = action.match(/^char-care-count-(inc|dec)-(\d+)$/);
      if (stepperMatch && app.pendingCharCare) {
        const target = app.pendingCharCare.actions[Number(stepperMatch[2])];
        if (target) {
          const info = charActionItemInfo(target);
          const max = info ? info.max : CONFIG.maxCareItemBatch;
          let count = Math.max(1, Math.min(Number(target.count) || 1, max));
          count = stepperMatch[1] === 'inc' ? Math.min(max, count + 1) : Math.max(1, count - 1);
          target.count = count;
        }
      }
      render();
      return;
    }
    if (action === 'char-care-allow') {
      const pkg = app.pendingCharCare;
      app.pendingCharCare = null;
      applyCharCarePackage(pkg);
      return;
    }
    if (action === 'char-care-reject') {
      app.pendingCharCare = null;
      app.message = '你暂时没有让角色操作拓麻歌子。';
      render();
      return;
    }
    if (action.startsWith('event-')) {
      const currentEventId = app.save?.events?.current?.id;
      const prefix = currentEventId ? `event-${currentEventId}-` : '';
      if (currentEventId && action.startsWith(prefix)) {
        const choiceId = action.slice(prefix.length);
        resolveRandomEvent(currentEventId, choiceId);
      } else {
        app.message = '这个事件已经结束或发生了变化，请等待下一次事件。';
        render();
      }
      return;
    }
    if (action.startsWith('shop-toggle-')) {
      const category = action.slice('shop-toggle-'.length);
      if (!(app.shopExpandedCategories instanceof Set)) app.shopExpandedCategories = new Set();
      if (app.shopExpandedCategories.has(category)) app.shopExpandedCategories.delete(category);
      else app.shopExpandedCategories.add(category);
      render();
      return;
    }
    if (action.startsWith('buy-item-')) {
      buyItem(action.slice('buy-item-'.length));
      saveCurrent();
      return;
    }
    if (action.startsWith('buy-accessory-')) {
      const id = action.slice('buy-accessory-'.length);
      const acc = ACCESSORY_DEFS[id];
      if (acc && app.save?.wardrobe && !app.save.wardrobe.owned[id]) {
        if (!spendCoins(app.save, acc.price)) { app.message = '金币不足。'; render(); return; }
        app.save.wardrobe.owned[id] = true;
        app.message = `购买了${acc.name}，去衣橱给宠物戴上吧。`;
        saveCurrent();
      }
      render();
      return;
    }
    if (action.startsWith('wardrobe-clear-')) {
      const slot = action.slice('wardrobe-clear-'.length);
      if ((slot === 'head' || slot === 'eyes') && app.save?.wardrobe?.equipped) {
        app.save.wardrobe.equipped[slot] = null;
        syncPetRogueWorkerVisuals();
        app.message = `取下了${slot === 'head' ? '头顶' : '眼部'}配饰。`;
        saveCurrent();
      }
      render();
      return;
    }
    if (action.startsWith('wardrobe-equip-')) {
      const rest = action.slice('wardrobe-equip-'.length);
      const dash = rest.indexOf('-');
      const slot = rest.slice(0, dash);
      const id = rest.slice(dash + 1);
      const acc = ACCESSORY_DEFS[id];
      if (acc && acc.slot === slot && app.save?.wardrobe?.owned?.[id]) {
        app.save.wardrobe.equipped[slot] = id;
        syncPetRogueWorkerVisuals();
        app.message = `给${app.save.pet?.name || '宠物'}戴上了${acc.name}。`;
        saveCurrent();
      }
      render();
      return;
    }
    const activeGameModule = gameModule(app.games.selected);
    if (activeGameModule && !activeGameModule.legacy && typeof activeGameModule.handleAction === 'function') {
      try {
        if (activeGameModule.handleAction(action, event, gameState(app.games.selected, false), gameExtensionApi(app.games.selected)) === true) return;
      } catch (error) { console.error(`[像素拓麻歌子] 小游戏 ${app.games.selected} 操作处理失败：`, error); }
    }
    if (action === 'game-manager-open') { pauseActiveGame(false); app.games.managerOpen = true; app.games.selected = null; syncBackgroundMusicForCurrentView(); render(); return; }
    if (action === 'game-manager-close') { app.games.managerOpen = false; render(); return; }
    if (action.startsWith('game-install-')) { const gameId = action.slice('game-install-'.length); if (setGameInstalled(gameId, true)) render(); return; }
    if (action.startsWith('game-uninstall-')) { const gameId = action.slice('game-uninstall-'.length); if (setGameInstalled(gameId, false)) render(); return; }
    if (action.startsWith('game-select-')) {
      const gameId = action.slice('game-select-'.length);
      if (GAME_DEFS[gameId] && isGameInstalled(gameId)) {
        pauseActiveGame(false);
        app.games.managerOpen = false;
        app.games.selected = gameId;
        app.games.leaderboardOpen = false;
        app.games.leaderboardGameId = gameId;
        gameState(gameId, true);
        syncBackgroundMusicForCurrentView();
        render();
        if (GAME_DEFS[gameId]?.leaderboard !== false) void loadLeaderboard(gameId, true);
      }
      return;
    }
    if (action.startsWith('game-minesweeper-preset-')) {
      setMinesweeperPreset(action.slice('game-minesweeper-preset-'.length));
      return;
    }
    if (action.startsWith('game-petrogue-start-')) {
      const weaponId = action.slice('game-petrogue-start-'.length);
      if (PET_ROGUE_WEAPONS[weaponId]) { app.games.petRogueStartWeapon = weaponId; app.games.petRogue = createPetRogueState(weaponId); render(); }
      return;
    }
    if (action === 'game-petrogue-reroll') { if (!sendPetRogueWorkerMessage('petRogueReroll')) petRogueRerollChoices(app.games.petRogue); return; }
    if (action.startsWith('game-petrogue-upgrade-')) { const index = Number(action.slice('game-petrogue-upgrade-'.length)); if (!sendPetRogueWorkerMessage('petRogueUpgrade', { index })) petRogueApplyUpgrade(app.games.petRogue, index); return; }
    if (action === 'game-petrogue-dash') { requestPetRogueDash(app.games.petRogue); return; }
    if (action.startsWith('game-start-')) {
      const gameId = action.slice('game-start-'.length);
      if (GAME_DEFS[gameId] && isGameInstalled(gameId)) startGame(gameId);
      return;
    }
    if (action === 'game-exit') {
      exitSelectedGame();
      return;
    }
    if (action === 'game-pause') {
      if (pauseActiveGame(true)) render();
      return;
    }
    if (action === 'game-resume') {
      resumeGame();
      return;
    }
    if (action === 'game-move-left') { moveTetris(-1, 0); render(); return; }
    if (action === 'game-move-right') { moveTetris(1, 0); render(); return; }
    if (action === 'game-soft-drop') { moveTetris(0, 1, true); render(); return; }
    if (action === 'game-hard-drop') { hardDropTetris(); render(); return; }
    if (action === 'game-rotate') { rotateTetris(); render(); return; }
