        pet.hunger = clampPetStat(pet, 'hunger', pet.hunger - 5 * petLossMultiplier(pet, 'hunger', 'activity'));
        pet.weight = Math.max(0.5, pet.weight - 0.1);
        rewardCompanionAction(app.save, 4);
        playTransient('tickle', extensionActionMessage(pet, 'play') || (getCompanionTier(pet.companionship).id === 'first' ? '它渐渐放松下来，开始跟着玩具移动。' : '再来一次！只要和你一起，我就还没有玩够。'), 1600);
