        if (!requireItem('soap')) return;
        pet.cleanliness = petStatMax(pet, 'cleanliness');
        pet.mess = 0;
        pet.wasteProgressHours = 0;
        pet.happiness = clamp(pet.happiness + 4);
        rewardCompanionAction(app.save, 2);
        playTransient('pat', extensionActionMessage(pet, 'clean') || '闪闪发亮！它把收拾好的位置留在你旁边。', 1500);
        break;
      case 'sleep': {
        if (!pet.sleeping) {
          const sleepAt = nowMs();
          pet.sleeping = true;
          pet.sleepStartedAt = sleepAt;
          pet.sleepStartEnergy = pet.energy;
          if (new Date(sleepAt).getHours() < CONFIG.scheduleStartHour) {
            pet.nightSleepDayKey = localDayKey(sleepAt);
            pet.nightSleepActive = true;
          } else {
            pet.nightSleepActive = false;
          }
          app.message = extensionActionMessage(pet, 'sleep') || '晚安……睡眠每小时恢复 10 点精力；夜间会在早上 8 点自动醒来。';
        } else {
          const sleptHours = Math.max(0, (nowMs() - Number(pet.sleepStartedAt || nowMs())) / 3600000);
          const recovered = Math.max(0, pet.energy - Number(pet.sleepStartEnergy ?? pet.energy));
          pet.sleeping = false;
          pet.sleepStartedAt = null;
          pet.sleepStartEnergy = null;
          pet.nightSleepActive = false;
          app.message = extensionActionMessage(pet, 'wake', { result: { sleptHours, recovered } }) || `睡了 ${formatDuration(sleptHours)}，精力恢复约 ${Math.round(recovered)} 点。`;
        }
        rewardCompanionAction(app.save, 1);
        app.transientAnimation = null;
        render();
        break;
      }
      case 'heal':
        if (pet.health >= petStatMax(pet, 'health')) {
          app.message = '健康已经是满值，不需要吃药。';
          render();
        } else {
          if (!requireItem('medicine')) return;
          pet.health = clampPetStat(pet, 'health', pet.health + 35);
          pet.happiness = clamp(pet.happiness - 4);
          pet.sick = pet.health < 35;
          rewardCompanionAction(app.save, 3);
          playTransient('hug', extensionActionMessage(pet, 'heal') || '药有一点苦，不过你在旁边，身体就舒服多了。', 1500);
        }
        break;
      default:
        return;
    }
    maybeTriggerRandomEvent(app.save);
    saveCurrent();
  }

