  function promptInventorySummary(save) {
    if (!save) return '空';
    const owned = Object.entries(ITEMS)
      .filter(([id]) => Number(save.inventory?.[id] || 0) > 0)
      .map(([id, item]) => `${id}=${item.name}×${Number(save.inventory[id] || 0)}[${item.category}]`);
    return owned.length ? owned.join('；') : '空';
  }

  function promptScheduleSummary(save) {
    if (!save) return '当前：无；今日执行：无；每日计划：无';
    const current = (save.schedule?.today || []).find((task) => task.status === 'active');
    const today = (save.schedule?.today || []).map((task, index) => {
      const def = activityDefinition(task.category, task.activityId);
      return `#${index + 1}{schedule_id:${task.id},category:${task.category},activity:${task.activityId},hours:${task.durationHours},name:${def?.name || task.activityId},status:${task.status}}`;
    }).join(' → ');
    const template = (save.schedule?.template || []).map((task, index) => {
      const def = activityDefinition(task.category, task.activityId);
      return `#${index + 1}{schedule_id:${task.templateId},category:${task.category},activity:${task.activityId},hours:${task.durationHours},name:${def?.name || task.activityId}}`;
    }).join(' → ');
    const flag = save.schedule?.todayTouched ? '今日执行已单独设定' : save.schedule?.planApplied ? '今日执行已套用每日计划' : '今日执行未设定（8点将自动套用每日计划）';
    return `当前：${current ? `${activityDefinition(current.category, current.activityId)?.name || current.activityId} ${Math.round((current.progressHours || 0) / Math.max(0.01, current.durationHours) * 100)}%` : '无'}；状态：${flag}；今日执行(scope=today，删除用其schedule_id)：${today || '无'}；每日计划(scope=template)：${template || '无'}`;
  }

  function promptActivityCatalog(save) {
