        } else if (STAT_LABEL[key]) {
          parts.push(`${STAT_LABEL[key]}${fmtNum(value)}`);
        }
      });
      if (effects.attributes) {
        Object.entries(effects.attributes).forEach(([key, value]) => parts.push(`${ATTRIBUTE_DEFS[key]?.name || key}${fmtNum(value)}`));
      }
      return parts.join('，') || '无直接数值';
    };
    const fmtAttrReward = (rewards = {}) => Object.entries(rewards)
