  function resolveWorldbookApi(name) {
    const direct = {
      getWorldbookNames: typeof getWorldbookNames === 'function' ? getWorldbookNames : null,
      getGlobalWorldbookNames: typeof getGlobalWorldbookNames === 'function' ? getGlobalWorldbookNames : null,
      rebindGlobalWorldbooks: typeof rebindGlobalWorldbooks === 'function' ? rebindGlobalWorldbooks : null,
      createWorldbook: typeof createWorldbook === 'function' ? createWorldbook : null,
      getWorldbook: typeof getWorldbook === 'function' ? getWorldbook : null,
      createWorldbookEntries: typeof createWorldbookEntries === 'function' ? createWorldbookEntries : null,
      updateWorldbookWith: typeof updateWorldbookWith === 'function' ? updateWorldbookWith : null,
    }[name];
    if (direct) return direct;
    const candidates = [
      typeof TavernHelper !== 'undefined' ? TavernHelper : null,
      host?.TavernHelper,
      window?.TavernHelper,
    ];
    for (const candidate of candidates) {
      if (candidate && typeof candidate[name] === 'function') return candidate[name].bind(candidate);
    }
    return null;
  }

  function managedWorldbookEntry(kind, content) {
    const meta = {
      rules: { name: WORLD_BOOK_RULE_ENTRY_NAME, marker: WORLD_BOOK_RULE_MARKER, order: 1001 },
      data: { name: WORLD_BOOK_DATA_ENTRY_NAME, marker: WORLD_BOOK_DATA_MARKER, order: 1000 },
      reference: { name: WORLD_BOOK_REFERENCE_ENTRY_NAME, marker: WORLD_BOOK_REFERENCE_MARKER, order: 1002 },
    }[kind] || { name: WORLD_BOOK_DATA_ENTRY_NAME, marker: WORLD_BOOK_DATA_MARKER, order: 1000 };
    return {
      name: meta.name,
      enabled: true,
      strategy: {
        type: 'constant',
        keys: [],
        keys_secondary: { logic: 'and_any', keys: [] },
        scan_depth: 'same_as_global',
      },
      position: { type: 'before_character_definition', role: 'system', depth: 0, order: meta.order },
      content,
      probability: 100,
      recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
      effect: { sticky: null, cooldown: null, delay: null },
      extra: { pixel_tamagotchi_marker: meta.marker },
    };
  }

  function worldbookEntryKind(entry) {
    const marker = entry?.extra?.pixel_tamagotchi_marker;
    if (marker === WORLD_BOOK_RULE_MARKER || entry?.name === WORLD_BOOK_RULE_ENTRY_NAME) return 'rules';
    if (marker === WORLD_BOOK_DATA_MARKER || entry?.name === WORLD_BOOK_DATA_ENTRY_NAME) return 'data';
    if (marker === WORLD_BOOK_REFERENCE_MARKER || entry?.name === WORLD_BOOK_REFERENCE_ENTRY_NAME) return 'reference';
    return null;
  }

  async function ensurePixelWorldbook() {
    const getNames = resolveWorldbookApi('getWorldbookNames');
    const createBook = resolveWorldbookApi('createWorldbook');
    const getBook = resolveWorldbookApi('getWorldbook');
    const createEntries = resolveWorldbookApi('createWorldbookEntries');
    if (!getNames || !createBook || !getBook || !createEntries) throw new Error('当前酒馆助手环境没有提供完整的世界书接口');

    const names = await Promise.resolve(getNames());
    if (!Array.isArray(names) || !names.includes(WORLD_BOOK_NAME)) {
      await createBook(WORLD_BOOK_NAME, []);
    }

    let entries = await getBook(WORLD_BOOK_NAME);
    const kinds = new Set((entries || []).map(worldbookEntryKind).filter(Boolean));
    const missing = [];
    if (!kinds.has('rules')) missing.push(managedWorldbookEntry('rules', DEFAULT_WORLD_BOOK_RULES));
    if (!kinds.has('data')) missing.push(managedWorldbookEntry('data', buildWorldbookStateContent()));
    if (!kinds.has('reference')) missing.push(managedWorldbookEntry('reference', buildWorldbookReferenceContent()));
    if (missing.length) {
      await createEntries(WORLD_BOOK_NAME, missing, { render: 'debounced' });
      entries = await getBook(WORLD_BOOK_NAME);
    }

    app.worldbookReady = true;
    return entries;
  }

  async function setPixelWorldbookGlobalEnabled(enabled) {
    const getGlobals = resolveWorldbookApi('getGlobalWorldbookNames');
    const bindGlobals = resolveWorldbookApi('rebindGlobalWorldbooks');
    if (!getGlobals || !bindGlobals) throw new Error('当前酒馆助手环境没有提供全局世界书绑定接口');

    const current = await Promise.resolve(getGlobals());
    const globals = Array.isArray(current) ? current.filter((name) => typeof name === 'string' && name) : [];
    const exists = globals.includes(WORLD_BOOK_NAME);
    const next = enabled
      ? (exists ? globals : [...globals, WORLD_BOOK_NAME])
      : globals.filter((name) => name !== WORLD_BOOK_NAME);

    if (next.length !== globals.length || next.some((name, index) => name !== globals[index])) {
      await bindGlobals(next);
    }
    return true;
  }

  function queueWorldbookSync(delay = 220, force = false) {
    if (app.worldbookSyncTimer) host.clearTimeout(app.worldbookSyncTimer);
    const token = ++app.worldbookSyncToken;
    app.worldbookSyncTimer = host.setTimeout(() => {
      app.worldbookSyncTimer = null;
      if (token !== app.worldbookSyncToken) return;
      void syncPixelWorldbookNow(force);
    }, Math.max(0, Number(delay) || 0));
  }

  async function syncPixelWorldbookNow(force = false) {
    const token = ++app.worldbookSyncToken;
    try {
      const enabled = Boolean(app.save?.settings?.charCareIntegration);
      await ensurePixelWorldbook();
      await setPixelWorldbookGlobalEnabled(enabled);
      if (token !== app.worldbookSyncToken) return false;
      const updater = resolveWorldbookApi('updateWorldbookWith');
      if (!updater) throw new Error('缺少 updateWorldbookWith 世界书更新接口');
      const stateContent = buildWorldbookStateContent();
      const referenceContent = buildWorldbookReferenceContent();
      const nextHash = simpleHash(`${enabled ? 1 : 0}|${app.characterKey || ''}|v2|${stateContent}|${referenceContent}`);
      if (!force && nextHash === app.worldbookLastHash) return true;

      await updater(WORLD_BOOK_NAME, (worldbook) => (worldbook || []).map((entry) => {
        const kind = worldbookEntryKind(entry);
        if (kind === 'rules') {
          const currentContent = String(entry.content || '');
          const isManagedDefault = [LEGACY_DEFAULT_WORLD_BOOK_RULES_V1, LEGACY_DEFAULT_WORLD_BOOK_RULES_V2]
            .some((legacy) => currentContent.trim() === legacy.trim());
          const migratedContent = isManagedDefault ? DEFAULT_WORLD_BOOK_RULES : currentContent;
          return {
            ...entry,
            content: migratedContent,
            enabled,
            strategy: managedWorldbookEntry('rules', '').strategy,
            position: managedWorldbookEntry('rules', '').position,
            probability: 100,
            recursion: managedWorldbookEntry('rules', '').recursion,
            effect: managedWorldbookEntry('rules', '').effect,
            extra: { ...(entry.extra || {}), pixel_tamagotchi_marker: WORLD_BOOK_RULE_MARKER },
          };
        }
        if (kind === 'data') {
          const managed = managedWorldbookEntry('data', stateContent);
          return { ...entry, ...managed, uid: entry.uid, extra: { ...(entry.extra || {}), ...managed.extra } };
        }
        if (kind === 'reference') {
          const managed = managedWorldbookEntry('reference', referenceContent);
          return { ...entry, ...managed, uid: entry.uid, extra: { ...(entry.extra || {}), ...managed.extra } };
        }
        return entry;
      }), { render: 'debounced' });
      app.worldbookLastHash = nextHash;
      return true;
    } catch (error) {
      console.warn('[像素拓麻歌子] 世界书同步失败：', error);
      app.worldbookReady = false;
      return false;
    }
  }

  function simpleHash(text) {
    let hash = 2166136261;
    for (let i = 0; i < text.length; i += 1) { hash ^= text.charCodeAt(i); hash = Math.imul(hash, 16777619); }
    return (hash >>> 0).toString(36);
  }

  function normalizeCharAction(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const aliases = {
      喂食: 'feed', 玩耍: 'play', 清洁: 'clean', 治疗: 'heal', 睡觉: 'sleep', 叫醒: 'wake', 触摸: 'touch',
      添加日程: 'schedule_add', 删除日程: 'schedule_delete', 清空日程: 'schedule_clear',
      换装: 'dress', 穿戴: 'dress', 戴上: 'dress', 装扮: 'dress', 脱下: 'undress', 卸下: 'undress', 取下: 'undress',
    };
    const type = aliases[String(raw.type || raw.action || '').trim()] || String(raw.type || raw.action || '').trim().toLowerCase();
    if (!['feed', 'play', 'clean', 'heal', 'sleep', 'wake', 'touch', 'schedule_add', 'schedule_delete', 'schedule_clear', 'dress', 'undress'].includes(type)) return null;
    if (['feed', 'play', 'clean', 'heal'].includes(type)) {
      let count = Math.floor(Number(raw.count ?? raw.quantity ?? raw.amount ?? 1));
      if (!Number.isFinite(count) || count < 1) count = 1;
      count = Math.min(count, CONFIG.maxCareItemBatch);
      return { type, item: String(raw.item || 'auto').trim() || 'auto', count };
    }
    const parseScope = (raw2) => {
      const v = String(raw2.scope || raw2.target || raw2.list || '').trim().toLowerCase();
      if (['template', 'daily', 'plan', '每日', '每日计划', '计划', '模板'].includes(v)) return 'template';
      return 'today';
    };
    if (type === 'schedule_add') {
      return {
        type,
        category: String(raw.category || '').trim().toLowerCase(),
        activity: String(raw.activity || raw.activityId || '').trim(),
        hours: Number(raw.hours ?? raw.durationHours),
        scope: parseScope(raw),
      };
    }
    if (type === 'schedule_delete') {
      return {
        type,
        scheduleId: String(raw.schedule_id || raw.scheduleId || raw.templateId || '').trim(),
        index: Number(raw.index),
        scope: parseScope(raw),
      };
    }
    if (type === 'schedule_clear') {
      return { type, scope: parseScope(raw) };
    }
    if (type === 'dress' || type === 'undress') {
      const slotRaw = String(raw.slot || raw.position || '').trim().toLowerCase();
      const slot = ['head', '头顶', '头', '发饰'].includes(slotRaw) ? 'head'
        : ['eyes', 'eye', '眼部', '眼', '眼睛', '面部'].includes(slotRaw) ? 'eyes'
        : '';
      if (type === 'undress') return { type, slot };
      return { type, slot, item: String(raw.item || raw.accessory || raw.id || '').trim() };
    }
    return { type };
  }

  function parseCharCareJson(payload) {
    const cleaned = String(payload || '')
      .trim()
      .replace(/^```(?:json)?\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();
    return JSON.parse(cleaned);
  }

  function decodeCharCareSource(text) {
    let source = String(text || '');
    // 某些酒馆版本/正则链会把控制标签转义一层；只在解析副本中还原，正文原文保持不动。
    for (let pass = 0; pass < 2; pass += 1) {
      source = source
        .replace(/&lt;/gi, '<')
        .replace(/&gt;/gi, '>')
        .replace(/&quot;/gi, '"')
        .replace(/&#(?:39|x27);/gi, "'")
        .replace(/&amp;/gi, '&');
    }
    return source;
  }

  function parseCharCareControls(text) {
    const original = String(text || '');
    const source = decodeCharCareSource(original);
    const groupedRegex = /<tama_actions>\s*([\s\S]*?)\s*<\/tama_actions>/gi;
    const legacyRegex = /<tama_action>\s*([\s\S]*?)\s*<\/tama_action>/gi;
    const thoughtRegex = /<tama_thought>\s*([\s\S]*?)\s*<\/tama_thought>/i;
    const actions = [];
    const appendAction = (raw) => {
      if (actions.length >= CONFIG.maxCharActionsPerReply) return;
      const parsed = normalizeCharAction(raw);
      if (parsed) actions.push(parsed);
    };

    let match;
    while ((match = groupedRegex.exec(source)) && actions.length < CONFIG.maxCharActionsPerReply) {
      try {
        const payload = parseCharCareJson(match[1]);
        const list = Array.isArray(payload)
          ? payload
          : (Array.isArray(payload?.actions) ? payload.actions : [payload]);
        for (const raw of list) {
          appendAction(raw);
          if (actions.length >= CONFIG.maxCharActionsPerReply) break;
        }
      } catch (error) {
        console.debug('[像素拓麻歌子] 忽略无法解析的角色操作数组：', match[1], error);
      }
    }

    // 兼容旧版逐条 <tama_action>，并允许心里话出现在操作前面或后面。
    while ((match = legacyRegex.exec(source)) && actions.length < CONFIG.maxCharActionsPerReply) {
      try {
        appendAction(parseCharCareJson(match[1]));
      } catch (error) {
        console.debug('[像素拓麻歌子] 忽略无法解析的旧版角色操作：', match[1], error);
      }
    }

    const thoughtMatch = source.match(thoughtRegex);
    const thought = thoughtMatch ? String(thoughtMatch[1]).trim().slice(0, 240) : '';
    return { actions, thought, cleaned: original.trim() };
  }

  function chooseCharItem(category, preferred) {
    if (preferred && preferred !== 'auto') {
      return ITEMS[preferred]?.category === category && Number(app.save.inventory[preferred] || 0) > 0 ? preferred : null;
    }
    const available = itemsByCategory(category).filter(([id]) => Number(app.save.inventory[id] || 0) > 0);
    return available[0]?.[0] || null;
  }

  function describeCharAction(action) {
    const names = { feed: '喂食', play: '陪它玩耍', clean: '帮它清洁', heal: '为它治疗', sleep: '哄它睡觉', wake: '叫醒它', touch: '摸摸它' };
    const category = { feed: 'food', play: 'toy', clean: 'clean', heal: 'medicine' }[action.type];
    if (category) {
      const item = action.item === 'auto' ? '自动选择物品' : ITEMS[action.item]?.name || action.item;
      return `${names[action.type]}（${item}）`;
    }
    if (action.type === 'schedule_add') {
      const def = activityDefinition(action.category, action.activity);
      return `${action.scope === 'template' ? '加入每日计划' : '加入今日执行'}：${def?.name || action.activity || '未知活动'} ${formatHours(action.hours)}`;
    }
    if (action.type === 'schedule_delete') {
      return `${action.scope === 'template' ? '删除每日计划' : '删除今日执行'}：${action.scheduleId || (Number.isFinite(action.index) ? `第${action.index}项` : '未指定')}`;
    }
    if (action.type === 'schedule_clear') return action.scope === 'template' ? '清空每日计划' : '清空今日执行';
    if (action.type === 'dress') {
      const acc = ACCESSORY_DEFS[action.item];
      const slot = (action.slot || acc?.slot) === 'head' ? '头顶' : '眼部';
      return `装扮${slot}（${acc ? acc.name : action.item || '配饰'}）`;
    }
    if (action.type === 'undress') return `取下${action.slot === 'head' ? '头顶' : '眼部'}配饰`;
    return names[action.type] || action.type;
  }

  function executeCharScheduleAdd(action) {
    const save = app.save;
    const pet = save?.pet;
    const category = action.category;
    const activityId = action.activity;
    const definition = activityDefinition(category, activityId);
    const hours = Number(action.hours);
    const scope = action.scope === 'template' ? 'template' : 'today';
    const scopeLabel = scope === 'template' ? '每日计划' : '今日执行';
    if (!save || !pet || !['study', 'fun', 'work', 'sleep'].includes(category) || !definition) {
      return { ok: false, text: '日程类型或具体行动无效。' };
    }
    const allowed = (definition.durations || []).some((value) => Math.abs(Number(value) - hours) < 0.0001);
    if (!Number.isFinite(hours) || !allowed) {
      return { ok: false, text: `「${definition.name}」不支持${formatHours(hours)}。` };
    }
    ensureScheduleDay(save, localDayKey());
    if (category === 'work' && !jobRequirementsMet(pet, definition)) {
      return { ok: false, text: `属性不足，无法安排「${definition.name}」。` };
    }
    const currentHours = scope === 'template' ? scheduleTemplateHours(save.schedule) : scheduleTodayHours(save.schedule);
    if (currentHours + hours > CONFIG.maxDailyScheduleHours + 0.0001) {
      return { ok: false, text: `${scopeLabel}超过${CONFIG.maxDailyScheduleHours}小时上限。` };
    }
    if (scope === 'template') {
      save.schedule.template.push({ templateId: scheduleId('tpl'), category, activityId, durationHours: hours });
    } else {
      save.schedule.today.push(cloneTemplateTaskForToday({ templateId: scheduleId('tpl'), category, activityId, durationHours: hours }));
      save.schedule.todayTouched = true;
      save.schedule.planApplied = true;
    }
    return { ok: true, text: `往${scopeLabel}添加了「${definition.name}」${formatHours(hours)}。`, mode: category === 'sleep' ? 'sleep' : 'highfive', logType: 'schedule_add', logText: `${scopeLabel}：「${definition.name}」${formatHours(hours)}` };
  }

  function executeCharScheduleDelete(action) {
    const schedule = app.save?.schedule;
    if (!schedule) return { ok: false, text: '当前没有日程数据。' };
    const scope = action.scope === 'template' ? 'template' : 'today';
    const scopeLabel = scope === 'template' ? '每日计划' : '今日执行';
    const list = scope === 'template' ? schedule.template : schedule.today;
    let target = null;
    if (action.scheduleId) target = list.find((task) => (scope === 'template' ? task.templateId : task.id) === action.scheduleId) || null;
    if (!target && Number.isFinite(action.index) && action.index >= 1) target = list[Math.floor(action.index) - 1] || null;
    if (!target) return { ok: false, text: `在${scopeLabel}里找不到要删除的日程。` };
    const definition = activityDefinition(target.category, target.activityId);
    if (scope === 'template') {
      schedule.template = schedule.template.filter((task) => task.templateId !== target.templateId);
    } else {
      schedule.today = schedule.today.filter((task) => task.id !== target.id);
      schedule.todayTouched = true;
      schedule.planApplied = true;
    }
    return { ok: true, text: `从${scopeLabel}删除了「${definition?.name || target.activityId}」${formatHours(target.durationHours)}。`, mode: 'pat', logType: 'schedule_delete', logText: `${scopeLabel}删除「${definition?.name || target.activityId}」` };
  }

  function executeCharScheduleClear(action) {
    const schedule = app.save?.schedule;
    if (!schedule) return { ok: false, text: '当前没有日程数据。' };
    const scope = action?.scope === 'template' ? 'template' : 'today';
    const scopeLabel = scope === 'template' ? '每日计划' : '今日执行';
    if (scope === 'template') {
      if (!schedule.template.length) return { ok: false, text: '每日计划本来就是空的。' };
      const count = schedule.template.length;
      schedule.template = [];
      return { ok: true, text: `清空了全部${count}项每日计划。`, mode: 'pat', logType: 'schedule_clear', logText: `清空每日计划（${count}项）` };
    }
    const pending = schedule.today.filter((task) => !['done', 'cancelled'].includes(task.status)).length;
    if (!schedule.today.length) return { ok: false, text: '今日执行本来就是空的。' };
    schedule.today = schedule.today.filter((task) => task.status === 'done');
    schedule.todayTouched = true;
    schedule.planApplied = true;
    return { ok: true, text: `清空了今日执行（${pending}项）。`, mode: 'pat', logType: 'schedule_clear', logText: `清空今日执行（${pending}项）` };
  }

  function executeCharCareAction(action) {
    const pet = app.save?.pet;
    if (!pet) return { ok: false, text: '当前没有宠物。' };
    const category = { feed: 'food', play: 'toy', clean: 'clean', heal: 'medicine' }[action.type];
    if (category) {
      const itemId = chooseCharItem(category, action.item);
      if (!itemId) {
        const requested = action.item && action.item !== 'auto' ? `指定物品「${action.item}」不可用或分类不匹配。` : `${ITEM_CATEGORY_META[category].name}已经用完了。`;
        return { ok: false, text: requested };
      }
      return useCareItem(itemId, 'char', Number(action.count) || 1);
    }
    if (action.type === 'schedule_add') return executeCharScheduleAdd(action);
    if (action.type === 'schedule_delete') return executeCharScheduleDelete(action);
    if (action.type === 'schedule_clear') return executeCharScheduleClear(action);
    if (action.type === 'sleep') {
      if (pet.sleeping) return { ok: false, text: `${pet.name}已经睡着了。` };
      const sleepAt = nowMs();
      pet.sleeping = true; pet.sleepStartedAt = sleepAt; pet.sleepStartEnergy = pet.energy;
      if (new Date(sleepAt).getHours() < CONFIG.scheduleStartHour) {
        pet.nightSleepDayKey = localDayKey(sleepAt);
        pet.nightSleepActive = true;
      } else pet.nightSleepActive = false;
      rewardCompanionAction(app.save, 0.5);
      return { ok: true, text: `哄${pet.name}睡着了。`, mode: 'sleep', logType: 'sleep', logText: '哄它睡觉' };
    }
    if (action.type === 'wake') {
      if (!pet.sleeping) return { ok: false, text: `${pet.name}现在是醒着的。` };
      pet.sleeping = false; pet.sleepStartedAt = null; pet.sleepStartEnergy = null; pet.nightSleepActive = false;
      return { ok: true, text: `轻轻叫醒了${pet.name}。`, mode: 'pat', logType: 'wake', logText: '叫醒它' };
    }
    if (action.type === 'touch') {
      if (pet.sleeping) return { ok: false, text: `${pet.name}正在睡觉。` };
      pet.happiness = clamp(pet.happiness + 3);
      changeCompanionship(app.save, 0.5);
      return { ok: true, text: `温柔地摸了摸${pet.name}。`, mode: 'pat', logType: 'touch', logText: '摸摸它' };
    }
    if (action.type === 'dress') {
      const acc = ACCESSORY_DEFS[action.item];
      if (!acc) return { ok: false, text: `没有名为「${action.item}」的配饰。` };
      const slot = action.slot && (action.slot === 'head' || action.slot === 'eyes') ? action.slot : acc.slot;
      if (acc.slot !== slot) return { ok: false, text: `${acc.name}不能戴在${slot === 'head' ? '头顶' : '眼部'}。` };
      if (!app.save?.wardrobe?.owned?.[action.item]) return { ok: false, text: `还没有购买${acc.name}，无法佩戴。` };
      app.save.wardrobe.equipped[slot] = action.item;
      syncPetRogueWorkerVisuals();
      return { ok: true, text: `给${pet.name}的${slot === 'head' ? '头顶' : '眼部'}戴上了${acc.name}。`, mode: 'shy', logType: 'dress', logText: `戴上「${acc.name}」` };
    }
    if (action.type === 'undress') {
      const slot = action.slot === 'head' || action.slot === 'eyes' ? action.slot : '';
      if (!slot) return { ok: false, text: '没有指定要取下的部位。' };
      const current = app.save?.wardrobe?.equipped?.[slot];
      if (!current) return { ok: false, text: `${slot === 'head' ? '头顶' : '眼部'}本来就没有配饰。` };
      const acc = ACCESSORY_DEFS[current];
      app.save.wardrobe.equipped[slot] = null;
      syncPetRogueWorkerVisuals();
      return { ok: true, text: `取下了${pet.name}${slot === 'head' ? '头顶' : '眼部'}的${acc?.name || '配饰'}。`, mode: 'pat', logType: 'undress', logText: `取下${slot === 'head' ? '头顶' : '眼部'}配饰` };
    }
    return { ok: false, text: '无法识别的操作。' };
  }

  function applyCharCarePackage(pkg) {
    if (!pkg || !app.save || app.save.lifecycle !== 'alive') return;
    const results = pkg.actions.map(executeCharCareAction);
    const success = results.filter((result) => result.ok);
    const summary = results.map((result) => result.text).join(' ');
    if (success.length) {
      results.forEach((result, index) => {
        if (!result.ok) return;
        const action = pkg.actions[index] || {};
        pushCareLog('char', result.logType || action.type || 'other', result.logText || result.text || '', { actorName: pkg.charName || (refreshLiveCharacterName() || '角色'), thought: index === 0 ? (pkg.thought || '') : '' });
      });
      app.save.charCare.history.push({ at: nowMs(), charName: pkg.charName, summary, thought: pkg.thought || '' });
      app.save.charCare.history = app.save.charCare.history.slice(-30);
      maybeTriggerRandomEvent(app.save);
      app.message = pkg.thought || `${pkg.charName}：${summary}`;
    } else {
      app.message = `${pkg.charName}想照顾宠物，但没有成功：${summary}`;
    }
    saveCurrent();
    updateFloatingButton();
    render();
  }

  function charActionItemInfo(action) {
    const category = { feed: 'food', play: 'toy', clean: 'clean', heal: 'medicine' }[action?.type];
    if (!category) return null;
    const resolvedId = chooseCharItem(category, action.item);
    const name = action.item && action.item !== 'auto'
      ? (ITEMS[action.item]?.name || action.item)
      : (resolvedId ? `${ITEMS[resolvedId]?.name || resolvedId}（自动）` : '自动选择物品');
    const available = resolvedId ? Number(app.save?.inventory?.[resolvedId] || 0) : 0;
    const max = Math.max(1, Math.min(CONFIG.maxCareItemBatch, available || 1));
    return { category, resolvedId, name, available, max };
  }

  function renderCharCareModal() {
    const pkg = app.pendingCharCare;
    if (!pkg) return '';
    const verbs = { feed: '喂食', play: '陪它玩耍', clean: '帮它清洁', heal: '为它治疗' };
    const rows = pkg.actions.map((action, index) => {
      const info = charActionItemInfo(action);
      if (info) {
        const count = Math.max(1, Math.min(Number(action.count) || 1, info.max));
        const avail = info.resolvedId ? `背包剩余 ${info.available}（最多可用 ${info.max}）` : '背包暂无可用物品';
        return `<div class="ptg-care-row"><div class="ptg-care-row-line"><span class="ptg-care-row-main">• ${escapeHtml(verbs[action.type] || '使用')}（${escapeHtml(info.name)}）</span><span class="ptg-care-stepper"><button type="button" data-action="char-care-count-dec-${index}" ${count <= 1 ? 'disabled' : ''}>−</button><b>×${count}</b><button type="button" data-action="char-care-count-inc-${index}" ${(count >= info.max || !info.resolvedId) ? 'disabled' : ''}>+</button></span></div><small class="ptg-care-avail">${escapeHtml(avail)}</small></div>`;
      }
      return `<div class="ptg-care-row"><div class="ptg-care-row-line"><span class="ptg-care-row-main">• ${escapeHtml(describeCharAction(action))}</span></div></div>`;
    }).join('');
    return `<div class="ptg-runtime-overlay ptg-char-care-overlay"><div class="ptg-runtime-card"><div class="ptg-runtime-head"><strong>${escapeHtml(pkg.charName)}想照顾宠物</strong></div><div class="ptg-runtime-note ptg-care-rows">${rows}</div>${pkg.thought ? `<div class="ptg-char-thought">心里话：“${escapeHtml(pkg.thought)}”</div>` : ''}<p>可调整每项物品的使用数量，再决定是否同步到存档。</p><div class="ptg-runtime-actions"><button type="button" class="ptg-primary" data-action="char-care-allow">允许操作</button><button type="button" class="ptg-secondary" data-action="char-care-reject">暂不允许</button></div></div></div>`;
  }

  function charCareGenerationActive() {
    try {
      if (typeof builtin !== 'undefined' && typeof builtin.duringGenerating === 'function') return Boolean(builtin.duringGenerating());
    } catch (_) {}
    return false;
  }

  function readAssistantMessageSnapshot(messageId) {
    if (typeof getChatMessages !== 'function') return null;
    const id = Number(messageId);
    if (!Number.isFinite(id)) return null;
    const messages = getChatMessages(id, { include_swipes: false }) || [];
    const message = messages.find((entry) => Number(entry?.message_id) === id) || messages[0] || null;
    if (!message || message.role !== 'assistant') return null;
    const text = String(message.message || '');
    return text ? { message, text } : null;
  }

  function hasCompleteCharCareAction(text) {
    const source = decodeCharCareSource(text);
    return /<\/tama_actions>|<\/tama_action>/i.test(source);
  }

  async function readStableAssistantMessage(messageId) {
    let latest = null;
    let previousText = '';
    let stableReads = 0;
    for (let attempt = 0; attempt < 24; attempt += 1) {
      const snapshot = readAssistantMessageSnapshot(messageId);
      if (snapshot) {
        latest = snapshot.message;
        if (snapshot.text === previousText) stableReads += 1;
        else {
          previousText = snapshot.text;
          stableReads = 0;
        }
        const generating = charCareGenerationActive();
        // 控制标签通常位于回复结尾。必须等完整闭合标签写入并至少稳定一次，避免流式生成时过早读取半截正文。
        if (hasCompleteCharCareAction(snapshot.text) && !generating && stableReads >= 1) return snapshot.message;
        // 没有操作标签的普通回复也在稳定后结束检查，避免长期轮询。
        if (!generating && stableReads >= 3) return snapshot.message;
      }
      await new Promise((resolve) => host.setTimeout(resolve, 120 + Math.min(attempt, 6) * 20));
    }
    return latest;
  }

  function clearRuntimeMessageBannerTimers() {
    app.runtimeMessageBannerTimers.forEach((timer) => host.clearTimeout(timer));
    app.runtimeMessageBannerTimers.clear();
  }

  function clearCharCareScanTimers() {
    app.charCareScanTimers.forEach((timer) => host.clearTimeout(timer));
    app.charCareScanTimers.clear();
    clearRuntimeMessageBannerTimers();
  }

  function messageBannerElement() {
    return app.root?.querySelector?.('.ptg-message-banner') || null;
  }

  function clearMessageBanner(immediate = true) {
    if (app.messageBannerTimer) {
      host.clearTimeout(app.messageBannerTimer);
      app.messageBannerTimer = null;
    }
    if (app.messageBannerHideTimer) {
      host.clearTimeout(app.messageBannerHideTimer);
      app.messageBannerHideTimer = null;
    }
    const banner = messageBannerElement();
    if (!banner) return;
    banner.classList.remove('is-visible');
    if (immediate) {
      banner.classList.remove('is-leaving');
      banner.hidden = true;
      return;
    }
    banner.classList.add('is-leaving');
    app.messageBannerHideTimer = host.setTimeout(() => {
      app.messageBannerHideTimer = null;
      banner.classList.remove('is-leaving');
      banner.hidden = true;
    }, 340);
  }

  function showCharacterMessageBanner(messageId, rawMessage, message) {
    if (!app.root?.classList.contains('ptg-open')) return;
    const key = `${Number(messageId)}:${simpleHash(String(rawMessage || ''))}`;
    if (app.processedMessageBanners.has(key)) return;
    app.processedMessageBanners.add(key);
    if (app.processedMessageBanners.size > 100) {
      app.processedMessageBanners = new Set([...app.processedMessageBanners].slice(-60));
    }

    const banner = messageBannerElement();
    if (!banner) return;
    const charName = String(message?.name || message?.character_name || refreshLiveCharacterName() || '角色').trim() || '角色';
    const text = banner.querySelector('[data-message-banner-text]');
    if (text) text.textContent = `${charName}给你发送了一条新消息~`;

    clearMessageBanner(true);
    banner.hidden = false;
    banner.classList.remove('is-leaving');
    // 强制浏览器提交隐藏状态，确保连续消息也会重新播放下滑动画。
    void banner.offsetWidth;
    banner.classList.add('is-visible');
    playSfx('message');
    app.messageBannerTimer = host.setTimeout(() => {
      app.messageBannerTimer = null;
      clearMessageBanner(false);
    }, 5000);
  }

  function scheduleRuntimeAssistantBanner(messageId, delay = 160) {
    const id = Number(messageId);
    if (!Number.isFinite(id) || !app.root?.classList.contains('ptg-open')) return;
    const previousTimer = app.runtimeMessageBannerTimers.get(id);
    if (previousTimer) host.clearTimeout(previousTimer);

    let attempts = 0;
    let previousText = '';
    let stableReads = 0;
    const poll = () => {
      app.runtimeMessageBannerTimers.delete(id);
      if (!app.root?.classList.contains('ptg-open')) return;
      const snapshot = readAssistantMessageSnapshot(id);
      const text = String(snapshot?.text || '');
      if (text && text === previousText) stableReads += 1;
      else {
        previousText = text;
        stableReads = 0;
      }
      attempts += 1;
      const generating = charCareGenerationActive();
      if (snapshot && !generating && stableReads >= 1) {
        showCharacterMessageBanner(id, text || `assistant-message:${id}`, snapshot.message);
        return;
      }
      // 只做轻量状态轮询，不在实时游戏中解析照顾指令；极端情况下超时后仍给出通用提示。
      if (attempts >= 240) {
        showCharacterMessageBanner(id, text || `assistant-message:${id}`, snapshot?.message || { name: refreshLiveCharacterName() || '角色' });
        return;
      }
      const timer = host.setTimeout(poll, 180);
      app.runtimeMessageBannerTimers.set(id, timer);
    };

    const timer = host.setTimeout(poll, Math.max(80, Number(delay) || 160));
    app.runtimeMessageBannerTimers.set(id, timer);
  }

  function scheduleAssistantMessageScan(messageId, delay = 260, showBanner = false) {
    const id = Number(messageId);
    if (!Number.isFinite(id)) return;
    if (shouldUseGameRuntime()) {
      // 游戏运行时仍立即显示新消息横幅，但把较重的回复解析延后到退出实时游戏后执行。
      if (showBanner) scheduleRuntimeAssistantBanner(id, delay);
      app.deferredAssistantScans.set(id, { showBanner: false });
      return;
    }
    const previous = app.charCareScanTimers.get(id);
    if (previous) host.clearTimeout(previous);
    const shouldShowBanner = Boolean(showBanner && app.root?.classList.contains('ptg-open'));
    const timer = host.setTimeout(() => { app.charCareScanTimers.delete(id); void onAssistantMessageReceived(id, shouldShowBanner); }, delay);
    app.charCareScanTimers.set(id, timer);
  }

  async function onAssistantMessageReceived(messageId, showBanner = false) {
    if (!Number.isFinite(Number(messageId))) return;
    try {
      const message = await readStableAssistantMessage(Number(messageId));
      if (!message) return;
      const rawMessage = String(message.message || '');
      if (showBanner) showCharacterMessageBanner(messageId, rawMessage, message);
      if (!app.save?.settings?.charCareIntegration) return;
      const parsed = parseCharCareControls(rawMessage);
      if (!parsed.actions.length) return;
      const key = `${messageId}:${simpleHash(rawMessage)}`;
      if (app.processedCharResponses.has(key)) return;
      app.processedCharResponses.add(key);
      if (app.processedCharResponses.size > 80) app.processedCharResponses = new Set([...app.processedCharResponses].slice(-50));
      const pkg = { actions: parsed.actions, thought: parsed.thought, charName: refreshLiveCharacterName() || '角色', messageId: Number(messageId) };
      if (app.root?.classList.contains('ptg-open')) {
        const state = selectedGameState();
        app.pendingCharCare = pkg;
        if (state?.status === 'running') { app.message = `${pkg.charName}想帮忙照顾宠物，已等你结束本局后确认。`; return; }
        app.message = `${pkg.charName}想帮忙照顾宠物，等待你的确认。`;
        render();
      } else {
        applyCharCarePackage(pkg);
      }
    } catch (error) {
      console.warn('[像素拓麻歌子] 读取角色照顾指令失败：', error);
    }
  }

  function onChatMessageSent() {
    if (!app.characterContextReady || !app.save || !app.save.settings.chatCompanion || app.save.lifecycle !== 'alive' || !app.save.pet) return;
    const info = getCharacterInfo();
    if (!info || info.key !== app.characterKey) return;
    resetDailyCounters(app.save);
    app.save.pet.happiness = clamp(app.save.pet.happiness + 1);
    changeCompanionship(app.save, 0.35);
    if (app.save.economy.chatCoinsToday < CONFIG.maxChatCoinsPerDay) {
      app.save.economy.chatCoinsToday += 1;
      addCoins(app.save, 1);
    }
    maybeTriggerRandomEvent(app.save);
    saveCurrent();
    if (app.root?.classList.contains('ptg-open')) {
      app.message = getCompanionTier(app.save.pet.companionship).id === 'beloved' ? '我听见你说话了。只要你在，我就不会觉得这个世界太小。' : companionLine(app.save.pet);
      render();
    }
  }

  function openPanel() {
    if (!ensureMainDom() || !app.root) return;
    const info = getCharacterInfo();
    if ((info?.key || null) !== app.characterKey || !app.characterContextReady) {
      loadCurrentCharacter(info);
    }
    if (app.save && app.characterContextReady) {
      settleTime(app.save);
      saveCurrent();
      app.message = getStatusMessage();
    } else if (info) {
      app.message = `正在读取「${info.name}」的宠物档与全局共享档……`;
    }
    const wasOpen = app.root.classList.contains('ptg-open');
    app.root.classList.add('ptg-open');
    if (!wasOpen) playSfx('power');
    syncBackgroundMusicForCurrentView();
    const backdrop = app.root.querySelector('.ptg-backdrop');
    if (backdrop) backdrop.style.setProperty('display', 'flex', 'important');
    if (app.pageOverflow === null) app.pageOverflow = doc.documentElement.style.overflow || '';
    doc.documentElement.style.setProperty('overflow', 'hidden', 'important');
    render();
    if (app.activeTab === 'games' && app.games.selected) {
      const state = selectedGameState();
      if (state && !['running', 'paused'].includes(state.status) && GAME_DEFS[app.games.selected]?.leaderboard !== false) {
        void loadLeaderboard(app.games.selected, true);
      }
    }
    app.root.querySelector('.ptg-close')?.focus();
  }

  function closePanel() {
    if (companionPlayState().open) resetCompanionPlay(false);
    app.itemPickerCategory = null;
    clearMessageBanner(true);
    pauseBackgroundMusic();
    pauseActiveGame(false);
    saveCurrent();
    // 关闭掌机前必须解除小游戏对酒馆主体的绘制隔离，否则主体会继续保持隐藏状态。
    leaveGameRuntime();
    app.root?.classList.remove('ptg-open');
    const backdrop = app.root?.querySelector('.ptg-backdrop');
    if (backdrop) backdrop.style.setProperty('display', 'none', 'important');
    if (app.pageOverflow !== null) {
      if (app.pageOverflow) doc.documentElement.style.setProperty('overflow', app.pageOverflow);
      else doc.documentElement.style.removeProperty('overflow');
      app.pageOverflow = null;
    }
  }

  function notify(type, message) {
    const toast = host.toastr || (typeof toastr !== 'undefined' ? toastr : null);
    if (toast?.[type]) toast[type](message);
    else console[type === 'error' ? 'error' : 'log'](`[像素拓麻歌子] ${message}`);
  }

  // v2 使用新的位置键：升级到本版时会自动放回左上方内侧，避开旧版遗留的贴底坐标。
  const FLOATING_POSITION_KEY = 'ptg_pixel_tamagotchi_floating_position_v2';
  const FLOATING_LEGACY_POSITION_KEYS = ['ptg_pixel_tamagotchi_floating_position_v1'];
  const FLOATING_SIZE = 58;
  const FLOATING_BUTTON_SIZE = 48;
  const FLOATING_MARGIN = 10;

  function floatingViewportSize() {
    const visualViewport = host.visualViewport;
    const width = Number(visualViewport?.width) || Number(host.innerWidth) || doc.documentElement.clientWidth || 360;
    const height = Number(visualViewport?.height) || Number(host.innerHeight) || doc.documentElement.clientHeight || 640;
    return {
      width: Math.max(FLOATING_SIZE + FLOATING_MARGIN * 2, width),
      height: Math.max(FLOATING_SIZE + FLOATING_MARGIN * 2, height),
    };
  }

  function defaultFloatingPosition() {
    const viewport = floatingViewportSize();
    // 默认放在左上区域的内侧，不紧贴屏幕边缘，也避开酒馆顶部工具栏。
    return {
      x: Math.round(clamp(viewport.width * 0.12, 36, 72)),
      y: Math.round(clamp(viewport.height * 0.18, 128, 190)),
    };
  }

  function clampFloatingPosition(position) {
    const viewport = floatingViewportSize();
    const fallback = defaultFloatingPosition();
    const rawX = Number(position?.x);
    const rawY = Number(position?.y);
    return {
      x: Math.round(clamp(Number.isFinite(rawX) ? rawX : fallback.x, FLOATING_MARGIN, Math.max(FLOATING_MARGIN, viewport.width - FLOATING_SIZE - FLOATING_MARGIN))),
      y: Math.round(clamp(Number.isFinite(rawY) ? rawY : fallback.y, FLOATING_MARGIN, Math.max(FLOATING_MARGIN, viewport.height - FLOATING_SIZE - FLOATING_MARGIN))),
    };
  }

  function readFloatingPosition() {
    try {
      const raw = host.localStorage?.getItem(FLOATING_POSITION_KEY);
      if (raw) return clampFloatingPosition(JSON.parse(raw));
      // 旧版坐标可能贴在底部栏下方。首次运行本版时清掉旧键并采用新的安全默认位置。
      FLOATING_LEGACY_POSITION_KEYS.forEach((key) => host.localStorage?.removeItem(key));
    } catch (error) {
      console.warn('[像素拓麻歌子] 读取悬浮球位置失败：', error);
    }
    return writeFloatingPosition(defaultFloatingPosition());
  }

  function writeFloatingPosition(position) {
    const next = clampFloatingPosition(position);
    try {
      host.localStorage?.setItem(FLOATING_POSITION_KEY, JSON.stringify(next));
    } catch (error) {
      console.warn('[像素拓麻歌子] 保存悬浮球位置失败：', error);
    }
    return next;
  }

  function placeFloatingBall(position, persist = false) {
    if (!app.floatingHost) return;
    const next = persist ? writeFloatingPosition(position) : clampFloatingPosition(position);
    app.floatingHost.style.setProperty('left', `${next.x}px`, 'important');
    app.floatingHost.style.setProperty('top', `${next.y}px`, 'important');
    app.floatingHost.style.removeProperty('right');
    app.floatingHost.style.removeProperty('bottom');
  }

  function resetFloatingBallPosition(showNotice = false) {
    const next = writeFloatingPosition(defaultFloatingPosition());
    placeFloatingBall(next);
    if (showNotice) notify('success', '悬浮球已复位到页面左上方内侧。');
  }

  function createFloatingBall() {
    [...doc.querySelectorAll(`#${FLOATING_ID},[data-pixel-tamagotchi-floating="true"]`)].forEach((node) => node.remove());
    if (app.floatingResizeHandler) {
      host.removeEventListener('resize', app.floatingResizeHandler);
      host.visualViewport?.removeEventListener('resize', app.floatingResizeHandler);
      app.floatingResizeHandler = null;
    }

    const floatingHost = doc.createElement('div');
    floatingHost.id = FLOATING_ID;
    floatingHost.setAttribute('data-pixel-tamagotchi-floating', 'true');
    floatingHost.style.setProperty('all', 'initial', 'important');
    floatingHost.style.setProperty('position', 'fixed', 'important');
    floatingHost.style.setProperty('width', `${FLOATING_SIZE}px`, 'important');
    floatingHost.style.setProperty('height', `${FLOATING_SIZE}px`, 'important');
    floatingHost.style.setProperty('z-index', '2147483647', 'important');
    floatingHost.style.setProperty('display', 'none', 'important');
    floatingHost.style.setProperty('place-items', 'center', 'important');
    floatingHost.style.setProperty('overflow', 'visible', 'important');
    floatingHost.style.setProperty('box-sizing', 'border-box', 'important');
    floatingHost.style.setProperty('visibility', 'visible', 'important');
    floatingHost.style.setProperty('opacity', '1', 'important');
    floatingHost.style.setProperty('pointer-events', 'auto', 'important');
    floatingHost.style.setProperty('margin', '0', 'important');
    floatingHost.style.setProperty('padding', '0', 'important');
    floatingHost.style.setProperty('transform', 'none', 'important');
    floatingHost.style.setProperty('user-select', 'none', 'important');
    floatingHost.style.setProperty('-webkit-user-select', 'none', 'important');

    const shadow = floatingHost.attachShadow({ mode: 'open' });
    shadow.innerHTML = `<style>
      :host{display:var(--ptg-floating-display,grid)!important;place-items:center!important;position:fixed!important;width:${FLOATING_SIZE}px!important;height:${FLOATING_SIZE}px!important;pointer-events:auto!important;box-sizing:border-box!important;contain:layout style!important;overflow:visible!important;--fab-border:#263532;--fab-bg1:#f6df8d;--fab-bg2:#d8ae4e;--fab-shadow:#6f572d}
      button{all:unset;box-sizing:border-box;position:relative;width:${FLOATING_BUTTON_SIZE}px;height:${FLOATING_BUTTON_SIZE}px;display:flex;align-items:center;justify-content:center;cursor:grab;border:3px solid var(--fab-border);border-radius:50%;background:linear-gradient(145deg,var(--fab-bg1),var(--fab-bg2));box-shadow:0 2px 7px #0004,0 0 0 1px #0002;overflow:hidden;touch-action:none;user-select:none;-webkit-user-select:none;transform-origin:center}
      button:focus-visible{outline:3px solid #fff;outline-offset:2px}
      button.dragging{cursor:grabbing;box-shadow:0 1px 4px #0004;transform:scale(.96)}
      button:not(.dragging):active{transform:scale(.94);box-shadow:0 1px 3px #0004}
      svg{width:35px;height:35px;display:block;image-rendering:pixelated;filter:none;animation:floatBob 1.8s steps(2,end) infinite;pointer-events:none}
      button.dragging svg{animation:none}.ptg-alert-dot{position:absolute;right:3px;top:3px;width:11px;height:11px;border-radius:50%;background:#e53935;border:2px solid #fff;box-shadow:0 1px 0 #7a1212,0 0 0 1px #263532;animation:alertPulse 1.1s steps(2,end) infinite;pointer-events:none}@keyframes alertPulse{0%,100%{transform:scale(1)}50%{transform:scale(.72)}}
      @keyframes floatBob{0%,100%{transform:translateY(0)}50%{transform:translateY(-3px)}}
    </style><button type="button" aria-label="打开像素拓麻歌子" title="拖动移动，点击打开"></button>`;
    (doc.body || doc.documentElement).appendChild(floatingHost);
    app.floatingHost = floatingHost;
    app.floatingShadow = shadow;
    placeFloatingBall(readFloatingPosition());

    const button = shadow.querySelector('button');
    let dragState = null;
    let suppressClick = false;

    button?.addEventListener('pointerdown', (event) => {
      if (event.pointerType === 'mouse' && event.button !== 0) return;
      const rect = floatingHost.getBoundingClientRect();
      dragState = {
        pointerId: event.pointerId,
        startClientX: event.clientX,
        startClientY: event.clientY,
        startLeft: rect.left,
        startTop: rect.top,
        moved: false,
      };
      button.setPointerCapture?.(event.pointerId);
      button.classList.add('dragging');
      event.preventDefault();
      event.stopPropagation();
    });

    button?.addEventListener('pointermove', (event) => {
      if (!dragState || event.pointerId !== dragState.pointerId) return;
      const dx = event.clientX - dragState.startClientX;
      const dy = event.clientY - dragState.startClientY;
      if (!dragState.moved && Math.hypot(dx, dy) >= 5) dragState.moved = true;
      if (!dragState.moved) return;
      placeFloatingBall({ x: dragState.startLeft + dx, y: dragState.startTop + dy });
      event.preventDefault();
      event.stopPropagation();
    });

    const finishDrag = (event) => {
      if (!dragState || event.pointerId !== dragState.pointerId) return;
      const moved = dragState.moved;
      dragState = null;
      button?.classList.remove('dragging');
      try { button?.releasePointerCapture?.(event.pointerId); } catch (_) {}
      if (moved) {
        const rect = floatingHost.getBoundingClientRect();
        placeFloatingBall({ x: rect.left, y: rect.top }, true);
        suppressClick = true;
        host.setTimeout(() => { suppressClick = false; }, 250);
      } else if (event.type === 'pointerup') {
        // 触屏环境中 pointerdown 的 preventDefault 可能阻止后续 click，轻点时直接打开。
        suppressClick = true;
        openPanel();
        host.setTimeout(() => { suppressClick = false; }, 250);
      }
      event.preventDefault();
      event.stopPropagation();
    };

    button?.addEventListener('pointerup', finishDrag);
    button?.addEventListener('pointercancel', finishDrag);
    button?.addEventListener('click', (event) => {
      event.preventDefault();
      event.stopPropagation();
      if (suppressClick) return;
      openPanel();
    });

    app.floatingResizeHandler = () => {
      if (app.floatingHost) {
        const rect = app.floatingHost.getBoundingClientRect();
        placeFloatingBall({ x: rect.left, y: rect.top }, true);
      }
      applyDeviceScale();
    };
    host.addEventListener('resize', app.floatingResizeHandler, { passive: true });
    host.visualViewport?.addEventListener('resize', app.floatingResizeHandler, { passive: true });
    updateFloatingButton();
  }

