    `;
  }

  function createDom() {
    doc.getElementById(APP_ID)?.remove();
    doc.getElementById(STYLE_ID)?.remove();
    doc.getElementById(CARE_LOG_STYLE_ID)?.remove();
    [...doc.querySelectorAll(`#${FLOATING_ID},[data-pixel-tamagotchi-floating="true"]`)].forEach((node) => node.remove());
    app.root = null;
    app.importInput = null;
    app.mainDomReady = false;

    // 首次加载只注入聊天记录样式和悬浮球；完整掌机 CSS/DOM 延迟到玩家第一次打开时创建。
    const careStyle = doc.createElement('style');
    careStyle.id = CARE_LOG_STYLE_ID;
    careStyle.textContent = buildCareLogStyle();
    doc.head.appendChild(careStyle);
    createFloatingBall();
  }

  function ensureMainDom() {
    if (app.mainDomReady && app.root?.isConnected && doc.getElementById(STYLE_ID)) return true;
    doc.getElementById(APP_ID)?.remove();
    doc.getElementById(STYLE_ID)?.remove();
    app.importInput?.remove?.();

    const style = doc.createElement('style');
    style.id = STYLE_ID;
    style.textContent = buildStyle();
    doc.head.appendChild(style);

    const root = doc.createElement('div');
    root.id = APP_ID;
    root.innerHTML = `<button type="button" class="ptg-message-banner" aria-live="polite" aria-label="关闭拓麻歌子并查看角色新消息" hidden><span class="ptg-message-banner-icon" aria-hidden="true">▣</span><span class="ptg-message-banner-copy"><strong data-message-banner-text>角色给你发送了一条新消息~</strong><small>点击关闭掌机并返回聊天</small></span><span class="ptg-message-banner-arrow" aria-hidden="true">›</span></button><div class="ptg-backdrop" role="dialog" aria-modal="true" aria-label="像素拓麻歌子"><div class="ptg-device" role="document"></div></div>`;
    doc.body.appendChild(root);
    app.root = root;

    const input = doc.createElement('input');
    input.type = 'file';
    input.accept = '.json,application/json';
    input.hidden = true;
    input.addEventListener('change', () => handleImportedFile(input.files?.[0]));
    doc.body.appendChild(input);
    app.importInput = input;

    root.querySelector('.ptg-message-banner')?.addEventListener('click', (event) => {
      event.preventDefault();
      event.stopPropagation();
      playSfx('back');
      closePanel();
    });
    root.querySelector('.ptg-backdrop')?.addEventListener('click', (event) => {
      if (event.target === event.currentTarget) { playSfx('back'); closePanel(); }
    });
    host.removeEventListener('keydown', onKeydown, true);
    host.removeEventListener('keyup', onKeyup, true);
    host.addEventListener('keydown', onKeydown, true);
    host.addEventListener('keyup', onKeyup, true);
    app.mainDomReady = true;
    return true;
  }

  const GAME_KEY_CODES = new Set([
    'KeyW', 'KeyA', 'KeyS', 'KeyD', 'Space',
    'ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight',
  ]);

  function isEditableKeyboardTarget(target) {
    if (!target || typeof target !== 'object') return false;
    const tag = String(target.tagName || '').toUpperCase();
    return tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || Boolean(target.isContentEditable);
  }

  function gameKeyboardIsActive() {
    if (!app.root?.classList.contains('ptg-open') || app.activeTab !== 'games') return false;
    const gameId = app.games.selected;
    const state = gameState(gameId);
    return Boolean(gameId && state && state.status === 'running');
  }

  function consumeKeyboardEvent(event) {
    event.preventDefault();
    event.stopPropagation();
    if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
  }

  function onKeydown(event) {
    const panelOpen = app.root?.classList.contains('ptg-open');
    if (event.key === 'Escape' && panelOpen) {
      consumeKeyboardEvent(event);
      playSfx('back');
      closePanel();
      return;
    }

    if (!gameKeyboardIsActive()) return;
    if (event.isComposing || event.ctrlKey || event.metaKey || event.altKey || isEditableKeyboardTarget(event.target)) return;
    if (!GAME_KEY_CODES.has(event.code)) return;

    // 游戏运行时先在捕获阶段吃掉按键，避免酒馆自己的快捷键先收到事件。
    consumeKeyboardEvent(event);

    // 方向键仅被屏蔽，不再控制游戏；PC 端统一使用 W/A/S/D。
    if (event.code.startsWith('Arrow')) return;

    const gameId = app.games.selected;
    if (gameId === 'tetris') {
      if (event.code === 'KeyA') moveTetris(-1, 0);
      else if (event.code === 'KeyD') moveTetris(1, 0);
      else if (event.code === 'KeyS') moveTetris(0, 1, true);
      else if (event.code === 'KeyW') rotateTetris();
      else if (event.code === 'Space') hardDropTetris();
      else return;
    } else if (gameId === 'snake') {
      if (event.code === 'KeyW') setSnakeDirection('up');
      else if (event.code === 'KeyS') setSnakeDirection('down');
      else if (event.code === 'KeyA') setSnakeDirection('left');
      else if (event.code === 'KeyD') setSnakeDirection('right');
      else return;
    } else if (gameId === '2048') {
      if (event.code === 'KeyW') move2048('up');
      else if (event.code === 'KeyS') move2048('down');
      else if (event.code === 'KeyA') move2048('left');
      else if (event.code === 'KeyD') move2048('right');
      else return;
    } else if (gameId === 'watermelon') {
      if (event.code === 'KeyA') adjustWatermelonAim(-18);
      else if (event.code === 'KeyD') adjustWatermelonAim(18);
      else if (event.code === 'Space' || event.code === 'KeyS') watermelonDropCurrent();
      else return;
      return;
    } else if (gameId === 'bulletHell') {
      if (['KeyW', 'KeyA', 'KeyS', 'KeyD'].includes(event.code)) {
        app.games.bulletHellKeys?.add?.(event.code);
        syncRealtimeWorkerInput();
        return;
      }
      return;
    } else if (gameId === 'petRogue') {
      if (['KeyW', 'KeyA', 'KeyS', 'KeyD'].includes(event.code)) { app.games.petRogueKeys?.add?.(event.code); syncRealtimeWorkerInput(); return; }
      if (event.code === 'Space') { requestPetRogueDash(app.games.petRogue); return; }
      return;
    } else return;

    render();
  }

  function onKeyup(event) {
    if (!gameKeyboardIsActive()) return;
    if (event.isComposing || event.ctrlKey || event.metaKey || event.altKey || isEditableKeyboardTarget(event.target)) return;
    if (app.games.selected === 'bulletHell' && ['KeyW', 'KeyA', 'KeyS', 'KeyD'].includes(event.code)) { app.games.bulletHellKeys?.delete?.(event.code); syncRealtimeWorkerInput(); }
    if (app.games.selected === 'petRogue' && ['KeyW', 'KeyA', 'KeyS', 'KeyD'].includes(event.code)) { app.games.petRogueKeys?.delete?.(event.code); syncRealtimeWorkerInput(); }
    if (GAME_KEY_CODES.has(event.code)) consumeKeyboardEvent(event);
  }

  function startTimers() {
    stopTimers();
    app.timers.push(host.setInterval(() => {
      app.frame += 1;
      syncGameExtensionsWithScriptStates(false);
      if (app.root?.classList.contains('ptg-open') && app.activeTab === 'home') {
        if (companionPlayState().open) return;
        if (homeScheduleInteractionIsActive() && scheduleInteractionDomMatches()) refreshHomeScheduleLiveText();
        else render();
      }
    }, 650));

    app.timers.push(host.setInterval(() => {
      if (shouldUseGameRuntime()) return;
      if (!app.save || !app.characterContextReady) return;
      const info = getCharacterInfo();
      if (!info || info.key !== app.characterKey) return;
      const beforeLifecycle = app.save.lifecycle;
      settleTime(app.save);
      if (beforeLifecycle === 'alive' && app.save.lifecycle === 'dead') notify('warning', '拓麻歌子已经离开，并被记录在生命纪念册中。');
      saveCurrent();
      if (app.root?.classList.contains('ptg-open')) {
        if (companionPlayState().open) return;
        if (!app.transientAnimation) app.message = getStatusMessage();
        const liveKitchen = app.activeTab === 'games' && app.games.selected === 'kitchen' && app.games.kitchen?.status === 'running';
        const liveMatch3 = app.activeTab === 'games' && app.games.selected === 'match3' && app.games.match3?.status === 'running';
        if (liveKitchen) refreshKitchenView(app.games.kitchen);
        else if (liveMatch3) refreshMatch3View(app.games.match3);
        else render();
      }
    }, 30000));

    app.timers.push(host.setInterval(() => {
      if (!app.root?.classList.contains('ptg-open') || shouldUseGameRuntime()) return;
      const previousName = app.characterName;
      const liveName = refreshLiveCharacterName();
      if (liveName && liveName !== previousName) {
        const label = app.root.querySelector('.ptg-card-name');
        if (label && app.save) label.textContent = `角色卡：${liveName}`;
      }
      if (app.activeTab === 'home') {
        if (companionPlayState().open) return;
        if (homeScheduleInteractionIsActive() && scheduleInteractionDomMatches()) refreshHomeScheduleLiveText();
        else render();
      }
    }, 1000));
  }

  function stopTimers() {
    app.timers.forEach((id) => host.clearInterval(id));
    app.timers = [];
  }

  function destroy() {
    if (app.scrollRenderGuard?.timer) { host.clearTimeout(app.scrollRenderGuard.timer); app.scrollRenderGuard.timer = null; }
    if (app.scrollRenderGuard) app.scrollRenderGuard.pending = false;
    clearCompanionPlayRuntime();
    if (app.pendingSaveTimer && app.characterContextReady) {
      clearPendingSave();
      saveCurrent();
    } else clearPendingSave();
    stopRealtimeGameWorker('script-destroy');
    stopLogicGameWorker('script-destroy');
    stopPerformanceDiagnostics();
    try { if (typeof uninjectPrompts === 'function') uninjectPrompts([CHAR_CARE_PROMPT_ID]); } catch (_) {}
    leaveGameRuntime();
    stopEventSubscriptions();
    pauseActiveGame(false);
    persistGameSnapshot(false);
    saveCurrent();
    clearGameTimer();
    stopTimers();
    clearCharCareScanTimers();
    clearMessageBanner(true);
    if (app.fortuneRollTimer) { host.clearTimeout(app.fortuneRollTimer); app.fortuneRollTimer = null; }
    if (app.fortuneMotionHandler) {
      host.removeEventListener('devicemotion', app.fortuneMotionHandler, true);
      app.fortuneMotionHandler = null;
    }
    if (app.worldbookSyncTimer) {
      host.clearTimeout(app.worldbookSyncTimer);
      app.worldbookSyncTimer = null;
    }
    if (app.leaderboard.syncTimer) {
      host.clearTimeout(app.leaderboard.syncTimer);
      app.leaderboard.syncTimer = null;
    }
    app.leaderboard.requestToken += 1;
    app.leaderboard.uploading.clear();
    closePanel();
    if (app.audio.bgm) {
      try { app.audio.bgm.pause(); app.audio.bgm.removeAttribute('src'); app.audio.bgm.load(); } catch (_) {}
      app.audio.bgm = null;
    }
    if (app.audio.context) { try { void app.audio.context.close(); } catch (_) {} app.audio.context = null; }
    app.audio.noiseBuffer = null;
    host.removeEventListener('keydown', onKeydown, true);
    host.removeEventListener('keyup', onKeyup, true);
    app.root?.remove();
    if (app.floatingResizeHandler) {
      host.removeEventListener('resize', app.floatingResizeHandler);
      host.visualViewport?.removeEventListener('resize', app.floatingResizeHandler);
      app.floatingResizeHandler = null;
    }
    app.floatingHost?.remove();
    app.importInput?.remove();
    doc.getElementById(STYLE_ID)?.remove();
    app.root = null;
    app.floatingHost = null;
    app.floatingShadow = null;
    app.importInput = null;
    app.mainDomReady = false;
    disconnectGameExtensionBus();
    if (petRogueModBus?.api === publicPetRogueModApi) petRogueModBus.api = null;
    if (host.PixelTamagotchiPetRogueModAPI === publicPetRogueModApi) { try { delete host.PixelTamagotchiPetRogueModAPI; } catch (_) { host.PixelTamagotchiPetRogueModAPI = null; } }
    if (host[ACTIVE_INSTANCE_KEY]?.destroy === destroy) { try { delete host[ACTIVE_INSTANCE_KEY]; } catch (_) { host[ACTIVE_INSTANCE_KEY] = null; } }
  }

  function initialize() {
    const previousInstance = host[ACTIVE_INSTANCE_KEY];
    if (previousInstance && previousInstance.destroy && previousInstance.destroy !== destroy) {
      try { previousInstance.destroy(); } catch (error) { console.warn('[像素拓麻歌子] 清理旧运行实例失败：', error); }
    }
    host[ACTIVE_INSTANCE_KEY] = { version: CORE_VERSION, destroy };
    connectGameExtensionBus();
    app.initialized = true;
    try {
      if (typeof replaceScriptButtons === 'function') replaceScriptButtons([{ name: BUTTON_NAME, visible: true }]);
    } catch (error) {
      console.debug('[像素拓麻歌子] 脚本按钮同步失败：', error);
    }
    createDom();
    startPerformanceDiagnostics();
    try { if (typeof uninjectPrompts === 'function') uninjectPrompts(['ptg-live-char-care-state']); } catch (_) {}
    loadCurrentCharacter();
    // 世界书构建延后到首屏与角色档读取完成后，减少刚打开酒馆时的主线程峰值。
    queueWorldbookSync(1200, true);
    startTimers();

    try {
      trackEventSubscription(eventOn(getButtonEvent(BUTTON_NAME), openPanel));
      trackEventSubscription(eventOn(tavern_events.CHAT_CHANGED, () => {
        beginCharacterTransition();
        app.pendingCharCare = null;
        app.processedCharResponses.clear();
        app.processedMessageBanners.clear();
        clearCharCareScanTimers();
        clearMessageBanner(true);
        closePanel();
        scheduleCharacterReload(90);
      }));
      if (tavern_events.CHARACTER_EDITED) trackEventSubscription(eventOn(tavern_events.CHARACTER_EDITED, () => {
        beginCharacterTransition();
        scheduleCharacterReload(90);
      }));
      if (tavern_events.MESSAGE_SENT) trackEventSubscription(eventOn(tavern_events.MESSAGE_SENT, onChatMessageSent));
      if (tavern_events.MESSAGE_RECEIVED) trackEventSubscription(eventOn(tavern_events.MESSAGE_RECEIVED, (messageId) => scheduleAssistantMessageScan(messageId, 320, true)));
      if (tavern_events.GENERATION_ENDED) trackEventSubscription(eventOn(tavern_events.GENERATION_ENDED, (messageId) => scheduleAssistantMessageScan(messageId, 100, true)));
      if (tavern_events.MESSAGE_SWIPED) trackEventSubscription(eventOn(tavern_events.MESSAGE_SWIPED, (messageId) => scheduleAssistantMessageScan(messageId, 260, false)));
    } catch (error) {
      console.warn('[像素拓麻歌子] 部分事件监听注册失败：', error);
    }

    window.addEventListener('pagehide', destroy, { once: true });
    console.info(`[像素拓麻歌子] v${CORE_VERSION} 已加载：小游戏扩展注册表已启用，当前检测到 ${GAME_IDS.length} 个组件。`);
  }

  if (doc.readyState === 'loading') doc.addEventListener('DOMContentLoaded', initialize, { once: true });
  else initialize();
})();
